{
  "name": "OSGB Tetkik Takip",
  "description": "OSGB çalışanları için işe giriş ve periyodik muayene tetkiklerinin takibi, sevk yönetimi ve sonuç analiz uygulaması."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Status {
  PENDING = 'PENDING',       // Bekliyor (Henüz gitmedi)
  AT_HOSPITAL = 'AT_HOSPITAL', // Hastanede / Tetkikte
  AWAITING_RESULT = 'AWAITING_RESULT', // Sonuç Bekleniyor
  COMPLETED = 'COMPLETED',   // Tamamlandı
  CANCELLED = 'CANCELLED'    // İptal
}

export enum ExamType {
  AUDIOMETRY = 'Odyometri',
  LUNG_XRAY = 'Akciğer Grafisi',
  HEMOGRAM = 'Hemogram',
  VISION = 'Göz Muayenesi',
  EKG = 'EKG',
  TETANUS = 'Tetanoz Aşısı',
  BLOOD_SUGAR = 'Açlık Kan Şekeri',
  LIVER_FUNC = 'Karaciğer Fonksiyon Testleri'
}

export interface Employee {
  id: string;
  fullName: string;
  tcNo: string;
  company: string;
  department?: string;
}

export interface Referral {
  id: string;
  employee: Employee;
  exams: ExamType[];
  status: Status;
  referralDate: string; // ISO Date string
  notes?: string;
  aiAnalysis?: string; // Gemini analysis result
  resultSummary?: string;
}

export interface Stats {
  total: number;
  pending: number;
  completed: number;
  today: number;
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  FileText, 
  Settings, 
  Plus, 
  Search,
  Activity,
  LogOut,
  Stethoscope
} from 'lucide-react';
import { ReferralList } from './components/ReferralList';
import { NewReferralModal } from './components/NewReferralModal';
import { StatsCards } from './components/StatsCards';
import { Referral, Status, ExamType } from './types';
import { loadReferrals, saveReferrals } from './services/storage';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'referrals' | 'settings'>('dashboard');
  const [referrals, setReferrals] = useState<Referral[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Initial load
  useEffect(() => {
    const data = loadReferrals();
    setReferrals(data);
  }, []);

  // Save on change
  useEffect(() => {
    saveReferrals(referrals);
  }, [referrals]);

  const handleCreateReferral = (referral: Referral) => {
    setReferrals(prev => [referral, ...prev]);
    setIsModalOpen(false);
  };

  const handleUpdateStatus = (id: string, newStatus: Status) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, status: newStatus } : r
    ));
  };

  const handleAnalyze = (id: string, analysis: string) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, aiAnalysis: analysis } : r
    ));
  };

  const handleDelete = (id: string) => {
    if(window.confirm('Bu kaydı silmek istediğinize emin misiniz?')) {
      setReferrals(prev => prev.filter(r => r.id !== id));
    }
  };

  const filteredReferrals = useMemo(() => {
    return referrals.filter(r => 
      r.employee.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.company.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.tcNo.includes(searchTerm)
    );
  }, [referrals, searchTerm]);

  const stats = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    return {
      total: referrals.length,
      pending: referrals.filter(r => r.status === Status.PENDING || r.status === Status.AT_HOSPITAL).length,
      completed: referrals.filter(r => r.status === Status.COMPLETED).length,
      today: referrals.filter(r => r.referralDate.startsWith(todayStr)).length
    };
  }, [referrals]);

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 text-white hidden md:flex flex-col shadow-xl">
        <div className="p-6 flex items-center space-x-3 border-b border-slate-700">
          <div className="p-2 bg-blue-500 rounded-lg">
            <Stethoscope className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight">OSGB Pro</h1>
            <p className="text-xs text-slate-400">Tetkik Takip Sistemi</p>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'dashboard' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-300 hover:bg-slate-800'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            <span className="font-medium">Genel Bakış</span>
          </button>

          <button 
            onClick={() => setActiveTab('referrals')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'referrals' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-300 hover:bg-slate-800'}`}
          >
            <Users className="w-5 h-5" />
            <span className="font-medium">Personel Takibi</span>
          </button>

          <button 
            onClick={() => setActiveTab('settings')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'settings' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-300 hover:bg-slate-800'}`}
          >
            <Settings className="w-5 h-5" />
            <span className="font-medium">Ayarlar</span>
          </button>
        </nav>

        <div className="p-4 border-t border-slate-700">
          <div className="flex items-center space-x-3 text-slate-400 hover:text-white cursor-pointer px-4 py-2">
            <LogOut className="w-5 h-5" />
            <span>Çıkış Yap</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative">
        {/* Header */}
        <header className="h-16 bg-white border-b border-gray-200 flex items-center justify-between px-8 shadow-sm z-10">
          <h2 className="text-xl font-semibold text-gray-800">
            {activeTab === 'dashboard' ? 'Kontrol Paneli' : 
             activeTab === 'referrals' ? 'Tetkik & Sevk Listesi' : 'Ayarlar'}
          </h2>

          <div className="flex items-center space-x-4">
             <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-4 h-4" />
              <input 
                type="text"
                placeholder="Personel veya Firma ara..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10 pr-4 py-2 border border-gray-300 rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 w-64 transition-all"
              />
            </div>
            <button 
              onClick={() => setIsModalOpen(true)}
              className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-md active:transform active:scale-95"
            >
              <Plus className="w-4 h-4" />
              <span>Yeni Sevk Oluştur</span>
            </button>
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-auto p-8">
          {activeTab === 'dashboard' && (
            <div className="space-y-6">
              <StatsCards stats={stats} />
              <div className="mt-8">
                <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
                  <Activity className="w-5 h-5 mr-2 text-blue-600" />
                  Son Hareketler
                </h3>
                <ReferralList 
                  referrals={filteredReferrals.slice(0, 5)} 
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                  compact
                />
              </div>
            </div>
          )}

          {activeTab === 'referrals' && (
            <div className="h-full flex flex-col">
               <ReferralList 
                  referrals={filteredReferrals} 
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                />
            </div>
          )}

          {activeTab === 'settings' && (
             <div className="bg-white p-8 rounded-xl border border-gray-200 shadow-sm max-w-2xl">
                <h3 className="text-lg font-medium mb-4">Uygulama Ayarları</h3>
                <p className="text-gray-500 text-sm">Bu demo sürümünde ayarlar pasiftir.</p>

                <div className="mt-6 space-y-4">
                  <div className="flex items-center justify-between py-4 border-b">
                    <div>
                      <h4 className="font-medium text-gray-900">Karanlık Mod</h4>
                      <p className="text-sm text-gray-500">Arayüz temasını değiştir</p>
                    </div>
                    <div className="w-11 h-6 bg-gray-200 rounded-full cursor-not-allowed"></div>
                  </div>
                  <div className="flex items-center justify-between py-4 border-b">
                    <div>
                      <h4 className="font-medium text-gray-900">Veri Yedekleme</h4>
                      <p className="text-sm text-gray-500">Otomatik yedekleme sıklığı</p>
                    </div>
                    <select className="border rounded p-1 text-sm bg-gray-50" disabled>
                      <option>Günlük</option>
                    </select>
                  </div>
                </div>
             </div>
          )}
        </div>
      </main>

      {/* Modal */}
      {isModalOpen && (
        <NewReferralModal 
          onClose={() => setIsModalOpen(false)} 
          onSubmit={handleCreateReferral} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { X, Building2, User, CreditCard, Activity } from 'lucide-react';
import { Referral, Status, ExamType } from '../types';
import { v4 as uuidv4 } from 'uuid'; // We'll implement a simple mock uuid since external deps might be tricky in pure React view, but I'll use a simple random string gen

interface NewReferralModalProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
}

export const NewReferralModal: React.FC<NewReferralModalProps> = ({ onClose, onSubmit }) => {
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');
  const [company, setCompany] = useState('');
  const [selectedExams, setSelectedExams] = useState<ExamType[]>([]);
  const [notes, setNotes] = useState('');

  const toggleExam = (exam: ExamType) => {
    setSelectedExams(prev => 
      prev.includes(exam) ? prev.filter(e => e !== exam) : [...prev, exam]
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!fullName || !company) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        company
      },
      exams: selectedExams.length > 0 ? selectedExams : [ExamType.HEMOGRAM, ExamType.LUNG_XRAY],
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes
    };

    onSubmit(newReferral);
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh]">
        <div className="px-6 py-4 border-b border-gray-200 flex justify-between items-center bg-gray-50">
          <h3 className="text-lg font-bold text-gray-800">Yeni Tetkik Sevki Oluştur</h3>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 hover:bg-gray-200 rounded-full p-1 transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6">
          <form id="referralForm" onSubmit={handleSubmit} className="space-y-6">

            {/* Personal Info Section */}
            <div className="space-y-4">
              <h4 className="text-sm font-semibold text-gray-500 uppercase tracking-wider mb-3">Personel Bilgileri</h4>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Ad Soyad</label>
                  <div className="relative">
                    <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                    <input 
                      required
                      type="text" 
                      value={fullName}
                      onChange={e => setFullName(e.target.value)}
                      className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                      placeholder="Örn: Ahmet Yılmaz"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">TC Kimlik No</label>
                  <div className="relative">
                    <CreditCard className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                    <input 
                      type="text" 
                      maxLength={11}
                      value={tcNo}
                      onChange={e => setTcNo(e.target.value.replace(/\D/g,''))}
                      className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                      placeholder="11 haneli TC no"
                    />
                  </div>
                </div>
                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-1">Firma Adı</label>
                  <div className="relative">
                    <Building2 className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                    <input 
                      required
                      type="text" 
                      value={company}
                      onChange={e => setCompany(e.target.value)}
                      className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                      placeholder="Örn: Mega İnşaat A.Ş."
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Exams Section */}
            <div className="space-y-4 pt-4 border-t border-gray-100">
               <h4 className="text-sm font-semibold text-gray-500 uppercase tracking-wider mb-3">İstenen Tetkikler</h4>
               <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                  {Object.values(ExamType).map((exam) => (
                    <div 
                      key={exam}
                      onClick={() => toggleExam(exam)}
                      className={`cursor-pointer p-3 rounded-lg border flex items-center space-x-2 transition-all ${
                        selectedExams.includes(exam) 
                        ? 'border-blue-500 bg-blue-50 text-blue-700 shadow-sm' 
                        : 'border-gray-200 hover:bg-gray-50 text-gray-600'
                      }`}
                    >
                      <div className={`w-4 h-4 rounded border flex items-center justify-center ${selectedExams.includes(exam) ? 'bg-blue-500 border-blue-500' : 'border-gray-300 bg-white'}`}>
                        {selectedExams.includes(exam) && <Activity className="w-3 h-3 text-white" />}
                      </div>
                      <span className="text-sm font-medium">{exam}</span>
                    </div>
                  ))}
               </div>
            </div>

            {/* Notes Section */}
             <div className="space-y-4 pt-4 border-t border-gray-100">
               <label className="block text-sm font-medium text-gray-700 mb-1">Notlar</label>
               <textarea 
                  value={notes}
                  onChange={e => setNotes(e.target.value)}
                  className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none h-24 text-sm"
                  placeholder="Eklemek istediğiniz notlar..."
               />
             </div>

          </form>
        </div>

        <div className="px-6 py-4 bg-gray-50 border-t border-gray-200 flex justify-end space-x-3">
          <button 
            type="button"
            onClick={onClose}
            className="px-4 py-2 text-gray-700 font-medium hover:bg-gray-200 rounded-lg transition-colors"
          >
            İptal
          </button>
          <button 
            type="submit"
            form="referralForm"
            className="px-6 py-2 bg-blue-600 hover:bg-blue-700 text-white font-medium rounded-lg shadow-md transition-all active:scale-95"
          >
            Sevk Oluştur
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { 
  MoreHorizontal, 
  CheckCircle, 
  Clock, 
  AlertCircle, 
  FileText, 
  Trash2,
  Sparkles
} from 'lucide-react';
import { Referral, Status } from '../types';
import { analyzeResults } from '../services/geminiService';

interface ReferralListProps {
  referrals: Referral[];
  onUpdateStatus: (id: string, status: Status) => void;
  onAnalyze: (id: string, result: string) => void;
  onDelete: (id: string) => void;
  compact?: boolean;
}

export const ReferralList: React.FC<ReferralListProps> = ({ 
  referrals, 
  onUpdateStatus, 
  onAnalyze,
  onDelete,
  compact = false 
}) => {
  const [analyzingId, setAnalyzingId] = useState<string | null>(null);

  const getStatusColor = (status: Status) => {
    switch (status) {
      case Status.COMPLETED: return 'bg-green-100 text-green-700 border-green-200';
      case Status.AT_HOSPITAL: return 'bg-blue-100 text-blue-700 border-blue-200';
      case Status.AWAITING_RESULT: return 'bg-amber-100 text-amber-700 border-amber-200';
      case Status.CANCELLED: return 'bg-red-100 text-red-700 border-red-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const getStatusText = (status: Status) => {
    switch (status) {
      case Status.COMPLETED: return 'Tamamlandı';
      case Status.AT_HOSPITAL: return 'Hastanede';
      case Status.AWAITING_RESULT: return 'Sonuç Bekleniyor';
      case Status.CANCELLED: return 'İptal Edildi';
      default: return 'Bekliyor';
    }
  };

  const handleAIAnalysis = async (referral: Referral) => {
    setAnalyzingId(referral.id);
    try {
      const result = await analyzeResults(referral);
      onAnalyze(referral.id, result);
    } catch (e) {
      alert("Analiz sırasında bir hata oluştu.");
    } finally {
      setAnalyzingId(null);
    }
  };

  if (referrals.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-gray-400 bg-white rounded-xl border border-dashed border-gray-300">
        <FileText className="w-12 h-12 mb-2 opacity-50" />
        <p>Henüz kayıt bulunmamaktadır.</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-gray-50 border-b border-gray-200">
              <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Personel</th>
              <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Firma</th>
              <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Tarih</th>
              <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Tetkikler</th>
              <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Durum</th>
              {!compact && <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider text-right">İşlemler</th>}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {referrals.map((referral) => (
              <tr key={referral.id} className="hover:bg-gray-50 transition-colors group">
                <td className="px-6 py-4">
                  <div className="flex flex-col">
                    <span className="font-medium text-gray-900">{referral.employee.fullName}</span>
                    <span className="text-xs text-gray-500 font-mono">{referral.employee.tcNo}</span>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <span className="text-sm text-gray-700">{referral.employee.company}</span>
                </td>
                <td className="px-6 py-4">
                  <span className="text-sm text-gray-600">
                    {new Date(referral.referralDate).toLocaleDateString('tr-TR')}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <div className="flex flex-wrap gap-1">
                    {referral.exams.slice(0, compact ? 2 : 4).map((exam, i) => (
                      <span key={i} className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-slate-100 text-slate-800 border border-slate-200">
                        {exam}
                      </span>
                    ))}
                    {referral.exams.length > (compact ? 2 : 4) && (
                      <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-gray-100 text-gray-600">
                        +{referral.exams.length - (compact ? 2 : 4)}
                      </span>
                    )}
                  </div>
                </td>
                <td className="px-6 py-4">
                  <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-xs font-medium border ${getStatusColor(referral.status)}`}>
                    {referral.status === Status.COMPLETED && <CheckCircle className="w-3 h-3 mr-1" />}
                    {referral.status === Status.PENDING && <Clock className="w-3 h-3 mr-1" />}
                    {referral.status === Status.AWAITING_RESULT && <AlertCircle className="w-3 h-3 mr-1" />}
                    {getStatusText(referral.status)}
                  </span>
                </td>
                {!compact && (
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end space-x-2">
                       {/* AI Analysis Button */}
                       {referral.status === Status.COMPLETED && !referral.aiAnalysis && (
                         <button 
                            onClick={() => handleAIAnalysis(referral)}
                            disabled={analyzingId === referral.id}
                            className="text-indigo-600 hover:bg-indigo-50 p-2 rounded-lg transition-colors flex items-center space-x-1"
                            title="AI ile Sonuçları Yorumla"
                         >
                            {analyzingId === referral.id ? (
                                <div className="animate-spin h-4 w-4 border-2 border-indigo-600 border-t-transparent rounded-full" />
                            ) : (
                                <Sparkles className="w-4 h-4" />
                            )}
                         </button>
                       )}

                       {referral.aiAnalysis && (
                          <div className="relative group/tooltip">
                            <span className="text-indigo-600 cursor-help bg-indigo-50 px-2 py-1 rounded text-xs border border-indigo-200">
                              AI Raporu
                            </span>
                            <div className="absolute right-0 bottom-full mb-2 w-64 bg-slate-800 text-white text-xs p-3 rounded shadow-lg opacity-0 group-hover/tooltip:opacity-100 pointer-events-none transition-opacity z-50">
                              {referral.aiAnalysis}
                            </div>
                          </div>
                       )}

                      <select 
                        className="text-sm border-gray-300 border rounded-md shadow-sm focus:border-blue-500 focus:ring-blue-500 py-1 px-2 bg-white"
                        value={referral.status}
                        onChange={(e) => onUpdateStatus(referral.id, e.target.value as Status)}
                      >
                        <option value={Status.PENDING}>Bekliyor</option>
                        <option value={Status.AT_HOSPITAL}>Hastanede</option>
                        <option value={Status.AWAITING_RESULT}>Sonuç Bekleniyor</option>
                        <option value={Status.COMPLETED}>Tamamlandı</option>
                        <option value={Status.CANCELLED}>İptal</option>
                      </select>

                      <button 
                        onClick={() => onDelete(referral.id)}
                        className="text-gray-400 hover:text-red-600 hover:bg-red-50 p-2 rounded-lg transition-colors"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </td>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import { Referral } from '../types';

const STORAGE_KEY = 'osgb_referrals_v1';

export const loadReferrals = (): Referral[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  } catch (error) {
    console.error('Failed to load referrals', error);
    return [];
  }
};

export const saveReferrals = (referrals: Referral[]) => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(referrals));
  } catch (error) {
    console.error('Failed to save referrals', error);
  }
};

import { Referral } from '../types';
import { GoogleGenAI } from "@google/genai";

// Note: In a real environment, this would call the actual API. 
// For this demo, we check if key exists, if not we mock it or fail gracefully.
// We strictly follow the provided guidance for @google/genai

export const analyzeResults = async (referral: Referral): Promise<string> => {
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    // Graceful fallback if no API key is provided in the environment
    return new Promise((resolve) => {
      setTimeout(() => {
        resolve("API Anahtarı bulunamadı. (Demo Modu: Hasta işe giriş için uygundur, işitme testi normal sınırlar içerisindedir.)");
      }, 1000);
    });
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    // Construct a prompt based on the referral data
    const prompt = `
      Aşağıdaki OSGB sağlık tarama verilerini analiz et ve işe uygunluk durumu hakkında 
      kısa, profesyonel bir özet yaz (maksimum 2 cümle).

      Personel: ${referral.employee.fullName}
      Tetkikler: ${referral.exams.join(', ')}
      Notlar: ${referral.notes || 'Yok'}

      Varsayım: Sonuçların genel olarak normal olduğunu varsayarak genel bir 'İşe Uygundur' veya 'Takip Gerekir' yorumu yap.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Analiz sonucu alınamadı.";

  } catch (error) {
    console.error("Gemini AI Error:", error);
    return "Analiz sırasında bir hata oluştu. Lütfen manuel kontrol sağlayınız.";
  }
};

