  exams: ExamDefinition[];
}

export const NewReferralModal: React.FC<NewReferralModalProps> = ({ onClose, onSubmit, companies, exams }) => {
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');

  // State for Company selection
  const [selectedCompanyId, setSelectedCompanyId] = useState('');
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);

  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');
  const [estimatedPrice, setEstimatedPrice] = useState(0);

  // Recalculate price when exams change
  useEffect(() => {
    const total = selectedExamIds.reduce((sum, id) => {
      const exam = exams.find(e => e.name === id); // id here is actually the name for legacy reasons or we can map properly
      // Actually, we are storing exam NAMES in the string array in types.ts now to be safe.
      // But let's look at how toggle works.
      // To support legacy and dynamic, let's assume `exams` prop contains all definitions.
      // And selectedExamIds stores the 'name' of the exam (as per previous ExamType logic).
      const price = exam ? exam.price : 0;
      return sum + price;
    }, 0);
    setEstimatedPrice(total);
  }, [selectedExamIds, exams]);

  const handleCompanyChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const companyId = e.target.value;
    setSelectedCompanyId(companyId);

    if (companyId) {
      const company = companies.find(c => c.id === companyId) || null;
      setSelectedCompanyData(company);
      // Auto-select required exams for this company
      if (company) {
        setSelectedExamIds(company.defaultExams);
      }
    } else {
      setSelectedCompanyData(null);
      setSelectedExamIds([]);
    }
  };

  const toggleExam = (examName: string) => {
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const getHazardClassColor = (hazard: HazardClass) => {
    switch (hazard) {
      case HazardClass.VERY_DANGEROUS: return 'bg-red-500/10 text-red-400 border-red-500/20';
      case HazardClass.DANGEROUS: return 'bg-orange-500/10 text-orange-400 border-orange-500/20';
      case HazardClass.LESS: return 'bg-green-500/10 text-green-400 border-green-500/20';
      default: return 'bg-slate-700 text-slate-300';
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!fullName || !selectedCompanyData) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        company: selectedCompanyData.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData.assignedDoctor,
      specialistName: selectedCompanyData.assignedSpecialist,
      totalPrice: estimatedPrice
    };

    onSubmit(newReferral);
  };

  return (
    <div className="fixed inset-0 bg-black/70 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-slate-800 rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh] border border-slate-700">
        <div className="px-6 py-4 border-b border-slate-700 flex justify-between items-center bg-slate-900/50">
          <h3 className="text-lg font-bold text-white">Yeni Tetkik Sevki Oluştur</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-white hover:bg-slate-700 rounded-full p-1 transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">
          <form id="referralForm" onSubmit={handleSubmit} className="space-y-6">

            {/* Personal Info Section */}
            <div className="space-y-4">
              <h4 className="text-sm font-semibold text-slate-500 uppercase tracking-wider mb-3">Personel Bilgileri</h4>

              <div>
                  <label className="block text-sm font-medium text-slate-300 mb-1">Firma Seçimi</label>
                  <div className="relative">
                    <Building2 className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                    <select
                      required
                      value={selectedCompanyId}
                      onChange={handleCompanyChange}
                      className="w-full pl-10 pr-10 py-2 bg-slate-900 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all appearance-none"
                    >
                      <option value="" className="bg-slate-800 text-slate-400">Firma Seçiniz...</option>
                      {companies.map(c => (
                        <option key={c.id} value={c.id} className="bg-slate-800 text-white">{c.name}</option>
                      ))}
                    </select>
                  </div>
              </div>

              {selectedCompanyData && (
                <div className="bg-slate-900/50 p-4 rounded-lg border border-slate-700 grid grid-cols-1 md:grid-cols-2 gap-4 animate-fadeIn">
                  <div className="md:col-span-2 flex items-center space-x-2">
                    <span className="text-sm text-slate-400 font-medium">Tehlike Sınıfı:</span>
                    <span className={`text-xs px-2 py-1 rounded-full border font-medium flex items-center ${getHazardClassColor(selectedCompanyData.hazardClass)}`}>
                      <AlertTriangle className="w-3 h-3 mr-1" />
                      {selectedCompanyData.hazardClass}
                    </span>
                  </div>

                  <div className="flex items-start space-x-2">
                    <Stethoscope className="w-4 h-4 text-blue-500 mt-1" />
                    <div>
                      <p className="text-xs text-slate-500">İşyeri Hekimi</p>
                      <p className="text-sm font-medium text-slate-200">{selectedCompanyData.assignedDoctor}</p>
                    </div>
                  </div>

                  <div className="flex items-start space-x-2">
                    <ShieldCheck className="w-4 h-4 text-emerald-500 mt-1" />
                    <div>
                      <p className="text-xs text-slate-500">İSG Uzmanı</p>
                      <p className="text-sm font-medium text-slate-200">{selectedCompanyData.assignedSpecialist}</p>
                    </div>
                  </div>
                </div>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-300 mb-1">Ad Soyad</label>
                  <div className="relative">
                    <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                    <input 
                      required
                      type="text" 
                      value={fullName}
                      onChange={e => setFullName(e.target.value)}
                      className="w-full pl-10 pr-3 py-2 bg-slate-900 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all placeholder-slate-600"
                      placeholder="Örn: Ahmet Yılmaz"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-300 mb-1">TC Kimlik No</label>
                  <div className="relative">
                    <CreditCard className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                    <input 
                      type="text" 
                      maxLength={11}
                      value={tcNo}
                      onChange={e => setTcNo(e.target.value.replace(/\D/g,''))}
                      className="w-full pl-10 pr-3 py-2 bg-slate-900 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all placeholder-slate-600"
                      placeholder="11 haneli TC no"
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Exams Section */}
            <div className="space-y-4 pt-4 border-t border-slate-700">
               <div className="flex justify-between items-center mb-3">
                  <h4 className="text-sm font-semibold text-slate-500 uppercase tracking-wider">İstenen Tetkikler</h4>
                  <div className="text-right">
                    <p className="text-xs text-slate-400">Tahmini Toplam</p>
                    <p className="text-lg font-bold text-emerald-400">₺{estimatedPrice.toLocaleString('tr-TR')}</p>
                  </div>
               </div>

               <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                  {exams.map((exam) => (
                    <div 
                      key={exam.id}
                      onClick={() => toggleExam(exam.name)}
                      className={`cursor-pointer p-3 rounded-lg border flex flex-col justify-between transition-all ${
                        selectedExamIds.includes(exam.name) 
                        ? 'border-blue-500 bg-blue-500/10 text-blue-400 shadow-sm' 
                        : 'border-slate-700 hover:bg-slate-700 text-slate-400'
                      }`}
                    >
                      <div className="flex items-center space-x-2">
                        <div className={`w-4 h-4 min-w-[16px] rounded border flex items-center justify-center ${selectedExamIds.includes(exam.name) ? 'bg-blue-500 border-blue-500' : 'border-slate-600 bg-slate-800'}`}>
                          {selectedExamIds.includes(exam.name) && <Activity className="w-3 h-3 text-white" />}
                        </div>
                        <span className="text-sm font-medium truncate">{exam.name}</span>
                      </div>
                      <span className="text-xs text-right mt-2 opacity-70">₺{exam.price}</span>
                    </div>
                  ))}
               </div>
            </div>

            {/* Notes Section */}
             <div className="space-y-4 pt-4 border-t border-slate-700">
               <label className="block text-sm font-medium text-slate-300 mb-1">Notlar</label>
               <textarea 
                  value={notes}
                  onChange={e => setNotes(e.target.value)}
                  className="w-full p-3 bg-slate-900 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-blue-500 outline-none h-24 text-sm placeholder-slate-600"
                  placeholder="Eklemek istediğiniz notlar..."
               />
             </div>

          </form>
        </div>

        <div className="px-6 py-4 bg-slate-900/50 border-t border-slate-700 flex justify-end space-x-3">
          <button 
            type="button"
            onClick={onClose}
            className="px-4 py-2 text-slate-300 font-medium hover:bg-slate-700 rounded-lg transition-colors"
          >
            İptal
          </button>
          <button 
            type="submit"
            form="referralForm"
            className="px-6 py-2 bg-blue-600 hover:bg-blue-500 text-white font-medium rounded-lg shadow-lg shadow-blue-900/20 transition-all active:scale-95"
          >
            Sevk Oluştur
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Settings, 
  Plus, 
  Search,
  Activity,
  LogOut,
  Stethoscope,
  Wallet
} from 'lucide-react';
import { ReferralList } from './components/ReferralList';
import { NewReferralModal } from './components/NewReferralModal';
import { StatsCards } from './components/StatsCards';
import { FinanceView } from './components/FinanceView';
import { SettingsView } from './components/SettingsView';
import { Referral, Status, Company, ExamDefinition, SafeTransaction } from './types';
import { 
  loadReferrals, saveReferrals, 
  loadCompanies, saveCompanies,
  loadExams, saveExams,
  loadTransactions, saveTransactions
} from './services/storage';
import { PREDEFINED_COMPANIES, DEFAULT_EXAMS } from './services/initialData';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'referrals' | 'finance' | 'settings'>('dashboard');

  // Data States
  const [referrals, setReferrals] = useState<Referral[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [exams, setExams] = useState<ExamDefinition[]>([]);
  const [transactions, setTransactions] = useState<SafeTransaction[]>([]);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Initial load
  useEffect(() => {
    setReferrals(loadReferrals());
    setCompanies(loadCompanies(PREDEFINED_COMPANIES));
    setExams(loadExams(DEFAULT_EXAMS));
    setTransactions(loadTransactions());
  }, []);

  // Save Effects
  useEffect(() => saveReferrals(referrals), [referrals]);
  useEffect(() => saveCompanies(companies), [companies]);
  useEffect(() => saveExams(exams), [exams]);
  useEffect(() => saveTransactions(transactions), [transactions]);

  // Handlers
  const handleCreateReferral = (referral: Referral) => {
    setReferrals(prev => [referral, ...prev]);
    setIsModalOpen(false);
  };

  const handleUpdateStatus = (id: string, newStatus: Status) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, status: newStatus } : r
    ));

    // Optional: Auto-add income to safe when completed? 
    // keeping manual for now based on specific user request "Kasa yap, kasadan para alma olsun"
  };

  const handleAnalyze = (id: string, analysis: string) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, aiAnalysis: analysis } : r
    ));
  };

  const handleDelete = (id: string) => {
    if(window.confirm('Bu kaydı silmek istediğinize emin misiniz?')) {
      setReferrals(prev => prev.filter(r => r.id !== id));
    }
  };

  // Settings Handlers
  const handleAddCompany = (c: Company) => setCompanies(prev => [...prev, c]);
  const handleDeleteCompany = (id: string) => setCompanies(prev => prev.filter(c => c.id !== id));

  const handleAddExam = (e: ExamDefinition) => setExams(prev => [...prev, e]);
  const handleUpdateExam = (updated: ExamDefinition) => setExams(prev => prev.map(e => e.id === updated.id ? updated : e));
  const handleDeleteExam = (id: string) => setExams(prev => prev.filter(e => e.id !== id));

  // Finance Handlers
  const handleAddTransaction = (t: SafeTransaction) => setTransactions(prev => [...prev, t]);

  const filteredReferrals = useMemo(() => {
    return referrals.filter(r => 
      r.employee.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.company.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.tcNo.includes(searchTerm)
    );
  }, [referrals, searchTerm]);

  const stats = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    return {
      total: referrals.length,
      pending: referrals.filter(r => r.status === Status.PENDING || r.status === Status.AT_HOSPITAL).length,
      completed: referrals.filter(r => r.status === Status.COMPLETED).length,
      today: referrals.filter(r => r.referralDate.startsWith(todayStr)).length
    };
  }, [referrals]);

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 border-r border-slate-800 text-white hidden md:flex flex-col shadow-xl">
        <div className="p-6 flex items-center space-x-3 border-b border-slate-800">
          <div className="p-2 bg-blue-600 rounded-lg shadow-lg shadow-blue-900/20">
            <Stethoscope className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight">OSGB Pro</h1>
            <p className="text-xs text-slate-400">Tetkik Takip Sistemi</p>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'dashboard' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            <span className="font-medium">Genel Bakış</span>
          </button>

          <button 
            onClick={() => setActiveTab('referrals')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'referrals' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Users className="w-5 h-5" />
            <span className="font-medium">Personel Takibi</span>
          </button>

          <button 
            onClick={() => setActiveTab('finance')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'finance' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Wallet className="w-5 h-5" />
            <span className="font-medium">Kasa & Finans</span>
          </button>

          <button 
            onClick={() => setActiveTab('settings')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'settings' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Settings className="w-5 h-5" />
            <span className="font-medium">Ayarlar</span>
          </button>
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="flex items-center space-x-3 text-slate-400 hover:text-white cursor-pointer px-4 py-2 transition-colors">
            <LogOut className="w-5 h-5" />
            <span>Çıkış Yap</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative bg-slate-950">
        {/* Header */}
        <header className="h-16 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-8 shadow-sm z-10">
          <h2 className="text-xl font-semibold text-white">
            {activeTab === 'dashboard' ? 'Kontrol Paneli' : 
             activeTab === 'referrals' ? 'Tetkik & Sevk Listesi' : 
             activeTab === 'finance' ? 'Kasa Yönetimi' : 'Ayarlar'}
          </h2>

          <div className="flex items-center space-x-4">
             <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400 w-4 h-4" />
              <input 
                type="text"
                placeholder="Personel veya Firma ara..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent w-64 transition-all placeholder-slate-500"
              />
            </div>
            <button 
              onClick={() => setIsModalOpen(true)}
              className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-lg shadow-blue-900/20 active:transform active:scale-95"
            >
              <Plus className="w-4 h-4" />
              <span>Yeni Sevk Oluştur</span>
            </button>
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-auto p-8 custom-scrollbar">
          {activeTab === 'dashboard' && (
            <div className="space-y-6">
              <StatsCards stats={stats} />
              <div className="mt-8">
                <h3 className="text-lg font-bold text-white mb-4 flex items-center">
                  <Activity className="w-5 h-5 mr-2 text-blue-500" />
                  Son Hareketler
                </h3>
                <ReferralList 
                  referrals={filteredReferrals.slice(0, 5)} 
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                  compact
                />
              </div>
            </div>
          )}

          {activeTab === 'referrals' && (
            <div className="h-full flex flex-col">
               <ReferralList 
                  referrals={filteredReferrals} 
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                />
            </div>
          )}

          {activeTab === 'finance' && (
            <FinanceView 
              transactions={transactions}
              onAddTransaction={handleAddTransaction}
            />
          )}

          {activeTab === 'settings' && (
             <SettingsView 
                companies={companies}
                onAddCompany={handleAddCompany}
                onDeleteCompany={handleDeleteCompany}
                exams={exams}
                onAddExam={handleAddExam}
                onUpdateExam={handleUpdateExam}
                onDeleteExam={handleDeleteExam}
             />
          )}
        </div>
      </main>

      {/* Modal */}
      {isModalOpen && (
        <NewReferralModal 
          onClose={() => setIsModalOpen(false)} 
          onSubmit={handleCreateReferral}
          companies={companies}
          exams={exams}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Settings, 
  Plus, 
  Search,
  Activity,
  LogOut,
  Stethoscope,
  Wallet
} from 'lucide-react';
import { ReferralList } from './components/ReferralList';
import { NewReferralModal } from './components/NewReferralModal';
import { StatsCards } from './components/StatsCards';
import { FinanceView } from './components/FinanceView';
import { SettingsView } from './components/SettingsView';
import { Referral, Status, Company, ExamDefinition, SafeTransaction } from './types';
import { 
  loadReferrals, saveReferrals, 
  loadCompanies, saveCompanies,
  loadExams, saveExams,
  loadTransactions, saveTransactions
} from './services/storage';
import { PREDEFINED_COMPANIES, DEFAULT_EXAMS } from './services/initialData';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'referrals' | 'finance' | 'settings'>('dashboard');

  // Data States
  const [referrals, setReferrals] = useState<Referral[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [exams, setExams] = useState<ExamDefinition[]>([]);
  const [transactions, setTransactions] = useState<SafeTransaction[]>([]);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Initial load
  useEffect(() => {
    setReferrals(loadReferrals());
    setCompanies(loadCompanies(PREDEFINED_COMPANIES));
    setExams(loadExams(DEFAULT_EXAMS));
    setTransactions(loadTransactions());
  }, []);

  // Save Effects
  useEffect(() => saveReferrals(referrals), [referrals]);
  useEffect(() => saveCompanies(companies), [companies]);
  useEffect(() => saveExams(exams), [exams]);
  useEffect(() => saveTransactions(transactions), [transactions]);

  // Handlers
  const handleCreateReferral = (referral: Referral) => {
    // 1. Add Referral
    setReferrals(prev => [referral, ...prev]);

    // 2. Auto-Add to Safe (Income)
    if (referral.totalPrice && referral.totalPrice > 0) {
      const newTransaction: SafeTransaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'INCOME',
        amount: referral.totalPrice,
        description: `Sevk Geliri: ${referral.employee.fullName} (${referral.employee.company})`,
        date: new Date().toISOString()
      };
      setTransactions(prev => [...prev, newTransaction]);
    }

    setIsModalOpen(false);
  };

  const handleUpdateStatus = (id: string, newStatus: Status) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, status: newStatus } : r
    ));
  };

  const handleAnalyze = (id: string, analysis: string) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, aiAnalysis: analysis } : r
    ));
  };

  const handleDelete = (id: string) => {
    if(window.confirm('Bu kaydı silmek istediğinize emin misiniz?')) {
      setReferrals(prev => prev.filter(r => r.id !== id));
    }
  };

  // Settings Handlers
  const handleAddCompany = (c: Company) => setCompanies(prev => [...prev, c]);
  const handleDeleteCompany = (id: string) => setCompanies(prev => prev.filter(c => c.id !== id));

  const handleAddExam = (e: ExamDefinition) => setExams(prev => [...prev, e]);
  const handleUpdateExam = (updated: ExamDefinition) => setExams(prev => prev.map(e => e.id === updated.id ? updated : e));
  const handleDeleteExam = (id: string) => setExams(prev => prev.filter(e => e.id !== id));

  // Finance Handlers
  const handleAddTransaction = (t: SafeTransaction) => setTransactions(prev => [...prev, t]);

  const filteredReferrals = useMemo(() => {
    return referrals.filter(r => 
      r.employee.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.company.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.tcNo.includes(searchTerm)
    );
  }, [referrals, searchTerm]);

  const stats = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    return {
      total: referrals.length,
      pending: referrals.filter(r => r.status === Status.PENDING || r.status === Status.AT_HOSPITAL).length,
      completed: referrals.filter(r => r.status === Status.COMPLETED).length,
      today: referrals.filter(r => r.referralDate.startsWith(todayStr)).length
    };
  }, [referrals]);

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 border-r border-slate-800 text-white hidden md:flex flex-col shadow-xl">
        <div className="p-6 flex items-center space-x-3 border-b border-slate-800">
          <div className="p-2 bg-blue-600 rounded-lg shadow-lg shadow-blue-900/20">
            <Stethoscope className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight">OSGB Pro</h1>
            <p className="text-xs text-slate-400">Tetkik Takip Sistemi</p>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'dashboard' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            <span className="font-medium">Genel Bakış</span>
          </button>

          <button 
            onClick={() => setActiveTab('referrals')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'referrals' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Users className="w-5 h-5" />
            <span className="font-medium">Personel Takibi</span>
          </button>

          <button 
            onClick={() => setActiveTab('finance')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'finance' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Wallet className="w-5 h-5" />
            <span className="font-medium">Kasa & Finans</span>
          </button>

          <button 
            onClick={() => setActiveTab('settings')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'settings' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Settings className="w-5 h-5" />
            <span className="font-medium">Ayarlar</span>
          </button>
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="flex items-center space-x-3 text-slate-400 hover:text-white cursor-pointer px-4 py-2 transition-colors">
            <LogOut className="w-5 h-5" />
            <span>Çıkış Yap</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative bg-slate-950">
        {/* Header */}
        <header className="h-16 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-8 shadow-sm z-10">
          <h2 className="text-xl font-semibold text-white">
            {activeTab === 'dashboard' ? 'Kontrol Paneli' : 
             activeTab === 'referrals' ? 'Tetkik & Sevk Listesi' : 
             activeTab === 'finance' ? 'Kasa Yönetimi' : 'Ayarlar'}
          </h2>

          <div className="flex items-center space-x-4">
             <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400 w-4 h-4" />
              <input 
                type="text"
                placeholder="Personel veya Firma ara..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent w-64 transition-all placeholder-slate-500"
              />
            </div>
            <button 
              onClick={() => setIsModalOpen(true)}
              className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-lg shadow-blue-900/20 active:transform active:scale-95"
            >
              <Plus className="w-4 h-4" />
              <span>Yeni Sevk Oluştur</span>
            </button>
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-auto p-8 custom-scrollbar">
          {activeTab === 'dashboard' && (
            <div className="space-y-6">
              <StatsCards stats={stats} />
              <div className="mt-8">
                <h3 className="text-lg font-bold text-white mb-4 flex items-center">
                  <Activity className="w-5 h-5 mr-2 text-blue-500" />
                  Son Hareketler
                </h3>
                <ReferralList 
                  referrals={filteredReferrals.slice(0, 5)} 
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                  compact
                />
              </div>
            </div>
          )}

          {activeTab === 'referrals' && (
            <div className="h-full flex flex-col">
               <ReferralList 
                  referrals={filteredReferrals} 
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                />
            </div>
          )}

          {activeTab === 'finance' && (
            <FinanceView 
              transactions={transactions}
              onAddTransaction={handleAddTransaction}
            />
          )}

          {activeTab === 'settings' && (
             <SettingsView 
                companies={companies}
                onAddCompany={handleAddCompany}
                onDeleteCompany={handleDeleteCompany}
                exams={exams}
                onAddExam={handleAddExam}
                onUpdateExam={handleUpdateExam}
                onDeleteExam={handleDeleteExam}
             />
          )}
        </div>
      </main>

      {/* Modal */}
      {isModalOpen && (
        <NewReferralModal 
          onClose={() => setIsModalOpen(false)} 
          onSubmit={handleCreateReferral}
          companies={companies}
          exams={exams}
        />
      )}
    </div>
  );
};

