import React, { useState } from 'react';
import { 
  MoreHorizontal, 
  CheckCircle, 
  Clock, 
  AlertCircle, 
  FileText, 
  Trash2,
  Sparkles
} from 'lucide-react';
import { Referral, Status } from '../types';
import { analyzeResults } from '../services/geminiService';

interface ReferralListProps {
  referrals: Referral[];
  onUpdateStatus: (id: string, status: Status) => void;
  onAnalyze: (id: string, result: string) => void;
  onDelete: (id: string) => void;
  compact?: boolean;
}

export const ReferralList: React.FC<ReferralListProps> = ({ 
  referrals, 
  onUpdateStatus, 
  onAnalyze,
  onDelete,
  compact = false 
}) => {
  const [analyzingId, setAnalyzingId] = useState<string | null>(null);

  const handleAIAnalysis = async (referral: Referral) => {
    setAnalyzingId(referral.id);
    try {
      const result = await analyzeResults(referral);
      onAnalyze(referral.id, result);
    } catch (e) {
      alert("Analiz sırasında bir hata oluştu.");
    } finally {
      setAnalyzingId(null);
    }
  };

  if (referrals.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-slate-500 bg-slate-800 rounded-xl border border-dashed border-slate-700">
        <FileText className="w-12 h-12 mb-2 opacity-50" />
        <p>Henüz kayıt bulunmamaktadır.</p>
      </div>
    );
  }

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-900/50 border-b border-slate-700">
              <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider">Personel</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider">Firma</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider">Tarih</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider">Tetkikler</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider text-right">Tutar</th>
              {!compact && <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider text-right">İşlemler</th>}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-700">
            {referrals.map((referral) => (
              <tr key={referral.id} className="hover:bg-slate-700/30 transition-colors group">
                <td className="px-6 py-4">
                  <div className="flex flex-col">
                    <span className="font-medium text-white">{referral.employee.fullName}</span>
                    <span className="text-xs text-slate-500 font-mono">{referral.employee.tcNo}</span>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <span className="text-sm text-slate-300">{referral.employee.company}</span>
                </td>
                <td className="px-6 py-4">
                  <span className="text-sm text-slate-400">
                    {new Date(referral.referralDate).toLocaleDateString('tr-TR')}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <div className="flex flex-wrap gap-1">
                    {referral.exams.slice(0, compact ? 2 : 4).map((exam, i) => (
                      <span key={i} className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-slate-700 text-slate-300 border border-slate-600">
                        {exam}
                      </span>
                    ))}
                    {referral.exams.length > (compact ? 2 : 4) && (
                      <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-slate-700 text-slate-400">
                        +{referral.exams.length - (compact ? 2 : 4)}
                      </span>
                    )}
                  </div>
                </td>
                <td className="px-6 py-4 text-right">
                   <span className="text-emerald-400 font-medium">₺{referral.totalPrice?.toLocaleString('tr-TR') || 0}</span>
                </td>
                {!compact && (
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end space-x-2">
                       {/* AI Analysis Button */}
                       {/* Simplified: Analysis button only shows if needed, but since we removed status flow, user might want to click it anytime */}
                       {!referral.aiAnalysis && (
                         <button 
                            onClick={() => handleAIAnalysis(referral)}
                            disabled={analyzingId === referral.id}
                            className="text-indigo-400 hover:bg-indigo-500/10 p-2 rounded-lg transition-colors flex items-center space-x-1"
                            title="AI ile Sonuçları Yorumla"
                         >
                            {analyzingId === referral.id ? (
                                <div className="animate-spin h-4 w-4 border-2 border-indigo-500 border-t-transparent rounded-full" />
                            ) : (
                                <Sparkles className="w-4 h-4" />
                            )}
                         </button>
                       )}

                       {referral.aiAnalysis && (
                          <div className="relative group/tooltip">
                            <span className="text-indigo-400 cursor-help bg-indigo-500/10 px-2 py-1 rounded text-xs border border-indigo-500/30">
                              AI Raporu
                            </span>
                            <div className="absolute right-0 bottom-full mb-2 w-64 bg-slate-900 border border-slate-700 text-slate-300 text-xs p-3 rounded shadow-xl opacity-0 group-hover/tooltip:opacity-100 pointer-events-none transition-opacity z-50">
                              {referral.aiAnalysis}
                            </div>
                          </div>
                       )}

                      <button 
                        onClick={() => onDelete(referral.id)}
                        className="text-slate-500 hover:text-red-400 hover:bg-red-500/10 p-2 rounded-lg transition-colors"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </td>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Company, ExamDefinition, HazardClass } from '../types';
import { Trash2, Plus, Building2, TestTube, Save, Check } from 'lucide-react';

interface SettingsViewProps {
  companies: Company[];
  onAddCompany: (c: Company) => void;
  onDeleteCompany: (id: string) => void;
  exams: ExamDefinition[];
  onAddExam: (e: ExamDefinition) => void;
  onUpdateExam: (e: ExamDefinition) => void;
  onDeleteExam: (id: string) => void;
}

export const SettingsView: React.FC<SettingsViewProps> = ({
  companies,
  onAddCompany,
  onDeleteCompany,
  exams,
  onAddExam,
  onUpdateExam,
  onDeleteExam
}) => {
  const [activeTab, setActiveTab] = useState<'companies' | 'exams'>('companies');

  // Company Form State
  const [cName, setCName] = useState('');
  const [cHazard, setCHazard] = useState<HazardClass>(HazardClass.LESS);
  const [cDoctor, setCDoctor] = useState('');
  const [cSpecialist, setCSpecialist] = useState('');
  const [cSelectedExams, setCSelectedExams] = useState<string[]>([]);

  // Exam Form State
  const [eName, setEName] = useState('');
  const [ePrice, setEPrice] = useState('');

  const toggleCompanyExam = (examName: string) => {
    setCSelectedExams(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const handleAddCompany = (e: React.FormEvent) => {
    e.preventDefault();
    if (!cName) return;
    const newCompany: Company = {
      id: Math.random().toString(36).substr(2, 9),
      name: cName,
      hazardClass: cHazard,
      assignedDoctor: cDoctor || 'Belirlenmedi',
      assignedSpecialist: cSpecialist || 'Belirlenmedi',
      defaultExams: cSelectedExams
    };
    onAddCompany(newCompany);
    setCName('');
    setCDoctor('');
    setCSpecialist('');
    setCSelectedExams([]);
  };

  const handleAddExam = (e: React.FormEvent) => {
    e.preventDefault();
    if (!eName || !ePrice) return;
    const newExam: ExamDefinition = {
      id: Math.random().toString(36).substr(2, 9),
      name: eName,
      price: parseFloat(ePrice)
    };
    onAddExam(newExam);
    setEName('');
    setEPrice('');
  };

  const handlePriceUpdate = (id: string, newPrice: string) => {
    const exam = exams.find(e => e.id === id);
    if (exam) {
      onUpdateExam({ ...exam, price: parseFloat(newPrice) });
    }
  };

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden">
      <div className="flex border-b border-slate-700">
        <button
          onClick={() => setActiveTab('companies')}
          className={`flex-1 py-4 text-center font-medium text-sm transition-colors ${activeTab === 'companies' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Firmalar
        </button>
        <button
          onClick={() => setActiveTab('exams')}
          className={`flex-1 py-4 text-center font-medium text-sm transition-colors ${activeTab === 'exams' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Tetkikler ve Fiyatlar
        </button>
      </div>

      <div className="p-6">
        {activeTab === 'companies' && (
          <div className="space-y-8">
            {/* Add Company Form */}
            <form onSubmit={handleAddCompany} className="bg-slate-900/30 p-4 rounded-lg border border-slate-700 space-y-4">
              <h4 className="text-sm font-bold text-white flex items-center">
                <Plus className="w-4 h-4 mr-2" /> Yeni Firma Ekle
              </h4>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <input required placeholder="Firma Adı" value={cName} onChange={e => setCName(e.target.value)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />
                <select value={cHazard} onChange={e => setCHazard(e.target.value as HazardClass)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm outline-none">
                  {Object.values(HazardClass).map(h => <option key={h} value={h}>{h}</option>)}
                </select>
                <input placeholder="İşyeri Hekimi" value={cDoctor} onChange={e => setCDoctor(e.target.value)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />
                <input placeholder="İSG Uzmanı" value={cSpecialist} onChange={e => setCSpecialist(e.target.value)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />
              </div>

              {/* Exam Selection for Company */}
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Firma Standart Tetkikleri</label>
                <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                   {exams.map(exam => (
                     <div 
                      key={exam.id}
                      onClick={() => toggleCompanyExam(exam.name)}
                      className={`cursor-pointer px-3 py-2 rounded border flex items-center justify-between transition-all ${cSelectedExams.includes(exam.name) ? 'bg-blue-600/20 border-blue-500 text-blue-200' : 'bg-slate-800 border-slate-600 text-slate-400 hover:bg-slate-700'}`}
                     >
                       <span className="text-xs truncate mr-2">{exam.name}</span>
                       {cSelectedExams.includes(exam.name) && <Check className="w-3 h-3 text-blue-400" />}
                     </div>
                   ))}
                </div>
              </div>

              <div className="flex justify-end">
                <button type="submit" className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded text-sm">Ekle</button>
              </div>
            </form>

            {/* Company List */}
            <div className="space-y-3">
              {companies.map(company => (
                <div key={company.id} className="flex flex-col md:flex-row items-start md:items-center justify-between p-4 bg-slate-700/30 border border-slate-700 rounded-lg gap-4">
                  <div className="flex items-center space-x-3">
                    <div className="p-2 bg-slate-800 rounded">
                      <Building2 className="w-5 h-5 text-slate-400" />
                    </div>
                    <div>
                      <h5 className="font-medium text-white">{company.name}</h5>
                      <p className="text-xs text-slate-400">{company.assignedDoctor} • {company.assignedSpecialist}</p>
                      <div className="flex flex-wrap gap-1 mt-1">
                        {company.defaultExams.map((ex, i) => (
                           <span key={i} className="text-[10px] px-1.5 py-0.5 bg-slate-800 text-slate-400 rounded border border-slate-600">{ex}</span>
                        ))}
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center space-x-3 w-full md:w-auto justify-end">
                    <span className="text-xs bg-slate-800 px-2 py-1 rounded border border-slate-600 text-slate-300">{company.hazardClass}</span>
                    <button onClick={() => onDeleteCompany(company.id)} className="text-slate-500 hover:text-red-400 p-1">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'exams' && (
          <div className="space-y-8">
            {/* Add Exam Form */}
            <form onSubmit={handleAddExam} className="bg-slate-900/30 p-4 rounded-lg border border-slate-700 space-y-4">
              <h4 className="text-sm font-bold text-white flex items-center">
                <Plus className="w-4 h-4 mr-2" /> Yeni Tetkik Ekle
              </h4>
              <div className="flex gap-4">
                <input required placeholder="Tetkik Adı (Örn: Portör)" value={eName} onChange={e => setEName(e.target.value)} className="flex-1 bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />
                <input required type="number" placeholder="Fiyat (TL)" value={ePrice} onChange={e => setEPrice(e.target.value)} className="w-32 bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />
                <button type="submit" className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded text-sm">Ekle</button>
              </div>
            </form>

            {/* Exam List */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {exams.map(exam => (
                <div key={exam.id} className="flex items-center justify-between p-4 bg-slate-700/30 border border-slate-700 rounded-lg">
                  <div className="flex items-center space-x-3">
                    <TestTube className="w-4 h-4 text-slate-400" />
                    <span className="font-medium text-white text-sm">{exam.name}</span>
                  </div>
                  <div className="flex items-center space-x-2">
                    <div className="relative">
                      <span className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-500 text-xs">₺</span>
                      <input 
                        type="number" 
                        defaultValue={exam.price} 
                        onBlur={(e) => handlePriceUpdate(exam.id, e.target.value)}
                        className="w-20 pl-5 pr-2 py-1 bg-slate-800 border border-slate-600 rounded text-xs text-white text-right focus:border-blue-500 outline-none"
                      />
                    </div>
                    <button onClick={() => onDeleteExam(exam.id)} className="text-slate-500 hover:text-red-400 p-1">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export enum Status {
  PENDING = 'PENDING',       // Bekliyor (Henüz gitmedi)
  AT_HOSPITAL = 'AT_HOSPITAL', // Hastanede / Tetkikte
  AWAITING_RESULT = 'AWAITING_RESULT', // Sonuç Bekleniyor
  COMPLETED = 'COMPLETED',   // Tamamlandı
  CANCELLED = 'CANCELLED'    // İptal
}

// Deprecated enum usage in favor of dynamic list, keeping for type safety in legacy code
export enum ExamType {
  AUDIOMETRY = 'Odyometri',
  LUNG_XRAY = 'Akciğer Grafisi',
  HEMOGRAM = 'Hemogram',
  VISION = 'Göz Muayenesi',
  EKG = 'EKG',
  TETANUS = 'Tetanoz Aşısı',
  BLOOD_SUGAR = 'Açlık Kan Şekeri',
  LIVER_FUNC = 'Karaciğer Fonksiyon Testleri'
}

export interface ExamDefinition {
  id: string;
  name: string;
  price: number;
}

export enum HazardClass {
  LESS = 'Az Tehlikeli',
  DANGEROUS = 'Tehlikeli',
  VERY_DANGEROUS = 'Çok Tehlikeli'
}

export interface Company {
  id: string;
  name: string;
  hazardClass: HazardClass;
  assignedDoctor: string;     // İşyeri Hekimi
  assignedSpecialist: string; // İSG Uzmanı
  defaultExams: string[];     // Changed from ExamType[] to string[] to support dynamic exams
}

export interface Employee {
  id: string;
  fullName: string;
  tcNo: string;
  company: string;
  department?: string;
}

export interface Referral {
  id: string;
  employee: Employee;
  exams: string[]; // Changed to string[]
  status: Status;
  referralDate: string; // ISO Date string
  notes?: string;
  aiAnalysis?: string; // Gemini analysis result
  resultSummary?: string;
  doctorName?: string; // Kayıt anındaki doktor
  specialistName?: string; // Kayıt anındaki uzman
  totalPrice?: number; // Calculated price at time of referral
}

export interface Stats {
  total: number;
  today: number;
  totalIncome: number;
}

export interface SafeTransaction {
  id: string;
  type: 'INCOME' | 'EXPENSE';
  amount: number;
  description: string;
  date: string;
  category?: string;
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Settings, 
  Plus, 
  Search,
  Activity,
  LogOut,
  Stethoscope,
  Wallet
} from 'lucide-react';
import { ReferralList } from './components/ReferralList';
import { NewReferralModal } from './components/NewReferralModal';
import { StatsCards } from './components/StatsCards';
import { FinanceView } from './components/FinanceView';
import { SettingsView } from './components/SettingsView';
import { Referral, Status, Company, ExamDefinition, SafeTransaction } from './types';
import { 
  loadReferrals, saveReferrals, 
  loadCompanies, saveCompanies,
  loadExams, saveExams,
  loadTransactions, saveTransactions
} from './services/storage';
import { PREDEFINED_COMPANIES, DEFAULT_EXAMS } from './services/initialData';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'referrals' | 'finance' | 'settings'>('dashboard');

  // Data States
  const [referrals, setReferrals] = useState<Referral[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [exams, setExams] = useState<ExamDefinition[]>([]);
  const [transactions, setTransactions] = useState<SafeTransaction[]>([]);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Initial load
  useEffect(() => {
    setReferrals(loadReferrals());
    setCompanies(loadCompanies(PREDEFINED_COMPANIES));
    setExams(loadExams(DEFAULT_EXAMS));
    setTransactions(loadTransactions());
  }, []);

  // Save Effects
  useEffect(() => saveReferrals(referrals), [referrals]);
  useEffect(() => saveCompanies(companies), [companies]);
  useEffect(() => saveExams(exams), [exams]);
  useEffect(() => saveTransactions(transactions), [transactions]);

  // Handlers
  const handleCreateReferral = (referral: Referral) => {
    // 1. Add Referral
    setReferrals(prev => [referral, ...prev]);

    // 2. Auto-Add to Safe (Income)
    if (referral.totalPrice && referral.totalPrice > 0) {
      const newTransaction: SafeTransaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'INCOME',
        amount: referral.totalPrice,
        description: `Sevk Geliri: ${referral.employee.fullName} (${referral.employee.company})`,
        date: new Date().toISOString()
      };
      setTransactions(prev => [...prev, newTransaction]);
    }

    setIsModalOpen(false);
  };

  const handleUpdateStatus = (id: string, newStatus: Status) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, status: newStatus } : r
    ));
  };

  const handleAnalyze = (id: string, analysis: string) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, aiAnalysis: analysis } : r
    ));
  };

  const handleDelete = (id: string) => {
    if(window.confirm('Bu kaydı silmek istediğinize emin misiniz?')) {
      setReferrals(prev => prev.filter(r => r.id !== id));
    }
  };

  // Settings Handlers
  const handleAddCompany = (c: Company) => setCompanies(prev => [...prev, c]);
  const handleDeleteCompany = (id: string) => setCompanies(prev => prev.filter(c => c.id !== id));

  const handleAddExam = (e: ExamDefinition) => setExams(prev => [...prev, e]);
  const handleUpdateExam = (updated: ExamDefinition) => setExams(prev => prev.map(e => e.id === updated.id ? updated : e));
  const handleDeleteExam = (id: string) => setExams(prev => prev.filter(e => e.id !== id));

  // Finance Handlers
  const handleAddTransaction = (t: SafeTransaction) => setTransactions(prev => [...prev, t]);

  const filteredReferrals = useMemo(() => {
    return referrals.filter(r => 
      r.employee.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.company.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.tcNo.includes(searchTerm)
    );
  }, [referrals, searchTerm]);

  const stats = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    const totalIncome = transactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);

    return {
      total: referrals.length,
      today: referrals.filter(r => r.referralDate.startsWith(todayStr)).length,
      totalIncome: totalIncome
    };
  }, [referrals, transactions]);

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 border-r border-slate-800 text-white hidden md:flex flex-col shadow-xl">
        <div className="p-6 flex items-center space-x-3 border-b border-slate-800">
          <div className="p-2 bg-blue-600 rounded-lg shadow-lg shadow-blue-900/20">
            <Stethoscope className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight">OSGB Pro</h1>
            <p className="text-xs text-slate-400">Tetkik Takip Sistemi</p>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'dashboard' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            <span className="font-medium">Genel Bakış</span>
          </button>

          <button 
            onClick={() => setActiveTab('referrals')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'referrals' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Users className="w-5 h-5" />
            <span className="font-medium">Personel Takibi</span>
          </button>

          <button 
            onClick={() => setActiveTab('finance')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'finance' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Wallet className="w-5 h-5" />
            <span className="font-medium">Kasa & Finans</span>
          </button>

          <button 
            onClick={() => setActiveTab('settings')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'settings' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Settings className="w-5 h-5" />
            <span className="font-medium">Ayarlar</span>
          </button>
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="flex items-center space-x-3 text-slate-400 hover:text-white cursor-pointer px-4 py-2 transition-colors">
            <LogOut className="w-5 h-5" />
            <span>Çıkış Yap</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative bg-slate-950">
        {/* Header */}
        <header className="h-16 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-8 shadow-sm z-10">
          <h2 className="text-xl font-semibold text-white">
            {activeTab === 'dashboard' ? 'Kontrol Paneli' : 
             activeTab === 'referrals' ? 'Tetkik & Sevk Listesi' : 
             activeTab === 'finance' ? 'Kasa Yönetimi' : 'Ayarlar'}
          </h2>

          <div className="flex items-center space-x-4">
             <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400 w-4 h-4" />
              <input 
                type="text"
                placeholder="Personel veya Firma ara..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent w-64 transition-all placeholder-slate-500"
              />
            </div>
            <button 
              onClick={() => setIsModalOpen(true)}
              className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-lg shadow-blue-900/20 active:transform active:scale-95"
            >
              <Plus className="w-4 h-4" />
              <span>Yeni Sevk Oluştur</span>
            </button>
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-auto p-8 custom-scrollbar">
          {activeTab === 'dashboard' && (
            <div className="space-y-6">
              <StatsCards stats={stats} />
              <div className="mt-8">
                <h3 className="text-lg font-bold text-white mb-4 flex items-center">
                  <Activity className="w-5 h-5 mr-2 text-blue-500" />
                  Son Hareketler
                </h3>
                <ReferralList 
                  referrals={filteredReferrals.slice(0, 5)} 
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                  compact
                />
              </div>
            </div>
          )}

          {activeTab === 'referrals' && (
            <div className="h-full flex flex-col">
               <ReferralList 
                  referrals={filteredReferrals} 
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                />
            </div>
          )}

          {activeTab === 'finance' && (
            <FinanceView 
              transactions={transactions}
              onAddTransaction={handleAddTransaction}
            />
          )}

          {activeTab === 'settings' && (
             <SettingsView 
                companies={companies}
                onAddCompany={handleAddCompany}
                onDeleteCompany={handleDeleteCompany}
                exams={exams}
                onAddExam={handleAddExam}
                onUpdateExam={handleUpdateExam}
                onDeleteExam={handleDeleteExam}
             />
          )}
        </div>
      </main>

      {/* Modal */}
      {isModalOpen && (
        <NewReferralModal 
          onClose={() => setIsModalOpen(false)} 
          onSubmit={handleCreateReferral}
          companies={companies}
          exams={exams}
        />
      )}
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';
import { X, Printer, Calculator, Calendar, Building2 } from 'lucide-react';
import { Referral, SafeTransaction } from '../types';

interface EndOfDayReportModalProps {
  onClose: () => void;
  referrals: Referral[];
  transactions: SafeTransaction[];
}

export const EndOfDayReportModal: React.FC<EndOfDayReportModalProps> = ({ onClose, referrals, transactions }) => {
  const todayStr = new Date().toISOString().split('T')[0];
  const now = new Date();

  const reportData = useMemo(() => {
    // Filter for today
    const todaysReferrals = referrals.filter(r => r.referralDate.startsWith(todayStr));
    const todaysTransactions = transactions.filter(t => t.date.startsWith(todayStr));

    // Calculate Finances
    const totalIncome = todaysTransactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);

    const totalExpense = todaysTransactions
      .filter(t => t.type === 'EXPENSE')
      .reduce((acc, curr) => acc + curr.amount, 0);

    // Calculate Total Balance (Current System State)
    const currentTotalBalance = transactions.reduce((acc, curr) => {
      return curr.type === 'INCOME' ? acc + curr.amount : acc - curr.amount;
    }, 0);

    // Opening Balance = Current - (Today's Net Change)
    // Today's Net Change = Income - Expense
    // So: Opening = Current - (Income - Expense)
    const openingBalance = currentTotalBalance - (totalIncome - totalExpense);

    return {
      todaysReferrals,
      todaysTransactions,
      totalIncome,
      totalExpense,
      openingBalance,
      closingBalance: currentTotalBalance
    };
  }, [referrals, transactions, todayStr]);

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4 print:p-0 print:bg-white print:fixed print:inset-0">
      <div className="bg-slate-900 rounded-2xl shadow-2xl w-full max-w-3xl overflow-hidden border border-slate-700 print:border-none print:shadow-none print:w-full print:max-w-none print:bg-white print:text-black">

        {/* Header - No Print controls */}
        <div className="px-6 py-4 border-b border-slate-700 flex justify-between items-center bg-slate-950/50 print:hidden">
          <h3 className="text-lg font-bold text-white flex items-center">
            <Calculator className="w-5 h-5 mr-2 text-blue-500" />
            Gün Sonu Raporu (Z Raporu)
          </h3>
          <div className="flex items-center space-x-2">
            <button 
              onClick={handlePrint}
              className="p-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg transition-colors flex items-center space-x-2 text-sm"
            >
              <Printer className="w-4 h-4" />
              <span>Yazdır</span>
            </button>
            <button onClick={onClose} className="text-slate-400 hover:text-white hover:bg-slate-700 rounded-full p-1 transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* Printable Content */}
        <div className="p-8 space-y-8 overflow-y-auto max-h-[85vh] custom-scrollbar print:overflow-visible print:max-h-none print:p-0">

          {/* Report Header */}
          <div className="text-center border-b border-slate-700 print:border-slate-300 pb-6">
            <h1 className="text-2xl font-bold text-white print:text-black mb-1">OSGB Tetkik Takip Sistemi</h1>
            <h2 className="text-lg text-slate-400 print:text-slate-600 font-medium">Gün Sonu Özeti</h2>
            <div className="flex items-center justify-center space-x-2 mt-2 text-sm text-slate-500 print:text-slate-500">
              <Calendar className="w-4 h-4" />
              <span>{now.toLocaleDateString('tr-TR')} {now.toLocaleTimeString('tr-TR')}</span>
            </div>
          </div>

          {/* Financial Summary Grid */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 print:grid-cols-4 print:gap-2">
            <div className="p-4 rounded-lg bg-slate-800/50 border border-slate-700 print:bg-transparent print:border-slate-300">
              <p className="text-xs text-slate-400 print:text-slate-600 mb-1">Güne Başlama (Devir)</p>
              <p className="text-lg font-bold text-white print:text-black">₺{reportData.openingBalance.toLocaleString('tr-TR')}</p>
            </div>
            <div className="p-4 rounded-lg bg-emerald-900/10 border border-emerald-500/20 print:bg-transparent print:border-slate-300">
              <p className="text-xs text-emerald-400 print:text-slate-600 mb-1">Günlük Tahsilat (+)</p>
              <p className="text-lg font-bold text-emerald-400 print:text-black">₺{reportData.totalIncome.toLocaleString('tr-TR')}</p>
            </div>
            <div className="p-4 rounded-lg bg-red-900/10 border border-red-500/20 print:bg-transparent print:border-slate-300">
              <p className="text-xs text-red-400 print:text-slate-600 mb-1">Günlük Çıkış (-)</p>
              <p className="text-lg font-bold text-red-400 print:text-black">₺{reportData.totalExpense.toLocaleString('tr-TR')}</p>
            </div>
            <div className="p-4 rounded-lg bg-blue-900/10 border border-blue-500/20 print:bg-transparent print:border-slate-300">
              <p className="text-xs text-blue-400 print:text-slate-600 mb-1">Gün Sonu Kasa</p>
              <p className="text-lg font-bold text-blue-400 print:text-black">₺{reportData.closingBalance.toLocaleString('tr-TR')}</p>
            </div>
          </div>

          {/* Personnel Summary */}
          <div>
            <h4 className="text-sm font-bold text-slate-300 print:text-black uppercase tracking-wider mb-3 flex items-center">
              <Building2 className="w-4 h-4 mr-2" />
              Bugünkü Personel İşlemleri ({reportData.todaysReferrals.length})
            </h4>

            <div className="bg-slate-800/50 border border-slate-700 rounded-lg overflow-hidden print:bg-transparent print:border-slate-300">
              <table className="w-full text-left text-sm">
                <thead>
                  <tr className="bg-slate-900/50 text-slate-400 border-b border-slate-700 print:bg-slate-100 print:text-black print:border-slate-300">
                    <th className="px-4 py-3 font-medium">Personel</th>
                    <th className="px-4 py-3 font-medium">Firma</th>
                    <th className="px-4 py-3 font-medium">Tetkikler</th>
                    <th className="px-4 py-3 font-medium text-right">Tutar</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-700 print:divide-slate-300">
                  {reportData.todaysReferrals.map((ref) => (
                    <tr key={ref.id} className="text-slate-300 print:text-black">
                      <td className="px-4 py-2 font-medium">{ref.employee.fullName}</td>
                      <td className="px-4 py-2 text-slate-400 print:text-slate-700">{ref.employee.company}</td>
                      <td className="px-4 py-2 text-xs text-slate-500 print:text-slate-600">
                        {ref.exams.length} Adet ({ref.exams.slice(0, 2).join(', ')}{ref.exams.length > 2 ? '...' : ''})
                      </td>
                      <td className="px-4 py-2 text-right font-mono">₺{ref.totalPrice?.toLocaleString('tr-TR')}</td>
                    </tr>
                  ))}
                  {reportData.todaysReferrals.length === 0 && (
                    <tr>
                      <td colSpan={4} className="px-4 py-6 text-center text-slate-500 italic">Bugün personel işlemi yapılmadı.</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>

          {/* Transaction Summary */}
          <div>
            <h4 className="text-sm font-bold text-slate-300 print:text-black uppercase tracking-wider mb-3 flex items-center">
               <Calculator className="w-4 h-4 mr-2" />
               Kasa Hareket Dökümü
            </h4>

            <div className="bg-slate-800/50 border border-slate-700 rounded-lg overflow-hidden print:bg-transparent print:border-slate-300">
              <table className="w-full text-left text-sm">
                <thead>
                   <tr className="bg-slate-900/50 text-slate-400 border-b border-slate-700 print:bg-slate-100 print:text-black print:border-slate-300">
                    <th className="px-4 py-3 font-medium">Saat</th>
                    <th className="px-4 py-3 font-medium">Açıklama</th>
                    <th className="px-4 py-3 font-medium text-right">Tutar</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-700 print:divide-slate-300">
                  {reportData.todaysTransactions.map((tx) => (
                    <tr key={tx.id} className="text-slate-300 print:text-black">
                      <td className="px-4 py-2 text-xs font-mono text-slate-500 print:text-slate-600">
                        {new Date(tx.date).toLocaleTimeString('tr-TR', {hour: '2-digit', minute:'2-digit'})}
                      </td>
                      <td className="px-4 py-2">
                        <span className={tx.type === 'INCOME' ? 'text-emerald-400 print:text-black' : 'text-red-400 print:text-black'}>
                           {tx.type === 'INCOME' ? '(+) ' : '(-) '}
                        </span>
                        {tx.description}
                      </td>
                      <td className="px-4 py-2 text-right font-mono">
                        ₺{tx.amount.toLocaleString('tr-TR')}
                      </td>
                    </tr>
                  ))}
                   {reportData.todaysTransactions.length === 0 && (
                    <tr>
                      <td colSpan={3} className="px-4 py-6 text-center text-slate-500 italic">Bugün finansal hareket olmadı.</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>

          <div className="pt-8 border-t border-slate-700 print:border-slate-300 text-center text-xs text-slate-500 print:text-slate-500">
            <p>Bu rapor {now.toLocaleDateString('tr-TR')} tarihinde oluşturulmuştur.</p>
            <p>OSGB Tetkik Takip Sistemi</p>
          </div>

        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Settings, 
  Plus, 
  Search,
  Activity,
  LogOut,
  Stethoscope,
  Wallet,
  FileText
} from 'lucide-react';
import { ReferralList } from './components/ReferralList';
import { NewReferralModal } from './components/NewReferralModal';
import { StatsCards } from './components/StatsCards';
import { FinanceView } from './components/FinanceView';
import { SettingsView } from './components/SettingsView';
import { EndOfDayReportModal } from './components/EndOfDayReportModal';
import { Referral, Status, Company, ExamDefinition, SafeTransaction } from './types';
import { 
  loadReferrals, saveReferrals, 
  loadCompanies, saveCompanies,
  loadExams, saveExams,
  loadTransactions, saveTransactions
} from './services/storage';
import { PREDEFINED_COMPANIES, DEFAULT_EXAMS } from './services/initialData';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'referrals' | 'finance' | 'settings'>('dashboard');

  // Data States
  const [referrals, setReferrals] = useState<Referral[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [exams, setExams] = useState<ExamDefinition[]>([]);
  const [transactions, setTransactions] = useState<SafeTransaction[]>([]);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Initial load
  useEffect(() => {
    setReferrals(loadReferrals());
    setCompanies(loadCompanies(PREDEFINED_COMPANIES));
    setExams(loadExams(DEFAULT_EXAMS));
    setTransactions(loadTransactions());
  }, []);

  // Save Effects
  useEffect(() => saveReferrals(referrals), [referrals]);
  useEffect(() => saveCompanies(companies), [companies]);
  useEffect(() => saveExams(exams), [exams]);
  useEffect(() => saveTransactions(transactions), [transactions]);

  // Handlers
  const handleCreateReferral = (referral: Referral) => {
    // 1. Add Referral
    setReferrals(prev => [referral, ...prev]);

    // 2. Auto-Add to Safe (Income)
    if (referral.totalPrice && referral.totalPrice > 0) {
      const newTransaction: SafeTransaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'INCOME',
        amount: referral.totalPrice,
        description: `Sevk Geliri: ${referral.employee.fullName} (${referral.employee.company})`,
        date: new Date().toISOString()
      };
      setTransactions(prev => [...prev, newTransaction]);
    }

    setIsModalOpen(false);
  };

  const handleUpdateStatus = (id: string, newStatus: Status) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, status: newStatus } : r
    ));
  };

  const handleAnalyze = (id: string, analysis: string) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, aiAnalysis: analysis } : r
    ));
  };

  const handleDelete = (id: string) => {
    if(window.confirm('Bu kaydı silmek istediğinize emin misiniz?')) {
      setReferrals(prev => prev.filter(r => r.id !== id));
    }
  };

  // Settings Handlers
  const handleAddCompany = (c: Company) => setCompanies(prev => [...prev, c]);
  const handleDeleteCompany = (id: string) => setCompanies(prev => prev.filter(c => c.id !== id));

  const handleAddExam = (e: ExamDefinition) => setExams(prev => [...prev, e]);
  const handleUpdateExam = (updated: ExamDefinition) => setExams(prev => prev.map(e => e.id === updated.id ? updated : e));
  const handleDeleteExam = (id: string) => setExams(prev => prev.filter(e => e.id !== id));

  // Finance Handlers
  const handleAddTransaction = (t: SafeTransaction) => setTransactions(prev => [...prev, t]);

  const filteredReferrals = useMemo(() => {
    return referrals.filter(r => 
      r.employee.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.company.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.tcNo.includes(searchTerm)
    );
  }, [referrals, searchTerm]);

  const stats = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    const totalIncome = transactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);

    return {
      total: referrals.length,
      today: referrals.filter(r => r.referralDate.startsWith(todayStr)).length,
      totalIncome: totalIncome
    };
  }, [referrals, transactions]);

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 border-r border-slate-800 text-white hidden md:flex flex-col shadow-xl print:hidden">
        <div className="p-6 flex items-center space-x-3 border-b border-slate-800">
          <div className="p-2 bg-blue-600 rounded-lg shadow-lg shadow-blue-900/20">
            <Stethoscope className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight">OSGB Pro</h1>
            <p className="text-xs text-slate-400">Tetkik Takip Sistemi</p>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'dashboard' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            <span className="font-medium">Genel Bakış</span>
          </button>

          <button 
            onClick={() => setActiveTab('referrals')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'referrals' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Users className="w-5 h-5" />
            <span className="font-medium">Personel Takibi</span>
          </button>

          <button 
            onClick={() => setActiveTab('finance')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'finance' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Wallet className="w-5 h-5" />
            <span className="font-medium">Kasa & Finans</span>
          </button>

          <button 
            onClick={() => setActiveTab('settings')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'settings' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Settings className="w-5 h-5" />
            <span className="font-medium">Ayarlar</span>
          </button>
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="flex items-center space-x-3 text-slate-400 hover:text-white cursor-pointer px-4 py-2 transition-colors">
            <LogOut className="w-5 h-5" />
            <span>Çıkış Yap</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative bg-slate-950">
        {/* Header */}
        <header className="h-16 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-8 shadow-sm z-10 print:hidden">
          <h2 className="text-xl font-semibold text-white">
            {activeTab === 'dashboard' ? 'Kontrol Paneli' : 
             activeTab === 'referrals' ? 'Tetkik & Sevk Listesi' : 
             activeTab === 'finance' ? 'Kasa Yönetimi' : 'Ayarlar'}
          </h2>

          <div className="flex items-center space-x-4">
             <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400 w-4 h-4" />
              <input 
                type="text"
                placeholder="Personel veya Firma ara..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent w-64 transition-all placeholder-slate-500"
              />
            </div>
            <button 
              onClick={() => setIsModalOpen(true)}
              className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-lg shadow-blue-900/20 active:transform active:scale-95"
            >
              <Plus className="w-4 h-4" />
              <span>Yeni Sevk Oluştur</span>
            </button>
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-auto p-8 custom-scrollbar print:p-0 print:overflow-visible">
          {activeTab === 'dashboard' && (
            <div className="space-y-6">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-bold text-white hidden md:block">Günlük Özet</h3>
                <button 
                  onClick={() => setIsReportModalOpen(true)}
                  className="flex items-center space-x-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-lg"
                >
                  <FileText className="w-4 h-4" />
                  <span>Gün Sonu Raporu Al (Z Raporu)</span>
                </button>
              </div>

              <StatsCards stats={stats} />

              <div className="mt-8">
                <h3 className="text-lg font-bold text-white mb-4 flex items-center">
                  <Activity className="w-5 h-5 mr-2 text-blue-500" />
                  Son Hareketler
                </h3>
                <ReferralList 
                  referrals={filteredReferrals.slice(0, 5)} 
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                  compact
                />
              </div>
            </div>
          )}

          {activeTab === 'referrals' && (
            <div className="h-full flex flex-col">
               <ReferralList 
                  referrals={filteredReferrals} 
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                />
            </div>
          )}

          {activeTab === 'finance' && (
            <FinanceView 
              transactions={transactions}
              onAddTransaction={handleAddTransaction}
            />
          )}

          {activeTab === 'settings' && (
             <SettingsView 
                companies={companies}
                onAddCompany={handleAddCompany}
                onDeleteCompany={handleDeleteCompany}
                exams={exams}
                onAddExam={handleAddExam}
                onUpdateExam={handleUpdateExam}
                onDeleteExam={handleDeleteExam}
             />
          )}
        </div>
      </main>

      {/* Modal */}
      {isModalOpen && (
        <NewReferralModal 
          onClose={() => setIsModalOpen(false)} 
          onSubmit={handleCreateReferral}
          companies={companies}
          exams={exams}
        />
      )}

      {/* End of Day Report Modal */}
      {isReportModalOpen && (
        <EndOfDayReportModal
          onClose={() => setIsReportModalOpen(false)}
          referrals={referrals}
          transactions={transactions}
        />
      )}
    </div>
  );
};

export default App;

export enum Status {
  PENDING = 'PENDING',       // Bekliyor (Henüz gitmedi)
  AT_HOSPITAL = 'AT_HOSPITAL', // Hastanede / Tetkikte
  AWAITING_RESULT = 'AWAITING_RESULT', // Sonuç Bekleniyor
  COMPLETED = 'COMPLETED',   // Tamamlandı
  CANCELLED = 'CANCELLED'    // İptal
}

// Deprecated enum usage in favor of dynamic list, keeping for type safety in legacy code
export enum ExamType {
  AUDIOMETRY = 'Odyometri',
  LUNG_XRAY = 'Akciğer Grafisi',
  HEMOGRAM = 'Hemogram',
  VISION = 'Göz Muayenesi',
  EKG = 'EKG',
  TETANUS = 'Tetanoz Aşısı',
  BLOOD_SUGAR = 'Açlık Kan Şekeri',
  LIVER_FUNC = 'Karaciğer Fonksiyon Testleri'
}

export interface ExamDefinition {
  id: string;
  name: string;
  price: number;
}

export enum HazardClass {
  LESS = 'Az Tehlikeli',
  DANGEROUS = 'Tehlikeli',
  VERY_DANGEROUS = 'Çok Tehlikeli'
}

export interface Company {
  id: string;
  name: string;
  hazardClass: HazardClass;
  assignedDoctor: string;     // İşyeri Hekimi
  assignedSpecialist: string; // İSG Uzmanı
  defaultExams: string[];     // Changed from ExamType[] to string[] to support dynamic exams
}

export interface Employee {
  id: string;
  fullName: string;
  tcNo: string;
  company: string;
  department?: string;
}

export interface Referral {
  id: string;
  employee: Employee;
  exams: string[]; // Changed to string[]
  status: Status;
  referralDate: string; // ISO Date string
  notes?: string;
  aiAnalysis?: string; // Gemini analysis result
  resultSummary?: string;
  doctorName?: string; // Kayıt anındaki doktor
  specialistName?: string; // Kayıt anındaki uzman
  totalPrice?: number; // Calculated price at time of referral
  paymentMethod: 'CASH' | 'INVOICE'; // Nakit (Kasa) veya Cari (Fatura)
}

export interface Stats {
  total: number;
  today: number;
  totalIncome: number;
}

export interface SafeTransaction {
  id: string;
  type: 'INCOME' | 'EXPENSE';
  amount: number;
  description: string;
  date: string;
  category?: string;
}

import React, { useState, useEffect } from 'react';
import { X, Building2, User, CreditCard, Activity, Briefcase, Stethoscope, ShieldCheck, AlertTriangle, Wallet, Receipt } from 'lucide-react';
import { Referral, Status, Company, HazardClass, ExamDefinition } from '../types';

interface NewReferralModalProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
  companies: Company[];
  exams: ExamDefinition[];
}

export const NewReferralModal: React.FC<NewReferralModalProps> = ({ onClose, onSubmit, companies, exams }) => {
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');

  // State for Company selection
  const [selectedCompanyId, setSelectedCompanyId] = useState('');
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);

  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');
  const [estimatedPrice, setEstimatedPrice] = useState(0);

  // Payment Method State
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');

  // Recalculate price when exams change
  useEffect(() => {
    const total = selectedExamIds.reduce((sum, id) => {
      const exam = exams.find(e => e.name === id); 
      const price = exam ? exam.price : 0;
      return sum + price;
    }, 0);
    setEstimatedPrice(total);
  }, [selectedExamIds, exams]);

  const handleCompanyChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const companyId = e.target.value;
    setSelectedCompanyId(companyId);

    if (companyId) {
      const company = companies.find(c => c.id === companyId) || null;
      setSelectedCompanyData(company);
      // Auto-select required exams for this company
      if (company) {
        setSelectedExamIds(company.defaultExams);
      }
    } else {
      setSelectedCompanyData(null);
      setSelectedExamIds([]);
    }
  };

  const toggleExam = (examName: string) => {
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const getHazardClassColor = (hazard: HazardClass) => {
    switch (hazard) {
      case HazardClass.VERY_DANGEROUS: return 'bg-red-500/10 text-red-400 border-red-500/20';
      case HazardClass.DANGEROUS: return 'bg-orange-500/10 text-orange-400 border-orange-500/20';
      case HazardClass.LESS: return 'bg-green-500/10 text-green-400 border-green-500/20';
      default: return 'bg-slate-700 text-slate-300';
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!fullName || !selectedCompanyData) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        company: selectedCompanyData.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData.assignedDoctor,
      specialistName: selectedCompanyData.assignedSpecialist,
      totalPrice: estimatedPrice,
      paymentMethod: paymentMethod
    };

    onSubmit(newReferral);
  };

  return (
    <div className="fixed inset-0 bg-black/70 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-slate-800 rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh] border border-slate-700">
        <div className="px-6 py-4 border-b border-slate-700 flex justify-between items-center bg-slate-900/50">
          <h3 className="text-lg font-bold text-white">Yeni Tetkik Sevki Oluştur</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-white hover:bg-slate-700 rounded-full p-1 transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">
          <form id="referralForm" onSubmit={handleSubmit} className="space-y-6">

            {/* Personal Info Section */}
            <div className="space-y-4">
              <h4 className="text-sm font-semibold text-slate-500 uppercase tracking-wider mb-3">Personel Bilgileri</h4>

              <div>
                  <label className="block text-sm font-medium text-slate-300 mb-1">Firma Seçimi</label>
                  <div className="relative">
                    <Building2 className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                    <select
                      required
                      value={selectedCompanyId}
                      onChange={handleCompanyChange}
                      className="w-full pl-10 pr-10 py-2 bg-slate-900 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all appearance-none"
                    >
                      <option value="" className="bg-slate-800 text-slate-400">Firma Seçiniz...</option>
                      {companies.map(c => (
                        <option key={c.id} value={c.id} className="bg-slate-800 text-white">{c.name}</option>
                      ))}
                    </select>
                  </div>
              </div>

              {selectedCompanyData && (
                <div className="bg-slate-900/50 p-4 rounded-lg border border-slate-700 grid grid-cols-1 md:grid-cols-2 gap-4 animate-fadeIn">
                  <div className="md:col-span-2 flex items-center space-x-2">
                    <span className="text-sm text-slate-400 font-medium">Tehlike Sınıfı:</span>
                    <span className={`text-xs px-2 py-1 rounded-full border font-medium flex items-center ${getHazardClassColor(selectedCompanyData.hazardClass)}`}>
                      <AlertTriangle className="w-3 h-3 mr-1" />
                      {selectedCompanyData.hazardClass}
                    </span>
                  </div>

                  <div className="flex items-start space-x-2">
                    <Stethoscope className="w-4 h-4 text-blue-500 mt-1" />
                    <div>
                      <p className="text-xs text-slate-500">İşyeri Hekimi</p>
                      <p className="text-sm font-medium text-slate-200">{selectedCompanyData.assignedDoctor}</p>
                    </div>
                  </div>

                  <div className="flex items-start space-x-2">
                    <ShieldCheck className="w-4 h-4 text-emerald-500 mt-1" />
                    <div>
                      <p className="text-xs text-slate-500">İSG Uzmanı</p>
                      <p className="text-sm font-medium text-slate-200">{selectedCompanyData.assignedSpecialist}</p>
                    </div>
                  </div>
                </div>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-300 mb-1">Ad Soyad</label>
                  <div className="relative">
                    <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                    <input 
                      required
                      type="text" 
                      value={fullName}
                      onChange={e => setFullName(e.target.value)}
                      className="w-full pl-10 pr-3 py-2 bg-slate-900 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all placeholder-slate-600"
                      placeholder="Örn: Ahmet Yılmaz"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-300 mb-1">TC Kimlik No</label>
                  <div className="relative">
                    <CreditCard className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                    <input 
                      type="text" 
                      maxLength={11}
                      value={tcNo}
                      onChange={e => setTcNo(e.target.value.replace(/\D/g,''))}
                      className="w-full pl-10 pr-3 py-2 bg-slate-900 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all placeholder-slate-600"
                      placeholder="11 haneli TC no"
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Exams Section */}
            <div className="space-y-4 pt-4 border-t border-slate-700">
               <div className="flex justify-between items-center mb-3">
                  <h4 className="text-sm font-semibold text-slate-500 uppercase tracking-wider">İstenen Tetkikler</h4>
                  <div className="text-right">
                    <p className="text-xs text-slate-400">Tahmini Toplam</p>
                    <p className="text-lg font-bold text-emerald-400">₺{estimatedPrice.toLocaleString('tr-TR')}</p>
                  </div>
               </div>

               <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                  {exams.map((exam) => (
                    <div 
                      key={exam.id}
                      onClick={() => toggleExam(exam.name)}
                      className={`cursor-pointer p-3 rounded-lg border flex flex-col justify-between transition-all ${
                        selectedExamIds.includes(exam.name) 
                        ? 'border-blue-500 bg-blue-500/10 text-blue-400 shadow-sm' 
                        : 'border-slate-700 hover:bg-slate-700 text-slate-400'
                      }`}
                    >
                      <div className="flex items-center space-x-2">
                        <div className={`w-4 h-4 min-w-[16px] rounded border flex items-center justify-center ${selectedExamIds.includes(exam.name) ? 'bg-blue-500 border-blue-500' : 'border-slate-600 bg-slate-800'}`}>
                          {selectedExamIds.includes(exam.name) && <Activity className="w-3 h-3 text-white" />}
                        </div>
                        <span className="text-sm font-medium truncate">{exam.name}</span>
                      </div>
                      <span className="text-xs text-right mt-2 opacity-70">₺{exam.price}</span>
                    </div>
                  ))}
               </div>
            </div>

            {/* Payment Method Section */}
            <div className="space-y-4 pt-4 border-t border-slate-700">
              <label className="block text-sm font-medium text-slate-300 mb-3">Ödeme Yöntemi</label>
              <div className="grid grid-cols-2 gap-4">
                <div 
                  onClick={() => setPaymentMethod('CASH')}
                  className={`cursor-pointer p-4 rounded-lg border-2 flex flex-col items-center justify-center transition-all ${
                    paymentMethod === 'CASH' 
                    ? 'border-emerald-500 bg-emerald-500/10 text-emerald-400' 
                    : 'border-slate-700 bg-slate-900/50 text-slate-400 hover:border-slate-600'
                  }`}
                >
                  <Wallet className="w-6 h-6 mb-2" />
                  <span className="font-semibold text-sm">Nakit / Elden</span>
                  <span className="text-[10px] opacity-70 mt-1">Kasaya İşlenir</span>
                </div>

                <div 
                  onClick={() => setPaymentMethod('INVOICE')}
                  className={`cursor-pointer p-4 rounded-lg border-2 flex flex-col items-center justify-center transition-all ${
                    paymentMethod === 'INVOICE' 
                    ? 'border-blue-500 bg-blue-500/10 text-blue-400' 
                    : 'border-slate-700 bg-slate-900/50 text-slate-400 hover:border-slate-600'
                  }`}
                >
                  <Receipt className="w-6 h-6 mb-2" />
                  <span className="font-semibold text-sm">Cari / Fatura</span>
                  <span className="text-[10px] opacity-70 mt-1">Kasaya İşlenmez</span>
                </div>
              </div>
            </div>

            {/* Notes Section */}
             <div className="space-y-4 pt-4 border-t border-slate-700">
               <label className="block text-sm font-medium text-slate-300 mb-1">Notlar</label>
               <textarea 
                  value={notes}
                  onChange={e => setNotes(e.target.value)}
                  className="w-full p-3 bg-slate-900 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-blue-500 outline-none h-24 text-sm placeholder-slate-600"
                  placeholder="Eklemek istediğiniz notlar..."
               />
             </div>

          </form>
        </div>

        <div className="px-6 py-4 bg-slate-900/50 border-t border-slate-700 flex justify-end space-x-3">
          <button 
            type="button"
            onClick={onClose}
            className="px-4 py-2 text-slate-300 font-medium hover:bg-slate-700 rounded-lg transition-colors"
          >
            İptal
          </button>
          <button 
            type="submit"
            form="referralForm"
            className="px-6 py-2 bg-blue-600 hover:bg-blue-500 text-white font-medium rounded-lg shadow-lg shadow-blue-900/20 transition-all active:scale-95"
          >
            Sevk Oluştur
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Settings, 
  Plus, 
  Search,
  Activity,
  LogOut,
  Stethoscope,
  Wallet,
  FileText
} from 'lucide-react';
import { ReferralList } from './components/ReferralList';
import { NewReferralModal } from './components/NewReferralModal';
import { StatsCards } from './components/StatsCards';
import { FinanceView } from './components/FinanceView';
import { SettingsView } from './components/SettingsView';
import { EndOfDayReportModal } from './components/EndOfDayReportModal';
import { Referral, Status, Company, ExamDefinition, SafeTransaction } from './types';
import { 
  loadReferrals, saveReferrals, 
  loadCompanies, saveCompanies,
  loadExams, saveExams,
  loadTransactions, saveTransactions
} from './services/storage';
import { PREDEFINED_COMPANIES, DEFAULT_EXAMS } from './services/initialData';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'referrals' | 'finance' | 'settings'>('dashboard');

  // Data States
  const [referrals, setReferrals] = useState<Referral[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [exams, setExams] = useState<ExamDefinition[]>([]);
  const [transactions, setTransactions] = useState<SafeTransaction[]>([]);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Initial load
  useEffect(() => {
    setReferrals(loadReferrals());
    setCompanies(loadCompanies(PREDEFINED_COMPANIES));
    setExams(loadExams(DEFAULT_EXAMS));
    setTransactions(loadTransactions());
  }, []);

  // Save Effects
  useEffect(() => saveReferrals(referrals), [referrals]);
  useEffect(() => saveCompanies(companies), [companies]);
  useEffect(() => saveExams(exams), [exams]);
  useEffect(() => saveTransactions(transactions), [transactions]);

  // Handlers
  const handleCreateReferral = (referral: Referral) => {
    // 1. Add Referral (Always)
    setReferrals(prev => [referral, ...prev]);

    // 2. Add to Safe ONLY if Payment Method is CASH
    if (referral.paymentMethod === 'CASH' && referral.totalPrice && referral.totalPrice > 0) {
      const newTransaction: SafeTransaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'INCOME',
        amount: referral.totalPrice,
        description: `Sevk Geliri (Nakit): ${referral.employee.fullName} (${referral.employee.company})`,
        date: new Date().toISOString()
      };
      setTransactions(prev => [...prev, newTransaction]);
    }
    // If INVOICE, do nothing with Safe/Transactions (as requested)

    setIsModalOpen(false);
  };

  const handleUpdateStatus = (id: string, newStatus: Status) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, status: newStatus } : r
    ));
  };

  const handleAnalyze = (id: string, analysis: string) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, aiAnalysis: analysis } : r
    ));
  };

  const handleDelete = (id: string) => {
    if(window.confirm('Bu kaydı silmek istediğinize emin misiniz?')) {
      setReferrals(prev => prev.filter(r => r.id !== id));
    }
  };

  // Settings Handlers
  const handleAddCompany = (c: Company) => setCompanies(prev => [...prev, c]);
  const handleDeleteCompany = (id: string) => setCompanies(prev => prev.filter(c => c.id !== id));

  const handleAddExam = (e: ExamDefinition) => setExams(prev => [...prev, e]);
  const handleUpdateExam = (updated: ExamDefinition) => setExams(prev => prev.map(e => e.id === updated.id ? updated : e));
  const handleDeleteExam = (id: string) => setExams(prev => prev.filter(e => e.id !== id));

  // Finance Handlers
  const handleAddTransaction = (t: SafeTransaction) => setTransactions(prev => [...prev, t]);

  const filteredReferrals = useMemo(() => {
    return referrals.filter(r => 
      r.employee.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.company.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.tcNo.includes(searchTerm)
    );
  }, [referrals, searchTerm]);

  const stats = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    const totalIncome = transactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);

    return {
      total: referrals.length,
      today: referrals.filter(r => r.referralDate.startsWith(todayStr)).length,
      totalIncome: totalIncome
    };
  }, [referrals, transactions]);

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 border-r border-slate-800 text-white hidden md:flex flex-col shadow-xl print:hidden">
        <div className="p-6 flex items-center space-x-3 border-b border-slate-800">
          <div className="p-2 bg-blue-600 rounded-lg shadow-lg shadow-blue-900/20">
            <Stethoscope className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight">OSGB Pro</h1>
            <p className="text-xs text-slate-400">Tetkik Takip Sistemi</p>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'dashboard' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            <span className="font-medium">Genel Bakış</span>
          </button>

          <button 
            onClick={() => setActiveTab('referrals')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'referrals' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Users className="w-5 h-5" />
            <span className="font-medium">Personel Takibi</span>
          </button>

          <button 
            onClick={() => setActiveTab('finance')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'finance' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Wallet className="w-5 h-5" />
            <span className="font-medium">Kasa & Finans</span>
          </button>

          <button 
            onClick={() => setActiveTab('settings')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'settings' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Settings className="w-5 h-5" />
            <span className="font-medium">Ayarlar</span>
          </button>
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="flex items-center space-x-3 text-slate-400 hover:text-white cursor-pointer px-4 py-2 transition-colors">
            <LogOut className="w-5 h-5" />
            <span>Çıkış Yap</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative bg-slate-950">
        {/* Header */}
        <header className="h-16 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-8 shadow-sm z-10 print:hidden">
          <h2 className="text-xl font-semibold text-white">
            {activeTab === 'dashboard' ? 'Kontrol Paneli' : 
             activeTab === 'referrals' ? 'Tetkik & Sevk Listesi' : 
             activeTab === 'finance' ? 'Kasa Yönetimi' : 'Ayarlar'}
          </h2>

          <div className="flex items-center space-x-4">
             <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400 w-4 h-4" />
              <input 
                type="text"
                placeholder="Personel veya Firma ara..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent w-64 transition-all placeholder-slate-500"
              />
            </div>
            <button 
              onClick={() => setIsModalOpen(true)}
              className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-lg shadow-blue-900/20 active:transform active:scale-95"
            >
              <Plus className="w-4 h-4" />
              <span>Yeni Sevk Oluştur</span>
            </button>
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-auto p-8 custom-scrollbar print:p-0 print:overflow-visible">
          {activeTab === 'dashboard' && (
            <div className="space-y-6">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-bold text-white hidden md:block">Günlük Özet</h3>
                <button 
                  onClick={() => setIsReportModalOpen(true)}
                  className="flex items-center space-x-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-lg"
                >
                  <FileText className="w-4 h-4" />
                  <span>Gün Sonu Raporu Al (Z Raporu)</span>
                </button>
              </div>

              <StatsCards stats={stats} />

              <div className="mt-8">
                <h3 className="text-lg font-bold text-white mb-4 flex items-center">
                  <Activity className="w-5 h-5 mr-2 text-blue-500" />
                  Son Hareketler
                </h3>
                <ReferralList 
                  referrals={filteredReferrals.slice(0, 5)} 
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                  compact
                />
              </div>
            </div>
          )}

          {activeTab === 'referrals' && (
            <div className="h-full flex flex-col">
               <ReferralList 
                  referrals={filteredReferrals} 
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                />
            </div>
          )}

          {activeTab === 'finance' && (
            <FinanceView 
              transactions={transactions}
              onAddTransaction={handleAddTransaction}
            />
          )}

          {activeTab === 'settings' && (
             <SettingsView 
                companies={companies}
                onAddCompany={handleAddCompany}
                onDeleteCompany={handleDeleteCompany}
                exams={exams}
                onAddExam={handleAddExam}
                onUpdateExam={handleUpdateExam}
                onDeleteExam={handleDeleteExam}
             />
          )}
        </div>
      </main>

      {/* Modal */}
      {isModalOpen && (
        <NewReferralModal 
          onClose={() => setIsModalOpen(false)} 
          onSubmit={handleCreateReferral}
          companies={companies}
          exams={exams}
        />
      )}

      {/* End of Day Report Modal */}
      {isReportModalOpen && (
        <EndOfDayReportModal
          onClose={() => setIsReportModalOpen(false)}
          referrals={referrals}
          transactions={transactions}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { 
  MoreHorizontal, 
  CheckCircle, 
  Clock, 
  AlertCircle, 
  FileText, 
  Trash2,
  Sparkles
} from 'lucide-react';
import { Referral, Status } from '../types';
import { analyzeResults } from '../services/geminiService';

interface ReferralListProps {
  referrals: Referral[];
  onUpdateStatus: (id: string, status: Status) => void;
  onAnalyze: (id: string, result: string) => void;
  onDelete: (id: string) => void;
  compact?: boolean;
}

export const ReferralList: React.FC<ReferralListProps> = ({ 
  referrals, 
  onUpdateStatus, 
  onAnalyze,
  onDelete,
  compact = false 
}) => {
  const [analyzingId, setAnalyzingId] = useState<string | null>(null);

  const handleAIAnalysis = async (referral: Referral) => {
    setAnalyzingId(referral.id);
    try {
      const result = await analyzeResults(referral);
      onAnalyze(referral.id, result);
    } catch (e) {
      alert("Analiz sırasında bir hata oluştu.");
    } finally {
      setAnalyzingId(null);
    }
  };

  if (referrals.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-slate-500 bg-slate-800 rounded-xl border border-dashed border-slate-700">
        <FileText className="w-12 h-12 mb-2 opacity-50" />
        <p>Henüz kayıt bulunmamaktadır.</p>
      </div>
    );
  }

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-900/50 border-b border-slate-700">
              <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider">Personel</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider">Firma</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider">Tarih</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider">Tetkikler</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider text-right">Tutar</th>
              {!compact && <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider text-right">İşlemler</th>}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-700">
            {referrals.map((referral) => (
              <tr key={referral.id} className="hover:bg-slate-700/30 transition-colors group">
                <td className="px-6 py-4">
                  <div className="flex flex-col">
                    <span className="font-medium text-white">{referral.employee.fullName}</span>
                    <span className="text-xs text-slate-500 font-mono">{referral.employee.tcNo}</span>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <span className="text-sm text-slate-300">{referral.employee.company}</span>
                </td>
                <td className="px-6 py-4">
                  <span className="text-sm text-slate-400">
                    {new Date(referral.referralDate).toLocaleDateString('tr-TR')}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <div className="flex flex-wrap gap-1">
                    {referral.exams.slice(0, compact ? 2 : 4).map((exam, i) => (
                      <span key={i} className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-slate-700 text-slate-300 border border-slate-600">
                        {exam}
                      </span>
                    ))}
                    {referral.exams.length > (compact ? 2 : 4) && (
                      <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-slate-700 text-slate-400">
                        +{referral.exams.length - (compact ? 2 : 4)}
                      </span>
                    )}
                  </div>
                </td>
                <td className="px-6 py-4 text-right">
                  <div className="flex flex-col items-end">
                    <span className="text-emerald-400 font-medium">₺{referral.totalPrice?.toLocaleString('tr-TR') || 0}</span>
                    <span className={`text-[10px] uppercase font-bold tracking-wider px-1.5 py-0.5 rounded ${referral.paymentMethod === 'CASH' ? 'text-emerald-300 bg-emerald-500/10' : 'text-blue-300 bg-blue-500/10'}`}>
                      {referral.paymentMethod === 'CASH' ? 'Nakit' : 'Cari'}
                    </span>
                  </div>
                </td>
                {!compact && (
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end space-x-2">
                       {/* AI Analysis Button */}
                       {/* Simplified: Analysis button only shows if needed, but since we removed status flow, user might want to click it anytime */}
                       {!referral.aiAnalysis && (
                         <button 
                            onClick={() => handleAIAnalysis(referral)}
                            disabled={analyzingId === referral.id}
                            className="text-indigo-400 hover:bg-indigo-500/10 p-2 rounded-lg transition-colors flex items-center space-x-1"
                            title="AI ile Sonuçları Yorumla"
                         >
                            {analyzingId === referral.id ? (
                                <div className="animate-spin h-4 w-4 border-2 border-indigo-500 border-t-transparent rounded-full" />
                            ) : (
                                <Sparkles className="w-4 h-4" />
                            )}
                         </button>
                       )}

                       {referral.aiAnalysis && (
                          <div className="relative group/tooltip">
                            <span className="text-indigo-400 cursor-help bg-indigo-500/10 px-2 py-1 rounded text-xs border border-indigo-500/30">
                              AI Raporu
                            </span>
                            <div className="absolute right-0 bottom-full mb-2 w-64 bg-slate-900 border border-slate-700 text-slate-300 text-xs p-3 rounded shadow-xl opacity-0 group-hover/tooltip:opacity-100 pointer-events-none transition-opacity z-50">
                              {referral.aiAnalysis}
                            </div>
                          </div>
                       )}

                      <button 
                        onClick={() => onDelete(referral.id)}
                        className="text-slate-500 hover:text-red-400 hover:bg-red-500/10 p-2 rounded-lg transition-colors"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </td>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export enum Status {
  PENDING = 'PENDING',       // Bekliyor (Henüz gitmedi)
  AT_HOSPITAL = 'AT_HOSPITAL', // Hastanede / Tetkikte
  AWAITING_RESULT = 'AWAITING_RESULT', // Sonuç Bekleniyor
  COMPLETED = 'COMPLETED',   // Tamamlandı
  CANCELLED = 'CANCELLED'    // İptal
}

// Deprecated enum usage in favor of dynamic list, keeping for type safety in legacy code
export enum ExamType {
  AUDIOMETRY = 'Odyometri',
  LUNG_XRAY = 'Akciğer Grafisi',
  HEMOGRAM = 'Hemogram',
  VISION = 'Göz Muayenesi',
  EKG = 'EKG',
  TETANUS = 'Tetanoz Aşısı',
  BLOOD_SUGAR = 'Açlık Kan Şekeri',
  LIVER_FUNC = 'Karaciğer Fonksiyon Testleri'
}

export interface ExamDefinition {
  id: string;
  name: string;
  price: number;
}

export enum HazardClass {
  LESS = 'Az Tehlikeli',
  DANGEROUS = 'Tehlikeli',
  VERY_DANGEROUS = 'Çok Tehlikeli'
}

export interface Company {
  id: string;
  name: string;
  hazardClass: HazardClass;
  assignedDoctor: string;     // İşyeri Hekimi
  assignedSpecialist: string; // İSG Uzmanı
  defaultExams: string[];     // Changed from ExamType[] to string[] to support dynamic exams
  defaultPaymentMethod: 'CASH' | 'INVOICE'; // Firmanın varsayılan ödeme yöntemi
}

export interface Employee {
  id: string;
  fullName: string;
  tcNo: string;
  company: string;
  department?: string;
}

export interface Referral {
  id: string;
  employee: Employee;
  exams: string[]; // Changed to string[]
  status: Status;
  referralDate: string; // ISO Date string
  notes?: string;
  aiAnalysis?: string; // Gemini analysis result
  resultSummary?: string;
  doctorName?: string; // Kayıt anındaki doktor
  specialistName?: string; // Kayıt anındaki uzman
  totalPrice?: number; // Calculated price at time of referral
  paymentMethod: 'CASH' | 'INVOICE'; // Nakit (Kasa) veya Cari (Fatura)
}

export interface Stats {
  total: number;
  today: number;
  totalIncome: number;
}

export interface SafeTransaction {
  id: string;
  type: 'INCOME' | 'EXPENSE';
  amount: number;
  description: string;
  date: string;
  category?: string;
}

import React, { useState } from 'react';
import { Company, ExamDefinition, HazardClass } from '../types';
import { Trash2, Plus, Building2, TestTube, Save, Check, Wallet, Receipt } from 'lucide-react';

interface SettingsViewProps {
  companies: Company[];
  onAddCompany: (c: Company) => void;
  onDeleteCompany: (id: string) => void;
  exams: ExamDefinition[];
  onAddExam: (e: ExamDefinition) => void;
  onUpdateExam: (e: ExamDefinition) => void;
  onDeleteExam: (id: string) => void;
}

export const SettingsView: React.FC<SettingsViewProps> = ({
  companies,
  onAddCompany,
  onDeleteCompany,
  exams,
  onAddExam,
  onUpdateExam,
  onDeleteExam
}) => {
  const [activeTab, setActiveTab] = useState<'companies' | 'exams'>('companies');

  // Company Form State
  const [cName, setCName] = useState('');
  const [cHazard, setCHazard] = useState<HazardClass>(HazardClass.LESS);
  const [cDoctor, setCDoctor] = useState('');
  const [cSpecialist, setCSpecialist] = useState('');
  const [cPaymentMethod, setCPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');
  const [cSelectedExams, setCSelectedExams] = useState<string[]>([]);

  // Exam Form State
  const [eName, setEName] = useState('');
  const [ePrice, setEPrice] = useState('');

  const toggleCompanyExam = (examName: string) => {
    setCSelectedExams(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const handleAddCompany = (e: React.FormEvent) => {
    e.preventDefault();
    if (!cName) return;
    const newCompany: Company = {
      id: Math.random().toString(36).substr(2, 9),
      name: cName,
      hazardClass: cHazard,
      assignedDoctor: cDoctor || 'Belirlenmedi',
      assignedSpecialist: cSpecialist || 'Belirlenmedi',
      defaultExams: cSelectedExams,
      defaultPaymentMethod: cPaymentMethod
    };
    onAddCompany(newCompany);
    setCName('');
    setCDoctor('');
    setCSpecialist('');
    setCPaymentMethod('INVOICE');
    setCSelectedExams([]);
  };

  const handleAddExam = (e: React.FormEvent) => {
    e.preventDefault();
    if (!eName || !ePrice) return;
    const newExam: ExamDefinition = {
      id: Math.random().toString(36).substr(2, 9),
      name: eName,
      price: parseFloat(ePrice)
    };
    onAddExam(newExam);
    setEName('');
    setEPrice('');
  };

  const handlePriceUpdate = (id: string, newPrice: string) => {
    const exam = exams.find(e => e.id === id);
    if (exam) {
      onUpdateExam({ ...exam, price: parseFloat(newPrice) });
    }
  };

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden">
      <div className="flex border-b border-slate-700">
        <button
          onClick={() => setActiveTab('companies')}
          className={`flex-1 py-4 text-center font-medium text-sm transition-colors ${activeTab === 'companies' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Firmalar
        </button>
        <button
          onClick={() => setActiveTab('exams')}
          className={`flex-1 py-4 text-center font-medium text-sm transition-colors ${activeTab === 'exams' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Tetkikler ve Fiyatlar
        </button>
      </div>

      <div className="p-6">
        {activeTab === 'companies' && (
          <div className="space-y-8">
            {/* Add Company Form */}
            <form onSubmit={handleAddCompany} className="bg-slate-900/30 p-4 rounded-lg border border-slate-700 space-y-4">
              <h4 className="text-sm font-bold text-white flex items-center">
                <Plus className="w-4 h-4 mr-2" /> Yeni Firma Ekle
              </h4>
