                          setCompanySearchTerm(e.target.value);
                          setIsCompanyDropdownOpen(true);
                          if(selectedCompanyData && e.target.value !== selectedCompanyData.name) {
                              setSelectedCompanyData(null);
                          }
                      }}
                      onClick={() => setIsCompanyDropdownOpen(true)}
                      placeholder="Firma Ara..."
                      className={`w-full pl-9 pr-8 py-2 bg-slate-900 border text-white text-sm rounded-lg focus:ring-1 focus:ring-blue-500 outline-none transition-colors ${!selectedCompanyData && companySearchTerm ? 'border-blue-500' : 'border-slate-600'}`}
                    />

