                         className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-500 hover:text-red-400"
                       >
                           <X className="w-4 h-4" />
                       </button>
                    ) : (
                       <ChevronDown className="absolute right-2 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 pointer-events-none" />
