                      {filteredCompanies.length > 0 ? (
                        filteredCompanies.map(c => (
                          <div
                            key={c.id}
                            onClick={() => handleSelectCompany(c)}
                            className="px-3 py-2 hover:bg-slate-800 cursor-pointer flex items-center justify-between border-b border-slate-800 last:border-0"
                          >
                            <span className="text-sm text-slate-200">{c.name}</span>
                            {selectedCompanyData?.id === c.id && <Check className="w-3 h-3 text-blue-500" />}
                          </div>
                        ))
                      ) : (
                         <div className="px-3 py-2 text-sm text-slate-500">Sonuç bulunamadı...</div>
                      )}
                    </div>
                  )}
                </div>

                {selectedCompanyData && (
                  <div className="bg-slate-900/50 p-3 rounded-lg border border-slate-700 space-y-2 animate-fadeIn">
                    <div className={`text-xs px-2 py-1 rounded border font-medium flex items-center justify-center ${getHazardClassColor(selectedCompanyData.hazardClass)}`}>
                      <AlertTriangle className="w-3 h-3 mr-1" />
                      {selectedCompanyData.hazardClass}
                    </div>

                    <div className="flex items-center space-x-2">
                      <Stethoscope className="w-3 h-3 text-blue-500" />
                      <div>
                        <p className="text-[10px] text-slate-500 uppercase">Hekim</p>
                        <p className="text-xs font-medium text-slate-300 truncate w-32">{selectedCompanyData.assignedDoctor}</p>
                      </div>
                    </div>

                    <div className="flex items-center space-x-2">
                      <ShieldCheck className="w-3 h-3 text-emerald-500" />
                      <div>
                        <p className="text-[10px] text-slate-500 uppercase">İSG Uzmanı</p>
                        <p className="text-xs font-medium text-slate-300 truncate w-32">{selectedCompanyData.assignedSpecialist}</p>
                      </div>
                    </div>
                  </div>
                )}

