                  <span className="font-semibold text-sm">Tetkik Seçimi</span>
                </div>
                <div className="text-xs text-slate-400">
                  {selectedExamIds.length} Seçili
                </div>
             </div>

             <div className="overflow-y-auto custom-scrollbar flex-1 pr-1">
                <div className="grid grid-cols-2 gap-2">
                  {exams.map((exam) => (
                    <div 
                      key={exam.id}
                      onClick={() => toggleExam(exam.name)}
                      className={`cursor-pointer px-3 py-2.5 rounded-lg border flex items-center justify-between transition-all select-none ${
                        selectedExamIds.includes(exam.name) 
                        ? 'border-blue-500 bg-blue-500/10 shadow-sm' 
                        : 'border-slate-700 bg-slate-900/30 hover:bg-slate-700'
                      }`}
                    >
                      <div className="flex items-center space-x-2 overflow-hidden">
                        <div className={`w-4 h-4 rounded border flex shrink-0 items-center justify-center transition-colors ${selectedExamIds.includes(exam.name) ? 'bg-blue-500 border-blue-500' : 'border-slate-600 bg-slate-900'}`}>
                          {selectedExamIds.includes(exam.name) && <Activity className="w-3 h-3 text-white" />}
                        </div>
                        <span className={`text-xs font-medium truncate ${selectedExamIds.includes(exam.name) ? 'text-blue-100' : 'text-slate-400'}`}>{exam.name}</span>
                      </div>
                      <span className="text-xs font-mono text-slate-500 ml-2">₺{exam.price}</span>
