                <button 
                  type="button"
                  onClick={onClose}
                  className="py-3 bg-slate-800 hover:bg-slate-700 border border-slate-700 text-slate-300 font-medium rounded-xl transition-colors flex items-center justify-center space-x-2"
                >
                  <XCircle className="w-4 h-4" />
                  <span>İptal</span>
                </button>
                <button 
                  type="submit"
                  className="py-3 bg-blue-600 hover:bg-blue-500 text-white font-bold rounded-xl shadow-lg shadow-blue-900/20 transition-all active:scale-95 flex items-center justify-center space-x-2"
                >
                  <Save className="w-4 h-4" />
                  <span>Kaydet</span>
                </button>
             </div>
          </div>

      </form>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Company, ExamDefinition, HazardClass } from '../types';
import { Trash2, Plus, Building2, TestTube, Save, Check, Wallet, Receipt, Upload, FileDown, AlertCircle } from 'lucide-react';

interface SettingsViewProps {
  companies: Company[];
  onAddCompany: (c: Company) => void;
  onDeleteCompany: (id: string) => void;
  exams: ExamDefinition[];
  onAddExam: (e: ExamDefinition) => void;
  onUpdateExam: (e: ExamDefinition) => void;
  onDeleteExam: (id: string) => void;
}

export const SettingsView: React.FC<SettingsViewProps> = ({
  companies,
  onAddCompany,
  onDeleteCompany,
  exams,
  onAddExam,
  onUpdateExam,
  onDeleteExam
}) => {
  const [activeTab, setActiveTab] = useState<'companies' | 'exams'>('companies');

  // Company Form State
  const [cName, setCName] = useState('');
  const [cHazard, setCHazard] = useState<HazardClass>(HazardClass.LESS);
  const [cDoctor, setCDoctor] = useState('');
  const [cSpecialist, setCSpecialist] = useState('');
  const [cPaymentMethod, setCPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');
  const [cSelectedExams, setCSelectedExams] = useState<string[]>([]);

  // File Import Ref
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Exam Form State
  const [eName, setEName] = useState('');
  const [ePrice, setEPrice] = useState('');

  const toggleCompanyExam = (examName: string) => {
    setCSelectedExams(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const handleAddCompany = (e: React.FormEvent) => {
    e.preventDefault();
    if (!cName) return;
    const newCompany: Company = {
      id: Math.random().toString(36).substr(2, 9),
      name: cName,
      hazardClass: cHazard,
      assignedDoctor: cDoctor || 'Belirlenmedi',
      assignedSpecialist: cSpecialist || 'Belirlenmedi',
      defaultExams: cSelectedExams,
      defaultPaymentMethod: cPaymentMethod
    };
    onAddCompany(newCompany);
    setCName('');
    setCDoctor('');
    setCSpecialist('');
    setCPaymentMethod('INVOICE');
    setCSelectedExams([]);
  };

  // --- Bulk Import / Template Logic ---

  const downloadTemplate = () => {
    const headers = "Firma Adi;Tehlike Sinifi (Az/Cok/Tehlikeli);Hekim Adi;Uzman Adi;Odeme Turu (Nakit/Fatura)";
    const example = "Ornek Firma Ltd;Az Tehlikeli;Dr. Ahmet;Uzm. Ayse;Fatura";
    const csvContent = "data:text/csv;charset=utf-8," + [headers, example].join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "firma_yukleme_sablonu.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const text = evt.target?.result as string;
      if (!text) return;

      const lines = text.split('\n');
      let successCount = 0;

      // Skip header (index 0)
      for (let i = 1; i < lines.length; i++) {
        const line = lines[i].trim();
        if (!line) continue;

        // Split by semicolon (common for excel csv) or comma
        const parts = line.includes(';') ? line.split(';') : line.split(',');

        if (parts.length >= 1) {
          const name = parts[0].trim();
          if(!name) continue;

          // Parse Hazard Class (Fuzzy match)
          let hazard = HazardClass.LESS;
          const hazardStr = parts[1]?.toLowerCase() || '';
          if (hazardStr.includes('çok') || hazardStr.includes('cok')) hazard = HazardClass.VERY_DANGEROUS;
          else if (hazardStr.includes('az')) hazard = HazardClass.LESS;
          else if (hazardStr.includes('tehlikeli')) hazard = HazardClass.DANGEROUS;

          // Parse Payment Method
          let payment: 'CASH' | 'INVOICE' = 'INVOICE';
          const payStr = parts[4]?.toLowerCase() || '';
          if (payStr.includes('nakit') || payStr.includes('elden')) payment = 'CASH';

          const newComp: Company = {
            id: Math.random().toString(36).substr(2, 9),
            name: name,
            hazardClass: hazard,
            assignedDoctor: parts[2]?.trim() || 'Belirlenmedi',
            assignedSpecialist: parts[3]?.trim() || 'Belirlenmedi',
            defaultPaymentMethod: payment,
            defaultExams: [] // Bulk import doesn't set detailed exams by default for simplicity
          };

          onAddCompany(newComp);
          successCount++;
        }
      }
      alert(`${successCount} adet firma başarıyla yüklendi.`);
      if(fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  // --- End Bulk Import Logic ---

  const handleAddExam = (e: React.FormEvent) => {
    e.preventDefault();
    if (!eName || !ePrice) return;
    const newExam: ExamDefinition = {
      id: Math.random().toString(36).substr(2, 9),
      name: eName,
      price: parseFloat(ePrice)
    };
    onAddExam(newExam);
    setEName('');
    setEPrice('');
  };

  const handlePriceUpdate = (id: string, newPrice: string) => {
    const exam = exams.find(e => e.id === id);
    if (exam) {
      onUpdateExam({ ...exam, price: parseFloat(newPrice) });
    }
  };

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden">
      <div className="flex border-b border-slate-700">
        <button
          onClick={() => setActiveTab('companies')}
          className={`flex-1 py-4 text-center font-medium text-sm transition-colors ${activeTab === 'companies' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Firmalar
        </button>
        <button
          onClick={() => setActiveTab('exams')}
          className={`flex-1 py-4 text-center font-medium text-sm transition-colors ${activeTab === 'exams' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Tetkikler ve Fiyatlar
        </button>
      </div>

      <div className="p-6">
        {activeTab === 'companies' && (
          <div className="space-y-8">

            {/* Bulk Import Section */}
            <div className="bg-slate-900/50 p-4 rounded-lg border border-dashed border-slate-600 flex flex-col md:flex-row items-center justify-between gap-4">
              <div className="flex items-center space-x-3">
                 <div className="p-2 bg-emerald-500/10 rounded">
                   <Upload className="w-6 h-6 text-emerald-500" />
                 </div>
                 <div>
                    <h5 className="text-sm font-bold text-white">Toplu Firma Yükleme (Excel/CSV)</h5>
                    <p className="text-xs text-slate-400">Şablonu indirin, doldurun ve yükleyin.</p>
                 </div>
              </div>
              <div className="flex space-x-3">
                 <button 
                   onClick={downloadTemplate}
                   type="button"
                   className="flex items-center space-x-2 px-3 py-2 bg-slate-800 hover:bg-slate-700 border border-slate-600 rounded text-xs text-slate-300 transition-colors"
                 >
                    <FileDown className="w-4 h-4" />
                    <span>Şablon İndir</span>
                 </button>
                 <label className="flex items-center space-x-2 px-3 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded text-xs font-medium cursor-pointer transition-colors shadow-lg shadow-blue-900/20">
                    <Upload className="w-4 h-4" />
                    <span>Dosya Yükle</span>
                    <input 
                      type="file" 
                      accept=".csv,.txt" 
                      className="hidden" 
                      ref={fileInputRef}
                      onChange={handleFileUpload}
                    />
                 </label>
              </div>
            </div>

            {/* Add Company Form */}
            <form onSubmit={handleAddCompany} className="bg-slate-900/30 p-4 rounded-lg border border-slate-700 space-y-4">
              <h4 className="text-sm font-bold text-white flex items-center">
                <Plus className="w-4 h-4 mr-2" /> Tek Firma Ekle
              </h4>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <input required placeholder="Firma Adı" value={cName} onChange={e => setCName(e.target.value)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />
                <select value={cHazard} onChange={e => setCHazard(e.target.value as HazardClass)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm outline-none">
                  {Object.values(HazardClass).map(h => <option key={h} value={h}>{h}</option>)}
                </select>
                <input placeholder="İşyeri Hekimi" value={cDoctor} onChange={e => setCDoctor(e.target.value)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />
                <input placeholder="İSG Uzmanı" value={cSpecialist} onChange={e => setCSpecialist(e.target.value)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />

                {/* Payment Method Selector */}
                <div className="flex space-x-2">
                   <button 
                    type="button"
                    onClick={() => setCPaymentMethod('INVOICE')}
                    className={`flex-1 py-2 rounded text-sm font-medium border flex items-center justify-center space-x-2 transition-all ${cPaymentMethod === 'INVOICE' ? 'bg-blue-600/20 border-blue-500 text-blue-200' : 'bg-slate-800 border-slate-600 text-slate-400'}`}
                   >
                     <Receipt className="w-4 h-4" />
                     <span>Fatura / Cari</span>
                   </button>
                   <button 
                    type="button"
                    onClick={() => setCPaymentMethod('CASH')}
                    className={`flex-1 py-2 rounded text-sm font-medium border flex items-center justify-center space-x-2 transition-all ${cPaymentMethod === 'CASH' ? 'bg-emerald-600/20 border-emerald-500 text-emerald-200' : 'bg-slate-800 border-slate-600 text-slate-400'}`}
                   >
                     <Wallet className="w-4 h-4" />
                     <span>Nakit / Elden</span>
                   </button>
                </div>
              </div>

              {/* Exam Selection for Company */}
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Firma Standart Tetkikleri</label>
                <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                   {exams.map(exam => (
                     <div 
                      key={exam.id}
                      onClick={() => toggleCompanyExam(exam.name)}
                      className={`cursor-pointer px-3 py-2 rounded border flex items-center justify-between transition-all ${cSelectedExams.includes(exam.name) ? 'bg-blue-600/20 border-blue-500 text-blue-200' : 'bg-slate-800 border-slate-600 text-slate-400 hover:bg-slate-700'}`}
                     >
                       <span className="text-xs truncate mr-2">{exam.name}</span>
                       {cSelectedExams.includes(exam.name) && <Check className="w-3 h-3 text-blue-400" />}
                     </div>
                   ))}
                </div>
              </div>

              <div className="flex justify-end">
                <button type="submit" className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded text-sm">Ekle</button>
              </div>
            </form>

            {/* Company List */}
            <div className="space-y-3">
              <div className="text-sm text-slate-400 mb-2">Toplam {companies.length} Firma Kayıtlı</div>
              {companies.map(company => (
                <div key={company.id} className="flex flex-col md:flex-row items-start md:items-center justify-between p-4 bg-slate-700/30 border border-slate-700 rounded-lg gap-4">
                  <div className="flex items-center space-x-3">
                    <div className="p-2 bg-slate-800 rounded">
                      <Building2 className="w-5 h-5 text-slate-400" />
                    </div>
                    <div>
                      <h5 className="font-medium text-white flex items-center">
                        {company.name}
                        {company.defaultPaymentMethod === 'CASH' ? (
                          <span className="ml-2 px-1.5 py-0.5 text-[10px] bg-emerald-900/30 text-emerald-400 border border-emerald-500/20 rounded uppercase">Nakit</span>
                        ) : (
                          <span className="ml-2 px-1.5 py-0.5 text-[10px] bg-blue-900/30 text-blue-400 border border-blue-500/20 rounded uppercase">Fatura</span>
                        )}
                      </h5>
                      <p className="text-xs text-slate-400">{company.assignedDoctor} • {company.assignedSpecialist}</p>
                      <div className="flex flex-wrap gap-1 mt-1">
                        {company.defaultExams.map((ex, i) => (
                           <span key={i} className="text-[10px] px-1.5 py-0.5 bg-slate-800 text-slate-400 rounded border border-slate-600">{ex}</span>
                        ))}
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center space-x-3 w-full md:w-auto justify-end">
                    <span className="text-xs bg-slate-800 px-2 py-1 rounded border border-slate-600 text-slate-300">{company.hazardClass}</span>
                    <button onClick={() => onDeleteCompany(company.id)} className="text-slate-500 hover:text-red-400 p-1">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'exams' && (
          <div className="space-y-8">
            {/* Add Exam Form */}
            <form onSubmit={handleAddExam} className="bg-slate-900/30 p-4 rounded-lg border border-slate-700 space-y-4">
              <h4 className="text-sm font-bold text-white flex items-center">
                <Plus className="w-4 h-4 mr-2" /> Yeni Tetkik Ekle
              </h4>
              <div className="flex gap-4">
                <input required placeholder="Tetkik Adı (Örn: Portör)" value={eName} onChange={e => setEName(e.target.value)} className="flex-1 bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />
                <input required type="number" placeholder="Fiyat (TL)" value={ePrice} onChange={e => setEPrice(e.target.value)} className="w-32 bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />
                <button type="submit" className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded text-sm">Ekle</button>
              </div>
            </form>

            {/* Exam List */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {exams.map(exam => (
                <div key={exam.id} className="flex items-center justify-between p-4 bg-slate-700/30 border border-slate-700 rounded-lg">
                  <div className="flex items-center space-x-3">
                    <TestTube className="w-4 h-4 text-slate-400" />
                    <span className="font-medium text-white text-sm">{exam.name}</span>
                  </div>
                  <div className="flex items-center space-x-2">
                    <div className="relative">
                      <span className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-500 text-xs">₺</span>
                      <input 
                        type="number" 
                        defaultValue={exam.price} 
                        onBlur={(e) => handlePriceUpdate(exam.id, e.target.value)}
                        className="w-20 pl-5 pr-2 py-1 bg-slate-800 border border-slate-600 rounded text-xs text-white text-right focus:border-blue-500 outline-none"
                      />
                    </div>
                    <button onClick={() => onDeleteExam(exam.id)} className="text-slate-500 hover:text-red-400 p-1">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Building2, User, Activity, Stethoscope, ShieldCheck, AlertTriangle, Wallet, Receipt, Save, XCircle, Search, Check, ChevronDown, X, Info } from 'lucide-react';
import { Referral, Status, Company, HazardClass, ExamDefinition } from '../types';

interface NewReferralViewProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
  companies: Company[];
  exams: ExamDefinition[];
}

export const NewReferralView: React.FC<NewReferralViewProps> = ({ onClose, onSubmit, companies, exams }) => {
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');

  // Searchable Company Dropdown State
  const [companySearchTerm, setCompanySearchTerm] = useState('');
  const [isCompanyDropdownOpen, setIsCompanyDropdownOpen] = useState(false);
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Exam Search State
  const [examSearchTerm, setExamSearchTerm] = useState('');

  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');
  const [estimatedPrice, setEstimatedPrice] = useState(0);

  // Payment Method State
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');

  // Filter companies based on search
  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(companySearchTerm.toLowerCase())
  );

  // Filter exams based on search
  const filteredExams = exams.filter(e => 
    e.name.toLowerCase().includes(examSearchTerm.toLowerCase())
  );

  // Handle click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCompanyDropdownOpen(false);
        if (selectedCompanyData) {
            setCompanySearchTerm(selectedCompanyData.name);
        } else {
            setCompanySearchTerm('');
        }
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [selectedCompanyData]);

  // Recalculate price when exams change
  useEffect(() => {
    const total = selectedExamIds.reduce((sum, id) => {
      const exam = exams.find(e => e.name === id); 
      const price = exam ? exam.price : 0;
      return sum + price;
    }, 0);
    setEstimatedPrice(total);
  }, [selectedExamIds, exams]);

  const handleSelectCompany = (company: Company) => {
      setSelectedCompanyData(company);
      setCompanySearchTerm(company.name);
      setIsCompanyDropdownOpen(false);

      // Auto-fill logic
      setSelectedExamIds(company.defaultExams);
      setPaymentMethod(company.defaultPaymentMethod || 'INVOICE');
  };

  const handleClearCompany = () => {
      setSelectedCompanyData(null);
      setCompanySearchTerm('');
      setSelectedExamIds([]);
  };

  const toggleExam = (examName: string) => {
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const getHazardClassStyles = (hazard: HazardClass) => {
    switch (hazard) {
      case HazardClass.VERY_DANGEROUS: 
        return { 
          bg: 'bg-red-500/10', 
          text: 'text-red-400', 
          border: 'border-red-500/30',
          badge: 'bg-red-500 text-white'
        };
      case HazardClass.DANGEROUS: 
        return { 
          bg: 'bg-orange-500/10', 
          text: 'text-orange-400', 
          border: 'border-orange-500/30',
          badge: 'bg-orange-500 text-white'
        };
      case HazardClass.LESS: 
        return { 
          bg: 'bg-emerald-500/10', 
          text: 'text-emerald-400', 
          border: 'border-emerald-500/30',
          badge: 'bg-emerald-500 text-white'
        };
      default: 
        return { 
          bg: 'bg-slate-700/50', 
          text: 'text-slate-300', 
          border: 'border-slate-600',
          badge: 'bg-slate-600 text-white'
        };
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!fullName || !selectedCompanyData) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        company: selectedCompanyData.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData.assignedDoctor,
      specialistName: selectedCompanyData.assignedSpecialist,
      totalPrice: estimatedPrice,
      paymentMethod: paymentMethod
    };

    onSubmit(newReferral);
  };

  return (
    <div className="h-full flex flex-col overflow-hidden animate-fadeIn bg-slate-950">
      {/* Header */}
      <div className="flex items-center justify-between mb-6 px-1 pt-1 shrink-0">
         <div className="flex items-center space-x-4">
            <button onClick={onClose} className="p-2.5 bg-slate-900 border border-slate-700 hover:border-slate-500 rounded-xl text-slate-400 hover:text-white transition-all shadow-sm">
               <ArrowLeft className="w-5 h-5" />
            </button>
            <div>
               <h1 className="text-2xl font-bold text-white tracking-tight">Yeni Sevk Kaydı</h1>
               <p className="text-sm text-slate-400 flex items-center">
                 <Info className="w-3 h-3 mr-1" /> 
                 Personel bilgilerini girin ve gerekli tetkikleri seçin.
               </p>
            </div>
         </div>
      </div>

      {/* Main 3-Column Layout */}
      <form id="referralForm" onSubmit={handleSubmit} className="flex-1 grid grid-cols-12 gap-6 min-h-0 pb-2">

          {/* COLUMN 1: Identity & Company (Span 3) */}
          <div className="col-span-12 lg:col-span-3 flex flex-col gap-6">
             {/* Company Section */}
             <div className="bg-slate-900/50 backdrop-blur-sm rounded-2xl border border-slate-800 p-5 shadow-xl">
                <div className="flex items-center space-x-2 text-slate-200 mb-4">
                   <div className="p-1.5 bg-blue-500/10 rounded-lg">
                      <Building2 className="w-4 h-4 text-blue-500" />
                   </div>
                   <span className="font-semibold">Firma Bilgileri</span>
                </div>

                <div ref={dropdownRef} className="relative mb-4">
                    <label className="text-xs font-medium text-slate-400 block mb-1.5 ml-1">Firma Seçimi</label>
                    <div className="relative group">
                      <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 group-focus-within:text-blue-500 transition-colors z-10" />
                      <input
                        type="text"
                        required
                        value={companySearchTerm}
                        onChange={(e) => {
                            setCompanySearchTerm(e.target.value);
                            setIsCompanyDropdownOpen(true);
                            if(selectedCompanyData && e.target.value !== selectedCompanyData.name) {
                                setSelectedCompanyData(null);
                            }
                        }}
                        onClick={() => setIsCompanyDropdownOpen(true)}
                        placeholder="Firma adı yazın..."
                        className={`w-full pl-10 pr-9 py-3 bg-slate-950 border text-white text-sm rounded-xl focus:ring-2 focus:ring-blue-500/50 outline-none transition-all shadow-inner ${!selectedCompanyData && companySearchTerm ? 'border-blue-500' : 'border-slate-700 group-hover:border-slate-600'}`}
                      />
                      {selectedCompanyData ? (
                         <button type="button" onClick={handleClearCompany} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-red-400 transition-colors">
