                     <div>
                        <h2 className="font-semibold">Tetkik Seçimi</h2>
                        <p className="text-xs text-slate-500">Yapılacak işlemleri işaretleyin</p>
                     </div>
                   </div>
                   <div className="px-3 py-1 bg-blue-500/10 rounded-full border border-blue-500/20 text-blue-400 text-xs font-bold">
                     {selectedExamIds.length} Seçili
                   </div>
                </div>

                {/* Exam Search */}
                <div className="relative">
                   <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                   <input 
