import React, { useState, useRef } from 'react';
import { Company, ExamDefinition, HazardClass } from '../types';
import { Trash2, Plus, Building2, TestTube, Save, Check, Wallet, Receipt, Upload, FileDown, AlertCircle } from 'lucide-react';
import * as XLSX from 'xlsx';

interface SettingsViewProps {
  companies: Company[];
  onAddCompany: (c: Company) => void;
  onDeleteCompany: (id: string) => void;
  exams: ExamDefinition[];
  onAddExam: (e: ExamDefinition) => void;
  onUpdateExam: (e: ExamDefinition) => void;
  onDeleteExam: (id: string) => void;
}

export const SettingsView: React.FC<SettingsViewProps> = ({
  companies,
  onAddCompany,
  onDeleteCompany,
  exams,
  onAddExam,
  onUpdateExam,
  onDeleteExam
}) => {
  const [activeTab, setActiveTab] = useState<'companies' | 'exams'>('companies');

  // Company Form State
  const [cName, setCName] = useState('');
  const [cHazard, setCHazard] = useState<HazardClass>(HazardClass.LESS);
  const [cDoctor, setCDoctor] = useState('');
  const [cSpecialist, setCSpecialist] = useState('');
  const [cPaymentMethod, setCPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');
  const [cSelectedExams, setCSelectedExams] = useState<string[]>([]);

  // File Import Ref
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Exam Form State
  const [eName, setEName] = useState('');
  const [ePrice, setEPrice] = useState('');

  const toggleCompanyExam = (examName: string) => {
    setCSelectedExams(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const handleAddCompany = (e: React.FormEvent) => {
    e.preventDefault();
    if (!cName) return;
    const newCompany: Company = {
      id: Math.random().toString(36).substr(2, 9),
      name: cName,
      hazardClass: cHazard,
      assignedDoctor: cDoctor || 'Belirlenmedi',
      assignedSpecialist: cSpecialist || 'Belirlenmedi',
      defaultExams: cSelectedExams,
      defaultPaymentMethod: cPaymentMethod
    };
    onAddCompany(newCompany);
    setCName('');
    setCDoctor('');
    setCSpecialist('');
    setCPaymentMethod('INVOICE');
    setCSelectedExams([]);
  };

  // --- Bulk Import / Template Logic (Excel .xlsx) ---

  const downloadTemplate = () => {
    // Define Headers and Example Data
    const headers = ["Firma Adı", "Tehlike Sınıfı (Az/Tehlikeli/Çok)", "Hekim Adı", "Uzman Adı", "Ödeme (Nakit/Fatura)"];
    const exampleRow = ["Örnek Metal A.Ş.", "Tehlikeli", "Dr. Ahmet Yılmaz", "Uzm. Ayşe Demir", "Fatura"];

    // Create Worksheet
    const ws = XLSX.utils.aoa_to_sheet([headers, exampleRow]);

    // Set column widths for better readability
    ws['!cols'] = [
      { wch: 30 }, // Firma Adı
      { wch: 25 }, // Tehlike Sınıfı
      { wch: 20 }, // Hekim
      { wch: 20 }, // Uzman
      { wch: 20 }  // Ödeme
    ];

    // Create Workbook and append sheet
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Firma_Listesi");

    // Write file
    XLSX.writeFile(wb, "firma_yukleme_sablonu.xlsx");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();

    reader.onload = (evt) => {
      const bstr = evt.target?.result;
      if (!bstr) return;

      try {
        const wb = XLSX.read(bstr, { type: 'binary' });

        // Get the first worksheet
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        // Convert to JSON array of arrays (header: 1 means raw arrays)
        const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];

        let successCount = 0;

        // Start from index 1 to skip headers
        for (let i = 1; i < data.length; i++) {
          const row = data[i];
          // Ensure row has at least the name
          if (!row || row.length === 0 || !row[0]) continue;

          const name = String(row[0]).trim();
          const hazardRaw = String(row[1] || '').toLowerCase();
          const doctor = String(row[2] || 'Belirlenmedi').trim();
          const specialist = String(row[3] || 'Belirlenmedi').trim();
          const paymentRaw = String(row[4] || '').toLowerCase();

          // Parse Hazard Class
          let hazard = HazardClass.LESS;
          if (hazardRaw.includes('çok') || hazardRaw.includes('cok')) hazard = HazardClass.VERY_DANGEROUS;
          else if (hazardRaw.includes('az')) hazard = HazardClass.LESS;
          else if (hazardRaw.includes('tehlikeli')) hazard = HazardClass.DANGEROUS;

          // Parse Payment
          let payment: 'CASH' | 'INVOICE' = 'INVOICE';
          if (paymentRaw.includes('nakit') || paymentRaw.includes('elden') || paymentRaw.includes('kasa')) {
            payment = 'CASH';
          }

          const newComp: Company = {
            id: Math.random().toString(36).substr(2, 9),
            name: name,
            hazardClass: hazard,
            assignedDoctor: doctor,
            assignedSpecialist: specialist,
            defaultPaymentMethod: payment,
            defaultExams: [] 
          };

          onAddCompany(newComp);
          successCount++;
        }

        alert(`${successCount} adet firma Excel dosyasından başarıyla yüklendi.`);
      } catch (error) {
        console.error("Excel okuma hatası:", error);
        alert("Dosya okunurken bir hata oluştu. Lütfen geçerli bir .xlsx dosyası yükleyin.");
      } finally {
        if(fileInputRef.current) fileInputRef.current.value = '';
      }
    };

    // Use readAsBinaryString for compatibility with the specific xlsx version CDN
    reader.readAsBinaryString(file);
  };

  // --- End Bulk Import Logic ---

  const handleAddExam = (e: React.FormEvent) => {
    e.preventDefault();
    if (!eName || !ePrice) return;
    const newExam: ExamDefinition = {
      id: Math.random().toString(36).substr(2, 9),
      name: eName,
      price: parseFloat(ePrice)
    };
    onAddExam(newExam);
    setEName('');
    setEPrice('');
  };

  const handlePriceUpdate = (id: string, newPrice: string) => {
    const exam = exams.find(e => e.id === id);
    if (exam) {
      onUpdateExam({ ...exam, price: parseFloat(newPrice) });
    }
  };

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden">
      <div className="flex border-b border-slate-700">
        <button
          onClick={() => setActiveTab('companies')}
          className={`flex-1 py-4 text-center font-medium text-sm transition-colors ${activeTab === 'companies' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Firmalar
        </button>
        <button
          onClick={() => setActiveTab('exams')}
          className={`flex-1 py-4 text-center font-medium text-sm transition-colors ${activeTab === 'exams' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Tetkikler ve Fiyatlar
        </button>
      </div>

      <div className="p-6">
        {activeTab === 'companies' && (
          <div className="space-y-8">

            {/* Bulk Import Section */}
            <div className="bg-slate-900/50 p-4 rounded-lg border border-dashed border-slate-600 flex flex-col md:flex-row items-center justify-between gap-4">
              <div className="flex items-center space-x-3">
                 <div className="p-2 bg-emerald-500/10 rounded">
                   <Upload className="w-6 h-6 text-emerald-500" />
                 </div>
                 <div>
                    <h5 className="text-sm font-bold text-white">Toplu Firma Yükleme (Excel)</h5>
                    <p className="text-xs text-slate-400">Excel (.xlsx) şablonunu indirin, doldurun ve yükleyin.</p>
                 </div>
              </div>
              <div className="flex space-x-3">
                 <button 
                   onClick={downloadTemplate}
                   type="button"
                   className="flex items-center space-x-2 px-3 py-2 bg-slate-800 hover:bg-slate-700 border border-slate-600 rounded text-xs text-slate-300 transition-colors"
                 >
                    <FileDown className="w-4 h-4" />
                    <span>Şablon İndir</span>
                 </button>
                 <label className="flex items-center space-x-2 px-3 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded text-xs font-medium cursor-pointer transition-colors shadow-lg shadow-blue-900/20">
                    <Upload className="w-4 h-4" />
                    <span>Excel Yükle</span>
                    <input 
                      type="file" 
                      accept=".xlsx, .xls" 
                      className="hidden" 
                      ref={fileInputRef}
                      onChange={handleFileUpload}
                    />
                 </label>
              </div>
            </div>

            {/* Add Company Form */}
            <form onSubmit={handleAddCompany} className="bg-slate-900/30 p-4 rounded-lg border border-slate-700 space-y-4">
              <h4 className="text-sm font-bold text-white flex items-center">
                <Plus className="w-4 h-4 mr-2" /> Tek Firma Ekle
              </h4>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <input required placeholder="Firma Adı" value={cName} onChange={e => setCName(e.target.value)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />
                <select value={cHazard} onChange={e => setCHazard(e.target.value as HazardClass)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm outline-none">
                  {Object.values(HazardClass).map(h => <option key={h} value={h}>{h}</option>)}
                </select>
                <input placeholder="İşyeri Hekimi" value={cDoctor} onChange={e => setCDoctor(e.target.value)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />
                <input placeholder="İSG Uzmanı" value={cSpecialist} onChange={e => setCSpecialist(e.target.value)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />

                {/* Payment Method Selector */}
                <div className="flex space-x-2">
                   <button 
                    type="button"
                    onClick={() => setCPaymentMethod('INVOICE')}
                    className={`flex-1 py-2 rounded text-sm font-medium border flex items-center justify-center space-x-2 transition-all ${cPaymentMethod === 'INVOICE' ? 'bg-blue-600/20 border-blue-500 text-blue-200' : 'bg-slate-800 border-slate-600 text-slate-400'}`}
                   >
                     <Receipt className="w-4 h-4" />
                     <span>Fatura / Cari</span>
                   </button>
                   <button 
                    type="button"
                    onClick={() => setCPaymentMethod('CASH')}
                    className={`flex-1 py-2 rounded text-sm font-medium border flex items-center justify-center space-x-2 transition-all ${cPaymentMethod === 'CASH' ? 'bg-emerald-600/20 border-emerald-500 text-emerald-200' : 'bg-slate-800 border-slate-600 text-slate-400'}`}
                   >
                     <Wallet className="w-4 h-4" />
                     <span>Nakit / Elden</span>
                   </button>
                </div>
              </div>

              {/* Exam Selection for Company */}
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Firma Standart Tetkikleri</label>
                <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                   {exams.map(exam => (
                     <div 
                      key={exam.id}
                      onClick={() => toggleCompanyExam(exam.name)}
                      className={`cursor-pointer px-3 py-2 rounded border flex items-center justify-between transition-all ${cSelectedExams.includes(exam.name) ? 'bg-blue-600/20 border-blue-500 text-blue-200' : 'bg-slate-800 border-slate-600 text-slate-400 hover:bg-slate-700'}`}
                     >
                       <span className="text-xs truncate mr-2">{exam.name}</span>
                       {cSelectedExams.includes(exam.name) && <Check className="w-3 h-3 text-blue-400" />}
                     </div>
                   ))}
                </div>
              </div>

              <div className="flex justify-end">
                <button type="submit" className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded text-sm">Ekle</button>
              </div>
            </form>

            {/* Company List */}
            <div className="space-y-3">
              <div className="text-sm text-slate-400 mb-2">Toplam {companies.length} Firma Kayıtlı</div>
              {companies.map(company => (
                <div key={company.id} className="flex flex-col md:flex-row items-start md:items-center justify-between p-4 bg-slate-700/30 border border-slate-700 rounded-lg gap-4">
                  <div className="flex items-center space-x-3">
                    <div className="p-2 bg-slate-800 rounded">
                      <Building2 className="w-5 h-5 text-slate-400" />
                    </div>
                    <div>
                      <h5 className="font-medium text-white flex items-center">
                        {company.name}
                        {company.defaultPaymentMethod === 'CASH' ? (
                          <span className="ml-2 px-1.5 py-0.5 text-[10px] bg-emerald-900/30 text-emerald-400 border border-emerald-500/20 rounded uppercase">Nakit</span>
                        ) : (
                          <span className="ml-2 px-1.5 py-0.5 text-[10px] bg-blue-900/30 text-blue-400 border border-blue-500/20 rounded uppercase">Fatura</span>
                        )}
                      </h5>
                      <p className="text-xs text-slate-400">{company.assignedDoctor} • {company.assignedSpecialist}</p>
                      <div className="flex flex-wrap gap-1 mt-1">
                        {company.defaultExams.map((ex, i) => (
                           <span key={i} className="text-[10px] px-1.5 py-0.5 bg-slate-800 text-slate-400 rounded border border-slate-600">{ex}</span>
                        ))}
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center space-x-3 w-full md:w-auto justify-end">
                    <span className="text-xs bg-slate-800 px-2 py-1 rounded border border-slate-600 text-slate-300">{company.hazardClass}</span>
                    <button onClick={() => onDeleteCompany(company.id)} className="text-slate-500 hover:text-red-400 p-1">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'exams' && (
          <div className="space-y-8">
            {/* Add Exam Form */}
            <form onSubmit={handleAddExam} className="bg-slate-900/30 p-4 rounded-lg border border-slate-700 space-y-4">
              <h4 className="text-sm font-bold text-white flex items-center">
                <Plus className="w-4 h-4 mr-2" /> Yeni Tetkik Ekle
              </h4>
              <div className="flex gap-4">
                <input required placeholder="Tetkik Adı (Örn: Portör)" value={eName} onChange={e => setEName(e.target.value)} className="flex-1 bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />
                <input required type="number" placeholder="Fiyat (TL)" value={ePrice} onChange={e => setEPrice(e.target.value)} className="w-32 bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />
                <button type="submit" className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded text-sm">Ekle</button>
              </div>
            </form>

            {/* Exam List */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {exams.map(exam => (
                <div key={exam.id} className="flex items-center justify-between p-4 bg-slate-700/30 border border-slate-700 rounded-lg">
                  <div className="flex items-center space-x-3">
                    <TestTube className="w-4 h-4 text-slate-400" />
                    <span className="font-medium text-white text-sm">{exam.name}</span>
                  </div>
                  <div className="flex items-center space-x-2">
                    <div className="relative">
                      <span className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-500 text-xs">₺</span>
                      <input 
                        type="number" 
                        defaultValue={exam.price} 
                        onBlur={(e) => handlePriceUpdate(exam.id, e.target.value)}
                        className="w-20 pl-5 pr-2 py-1 bg-slate-800 border border-slate-600 rounded text-xs text-white text-right focus:border-blue-500 outline-none"
                      />
                    </div>
                    <button onClick={() => onDeleteExam(exam.id)} className="text-slate-500 hover:text-red-400 p-1">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export enum Status {
  PENDING = 'PENDING',       // Bekliyor (Henüz gitmedi)
  AT_HOSPITAL = 'AT_HOSPITAL', // Hastanede / Tetkikte
  AWAITING_RESULT = 'AWAITING_RESULT', // Sonuç Bekleniyor
  COMPLETED = 'COMPLETED',   // Tamamlandı
  CANCELLED = 'CANCELLED'    // İptal
}

// Deprecated enum usage in favor of dynamic list, keeping for type safety in legacy code
export enum ExamType {
  AUDIOMETRY = 'Odyometri',
  LUNG_XRAY = 'Akciğer Grafisi',
  HEMOGRAM = 'Hemogram',
  VISION = 'Göz Muayenesi',
  EKG = 'EKG',
  TETANUS = 'Tetanoz Aşısı',
  BLOOD_SUGAR = 'Açlık Kan Şekeri',
  LIVER_FUNC = 'Karaciğer Fonksiyon Testleri'
}

export interface ExamDefinition {
  id: string;
  code: string; // Excel mapping code (e.g. "101", "HEM")
  name: string;
  price: number;
}

export enum HazardClass {
  LESS = 'Az Tehlikeli',
  DANGEROUS = 'Tehlikeli',
  VERY_DANGEROUS = 'Çok Tehlikeli'
}

export interface Company {
  id: string;
  name: string;
  hazardClass: HazardClass;
  assignedDoctor: string;     // İşyeri Hekimi
  assignedSpecialist: string; // İSG Uzmanı
  defaultExams: string[];     // Changed from ExamType[] to string[] to support dynamic exams
  defaultPaymentMethod: 'CASH' | 'INVOICE'; // Firmanın varsayılan ödeme yöntemi
}

export interface Employee {
  id: string;
  fullName: string;
  tcNo: string;
  company: string;
  department?: string;
}

export interface Referral {
  id: string;
  employee: Employee;
  exams: string[]; // Changed to string[]
  status: Status;
  referralDate: string; // ISO Date string
  notes?: string;
  aiAnalysis?: string; // Gemini analysis result
  resultSummary?: string;
  doctorName?: string; // Kayıt anındaki doktor
  specialistName?: string; // Kayıt anındaki uzman
  totalPrice?: number; // Calculated price at time of referral
  paymentMethod: 'CASH' | 'INVOICE'; // Nakit (Kasa) veya Cari (Fatura)
}

export interface Stats {
  total: number;
  today: number;
  totalIncome: number;
}

export interface SafeTransaction {
  id: string;
  type: 'INCOME' | 'EXPENSE';
  amount: number;
  description: string;
  date: string;
  category?: string;
}

import React, { useState, useRef } from 'react';
import { Company, ExamDefinition, HazardClass } from '../types';
import { Trash2, Plus, Building2, TestTube, Save, Check, Wallet, Receipt, Upload, FileDown, AlertCircle } from 'lucide-react';
import * as XLSX from 'xlsx';

interface SettingsViewProps {
  companies: Company[];
  onAddCompany: (c: Company) => void;
  onDeleteCompany: (id: string) => void;
  exams: ExamDefinition[];
  onAddExam: (e: ExamDefinition) => void;
  onUpdateExam: (e: ExamDefinition) => void;
  onDeleteExam: (id: string) => void;
}

export const SettingsView: React.FC<SettingsViewProps> = ({
  companies,
  onAddCompany,
  onDeleteCompany,
  exams,
  onAddExam,
  onUpdateExam,
  onDeleteExam
}) => {
  const [activeTab, setActiveTab] = useState<'companies' | 'exams'>('companies');

  // Company Form State
  const [cName, setCName] = useState('');
  const [cHazard, setCHazard] = useState<HazardClass>(HazardClass.LESS);
  const [cDoctor, setCDoctor] = useState('');
  const [cSpecialist, setCSpecialist] = useState('');
  const [cPaymentMethod, setCPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');
  const [cSelectedExams, setCSelectedExams] = useState<string[]>([]);

  // File Import Ref
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Exam Form State
  const [eName, setEName] = useState('');
  const [eCode, setECode] = useState('');
  const [ePrice, setEPrice] = useState('');

  const toggleCompanyExam = (examName: string) => {
    setCSelectedExams(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const handleAddCompany = (e: React.FormEvent) => {
    e.preventDefault();
    if (!cName) return;
    const newCompany: Company = {
      id: Math.random().toString(36).substr(2, 9),
      name: cName,
      hazardClass: cHazard,
      assignedDoctor: cDoctor || 'Belirlenmedi',
      assignedSpecialist: cSpecialist || 'Belirlenmedi',
      defaultExams: cSelectedExams,
      defaultPaymentMethod: cPaymentMethod
    };
    onAddCompany(newCompany);
    setCName('');
    setCDoctor('');
    setCSpecialist('');
    setCPaymentMethod('INVOICE');
    setCSelectedExams([]);
  };

  // --- Bulk Import / Template Logic (Excel .xlsx) ---

  const downloadTemplate = () => {
    // Sheet 1: Firmalar (Template to fill)
    const headers = ["Firma Adı", "Tehlike Sınıfı (Az/Tehlikeli/Çok)", "Hekim Adı", "Uzman Adı", "Ödeme (Nakit/Fatura)", "Tetkik Kodları (Virgül ile)"];
    const exampleRow = ["Örnek Metal A.Ş.", "Tehlikeli", "Dr. Ahmet Yılmaz", "Uzm. Ayşe Demir", "Fatura", "101, 103, 105"];
    const wsFirmalar = XLSX.utils.aoa_to_sheet([headers, exampleRow]);

    wsFirmalar['!cols'] = [
      { wch: 30 }, // Firma Adı
      { wch: 25 }, // Tehlike
      { wch: 20 }, // Hekim
      { wch: 20 }, // Uzman
      { wch: 20 }, // Ödeme
      { wch: 30 }  // Tetkik Kodları
    ];

    // Sheet 2: Tetkik Referans (Read-only reference)
    const refHeaders = ["Tetkik Kodu", "Tetkik Adı", "Fiyat"];
    const refRows = exams.map(e => [e.code, e.name, e.price]);
    const wsRef = XLSX.utils.aoa_to_sheet([refHeaders, ...refRows]);
    wsRef['!cols'] = [{ wch: 15 }, { wch: 30 }, { wch: 10 }];

    // Create Workbook
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, wsFirmalar, "Firma_Listesi");
    XLSX.utils.book_append_sheet(wb, wsRef, "Tetkik_Referans_Listesi");

    // Write file
    XLSX.writeFile(wb, "firma_yukleme_sablonu.xlsx");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();

    reader.onload = (evt) => {
      const bstr = evt.target?.result;
      if (!bstr) return;

      try {
        const wb = XLSX.read(bstr, { type: 'binary' });

        // Use the first sheet
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        // Convert to JSON array
        const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];

        let successCount = 0;

        // Skip header row
        for (let i = 1; i < data.length; i++) {
          const row = data[i];
          if (!row || row.length === 0 || !row[0]) continue;

          const name = String(row[0]).trim();
          const hazardRaw = String(row[1] || '').toLowerCase();
          const doctor = String(row[2] || 'Belirlenmedi').trim();
          const specialist = String(row[3] || 'Belirlenmedi').trim();
          const paymentRaw = String(row[4] || '').toLowerCase();
          const examCodesStr = String(row[5] || '').trim();

          // Hazard Class
          let hazard = HazardClass.LESS;
          if (hazardRaw.includes('çok') || hazardRaw.includes('cok')) hazard = HazardClass.VERY_DANGEROUS;
          else if (hazardRaw.includes('az')) hazard = HazardClass.LESS;
          else if (hazardRaw.includes('tehlikeli')) hazard = HazardClass.DANGEROUS;

          // Payment
          let payment: 'CASH' | 'INVOICE' = 'INVOICE';
          if (paymentRaw.includes('nakit') || paymentRaw.includes('elden') || paymentRaw.includes('kasa')) {
            payment = 'CASH';
          }

          // Process Exam Codes (e.g., "101, 105") -> Match to Exam Names
          const requestedCodes = examCodesStr.split(',').map(s => s.trim()).filter(s => s !== '');
          const matchedExams = exams
            .filter(e => requestedCodes.includes(e.code) || requestedCodes.includes(e.code.toString()))
            .map(e => e.name);

          const newComp: Company = {
            id: Math.random().toString(36).substr(2, 9),
            name: name,
            hazardClass: hazard,
            assignedDoctor: doctor,
            assignedSpecialist: specialist,
            defaultPaymentMethod: payment,
            defaultExams: matchedExams 
          };

          onAddCompany(newComp);
          successCount++;
        }

        alert(`${successCount} adet firma ve ilişkili tetkikleri başarıyla yüklendi.`);
      } catch (error) {
        console.error("Excel okuma hatası:", error);
        alert("Dosya okunurken bir hata oluştu.");
      } finally {
        if(fileInputRef.current) fileInputRef.current.value = '';
      }
    };

    reader.readAsBinaryString(file);
  };

  // --- End Bulk Import Logic ---

  const handleAddExam = (e: React.FormEvent) => {
    e.preventDefault();
    if (!eName || !ePrice || !eCode) return;

    // Check for duplicate code
    if(exams.some(ex => ex.code === eCode)) {
        alert("Bu tetkik kodu zaten kullanılıyor!");
        return;
    }

    const newExam: ExamDefinition = {
      id: Math.random().toString(36).substr(2, 9),
      code: eCode,
      name: eName,
      price: parseFloat(ePrice)
    };
    onAddExam(newExam);
    setEName('');
    setECode('');
    setEPrice('');
  };

  const handleUpdateExamField = (id: string, field: keyof ExamDefinition, value: string) => {
    const exam = exams.find(e => e.id === id);
    if (exam) {
      const updated = { ...exam };
      if (field === 'price') updated.price = parseFloat(value);
      if (field === 'code') updated.code = value;
      // Name update could be added here if needed
      onUpdateExam(updated);
    }
  };

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden">
      <div className="flex border-b border-slate-700">
        <button
          onClick={() => setActiveTab('companies')}
          className={`flex-1 py-4 text-center font-medium text-sm transition-colors ${activeTab === 'companies' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Firmalar
        </button>
        <button
          onClick={() => setActiveTab('exams')}
          className={`flex-1 py-4 text-center font-medium text-sm transition-colors ${activeTab === 'exams' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Tetkikler ve Kodlar
        </button>
      </div>

      <div className="p-6">
        {activeTab === 'companies' && (
          <div className="space-y-8">

            {/* Bulk Import Section */}
            <div className="bg-slate-900/50 p-4 rounded-lg border border-dashed border-slate-600 flex flex-col md:flex-row items-center justify-between gap-4">
              <div className="flex items-center space-x-3">
                 <div className="p-2 bg-emerald-500/10 rounded">
                   <Upload className="w-6 h-6 text-emerald-500" />
                 </div>
                 <div>
                    <h5 className="text-sm font-bold text-white">Toplu Firma Yükleme (Excel)</h5>
                    <p className="text-xs text-slate-400">Şablonu indirin, <strong>2. Sayfadaki tetkik kodlarına bakarak</strong> doldurun ve yükleyin.</p>
                 </div>
              </div>
              <div className="flex space-x-3">
                 <button 
                   onClick={downloadTemplate}
                   type="button"
                   className="flex items-center space-x-2 px-3 py-2 bg-slate-800 hover:bg-slate-700 border border-slate-600 rounded text-xs text-slate-300 transition-colors"
                 >
                    <FileDown className="w-4 h-4" />
                    <span>Şablon (Kodlu) İndir</span>
                 </button>
                 <label className="flex items-center space-x-2 px-3 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded text-xs font-medium cursor-pointer transition-colors shadow-lg shadow-blue-900/20">
                    <Upload className="w-4 h-4" />
                    <span>Excel Yükle</span>
                    <input 
                      type="file" 
                      accept=".xlsx, .xls" 
                      className="hidden" 
                      ref={fileInputRef}
                      onChange={handleFileUpload}
                    />
                 </label>
              </div>
            </div>

            {/* Add Company Form */}
            <form onSubmit={handleAddCompany} className="bg-slate-900/30 p-4 rounded-lg border border-slate-700 space-y-4">
              <h4 className="text-sm font-bold text-white flex items-center">
                <Plus className="w-4 h-4 mr-2" /> Tek Firma Ekle
              </h4>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <input required placeholder="Firma Adı" value={cName} onChange={e => setCName(e.target.value)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />
                <select value={cHazard} onChange={e => setCHazard(e.target.value as HazardClass)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm outline-none">
                  {Object.values(HazardClass).map(h => <option key={h} value={h}>{h}</option>)}
                </select>
                <input placeholder="İşyeri Hekimi" value={cDoctor} onChange={e => setCDoctor(e.target.value)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />
                <input placeholder="İSG Uzmanı" value={cSpecialist} onChange={e => setCSpecialist(e.target.value)} className="bg-slate-800 border-slate-600 rounded px-3 py-2 text-white text-sm focus:ring-blue-500 outline-none" />

                {/* Payment Method Selector */}
                <div className="flex space-x-2">
                   <button 
                    type="button"
                    onClick={() => setCPaymentMethod('INVOICE')}
                    className={`flex-1 py-2 rounded text-sm font-medium border flex items-center justify-center space-x-2 transition-all ${cPaymentMethod === 'INVOICE' ? 'bg-blue-600/20 border-blue-500 text-blue-200' : 'bg-slate-800 border-slate-600 text-slate-400'}`}
                   >
                     <Receipt className="w-4 h-4" />
                     <span>Fatura / Cari</span>
                   </button>
                   <button 
                    type="button"
                    onClick={() => setCPaymentMethod('CASH')}
                    className={`flex-1 py-2 rounded text-sm font-medium border flex items-center justify-center space-x-2 transition-all ${cPaymentMethod === 'CASH' ? 'bg-emerald-600/20 border-emerald-500 text-emerald-200' : 'bg-slate-800 border-slate-600 text-slate-400'}`}
                   >
                     <Wallet className="w-4 h-4" />
                     <span>Nakit / Elden</span>
                   </button>
                </div>
              </div>

              {/* Exam Selection for Company */}
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Firma Standart Tetkikleri</label>
                <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                   {exams.map(exam => (
                     <div 
                      key={exam.id}
                      onClick={() => toggleCompanyExam(exam.name)}
                      className={`cursor-pointer px-3 py-2 rounded border flex items-center justify-between transition-all ${cSelectedExams.includes(exam.name) ? 'bg-blue-600/20 border-blue-500 text-blue-200' : 'bg-slate-800 border-slate-600 text-slate-400 hover:bg-slate-700'}`}
                     >
                       <span className="text-xs truncate mr-2">{exam.name}</span>
                       {cSelectedExams.includes(exam.name) && <Check className="w-3 h-3 text-blue-400" />}
                     </div>
                   ))}
                </div>
              </div>

              <div className="flex justify-end">
                <button type="submit" className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded text-sm">Ekle</button>
              </div>
            </form>

            {/* Company List */}
            <div className="space-y-3">
              <div className="text-sm text-slate-400 mb-2">Toplam {companies.length} Firma Kayıtlı</div>
              {companies.map(company => (
                <div key={company.id} className="flex flex-col md:flex-row items-start md:items-center justify-between p-4 bg-slate-700/30 border border-slate-700 rounded-lg gap-4">
                  <div className="flex items-center space-x-3">
                    <div className="p-2 bg-slate-800 rounded">
                      <Building2 className="w-5 h-5 text-slate-400" />
                    </div>
                    <div>
                      <h5 className="font-medium text-white flex items-center">
                        {company.name}
                        {company.defaultPaymentMethod === 'CASH' ? (
                          <span className="ml-2 px-1.5 py-0.5 text-[10px] bg-emerald-900/30 text-emerald-400 border border-emerald-500/20 rounded uppercase">Nakit</span>
                        ) : (
                          <span className="ml-2 px-1.5 py-0.5 text-[10px] bg-blue-900/30 text-blue-400 border border-blue-500/20 rounded uppercase">Fatura</span>
                        )}
                      </h5>
                      <p className="text-xs text-slate-400">{company.assignedDoctor} • {company.assignedSpecialist}</p>
                      <div className="flex flex-wrap gap-1 mt-1">
                        {company.defaultExams.map((ex, i) => (
