                       </span>
                    </div>

                    <div className="space-y-2 pt-1">
                      <div className="flex items-center space-x-2">
                        <div className="w-6 h-6 rounded-full bg-slate-900/50 flex items-center justify-center shrink-0">
                           <Stethoscope className="w-3 h-3 text-blue-400" />
                        </div>
                        <div className="overflow-hidden">
                          <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">İşyeri Hekimi</p>
                          <p className="text-xs font-medium text-slate-200 truncate">{selectedCompanyData.assignedDoctor}</p>
                        </div>
                      </div>

                      <div className="flex items-center space-x-2">
                         <div className="w-6 h-6 rounded-full bg-slate-900/50 flex items-center justify-center shrink-0">
                           <ShieldCheck className="w-3 h-3 text-emerald-400" />
                        </div>
                        <div className="overflow-hidden">
                          <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">İSG Uzmanı</p>
                          <p className="text-xs font-medium text-slate-200 truncate">{selectedCompanyData.assignedSpecialist}</p>
                        </div>
                      </div>
                    </div>
                  </div>
                )}
             </div>

             {/* Personal Info Section */}
             <div className="bg-slate-900/50 backdrop-blur-sm rounded-2xl border border-slate-800 p-5 shadow-xl flex-1">
                <div className="flex items-center space-x-2 text-slate-200 mb-4">
                   <div className="p-1.5 bg-indigo-500/10 rounded-lg">
                      <User className="w-4 h-4 text-indigo-500" />
                   </div>
                   <span className="font-semibold">Personel Kimlik</span>
                </div>

                <div className="space-y-4">
                  <div>
                    <label className="text-xs font-medium text-slate-400 block mb-1.5 ml-1">Ad Soyad</label>
                    <input 
                      required
                      type="text" 
                      value={fullName}
                      onChange={e => setFullName(e.target.value)}
                      className="w-full px-4 py-3 bg-slate-950 border border-slate-700 text-white text-sm rounded-xl focus:ring-2 focus:ring-indigo-500/50 outline-none transition-all placeholder-slate-600 shadow-inner focus:border-indigo-500"
                      placeholder="Örn: Ahmet Yılmaz"
                    />
                  </div>

                  <div>
                    <label className="text-xs font-medium text-slate-400 block mb-1.5 ml-1">TC Kimlik No</label>
                    <input 
                      type="text" 
                      maxLength={11}
                      value={tcNo}
                      onChange={e => setTcNo(e.target.value.replace(/\D/g,''))}
                      className="w-full px-4 py-3 bg-slate-950 border border-slate-700 text-white text-sm rounded-xl focus:ring-2 focus:ring-indigo-500/50 outline-none transition-all placeholder-slate-600 shadow-inner focus:border-indigo-500"
                      placeholder="11 haneli TC No"
                    />
                  </div>
                </div>
             </div>
          </div>

          {/* COLUMN 2: Exams (Span 6) */}
          <div className="col-span-12 lg:col-span-6 bg-slate-900/50 backdrop-blur-sm rounded-2xl border border-slate-800 shadow-xl flex flex-col overflow-hidden">
             {/* Exam Header */}
             <div className="p-5 border-b border-slate-800 bg-slate-900/30">
                <div className="flex justify-between items-center mb-4">
                   <div className="flex items-center space-x-2 text-slate-200">
                     <div className="p-1.5 bg-pink-500/10 rounded-lg">
                        <Activity className="w-4 h-4 text-pink-500" />
                     </div>
                     <div>
                        <h2 className="font-semibold">Tetkik Seçimi</h2>
                        <p className="text-xs text-slate-500">Yapılacak işlemleri işaretleyin</p>
                     </div>
                   </div>
                   <div className="px-3 py-1 bg-blue-500/10 rounded-full border border-blue-500/20 text-blue-400 text-xs font-bold">
                     {selectedExamIds.length} Seçili
                   </div>
                </div>

                {/* Exam Search */}
                <div className="relative">
                   <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                   <input 
                      type="text" 
                      value={examSearchTerm}
                      onChange={e => setExamSearchTerm(e.target.value)}
                      placeholder="Tetkik ara..."
                      className="w-full pl-9 pr-4 py-2 bg-slate-950 border border-slate-700 rounded-lg text-sm text-white focus:border-pink-500 focus:ring-1 focus:ring-pink-500 outline-none transition-all"
                   />
                </div>
             </div>

             {/* Exam List Grid */}
             <div className="flex-1 overflow-y-auto custom-scrollbar p-5 bg-slate-950/30">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                  {filteredExams.map((exam) => {
                    const isSelected = selectedExamIds.includes(exam.name);
                    return (
                      <div 
                        key={exam.id}
                        onClick={() => toggleExam(exam.name)}
                        className={`group relative cursor-pointer p-3 rounded-xl border transition-all duration-200 select-none flex items-center justify-between ${
                          isSelected 
                          ? 'bg-blue-600/10 border-blue-500 shadow-[0_0_15px_-3px_rgba(59,130,246,0.3)]' 
                          : 'bg-slate-800/40 border-slate-700 hover:bg-slate-800 hover:border-slate-600'
                        }`}
                      >
                         <div className="flex items-center space-x-3 overflow-hidden">
                            <div className={`w-5 h-5 rounded-md border flex items-center justify-center transition-all ${isSelected ? 'bg-blue-500 border-blue-500 scale-110' : 'border-slate-600 bg-slate-900 group-hover:border-slate-500'}`}>
                               {isSelected && <Check className="w-3.5 h-3.5 text-white stroke-[3]" />}
                            </div>
                            <span className={`text-sm font-medium truncate transition-colors ${isSelected ? 'text-white' : 'text-slate-400 group-hover:text-slate-200'}`}>
                               {exam.name}
                            </span>
                         </div>
                         <span className={`text-xs font-mono font-medium px-2 py-1 rounded ${isSelected ? 'bg-blue-500/20 text-blue-200' : 'bg-slate-900 text-slate-500'}`}>
                            ₺{exam.price}
                         </span>
                      </div>
                    );
                  })}
                  {filteredExams.length === 0 && (
                     <div className="col-span-2 text-center py-8 text-slate-500">
                        Aradığınız tetkik bulunamadı.
                     </div>
                  )}
                </div>
             </div>
          </div>

          {/* COLUMN 3: Payment & Actions (Span 3) */}
          <div className="col-span-12 lg:col-span-3 flex flex-col gap-6">
             {/* Payment Card */}
             <div className="bg-slate-900/50 backdrop-blur-sm rounded-2xl border border-slate-800 p-5 shadow-xl flex-1 flex flex-col relative overflow-hidden">
                {/* Background Decor */}
                <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 rounded-full blur-3xl pointer-events-none" />

                <div className="flex items-center space-x-2 text-slate-200 mb-6 relative z-10">
                  <div className="p-1.5 bg-emerald-500/10 rounded-lg">
                     <Wallet className="w-4 h-4 text-emerald-500" />
                  </div>
                  <span className="font-semibold">Finansal Özet</span>
                </div>

                <div className="bg-slate-950/50 rounded-xl p-1.5 flex mb-6 border border-slate-800 relative z-10">
                  <button
                    type="button"
                    onClick={() => setPaymentMethod('INVOICE')}
                    className={`flex-1 flex flex-col items-center justify-center py-3 rounded-lg text-xs font-bold transition-all ${paymentMethod === 'INVOICE' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20 ring-1 ring-blue-400/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
                  >
                    <Receipt className="w-5 h-5 mb-1" />
                    <span>CARİ / FATURA</span>
                  </button>
                  <button
                    type="button"
                    onClick={() => setPaymentMethod('CASH')}
                    className={`flex-1 flex flex-col items-center justify-center py-3 rounded-lg text-xs font-bold transition-all ${paymentMethod === 'CASH' ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/20 ring-1 ring-emerald-400/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
                  >
                    <Wallet className="w-5 h-5 mb-1" />
                    <span>NAKİT / ELDEN</span>
                  </button>
                </div>

                <div className="flex flex-col items-end justify-center py-6 px-4 bg-slate-950 rounded-xl border border-slate-800 mb-6 relative group overflow-hidden">
                   <div className={`absolute left-0 top-0 bottom-0 w-1 ${paymentMethod === 'CASH' ? 'bg-emerald-500' : 'bg-blue-500'}`} />
                   <span className="text-xs text-slate-400 font-medium mb-1 uppercase tracking-wider">Tahmini Tutar</span>
                   <div className="flex items-baseline">
                      <span className="text-2xl font-light text-slate-500 mr-1">₺</span>
                      <span className={`text-4xl font-bold tracking-tight ${paymentMethod === 'CASH' ? 'text-emerald-400' : 'text-blue-400'}`}>
                        {estimatedPrice.toLocaleString('tr-TR')}
                      </span>
                   </div>
                   <span className="text-[10px] text-slate-500 mt-2 flex items-center">
                      {paymentMethod === 'CASH' ? <Check className="w-3 h-3 mr-1" /> : <Info className="w-3 h-3 mr-1" />}
                      {paymentMethod === 'CASH' ? 'Kasa hesabına işlenecek' : 'Cari hesaba yansıtılacak'}
                   </span>
                </div>

                <div className="flex-1 flex flex-col relative z-10">
                   <label className="text-xs font-medium text-slate-400 block mb-1.5 ml-1">İlave Notlar</label>
                   <textarea 
                      value={notes}
                      onChange={e => setNotes(e.target.value)}
                      className="flex-1 w-full p-3 bg-slate-950 border border-slate-700 text-white rounded-xl focus:ring-2 focus:ring-slate-500/30 outline-none text-xs resize-none placeholder-slate-600 shadow-inner"
                      placeholder="Varsa özel durumları belirtiniz..."
                   />
                </div>
             </div>

             {/* Action Buttons */}
             <div className="grid grid-cols-2 gap-4 shrink-0">
                <button 
                  type="button"
                  onClick={onClose}
                  className="py-4 bg-slate-900 hover:bg-slate-800 border border-slate-700 hover:border-slate-600 text-slate-400 hover:text-white font-semibold rounded-2xl transition-all flex items-center justify-center space-x-2 shadow-sm"
                >
                  <XCircle className="w-5 h-5" />
                  <span>İptal</span>
                </button>
                <button 
                  type="submit"
                  className="py-4 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white font-bold rounded-2xl shadow-lg shadow-blue-900/30 transition-all active:scale-95 flex items-center justify-center space-x-2 border border-blue-500/20"
                >
                  <Save className="w-5 h-5" />
                  <span>KAYDET</span>
                </button>
             </div>
          </div>

      </form>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Building2, User, Activity, Stethoscope, ShieldCheck, AlertTriangle, Wallet, Receipt, Save, XCircle, Search, Check, ChevronDown, X, Info } from 'lucide-react';
import { Referral, Status, Company, HazardClass, ExamDefinition } from '../types';

interface NewReferralViewProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
  companies: Company[];
  exams: ExamDefinition[];
}

export const NewReferralView: React.FC<NewReferralViewProps> = ({ onClose, onSubmit, companies, exams }) => {
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');

  // Searchable Company Dropdown State
  const [companySearchTerm, setCompanySearchTerm] = useState('');
  const [isCompanyDropdownOpen, setIsCompanyDropdownOpen] = useState(false);
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Exam Search State
  const [examSearchTerm, setExamSearchTerm] = useState('');

  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');
  const [estimatedPrice, setEstimatedPrice] = useState(0);

  // Payment Method State
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');

  // Filter companies based on search
  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(companySearchTerm.toLowerCase())
  );

  // Filter exams based on search
  const filteredExams = exams.filter(e => 
    e.name.toLowerCase().includes(examSearchTerm.toLowerCase())
  );

  // Handle click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCompanyDropdownOpen(false);
        if (selectedCompanyData) {
            setCompanySearchTerm(selectedCompanyData.name);
        } else {
            setCompanySearchTerm('');
        }
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [selectedCompanyData]);

  // Recalculate price when exams change
  useEffect(() => {
    const total = selectedExamIds.reduce((sum, id) => {
      const exam = exams.find(e => e.name === id); 
      const price = exam ? exam.price : 0;
      return sum + price;
    }, 0);
    setEstimatedPrice(total);
  }, [selectedExamIds, exams]);

  const handleSelectCompany = (company: Company) => {
      setSelectedCompanyData(company);
      setCompanySearchTerm(company.name);
      setIsCompanyDropdownOpen(false);

      // Auto-fill logic
      setSelectedExamIds(company.defaultExams);
      setPaymentMethod(company.defaultPaymentMethod || 'INVOICE');
  };

  const handleClearCompany = () => {
      setSelectedCompanyData(null);
      setCompanySearchTerm('');
      setSelectedExamIds([]);
  };

  const toggleExam = (examName: string) => {
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const getHazardClassStyles = (hazard: HazardClass) => {
    switch (hazard) {
      case HazardClass.VERY_DANGEROUS: 
        return { 
          bg: 'bg-red-500/10', 
          text: 'text-red-400', 
          border: 'border-red-500/30',
          badge: 'bg-red-500 text-white'
        };
      case HazardClass.DANGEROUS: 
        return { 
          bg: 'bg-orange-500/10', 
          text: 'text-orange-400', 
          border: 'border-orange-500/30',
          badge: 'bg-orange-500 text-white'
        };
      case HazardClass.LESS: 
        return { 
          bg: 'bg-emerald-500/10', 
          text: 'text-emerald-400', 
          border: 'border-emerald-500/30',
          badge: 'bg-emerald-500 text-white'
        };
      default: 
        return { 
          bg: 'bg-slate-700/50', 
          text: 'text-slate-300', 
          border: 'border-slate-600',
          badge: 'bg-slate-600 text-white'
        };
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!fullName || !selectedCompanyData) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        company: selectedCompanyData.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData.assignedDoctor,
      specialistName: selectedCompanyData.assignedSpecialist,
      totalPrice: estimatedPrice,
      paymentMethod: paymentMethod
    };

    onSubmit(newReferral);
  };

  return (
    <div className="h-full flex flex-col overflow-hidden animate-fadeIn bg-slate-950">
      {/* Header */}
      <div className="flex items-center justify-between mb-6 px-1 pt-1 shrink-0">
         <div className="flex items-center space-x-4">
            <button onClick={onClose} className="p-2.5 bg-slate-900 border border-slate-700 hover:border-slate-500 rounded-xl text-slate-400 hover:text-white transition-all shadow-sm">
               <ArrowLeft className="w-5 h-5" />
            </button>
            <div>
               <h1 className="text-2xl font-bold text-white tracking-tight">Yeni Sevk Kaydı</h1>
               <p className="text-sm text-slate-400 flex items-center">
                 <Info className="w-3 h-3 mr-1" /> 
                 Personel bilgilerini girin ve gerekli tetkikleri seçin.
               </p>
            </div>
         </div>
      </div>

      {/* Main 3-Column Layout */}
      <form id="referralForm" onSubmit={handleSubmit} className="flex-1 grid grid-cols-12 gap-6 min-h-0 pb-2">

          {/* COLUMN 1: Identity & Company (Span 3) - REFACTORED FOR BETTER STACKING */}
          <div className="col-span-12 lg:col-span-3 flex flex-col gap-4 overflow-y-auto custom-scrollbar pr-1">

             {/* 1. Company Selection Box */}
             <div className="bg-slate-900/50 backdrop-blur-sm rounded-2xl border border-slate-800 p-5 shadow-xl shrink-0">
                <div className="flex items-center space-x-2 text-slate-200 mb-4">
                   <div className="p-1.5 bg-blue-500/10 rounded-lg">
                      <Building2 className="w-4 h-4 text-blue-500" />
                   </div>
                   <span className="font-semibold">Firma Seçimi</span>
                </div>

                <div ref={dropdownRef} className="relative">
                    <div className="relative group">
                      <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 group-focus-within:text-blue-500 transition-colors z-10" />
                      <input
                        type="text"
                        required
                        value={companySearchTerm}
                        onChange={(e) => {
                            setCompanySearchTerm(e.target.value);
                            setIsCompanyDropdownOpen(true);
                            if(selectedCompanyData && e.target.value !== selectedCompanyData.name) {
                                setSelectedCompanyData(null);
                            }
                        }}
                        onClick={() => setIsCompanyDropdownOpen(true)}
                        placeholder="Firma ara..."
                        className={`w-full pl-10 pr-9 py-3 bg-slate-950 border text-white text-sm rounded-xl focus:ring-2 focus:ring-blue-500/50 outline-none transition-all shadow-inner ${!selectedCompanyData && companySearchTerm ? 'border-blue-500' : 'border-slate-700 group-hover:border-slate-600'}`}
                      />
                      {selectedCompanyData ? (
                         <button type="button" onClick={handleClearCompany} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-red-400 transition-colors">
                             <X className="w-4 h-4" />
                         </button>
                      ) : (
                         <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 pointer-events-none" />
                      )}
                    </div>

                    {isCompanyDropdownOpen && (
                      <div className="absolute top-full left-0 right-0 mt-2 max-h-64 overflow-y-auto bg-slate-900 border border-slate-700 rounded-xl shadow-2xl z-50 custom-scrollbar divide-y divide-slate-800">
                        {filteredCompanies.length > 0 ? (
                          filteredCompanies.map(c => (
                            <div
                              key={c.id}
                              onClick={() => handleSelectCompany(c)}
                              className="px-4 py-3 hover:bg-slate-800 cursor-pointer flex items-center justify-between transition-colors group"
                            >
                              <div>
                                <div className="text-sm text-slate-200 font-medium group-hover:text-white">{c.name}</div>
                                <div className="text-[10px] text-slate-500">{c.assignedDoctor}</div>
                              </div>
                              {selectedCompanyData?.id === c.id && <Check className="w-4 h-4 text-blue-500" />}
                            </div>
                          ))
                        ) : (
                           <div className="px-4 py-3 text-sm text-slate-500">Sonuç bulunamadı...</div>
                        )}
                      </div>
                    )}
                </div>
             </div>

             {/* 2. Selected Company Details (Visible only when selected) */}
             {selectedCompanyData && (
               <div className="bg-slate-900/50 backdrop-blur-sm rounded-2xl border border-slate-800 p-4 shadow-xl shrink-0 animate-fadeIn">
                  <div className={`p-4 rounded-xl border ${getHazardClassStyles(selectedCompanyData.hazardClass).bg} ${getHazardClassStyles(selectedCompanyData.hazardClass).border} space-y-3`}>
                    <div className="flex items-center justify-between">
                       <span className={`text-[10px] font-bold px-2 py-1 rounded shadow-sm ${getHazardClassStyles(selectedCompanyData.hazardClass).badge}`}>
                          {selectedCompanyData.hazardClass.toUpperCase()}
                       </span>
                    </div>

                    <div className="space-y-2 pt-1">
                      <div className="flex items-center space-x-2">
                        <div className="w-6 h-6 rounded-full bg-slate-900/50 flex items-center justify-center shrink-0">
                           <Stethoscope className="w-3 h-3 text-blue-400" />
                        </div>
                        <div className="overflow-hidden">
                          <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">İşyeri Hekimi</p>
                          <p className="text-xs font-medium text-slate-200 truncate">{selectedCompanyData.assignedDoctor}</p>
                        </div>
                      </div>

                      <div className="flex items-center space-x-2">
                         <div className="w-6 h-6 rounded-full bg-slate-900/50 flex items-center justify-center shrink-0">
                           <ShieldCheck className="w-3 h-3 text-emerald-400" />
                        </div>
                        <div className="overflow-hidden">
                          <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">İSG Uzmanı</p>
                          <p className="text-xs font-medium text-slate-200 truncate">{selectedCompanyData.assignedSpecialist}</p>
                        </div>
                      </div>
                    </div>
                  </div>
               </div>
             )}

             {/* 3. Personal Info Box */}
             <div className="bg-slate-900/50 backdrop-blur-sm rounded-2xl border border-slate-800 p-5 shadow-xl shrink-0">
                <div className="flex items-center space-x-2 text-slate-200 mb-4">
                   <div className="p-1.5 bg-indigo-500/10 rounded-lg">
                      <User className="w-4 h-4 text-indigo-500" />
                   </div>
                   <span className="font-semibold">Personel Kimlik</span>
                </div>

                <div className="space-y-4">
                  <div>
                    <label className="text-xs font-medium text-slate-400 block mb-1.5 ml-1">Ad Soyad</label>
                    <input 
                      required
                      type="text" 
                      value={fullName}
                      onChange={e => setFullName(e.target.value)}
                      className="w-full px-4 py-3 bg-slate-950 border border-slate-700 text-white text-sm rounded-xl focus:ring-2 focus:ring-indigo-500/50 outline-none transition-all placeholder-slate-600 shadow-inner focus:border-indigo-500"
                      placeholder="Örn: Ahmet Yılmaz"
                    />
                  </div>

                  <div>
                    <label className="text-xs font-medium text-slate-400 block mb-1.5 ml-1">TC Kimlik No</label>
                    <input 
                      type="text" 
                      maxLength={11}
                      value={tcNo}
                      onChange={e => setTcNo(e.target.value.replace(/\D/g,''))}
                      className="w-full px-4 py-3 bg-slate-950 border border-slate-700 text-white text-sm rounded-xl focus:ring-2 focus:ring-indigo-500/50 outline-none transition-all placeholder-slate-600 shadow-inner focus:border-indigo-500"
                      placeholder="11 haneli TC No"
                    />
                  </div>
                </div>
             </div>
          </div>

          {/* COLUMN 2: Exams (Span 6) */}
          <div className="col-span-12 lg:col-span-6 bg-slate-900/50 backdrop-blur-sm rounded-2xl border border-slate-800 shadow-xl flex flex-col overflow-hidden">
             {/* Exam Header */}
             <div className="p-5 border-b border-slate-800 bg-slate-900/30">
                <div className="flex justify-between items-center mb-4">
                   <div className="flex items-center space-x-2 text-slate-200">
                     <div className="p-1.5 bg-pink-500/10 rounded-lg">
                        <Activity className="w-4 h-4 text-pink-500" />
                     </div>
                     <div>
                        <h2 className="font-semibold">Tetkik Seçimi</h2>
                        <p className="text-xs text-slate-500">Yapılacak işlemleri işaretleyin</p>
                     </div>
                   </div>
                   <div className="px-3 py-1 bg-blue-500/10 rounded-full border border-blue-500/20 text-blue-400 text-xs font-bold">
                     {selectedExamIds.length} Seçili
                   </div>
                </div>

                {/* Exam Search */}
                <div className="relative">
                   <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                   <input 
                      type="text" 
                      value={examSearchTerm}
                      onChange={e => setExamSearchTerm(e.target.value)}
                      placeholder="Tetkik ara..."
                      className="w-full pl-9 pr-4 py-2 bg-slate-950 border border-slate-700 rounded-lg text-sm text-white focus:border-pink-500 focus:ring-1 focus:ring-pink-500 outline-none transition-all"
                   />
                </div>
             </div>

             {/* Exam List Grid */}
             <div className="flex-1 overflow-y-auto custom-scrollbar p-5 bg-slate-950/30">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                  {filteredExams.map((exam) => {
                    const isSelected = selectedExamIds.includes(exam.name);
                    return (
                      <div 
                        key={exam.id}
                        onClick={() => toggleExam(exam.name)}
                        className={`group relative cursor-pointer p-3 rounded-xl border transition-all duration-200 select-none flex items-center justify-between ${
                          isSelected 
                          ? 'bg-blue-600/10 border-blue-500 shadow-[0_0_15px_-3px_rgba(59,130,246,0.3)]' 
                          : 'bg-slate-800/40 border-slate-700 hover:bg-slate-800 hover:border-slate-600'
                        }`}
                      >
                         <div className="flex items-center space-x-3 overflow-hidden">
                            <div className={`w-5 h-5 rounded-md border flex items-center justify-center transition-all ${isSelected ? 'bg-blue-500 border-blue-500 scale-110' : 'border-slate-600 bg-slate-900 group-hover:border-slate-500'}`}>
                               {isSelected && <Check className="w-3.5 h-3.5 text-white stroke-[3]" />}
                            </div>
                            <span className={`text-sm font-medium truncate transition-colors ${isSelected ? 'text-white' : 'text-slate-400 group-hover:text-slate-200'}`}>
                               {exam.name}
                            </span>
                         </div>
                         <span className={`text-xs font-mono font-medium px-2 py-1 rounded ${isSelected ? 'bg-blue-500/20 text-blue-200' : 'bg-slate-900 text-slate-500'}`}>
                            ₺{exam.price}
                         </span>
                      </div>
                    );
                  })}
                  {filteredExams.length === 0 && (
                     <div className="col-span-2 text-center py-8 text-slate-500">
                        Aradığınız tetkik bulunamadı.
                     </div>
                  )}
                </div>
             </div>
          </div>

          {/* COLUMN 3: Payment & Actions (Span 3) */}
          <div className="col-span-12 lg:col-span-3 flex flex-col gap-6">
             {/* Payment Card */}
             <div className="bg-slate-900/50 backdrop-blur-sm rounded-2xl border border-slate-800 p-5 shadow-xl flex-1 flex flex-col relative overflow-hidden">
                {/* Background Decor */}
                <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 rounded-full blur-3xl pointer-events-none" />

                <div className="flex items-center space-x-2 text-slate-200 mb-6 relative z-10">
                  <div className="p-1.5 bg-emerald-500/10 rounded-lg">
                     <Wallet className="w-4 h-4 text-emerald-500" />
                  </div>
                  <span className="font-semibold">Finansal Özet</span>
                </div>

                <div className="bg-slate-950/50 rounded-xl p-1.5 flex mb-6 border border-slate-800 relative z-10">
                  <button
                    type="button"
                    onClick={() => setPaymentMethod('INVOICE')}
                    className={`flex-1 flex flex-col items-center justify-center py-3 rounded-lg text-xs font-bold transition-all ${paymentMethod === 'INVOICE' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20 ring-1 ring-blue-400/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
                  >
                    <Receipt className="w-5 h-5 mb-1" />
                    <span>CARİ / FATURA</span>
                  </button>
                  <button
                    type="button"
                    onClick={() => setPaymentMethod('CASH')}
                    className={`flex-1 flex flex-col items-center justify-center py-3 rounded-lg text-xs font-bold transition-all ${paymentMethod === 'CASH' ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/20 ring-1 ring-emerald-400/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
                  >
                    <Wallet className="w-5 h-5 mb-1" />
                    <span>NAKİT / ELDEN</span>
                  </button>
                </div>

                <div className="flex flex-col items-end justify-center py-6 px-4 bg-slate-950 rounded-xl border border-slate-800 mb-6 relative group overflow-hidden">
                   <div className={`absolute left-0 top-0 bottom-0 w-1 ${paymentMethod === 'CASH' ? 'bg-emerald-500' : 'bg-blue-500'}`} />
                   <span className="text-xs text-slate-400 font-medium mb-1 uppercase tracking-wider">Tahmini Tutar</span>
                   <div className="flex items-baseline">
                      <span className="text-2xl font-light text-slate-500 mr-1">₺</span>
                      <span className={`text-4xl font-bold tracking-tight ${paymentMethod === 'CASH' ? 'text-emerald-400' : 'text-blue-400'}`}>
                        {estimatedPrice.toLocaleString('tr-TR')}
                      </span>
                   </div>
                   <span className="text-[10px] text-slate-500 mt-2 flex items-center">
                      {paymentMethod === 'CASH' ? <Check className="w-3 h-3 mr-1" /> : <Info className="w-3 h-3 mr-1" />}
                      {paymentMethod === 'CASH' ? 'Kasa hesabına işlenecek' : 'Cari hesaba yansıtılacak'}
                   </span>
                </div>

                <div className="flex-1 flex flex-col relative z-10">
                   <label className="text-xs font-medium text-slate-400 block mb-1.5 ml-1">İlave Notlar</label>
                   <textarea 
                      value={notes}
                      onChange={e => setNotes(e.target.value)}
                      className="flex-1 w-full p-3 bg-slate-950 border border-slate-700 text-white rounded-xl focus:ring-2 focus:ring-slate-500/30 outline-none text-xs resize-none placeholder-slate-600 shadow-inner"
                      placeholder="Varsa özel durumları belirtiniz..."
                   />
                </div>
             </div>

             {/* Action Buttons */}
             <div className="grid grid-cols-2 gap-4 shrink-0">
                <button 
                  type="button"
                  onClick={onClose}
                  className="py-4 bg-slate-900 hover:bg-slate-800 border border-slate-700 hover:border-slate-600 text-slate-400 hover:text-white font-semibold rounded-2xl transition-all flex items-center justify-center space-x-2 shadow-sm"
                >
                  <XCircle className="w-5 h-5" />
                  <span>İptal</span>
                </button>
                <button 
                  type="submit"
                  className="py-4 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white font-bold rounded-2xl shadow-lg shadow-blue-900/30 transition-all active:scale-95 flex items-center justify-center space-x-2 border border-blue-500/20"
                >
                  <Save className="w-5 h-5" />
                  <span>KAYDET</span>
                </button>
             </div>
          </div>

      </form>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Building2, User, Activity, Stethoscope, ShieldCheck, AlertTriangle, Wallet, Receipt, Save, XCircle, Search, Check, ChevronDown, X, Info } from 'lucide-react';
import { Referral, Status, Company, HazardClass, ExamDefinition } from '../types';

interface NewReferralViewProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
  companies: Company[];
  exams: ExamDefinition[];
}

export const NewReferralView: React.FC<NewReferralViewProps> = ({ onClose, onSubmit, companies, exams }) => {
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');

  // Searchable Company Dropdown State
  const [companySearchTerm, setCompanySearchTerm] = useState('');
  const [isCompanyDropdownOpen, setIsCompanyDropdownOpen] = useState(false);
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Exam Search State
  const [examSearchTerm, setExamSearchTerm] = useState('');

  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');
  const [estimatedPrice, setEstimatedPrice] = useState(0);

  // Payment Method State
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');

  // Filter companies based on search
  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(companySearchTerm.toLowerCase())
  );

  // Filter exams based on search
  const filteredExams = exams.filter(e => 
    e.name.toLowerCase().includes(examSearchTerm.toLowerCase())
  );

  // Handle click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCompanyDropdownOpen(false);
        if (selectedCompanyData) {
            setCompanySearchTerm(selectedCompanyData.name);
        } else {
            setCompanySearchTerm('');
        }
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [selectedCompanyData]);

  // Recalculate price when exams change
  useEffect(() => {
    const total = selectedExamIds.reduce((sum, id) => {
      const exam = exams.find(e => e.name === id); 
      const price = exam ? exam.price : 0;
      return sum + price;
    }, 0);
    setEstimatedPrice(total);
  }, [selectedExamIds, exams]);

  const handleSelectCompany = (company: Company) => {
      setSelectedCompanyData(company);
      setCompanySearchTerm(company.name);
      setIsCompanyDropdownOpen(false);

      // Auto-fill logic
      setSelectedExamIds(company.defaultExams);
      setPaymentMethod(company.defaultPaymentMethod || 'INVOICE');
  };

  const handleClearCompany = () => {
      setSelectedCompanyData(null);
      setCompanySearchTerm('');
      setSelectedExamIds([]);
  };

  const toggleExam = (examName: string) => {
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const getHazardClassStyles = (hazard: HazardClass) => {
    switch (hazard) {
      case HazardClass.VERY_DANGEROUS: 
        return { 
          bg: 'bg-red-500/10', 
          text: 'text-red-400', 
          border: 'border-red-500/30',
          badge: 'bg-red-500 text-white'
        };
      case HazardClass.DANGEROUS: 
        return { 
          bg: 'bg-orange-500/10', 
          text: 'text-orange-400', 
          border: 'border-orange-500/30',
          badge: 'bg-orange-500 text-white'
        };
      case HazardClass.LESS: 
        return { 
          bg: 'bg-emerald-500/10', 
          text: 'text-emerald-400', 
          border: 'border-emerald-500/30',
          badge: 'bg-emerald-500 text-white'
        };
      default: 
        return { 
          bg: 'bg-slate-700/50', 
          text: 'text-slate-300', 
          border: 'border-slate-600',
          badge: 'bg-slate-600 text-white'
        };
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!fullName || !selectedCompanyData) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        company: selectedCompanyData.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData.assignedDoctor,
      specialistName: selectedCompanyData.assignedSpecialist,
      totalPrice: estimatedPrice,
      paymentMethod: paymentMethod
    };

    onSubmit(newReferral);
  };

  return (
    <div className="h-full flex flex-col overflow-hidden animate-fadeIn bg-slate-950">
      {/* Header */}
      <div className="flex items-center justify-between mb-6 px-1 pt-1 shrink-0">
         <div className="flex items-center space-x-4">
            <button onClick={onClose} className="p-2.5 bg-slate-900 border border-slate-700 hover:border-slate-500 rounded-xl text-slate-400 hover:text-white transition-all shadow-sm">
               <ArrowLeft className="w-5 h-5" />
            </button>
            <div>
               <h1 className="text-2xl font-bold text-white tracking-tight">Yeni Sevk Kaydı</h1>
               <p className="text-sm text-slate-400 flex items-center">
                 <Info className="w-3 h-3 mr-1" /> 
                 Sırasıyla personel bilgileri, firma seçimi ve tetkik işlemlerini tamamlayın.
               </p>
            </div>
         </div>
      </div>

      {/* Main 3-Column Layout */}
      <form id="referralForm" onSubmit={handleSubmit} className="flex-1 grid grid-cols-12 gap-6 min-h-0 pb-2">

          {/* COLUMN 1: Identity & Company (Span 3) - REORDERED: Person -> Company */}
          <div className="col-span-12 lg:col-span-3 flex flex-col gap-4 overflow-y-auto custom-scrollbar pr-1">

             {/* 1. Personal Info Box (Moved to Top) */}
             <div className="bg-slate-900/50 backdrop-blur-sm rounded-2xl border border-slate-800 p-5 shadow-xl shrink-0">
                <div className="flex items-center space-x-2 text-slate-200 mb-4">
                   <div className="p-1.5 bg-indigo-500/10 rounded-lg">
                      <User className="w-4 h-4 text-indigo-500" />
                   </div>
                   <span className="font-semibold">1. Personel Kimlik</span>
                </div>

                <div className="space-y-4">
                  <div>
                    <label className="text-xs font-medium text-slate-400 block mb-1.5 ml-1">Ad Soyad</label>
                    <input 
                      required
                      autoFocus
                      type="text" 
                      value={fullName}
                      onChange={e => setFullName(e.target.value)}
                      className="w-full px-4 py-3 bg-slate-950 border border-slate-700 text-white text-sm rounded-xl focus:ring-2 focus:ring-indigo-500/50 outline-none transition-all placeholder-slate-600 shadow-inner focus:border-indigo-500"
                      placeholder="Örn: Ahmet Yılmaz"
                    />
                  </div>

                  <div>
                    <label className="text-xs font-medium text-slate-400 block mb-1.5 ml-1">TC Kimlik No</label>
                    <input 
                      type="text" 
                      maxLength={11}
                      value={tcNo}
                      onChange={e => setTcNo(e.target.value.replace(/\D/g,''))}
                      className="w-full px-4 py-3 bg-slate-950 border border-slate-700 text-white text-sm rounded-xl focus:ring-2 focus:ring-indigo-500/50 outline-none transition-all placeholder-slate-600 shadow-inner focus:border-indigo-500"
                      placeholder="11 haneli TC No"
                    />
                  </div>
                </div>
             </div>

             {/* 2. Company Selection Box (Moved below Personal Info) */}
             <div className="bg-slate-900/50 backdrop-blur-sm rounded-2xl border border-slate-800 p-5 shadow-xl shrink-0">
                <div className="flex items-center space-x-2 text-slate-200 mb-4">
                   <div className="p-1.5 bg-blue-500/10 rounded-lg">
                      <Building2 className="w-4 h-4 text-blue-500" />
                   </div>
                   <span className="font-semibold">2. Firma Seçimi</span>
                </div>

                <div ref={dropdownRef} className="relative">
                    <div className="relative group">
                      <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 group-focus-within:text-blue-500 transition-colors z-10" />
                      <input
                        type="text"
                        required
                        value={companySearchTerm}
                        onChange={(e) => {
                            setCompanySearchTerm(e.target.value);
                            setIsCompanyDropdownOpen(true);
                            if(selectedCompanyData && e.target.value !== selectedCompanyData.name) {
                                setSelectedCompanyData(null);
                            }
                        }}
                        onClick={() => setIsCompanyDropdownOpen(true)}
                        placeholder="Firma ara..."
                        className={`w-full pl-10 pr-9 py-3 bg-slate-950 border text-white text-sm rounded-xl focus:ring-2 focus:ring-blue-500/50 outline-none transition-all shadow-inner ${!selectedCompanyData && companySearchTerm ? 'border-blue-500' : 'border-slate-700 group-hover:border-slate-600'}`}
                      />
                      {selectedCompanyData ? (
                         <button type="button" onClick={handleClearCompany} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-red-400 transition-colors">
                             <X className="w-4 h-4" />
                         </button>
                      ) : (
                         <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 pointer-events-none" />
                      )}
                    </div>

                    {isCompanyDropdownOpen && (
                      <div className="absolute top-full left-0 right-0 mt-2 max-h-64 overflow-y-auto bg-slate-900 border border-slate-700 rounded-xl shadow-2xl z-50 custom-scrollbar divide-y divide-slate-800">
                        {filteredCompanies.length > 0 ? (
                          filteredCompanies.map(c => (
                            <div
                              key={c.id}
                              onClick={() => handleSelectCompany(c)}
                              className="px-4 py-3 hover:bg-slate-800 cursor-pointer flex items-center justify-between transition-colors group"
                            >
                              <div>
                                <div className="text-sm text-slate-200 font-medium group-hover:text-white">{c.name}</div>
                                <div className="text-[10px] text-slate-500">{c.assignedDoctor}</div>
                              </div>
                              {selectedCompanyData?.id === c.id && <Check className="w-4 h-4 text-blue-500" />}
                            </div>
                          ))
                        ) : (
                           <div className="px-4 py-3 text-sm text-slate-500">Sonuç bulunamadı...</div>
                        )}
                      </div>
                    )}
                </div>
             </div>

             {/* 3. Selected Company Details (Visible only when selected) */}
             {selectedCompanyData && (
               <div className="bg-slate-900/50 backdrop-blur-sm rounded-2xl border border-slate-800 p-4 shadow-xl shrink-0 animate-fadeIn">
                  <div className={`p-4 rounded-xl border ${getHazardClassStyles(selectedCompanyData.hazardClass).bg} ${getHazardClassStyles(selectedCompanyData.hazardClass).border} space-y-3`}>
                    <div className="flex items-center justify-between">
                       <span className={`text-[10px] font-bold px-2 py-1 rounded shadow-sm ${getHazardClassStyles(selectedCompanyData.hazardClass).badge}`}>
                          {selectedCompanyData.hazardClass.toUpperCase()}
                       </span>
                    </div>

                    <div className="space-y-2 pt-1">
                      <div className="flex items-center space-x-2">
                        <div className="w-6 h-6 rounded-full bg-slate-900/50 flex items-center justify-center shrink-0">
                           <Stethoscope className="w-3 h-3 text-blue-400" />
                        </div>
                        <div className="overflow-hidden">
                          <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">İşyeri Hekimi</p>
                          <p className="text-xs font-medium text-slate-200 truncate">{selectedCompanyData.assignedDoctor}</p>
                        </div>
                      </div>

                      <div className="flex items-center space-x-2">
                         <div className="w-6 h-6 rounded-full bg-slate-900/50 flex items-center justify-center shrink-0">
                           <ShieldCheck className="w-3 h-3 text-emerald-400" />
                        </div>
                        <div className="overflow-hidden">
                          <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">İSG Uzmanı</p>
                          <p className="text-xs font-medium text-slate-200 truncate">{selectedCompanyData.assignedSpecialist}</p>
                        </div>
                      </div>
                    </div>
                  </div>
               </div>
             )}
          </div>

          {/* COLUMN 2: Exams (Span 6) */}
          <div className="col-span-12 lg:col-span-6 bg-slate-900/50 backdrop-blur-sm rounded-2xl border border-slate-800 shadow-xl flex flex-col overflow-hidden">
             {/* Exam Header */}
             <div className="p-5 border-b border-slate-800 bg-slate-900/30">
                <div className="flex justify-between items-center mb-4">
                   <div className="flex items-center space-x-2 text-slate-200">
                     <div className="p-1.5 bg-pink-500/10 rounded-lg">
                        <Activity className="w-4 h-4 text-pink-500" />
                     </div>
                     <div>
                        <h2 className="font-semibold">3. Tetkik Seçimi</h2>
                        <p className="text-xs text-slate-500">Yapılacak işlemleri işaretleyin</p>
                     </div>
                   </div>
                   <div className="px-3 py-1 bg-blue-500/10 rounded-full border border-blue-500/20 text-blue-400 text-xs font-bold">
                     {selectedExamIds.length} Seçili
                   </div>
                </div>

                {/* Exam Search */}
                <div className="relative">
                   <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                   <input 
                      type="text" 
                      value={examSearchTerm}
                      onChange={e => setExamSearchTerm(e.target.value)}
                      placeholder="Tetkik ara..."
                      className="w-full pl-9 pr-4 py-2 bg-slate-950 border border-slate-700 rounded-lg text-sm text-white focus:border-pink-500 focus:ring-1 focus:ring-pink-500 outline-none transition-all"
                   />
                </div>
             </div>

             {/* Exam List Grid */}
             <div className="flex-1 overflow-y-auto custom-scrollbar p-5 bg-slate-950/30">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                  {filteredExams.map((exam) => {
                    const isSelected = selectedExamIds.includes(exam.name);
                    return (
                      <div 
                        key={exam.id}
                        onClick={() => toggleExam(exam.name)}
                        className={`group relative cursor-pointer p-3 rounded-xl border transition-all duration-200 select-none flex items-center justify-between ${
                          isSelected 
                          ? 'bg-blue-600/10 border-blue-500 shadow-[0_0_15px_-3px_rgba(59,130,246,0.3)]' 
                          : 'bg-slate-800/40 border-slate-700 hover:bg-slate-800 hover:border-slate-600'
                        }`}
                      >
                         <div className="flex items-center space-x-3 overflow-hidden">
                            <div className={`w-5 h-5 rounded-md border flex items-center justify-center transition-all ${isSelected ? 'bg-blue-500 border-blue-500 scale-110' : 'border-slate-600 bg-slate-900 group-hover:border-slate-500'}`}>
                               {isSelected && <Check className="w-3.5 h-3.5 text-white stroke-[3]" />}
                            </div>
                            <span className={`text-sm font-medium truncate transition-colors ${isSelected ? 'text-white' : 'text-slate-400 group-hover:text-slate-200'}`}>
                               {exam.name}
                            </span>
                         </div>
                         <span className={`text-xs font-mono font-medium px-2 py-1 rounded ${isSelected ? 'bg-blue-500/20 text-blue-200' : 'bg-slate-900 text-slate-500'}`}>
                            ₺{exam.price}
                         </span>
                      </div>
                    );
                  })}
                  {filteredExams.length === 0 && (
                     <div className="col-span-2 text-center py-8 text-slate-500">
                        Aradığınız tetkik bulunamadı.
                     </div>
                  )}
                </div>
             </div>
          </div>

          {/* COLUMN 3: Payment & Actions (Span 3) */}
          <div className="col-span-12 lg:col-span-3 flex flex-col gap-6">
             {/* Payment Card */}
             <div className="bg-slate-900/50 backdrop-blur-sm rounded-2xl border border-slate-800 p-5 shadow-xl flex-1 flex flex-col relative overflow-hidden">
                {/* Background Decor */}
                <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 rounded-full blur-3xl pointer-events-none" />

                <div className="flex items-center space-x-2 text-slate-200 mb-6 relative z-10">
                  <div className="p-1.5 bg-emerald-500/10 rounded-lg">
                     <Wallet className="w-4 h-4 text-emerald-500" />
                  </div>
                  <span className="font-semibold">4. Finansal Özet</span>
                </div>

                <div className="bg-slate-950/50 rounded-xl p-1.5 flex mb-6 border border-slate-800 relative z-10">
                  <button
                    type="button"
                    onClick={() => setPaymentMethod('INVOICE')}
                    className={`flex-1 flex flex-col items-center justify-center py-3 rounded-lg text-xs font-bold transition-all ${paymentMethod === 'INVOICE' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20 ring-1 ring-blue-400/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
                  >
                    <Receipt className="w-5 h-5 mb-1" />
                    <span>CARİ / FATURA</span>
                  </button>
                  <button
                    type="button"
                    onClick={() => setPaymentMethod('CASH')}
                    className={`flex-1 flex flex-col items-center justify-center py-3 rounded-lg text-xs font-bold transition-all ${paymentMethod === 'CASH' ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/20 ring-1 ring-emerald-400/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
                  >
                    <Wallet className="w-5 h-5 mb-1" />
                    <span>NAKİT / ELDEN</span>
                  </button>
                </div>

                <div className="flex flex-col items-end justify-center py-6 px-4 bg-slate-950 rounded-xl border border-slate-800 mb-6 relative group overflow-hidden">
                   <div className={`absolute left-0 top-0 bottom-0 w-1 ${paymentMethod === 'CASH' ? 'bg-emerald-500' : 'bg-blue-500'}`} />
                   <span className="text-xs text-slate-400 font-medium mb-1 uppercase tracking-wider">Tahmini Tutar</span>
                   <div className="flex items-baseline">
                      <span className="text-2xl font-light text-slate-500 mr-1">₺</span>
                      <span className={`text-4xl font-bold tracking-tight ${paymentMethod === 'CASH' ? 'text-emerald-400' : 'text-blue-400'}`}>
                        {estimatedPrice.toLocaleString('tr-TR')}
                      </span>
                   </div>
                   <span className="text-[10px] text-slate-500 mt-2 flex items-center">
                      {paymentMethod === 'CASH' ? <Check className="w-3 h-3 mr-1" /> : <Info className="w-3 h-3 mr-1" />}
                      {paymentMethod === 'CASH' ? 'Kasa hesabına işlenecek' : 'Cari hesaba yansıtılacak'}
                   </span>
                </div>

                <div className="flex-1 flex flex-col relative z-10">
                   <label className="text-xs font-medium text-slate-400 block mb-1.5 ml-1">İlave Notlar</label>
                   <textarea 
                      value={notes}
                      onChange={e => setNotes(e.target.value)}
                      className="flex-1 w-full p-3 bg-slate-950 border border-slate-700 text-white rounded-xl focus:ring-2 focus:ring-slate-500/30 outline-none text-xs resize-none placeholder-slate-600 shadow-inner"
                      placeholder="Varsa özel durumları belirtiniz..."
                   />
                </div>
             </div>

             {/* Action Buttons */}
             <div className="grid grid-cols-2 gap-4 shrink-0">
                <button 
                  type="button"
                  onClick={onClose}
                  className="py-4 bg-slate-900 hover:bg-slate-800 border border-slate-700 hover:border-slate-600 text-slate-400 hover:text-white font-semibold rounded-2xl transition-all flex items-center justify-center space-x-2 shadow-sm"
                >
                  <XCircle className="w-5 h-5" />
                  <span>İptal</span>
                </button>
                <button 
                  type="submit"
                  className="py-4 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white font-bold rounded-2xl shadow-lg shadow-blue-900/30 transition-all active:scale-95 flex items-center justify-center space-x-2 border border-blue-500/20"
                >
                  <Save className="w-5 h-5" />
                  <span>KAYDET</span>
                </button>
             </div>
          </div>

      </form>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Building2, User, Activity, Stethoscope, ShieldCheck, Wallet, Receipt, Save, XCircle, Search, Check, ChevronDown, X, Info } from 'lucide-react';
import { Referral, Status, Company, HazardClass, ExamDefinition } from '../types';

interface NewReferralViewProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
  companies: Company[];
  exams: ExamDefinition[];
}

export const NewReferralView: React.FC<NewReferralViewProps> = ({ onClose, onSubmit, companies, exams }) => {
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');

  // Searchable Company Dropdown State
  const [companySearchTerm, setCompanySearchTerm] = useState('');
  const [isCompanyDropdownOpen, setIsCompanyDropdownOpen] = useState(false);
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Exam Search State
  const [examSearchTerm, setExamSearchTerm] = useState('');

  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');
  const [estimatedPrice, setEstimatedPrice] = useState(0);

  // Payment Method State
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');

  // Filter companies based on search
  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(companySearchTerm.toLowerCase())
  );

  // Filter exams based on search
  const filteredExams = exams.filter(e => 
    e.name.toLowerCase().includes(examSearchTerm.toLowerCase())
  );

  // Handle click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCompanyDropdownOpen(false);
        if (selectedCompanyData) {
            setCompanySearchTerm(selectedCompanyData.name);
        } else {
            setCompanySearchTerm('');
        }
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [selectedCompanyData]);

  // Recalculate price when exams change
  useEffect(() => {
    const total = selectedExamIds.reduce((sum, id) => {
      const exam = exams.find(e => e.name === id); 
      const price = exam ? exam.price : 0;
      return sum + price;
    }, 0);
    setEstimatedPrice(total);
  }, [selectedExamIds, exams]);

  const handleSelectCompany = (company: Company) => {
      setSelectedCompanyData(company);
      setCompanySearchTerm(company.name);
      setIsCompanyDropdownOpen(false);

      // Auto-fill logic
      setSelectedExamIds(company.defaultExams);
      setPaymentMethod(company.defaultPaymentMethod || 'INVOICE');
  };

  const handleClearCompany = () => {
      setSelectedCompanyData(null);
      setCompanySearchTerm('');
      setSelectedExamIds([]);
  };

  const toggleExam = (examName: string) => {
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const getHazardClassStyles = (hazard: HazardClass) => {
    switch (hazard) {
      case HazardClass.VERY_DANGEROUS: 
        return { 
          bg: 'bg-red-500/10', 
          border: 'border-red-500/30',
          badge: 'bg-red-500 text-white'
        };
      case HazardClass.DANGEROUS: 
        return { 
          bg: 'bg-orange-500/10', 
          border: 'border-orange-500/30',
          badge: 'bg-orange-500 text-white'
        };
      case HazardClass.LESS: 
        return { 
          bg: 'bg-emerald-500/10', 
          border: 'border-emerald-500/30',
          badge: 'bg-emerald-500 text-white'
        };
      default: 
        return { 
          bg: 'bg-slate-700/50', 
          border: 'border-slate-600',
          badge: 'bg-slate-600 text-white'
        };
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!fullName || !selectedCompanyData) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        company: selectedCompanyData.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData.assignedDoctor,
      specialistName: selectedCompanyData.assignedSpecialist,
      totalPrice: estimatedPrice,
      paymentMethod: paymentMethod
    };

    onSubmit(newReferral);
  };

  return (
    <div className="h-full flex flex-col overflow-hidden animate-fadeIn bg-slate-950">
      {/* Header */}
      <div className="flex items-center justify-between mb-4 px-1 pt-1 shrink-0">
         <div className="flex items-center space-x-4">
            <button onClick={onClose} className="p-2 bg-slate-900 border border-slate-700 hover:border-slate-500 rounded-lg text-slate-400 hover:text-white transition-all shadow-sm">
               <ArrowLeft className="w-5 h-5" />
            </button>
            <div>
               <h1 className="text-xl font-bold text-white tracking-tight">Yeni Sevk Kaydı</h1>
               <p className="text-xs text-slate-400">
                 Sol taraftaki bilgileri sırasıyla doldurunuz.
               </p>
            </div>
         </div>
      </div>

      {/* Main 2-Column Layout */}
      <form id="referralForm" onSubmit={handleSubmit} className="flex-1 grid grid-cols-12 gap-6 min-h-0 pb-2">

          {/* LEFT COLUMN: Input Flow (Person -> Company -> Finance) */}
          <div className="col-span-12 lg:col-span-4 flex flex-col gap-4 overflow-y-auto custom-scrollbar pr-1">

             {/* 1. STEP: PERSONEL */}
             <div className="bg-slate-900/80 backdrop-blur-sm rounded-xl border border-slate-800 p-5 shadow-lg">
                <div className="flex items-center space-x-2 text-slate-200 mb-4 border-b border-slate-800 pb-2">
                   <div className="p-1.5 bg-indigo-500/10 rounded-lg">
                      <User className="w-4 h-4 text-indigo-500" />
                   </div>
                   <span className="font-bold text-sm">1. Personel Bilgileri</span>
                </div>

                <div className="space-y-3">
                  <div>
                    <label className="text-xs font-medium text-slate-400 block mb-1">Ad Soyad</label>
                    <input 
                      required
                      autoFocus
                      type="text" 
                      value={fullName}
                      onChange={e => setFullName(e.target.value)}
                      className="w-full px-3 py-2.5 bg-slate-950 border border-slate-700 text-white text-sm rounded-lg focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all placeholder-slate-600"
                      placeholder="Örn: Ahmet Yılmaz"
                    />
                  </div>

                  <div>
                    <label className="text-xs font-medium text-slate-400 block mb-1">TC Kimlik No</label>
                    <input 
                      type="text" 
                      maxLength={11}
                      value={tcNo}
                      onChange={e => setTcNo(e.target.value.replace(/\D/g,''))}
                      className="w-full px-3 py-2.5 bg-slate-950 border border-slate-700 text-white text-sm rounded-lg focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all placeholder-slate-600"
                      placeholder="11 haneli TC No"
                    />
                  </div>
                </div>
             </div>

             {/* 2. STEP: FIRMA */}
             <div className="bg-slate-900/80 backdrop-blur-sm rounded-xl border border-slate-800 p-5 shadow-lg">
                <div className="flex items-center space-x-2 text-slate-200 mb-4 border-b border-slate-800 pb-2">
                   <div className="p-1.5 bg-blue-500/10 rounded-lg">
                      <Building2 className="w-4 h-4 text-blue-500" />
                   </div>
                   <span className="font-bold text-sm">2. Firma Seçimi</span>
                </div>

                <div ref={dropdownRef} className="relative">
                    <div className="relative group mb-3">
                      <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 z-10" />
                      <input
                        type="text"
                        required
                        value={companySearchTerm}
                        onChange={(e) => {
                            setCompanySearchTerm(e.target.value);
                            setIsCompanyDropdownOpen(true);
                            if(selectedCompanyData && e.target.value !== selectedCompanyData.name) {
                                setSelectedCompanyData(null);
                            }
                        }}
                        onClick={() => setIsCompanyDropdownOpen(true)}
                        placeholder="Firma ara..."
                        className={`w-full pl-9 pr-8 py-2.5 bg-slate-950 border text-white text-sm rounded-lg focus:ring-1 focus:ring-blue-500 outline-none transition-all ${!selectedCompanyData && companySearchTerm ? 'border-blue-500' : 'border-slate-700'}`}
                      />
                      {selectedCompanyData ? (
                         <button type="button" onClick={handleClearCompany} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-red-400">
                             <X className="w-4 h-4" />
                         </button>
                      ) : (
                         <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 pointer-events-none" />
                      )}
                    </div>

                    {isCompanyDropdownOpen && (
                      <div className="absolute top-full left-0 right-0 mt-1 max-h-48 overflow-y-auto bg-slate-900 border border-slate-700 rounded-lg shadow-xl z-50 custom-scrollbar divide-y divide-slate-800">
                        {filteredCompanies.length > 0 ? (
                          filteredCompanies.map(c => (
                            <div
                              key={c.id}
                              onClick={() => handleSelectCompany(c)}
                              className="px-4 py-3 hover:bg-slate-800 cursor-pointer flex items-center justify-between transition-colors group"
                            >
                              <div className="text-sm text-slate-200">{c.name}</div>
                              {selectedCompanyData?.id === c.id && <Check className="w-4 h-4 text-blue-500" />}
                            </div>
                          ))
                        ) : (
                           <div className="px-4 py-3 text-sm text-slate-500">Sonuç bulunamadı.</div>
                        )}
                      </div>
                    )}
                </div>

                {/* Company Details (Shows statically inside the block without shifting the whole layout) */}
                {selectedCompanyData && (
                  <div className={`p-3 rounded-lg border ${getHazardClassStyles(selectedCompanyData.hazardClass).bg} ${getHazardClassStyles(selectedCompanyData.hazardClass).border} space-y-2 animate-fadeIn`}>
                    <div className="flex items-center justify-between">
                       <span className={`text-[10px] font-bold px-2 py-0.5 rounded ${getHazardClassStyles(selectedCompanyData.hazardClass).badge}`}>
                          {selectedCompanyData.hazardClass.toUpperCase()}
                       </span>
                    </div>
                    <div className="grid grid-cols-2 gap-2 pt-1">
                      <div className="flex flex-col">
                        <span className="text-[10px] text-slate-500 uppercase font-bold">İşyeri Hekimi</span>
                        <span className="text-xs text-slate-200 truncate">{selectedCompanyData.assignedDoctor}</span>
                      </div>
                      <div className="flex flex-col">
                         <span className="text-[10px] text-slate-500 uppercase font-bold">İSG Uzmanı</span>
                         <span className="text-xs text-slate-200 truncate">{selectedCompanyData.assignedSpecialist}</span>
                      </div>
                    </div>
                  </div>
                )}
             </div>

             {/* 3. STEP: FINANS (The End) */}
             <div className="bg-slate-900/80 backdrop-blur-sm rounded-xl border border-slate-800 p-5 shadow-lg flex-1 flex flex-col justify-end">
                <div className="flex items-center space-x-2 text-slate-200 mb-4 border-b border-slate-800 pb-2">
                   <div className="p-1.5 bg-emerald-500/10 rounded-lg">
                      <Wallet className="w-4 h-4 text-emerald-500" />
                   </div>
                   <span className="font-bold text-sm">3. Ücret ve Ödeme</span>
                </div>

                {/* Payment Method Toggle */}
                <div className="bg-slate-950 rounded-lg p-1 flex mb-4 border border-slate-800">
                  <button
                    type="button"
                    onClick={() => setPaymentMethod('INVOICE')}
                    className={`flex-1 py-2 rounded text-xs font-bold transition-all flex items-center justify-center space-x-1 ${paymentMethod === 'INVOICE' ? 'bg-blue-600 text-white shadow' : 'text-slate-500 hover:text-slate-300'}`}
                  >
                    <Receipt className="w-3 h-3" />
                    <span>CARİ / FATURA</span>
                  </button>
                  <button
                    type="button"
                    onClick={() => setPaymentMethod('CASH')}
                    className={`flex-1 py-2 rounded text-xs font-bold transition-all flex items-center justify-center space-x-1 ${paymentMethod === 'CASH' ? 'bg-emerald-600 text-white shadow' : 'text-slate-500 hover:text-slate-300'}`}
                  >
                    <Wallet className="w-3 h-3" />
                    <span>NAKİT / ELDEN</span>
                  </button>
                </div>

                {/* Price Display */}
                <div className={`p-4 rounded-xl border mb-4 text-center transition-all ${paymentMethod === 'CASH' ? 'bg-emerald-900/20 border-emerald-500/50' : 'bg-slate-950 border-slate-800'}`}>
                   <span className="text-xs text-slate-400 font-medium block mb-1 uppercase tracking-wider">
                      {paymentMethod === 'CASH' ? 'Tahsil Edilecek Tutar' : 'Cari Hesaba İşlenecek'}
                   </span>
                   <div className="flex items-center justify-center">
                      <span className="text-xl font-light text-slate-500 mr-1">₺</span>
                      <span className={`text-4xl font-bold tracking-tight ${paymentMethod === 'CASH' ? 'text-emerald-400' : 'text-blue-400'}`}>
                        {estimatedPrice.toLocaleString('tr-TR')}
                      </span>
                   </div>
                </div>

                {/* Notes Input */}
                <div className="mb-4">
                   <label className="text-xs font-medium text-slate-500 block mb-1">Notlar</label>
                   <textarea 
                      value={notes}
                      onChange={e => setNotes(e.target.value)}
                      rows={2}
                      className="w-full p-2.5 bg-slate-950 border border-slate-700 text-white rounded-lg focus:ring-1 focus:ring-slate-500 outline-none text-xs resize-none"
                      placeholder="İşlem notu..."
                   />
                </div>

                {/* Action Buttons */}
                <div className="grid grid-cols-2 gap-3 mt-auto">
                    <button 
                      type="button"
                      onClick={onClose}
                      className="py-3 bg-slate-800 hover:bg-slate-700 border border-slate-700 text-slate-300 font-medium rounded-xl transition-all"
                    >
                      İptal
                    </button>
                    <button 
                      type="submit"
                      className={`py-3 text-white font-bold rounded-xl shadow-lg transition-all flex items-center justify-center space-x-2 active:scale-95 ${paymentMethod === 'CASH' ? 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-900/20' : 'bg-blue-600 hover:bg-blue-500 shadow-blue-900/20'}`}
                    >
                      <Save className="w-4 h-4" />
                      <span>KAYDET</span>
                    </button>
                </div>
             </div>
          </div>

          {/* RIGHT COLUMN: Exams (Span 8) */}
          <div className="col-span-12 lg:col-span-8 bg-slate-900/80 backdrop-blur-sm rounded-xl border border-slate-800 shadow-lg flex flex-col overflow-hidden">
             <div className="p-4 border-b border-slate-800 bg-slate-900/50 flex justify-between items-center">
                 <div className="flex items-center space-x-2">
                     <Activity className="w-5 h-5 text-pink-500" />
                     <h2 className="font-bold text-slate-200">Tetkik Seçimi</h2>
                 </div>

                 {/* Exam Search */}
                 <div className="relative w-64">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-500" />
                    <input 
                        type="text" 
                        value={examSearchTerm}
                        onChange={e => setExamSearchTerm(e.target.value)}
                        placeholder="Tetkik ara..."
                        className="w-full pl-8 pr-3 py-1.5 bg-slate-950 border border-slate-700 rounded-lg text-xs text-white focus:border-pink-500 outline-none transition-all"
                    />
                 </div>
             </div>

             <div className="flex-1 overflow-y-auto custom-scrollbar p-5 bg-slate-950/30">
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                  {filteredExams.map((exam) => {
                    const isSelected = selectedExamIds.includes(exam.name);
                    return (
                      <div 
                        key={exam.id}
                        onClick={() => toggleExam(exam.name)}
                        className={`group relative cursor-pointer p-3 rounded-xl border transition-all duration-150 select-none flex items-center justify-between ${
                          isSelected 
                          ? 'bg-blue-600/10 border-blue-500' 
                          : 'bg-slate-800/40 border-slate-700 hover:bg-slate-800 hover:border-slate-600'
                        }`}
                      >
                         <div className="flex items-center space-x-3 overflow-hidden">
                            <div className={`w-4 h-4 rounded border flex items-center justify-center transition-all ${isSelected ? 'bg-blue-500 border-blue-500' : 'border-slate-600 bg-slate-900 group-hover:border-slate-500'}`}>
                               {isSelected && <Check className="w-3 h-3 text-white stroke-[3]" />}
                            </div>
                            <span className={`text-xs font-medium truncate transition-colors ${isSelected ? 'text-white' : 'text-slate-400 group-hover:text-slate-200'}`}>
                               {exam.name}
                            </span>
                         </div>
                         <span className={`text-[10px] font-mono font-medium px-1.5 py-0.5 rounded ${isSelected ? 'bg-blue-500/20 text-blue-200' : 'bg-slate-900 text-slate-500'}`}>
                            ₺{exam.price}
                         </span>
                      </div>
                    );
                  })}
                </div>
             </div>

             <div className="p-3 border-t border-slate-800 bg-slate-900/50 text-right">
                <span className="text-xs text-slate-500">
                    Toplam {selectedExamIds.length} tetkik seçildi.
                </span>
             </div>
          </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Building2, User, Activity, Stethoscope, ShieldCheck, Wallet, Receipt, Save, XCircle, Search, Check, ChevronDown, X, Info, Plus } from 'lucide-react';
import { Referral, Status, Company, HazardClass, ExamDefinition } from '../types';

interface NewReferralViewProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
  companies: Company[];
  exams: ExamDefinition[];
}

export const NewReferralView: React.FC<NewReferralViewProps> = ({ onClose, onSubmit, companies, exams }) => {
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');

  // Searchable Company Dropdown State
  const [companySearchTerm, setCompanySearchTerm] = useState('');
  const [isCompanyDropdownOpen, setIsCompanyDropdownOpen] = useState(false);
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Exam Search State
  const [examSearchTerm, setExamSearchTerm] = useState('');

  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');
  const [estimatedPrice, setEstimatedPrice] = useState(0);

  // Payment Method State
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');

  // Filter companies based on search
  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(companySearchTerm.toLowerCase())
  );

  // Filter exams based on search
  const filteredExams = exams.filter(e => 
    e.name.toLowerCase().includes(examSearchTerm.toLowerCase())
  );

  // Handle click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCompanyDropdownOpen(false);
        if (selectedCompanyData) {
            setCompanySearchTerm(selectedCompanyData.name);
        } else {
            setCompanySearchTerm('');
        }
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [selectedCompanyData]);

  // Recalculate price when exams change
  useEffect(() => {
    const total = selectedExamIds.reduce((sum, id) => {
      const exam = exams.find(e => e.name === id); 
      const price = exam ? exam.price : 0;
      return sum + price;
    }, 0);
    setEstimatedPrice(total);
  }, [selectedExamIds, exams]);

  const handleSelectCompany = (company: Company) => {
      setSelectedCompanyData(company);
      setCompanySearchTerm(company.name);
      setIsCompanyDropdownOpen(false);

      // Auto-fill logic
      setSelectedExamIds(company.defaultExams);
      setPaymentMethod(company.defaultPaymentMethod || 'INVOICE');
  };

  const handleClearCompany = () => {
      setSelectedCompanyData(null);
      setCompanySearchTerm('');
      setSelectedExamIds([]);
  };

  const toggleExam = (examName: string) => {
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const getHazardClassStyles = (hazard: HazardClass) => {
    switch (hazard) {
      case HazardClass.VERY_DANGEROUS: 
        return { 
          bg: 'bg-red-500/10', 
          border: 'border-red-500/30',
          badge: 'bg-red-500 text-white'
        };
      case HazardClass.DANGEROUS: 
        return { 
          bg: 'bg-orange-500/10', 
          border: 'border-orange-500/30',
          badge: 'bg-orange-500 text-white'
        };
      case HazardClass.LESS: 
        return { 
          bg: 'bg-emerald-500/10', 
          border: 'border-emerald-500/30',
          badge: 'bg-emerald-500 text-white'
        };
      default: 
        return { 
          bg: 'bg-slate-700/50', 
          border: 'border-slate-600',
          badge: 'bg-slate-600 text-white'
        };
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!fullName || !selectedCompanyData) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        company: selectedCompanyData.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData.assignedDoctor,
      specialistName: selectedCompanyData.assignedSpecialist,
      totalPrice: estimatedPrice,
      paymentMethod: paymentMethod
    };

    onSubmit(newReferral);
  };

  return (
    <div className="h-full flex flex-col overflow-hidden animate-fadeIn bg-slate-950">
      {/* Header */}
      <div className="flex items-center justify-between mb-4 px-1 pt-1 shrink-0">
         <div className="flex items-center space-x-4">
            <button onClick={onClose} className="p-2 bg-slate-900 border border-slate-700 hover:border-slate-500 rounded-lg text-slate-400 hover:text-white transition-all shadow-sm">
               <ArrowLeft className="w-5 h-5" />
            </button>
            <div>
               <h1 className="text-xl font-bold text-white tracking-tight">Yeni Sevk Kaydı</h1>
               <p className="text-xs text-slate-400">
                 Personel, firma ve tetkik bilgilerini sırasıyla kontrol ediniz.
               </p>
            </div>
         </div>
      </div>

      {/* Main Layout: 9 Columns Left (Form), 3 Columns Right (Finance) */}
      <form id="referralForm" onSubmit={handleSubmit} className="flex-1 grid grid-cols-12 gap-6 min-h-0 pb-2">

          {/* LEFT COLUMN: Main Form Flow (Person -> Company -> Exams) */}
          <div className="col-span-12 lg:col-span-9 flex flex-col gap-4 overflow-y-auto custom-scrollbar pr-2">

             {/* 1. STEP: PERSONEL */}
             <div className="bg-slate-900/80 backdrop-blur-sm rounded-xl border border-slate-800 p-5 shadow-lg">
                <div className="flex items-center space-x-2 text-slate-200 mb-4 border-b border-slate-800 pb-2">
                   <div className="p-1.5 bg-indigo-500/10 rounded-lg">
                      <User className="w-4 h-4 text-indigo-500" />
                   </div>
                   <span className="font-bold text-sm">1. Personel Bilgileri</span>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="text-xs font-medium text-slate-400 block mb-1">Ad Soyad</label>
                    <input 
                      required
                      autoFocus
                      type="text" 
                      value={fullName}
                      onChange={e => setFullName(e.target.value)}
                      className="w-full px-3 py-2.5 bg-slate-950 border border-slate-700 text-white text-sm rounded-lg focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all placeholder-slate-600"
                      placeholder="Örn: Ahmet Yılmaz"
                    />
                  </div>

                  <div>
                    <label className="text-xs font-medium text-slate-400 block mb-1">TC Kimlik No</label>
                    <input 
                      type="text" 
                      maxLength={11}
                      value={tcNo}
                      onChange={e => setTcNo(e.target.value.replace(/\D/g,''))}
                      className="w-full px-3 py-2.5 bg-slate-950 border border-slate-700 text-white text-sm rounded-lg focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all placeholder-slate-600"
                      placeholder="11 haneli TC No"
                    />
                  </div>
                </div>
             </div>

             {/* 2. STEP: FIRMA */}
             <div className="bg-slate-900/80 backdrop-blur-sm rounded-xl border border-slate-800 p-5 shadow-lg">
                <div className="flex items-center space-x-2 text-slate-200 mb-4 border-b border-slate-800 pb-2">
                   <div className="p-1.5 bg-blue-500/10 rounded-lg">
                      <Building2 className="w-4 h-4 text-blue-500" />
                   </div>
                   <span className="font-bold text-sm">2. Firma Seçimi</span>
                </div>

                <div ref={dropdownRef} className="relative mb-4">
                    <div className="relative group">
                      <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 z-10" />
                      <input
                        type="text"
                        required
                        value={companySearchTerm}
                        onChange={(e) => {
                            setCompanySearchTerm(e.target.value);
                            setIsCompanyDropdownOpen(true);
                            if(selectedCompanyData && e.target.value !== selectedCompanyData.name) {
                                setSelectedCompanyData(null);
                            }
                        }}
                        onClick={() => setIsCompanyDropdownOpen(true)}
                        placeholder="Firma ara..."
                        className={`w-full pl-9 pr-8 py-3 bg-slate-950 border text-white text-sm rounded-lg focus:ring-1 focus:ring-blue-500 outline-none transition-all ${!selectedCompanyData && companySearchTerm ? 'border-blue-500' : 'border-slate-700'}`}
                      />
                      {selectedCompanyData ? (
                         <button type="button" onClick={handleClearCompany} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-red-400">
                             <X className="w-4 h-4" />
                         </button>
                      ) : (
                         <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 pointer-events-none" />
                      )}
                    </div>

                    {isCompanyDropdownOpen && (
                      <div className="absolute top-full left-0 right-0 mt-1 max-h-48 overflow-y-auto bg-slate-900 border border-slate-700 rounded-lg shadow-xl z-50 custom-scrollbar divide-y divide-slate-800">
                        {filteredCompanies.length > 0 ? (
                          filteredCompanies.map(c => (
                            <div
                              key={c.id}
                              onClick={() => handleSelectCompany(c)}
                              className="px-4 py-3 hover:bg-slate-800 cursor-pointer flex items-center justify-between transition-colors group"
                            >
                              <div className="text-sm text-slate-200">{c.name}</div>
                              {selectedCompanyData?.id === c.id && <Check className="w-4 h-4 text-blue-500" />}
                            </div>
                          ))
                        ) : (
                           <div className="px-4 py-3 text-sm text-slate-500">Sonuç bulunamadı.</div>
                        )}
                      </div>
                    )}
                </div>

                {/* Company Details */}
                {selectedCompanyData && (
                  <div className={`p-4 rounded-lg border ${getHazardClassStyles(selectedCompanyData.hazardClass).bg} ${getHazardClassStyles(selectedCompanyData.hazardClass).border} space-y-3 animate-fadeIn`}>
                    <div className="flex items-center justify-between">
                       <span className={`text-xs font-bold px-2 py-1 rounded ${getHazardClassStyles(selectedCompanyData.hazardClass).badge}`}>
                          {selectedCompanyData.hazardClass.toUpperCase()}
                       </span>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="flex items-center space-x-3">
                        <div className="p-2 bg-slate-900/50 rounded-full">
                           <Stethoscope className="w-4 h-4 text-blue-400" />
                        </div>
                        <div>
                           <span className="text-[10px] text-slate-500 uppercase font-bold block">İşyeri Hekimi</span>
                           <span className="text-sm text-slate-200">{selectedCompanyData.assignedDoctor}</span>
                        </div>
                      </div>
                      <div className="flex items-center space-x-3">
                         <div className="p-2 bg-slate-900/50 rounded-full">
                           <ShieldCheck className="w-4 h-4 text-emerald-400" />
                        </div>
                         <div>
                           <span className="text-[10px] text-slate-500 uppercase font-bold block">İSG Uzmanı</span>
                           <span className="text-sm text-slate-200">{selectedCompanyData.assignedSpecialist}</span>
                        </div>
                      </div>
                    </div>
                  </div>
                )}
             </div>

             {/* 3. STEP: EXAMS (Compact) */}
             <div className="bg-slate-900/80 backdrop-blur-sm rounded-xl border border-slate-800 p-5 shadow-lg">
                <div className="flex items-center justify-between mb-4 border-b border-slate-800 pb-2">
                   <div className="flex items-center space-x-2 text-slate-200">
                      <div className="p-1.5 bg-pink-500/10 rounded-lg">
                         <Activity className="w-4 h-4 text-pink-500" />
                      </div>
                      <span className="font-bold text-sm">3. Tetkik Seçimi</span>
                   </div>
                   <div className="text-xs text-slate-500">
                     {selectedExamIds.length} tetkik seçili
                   </div>
                </div>

                {/* Selected Exams (Badges) */}
                <div className="mb-6">
                   <label className="text-xs font-medium text-slate-400 block mb-2">Yapılacak İşlemler</label>
                   {selectedExamIds.length > 0 ? (
                     <div className="flex flex-wrap gap-2">
                       {selectedExamIds.map(id => {
                          const exam = exams.find(e => e.name === id);
                          return (
                            <div key={id} className="group flex items-center pl-3 pr-2 py-2 bg-blue-600/20 border border-blue-500/30 rounded-lg text-sm text-blue-200 transition-all hover:bg-blue-600/30">
                               <span className="mr-2 font-medium">{id}</span>
                               <span className="text-xs opacity-60 mr-2">| ₺{exam?.price}</span>
                               <button 
                                 type="button" 
                                 onClick={() => toggleExam(id)}
                                 className="p-0.5 hover:bg-blue-500/20 rounded-full text-blue-400 hover:text-white transition-colors"
                               >
                                  <X className="w-3.5 h-3.5" />
                               </button>
                            </div>
                          );
                       })}
                     </div>
                   ) : (
                     <div className="text-sm text-slate-500 italic p-2 border border-dashed border-slate-700 rounded-lg">
                        Henüz tetkik seçilmedi. Firma seçildiğinde otomatik doldurulur.
                     </div>
                   )}
                </div>

                {/* Add More Exams (Small Grid) */}
                <div className="bg-slate-950/50 rounded-lg p-3 border border-slate-800">
                   <div className="flex items-center space-x-2 mb-3">
                      <Search className="w-3.5 h-3.5 text-slate-500" />
                      <input 
                        type="text" 
                        value={examSearchTerm}
                        onChange={e => setExamSearchTerm(e.target.value)}
                        placeholder="Listede olmayan tetkik ekle..."
                        className="bg-transparent border-none text-xs text-white placeholder-slate-600 focus:ring-0 w-full outline-none"
                      />
                   </div>
                   <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-2 max-h-40 overflow-y-auto custom-scrollbar">
                      {filteredExams.filter(e => !selectedExamIds.includes(e.name)).map(exam => (
                         <button
                           key={exam.id}
                           type="button"
                           onClick={() => toggleExam(exam.name)}
                           className="flex items-center justify-between px-3 py-2 bg-slate-800 hover:bg-slate-700 border border-slate-700 hover:border-slate-600 rounded text-xs text-slate-300 transition-all text-left group"
                         >
                            <span className="truncate mr-1">{exam.name}</span>
                            <Plus className="w-3 h-3 opacity-0 group-hover:opacity-100 text-blue-400" />
                         </button>
                      ))}
                      {filteredExams.length === 0 && (
                         <span className="col-span-full text-center text-xs text-slate-600 py-2">Tetkik bulunamadı.</span>
                      )}
                   </div>
                </div>
             </div>
          </div>

          {/* RIGHT COLUMN: Finance & Actions (Span 3) */}
          <div className="col-span-12 lg:col-span-3 lg:h-fit sticky top-4">
             <div className="bg-slate-900/80 backdrop-blur-sm rounded-xl border border-slate-800 p-5 shadow-lg flex flex-col gap-6">
                <div className="flex items-center space-x-2 text-slate-200 border-b border-slate-800 pb-2">
                   <div className="p-1.5 bg-emerald-500/10 rounded-lg">
                      <Wallet className="w-4 h-4 text-emerald-500" />
                   </div>
                   <span className="font-bold text-sm">4. Finansal Özet</span>
                </div>

                {/* Payment Method Toggle */}
                <div className="bg-slate-950 rounded-lg p-1 flex border border-slate-800">
                  <button
                    type="button"
                    onClick={() => setPaymentMethod('INVOICE')}
                    className={`flex-1 py-2 rounded text-[10px] font-bold transition-all flex flex-col items-center justify-center space-y-1 ${paymentMethod === 'INVOICE' ? 'bg-blue-600 text-white shadow' : 'text-slate-500 hover:text-slate-300'}`}
                  >
                    <Receipt className="w-4 h-4" />
                    <span>CARİ / FATURA</span>
                  </button>
                  <button
                    type="button"
                    onClick={() => setPaymentMethod('CASH')}
                    className={`flex-1 py-2 rounded text-[10px] font-bold transition-all flex flex-col items-center justify-center space-y-1 ${paymentMethod === 'CASH' ? 'bg-emerald-600 text-white shadow' : 'text-slate-500 hover:text-slate-300'}`}
                  >
                    <Wallet className="w-4 h-4" />
                    <span>NAKİT / ELDEN</span>
                  </button>
                </div>

                {/* Price Display */}
                <div className={`p-4 rounded-xl border text-center transition-all ${paymentMethod === 'CASH' ? 'bg-emerald-900/20 border-emerald-500/50' : 'bg-slate-950 border-slate-800'}`}>
                   <span className="text-[10px] text-slate-400 font-medium block mb-1 uppercase tracking-wider">
                      {paymentMethod === 'CASH' ? 'Tahsil Edilecek' : 'Cari Bakiye'}
                   </span>
                   <div className="flex items-center justify-center">
                      <span className="text-lg font-light text-slate-500 mr-1">₺</span>
                      <span className={`text-3xl font-bold tracking-tight ${paymentMethod === 'CASH' ? 'text-emerald-400' : 'text-blue-400'}`}>
                        {estimatedPrice.toLocaleString('tr-TR')}
                      </span>
                   </div>
                </div>

                {/* Notes Input */}
                <div>
                   <label className="text-xs font-medium text-slate-500 block mb-1">Notlar</label>
                   <textarea 
                      value={notes}
                      onChange={e => setNotes(e.target.value)}
                      rows={3}
                      className="w-full p-3 bg-slate-950 border border-slate-700 text-white rounded-lg focus:ring-1 focus:ring-slate-500 outline-none text-xs resize-none"
                      placeholder="İşlem notu..."
                   />
                </div>

                {/* Action Buttons */}
                <div className="grid grid-cols-2 gap-3 mt-2">
                    <button 
                      type="button"
                      onClick={onClose}
                      className="py-3 bg-slate-800 hover:bg-slate-700 border border-slate-700 text-slate-300 font-medium rounded-xl transition-all text-sm"
                    >
                      İptal
                    </button>
                    <button 
                      type="submit"
                      className={`py-3 text-white font-bold rounded-xl shadow-lg transition-all flex items-center justify-center space-x-2 active:scale-95 text-sm ${paymentMethod === 'CASH' ? 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-900/20' : 'bg-blue-600 hover:bg-blue-500 shadow-blue-900/20'}`}
                    >
                      <Save className="w-4 h-4" />
                      <span>KAYDET</span>
                    </button>
                </div>
             </div>
          </div>
      </form>
    </div>
  );
};

