              <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider">Firma</th>
              {!compact && <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider">Kurum</th>}
              <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider">Tarih</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider">Tetkikler</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider text-right">Tutar</th>
              {!compact && <th className="px-6 py-4 text-xs font-semibold text-slate-400 uppercase tracking-wider text-right">İşlemler</th>}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-700">
            {referrals.map((referral) => {
               const instName = getInstitutionName(referral.targetInstitutionId);
               return (
              <tr key={referral.id} className="hover:bg-slate-700/30 transition-colors group">
                <td className="px-6 py-4">
                  <div className="flex flex-col">
                    <span className="font-medium text-white text-sm">{referral.employee.fullName}</span>
                    <span className="text-xs text-slate-500 font-mono">{referral.employee.tcNo}</span>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <div className="flex items-center space-x-2">
                     <Building2 className="w-3 h-3 text-slate-500" />
                     <span className="text-sm text-slate-300">{referral.employee.company}</span>
                  </div>
                </td>
                {!compact && (
                  <td className="px-6 py-4">
                    {instName ? (
                      <div className="flex items-center space-x-2 text-purple-300 bg-purple-500/10 px-2 py-1 rounded border border-purple-500/20 w-fit">
                         <MapPin className="w-3 h-3" />
                         <span className="text-xs font-medium">{instName}</span>
                      </div>
                    ) : (
                      <span className="text-xs text-slate-600 italic">Kurum Seçilmedi</span>
                    )}
                  </td>
                )}
                <td className="px-6 py-4">
                  <span className="text-sm text-slate-400">
                    {new Date(referral.referralDate).toLocaleDateString('tr-TR')}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <div className="flex flex-wrap gap-1">
                    {referral.exams.slice(0, compact ? 2 : 3).map((exam, i) => (
                      <span key={i} className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-medium bg-slate-700 text-slate-300 border border-slate-600">
                        {exam}
                      </span>
                    ))}
                    {referral.exams.length > (compact ? 2 : 3) && (
                      <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-medium bg-slate-700 text-slate-400">
                        +{referral.exams.length - (compact ? 2 : 3)}
                      </span>
                    )}
                  </div>
                </td>
                <td className="px-6 py-4 text-right">
                  <div className="flex flex-col items-end">
                    <span className="text-emerald-400 font-medium text-sm">₺{referral.totalPrice?.toLocaleString('tr-TR') || 0}</span>
                    <span className={`text-[10px] uppercase font-bold tracking-wider px-1.5 py-0.5 rounded ${referral.paymentMethod === 'CASH' ? 'text-emerald-300 bg-emerald-500/10' : 'text-blue-300 bg-blue-500/10'}`}>
                      {referral.paymentMethod === 'CASH' ? 'Nakit' : 'Cari'}
