                       )}

                       {referral.aiAnalysis && (
                          <div className="relative group/tooltip">
                            <span className="text-indigo-400 cursor-help bg-indigo-500/10 px-2 py-1 rounded text-xs border border-indigo-500/30">
                              AI Raporu
                            </span>
                            <div className="absolute right-0 bottom-full mb-2 w-64 bg-slate-900 border border-slate-700 text-slate-300 text-xs p-3 rounded shadow-xl opacity-0 group-hover/tooltip:opacity-100 pointer-events-none transition-opacity z-50">
                              {referral.aiAnalysis}
                            </div>
                          </div>
                       )}

                      <button 
                        onClick={() => onDelete(referral.id)}
                        className="text-slate-500 hover:text-red-400 hover:bg-red-500/10 p-2 rounded-lg transition-colors"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </td>
                )}
              </tr>
            )})}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Building2, User, Activity, Stethoscope, ShieldCheck, Wallet, Receipt, Save, XCircle, Search, Check, ChevronDown, X, Info, Plus, MapPin, Hash } from 'lucide-react';
import { Referral, Status, Company, HazardClass, ExamDefinition, MedicalInstitution } from '../types';

interface NewReferralViewProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
  companies: Company[];
  exams: ExamDefinition[];
  institutions: MedicalInstitution[];
}

export const NewReferralView: React.FC<NewReferralViewProps> = ({ onClose, onSubmit, companies, exams, institutions }) => {
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');

  // Searchable Company Dropdown State
  const [companySearchTerm, setCompanySearchTerm] = useState('');
  const [isCompanyDropdownOpen, setIsCompanyDropdownOpen] = useState(false);
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Institution Selection
  const [selectedInstitutionId, setSelectedInstitutionId] = useState<string>('');
  const [isInstitutionLocked, setIsInstitutionLocked] = useState(false);

  // Exam Search State
  const [examSearchTerm, setExamSearchTerm] = useState('');

  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');
  const [estimatedPrice, setEstimatedPrice] = useState(0);

  // Payment Method State
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');

  // Filter companies based on search
  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(companySearchTerm.toLowerCase())
  );

  // Filter exams based on search
  const filteredExams = exams.filter(e => 
    e.name.toLowerCase().includes(examSearchTerm.toLowerCase())
  );

  // Handle click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCompanyDropdownOpen(false);
        if (selectedCompanyData) {
            setCompanySearchTerm(selectedCompanyData.name);
        } else {
            setCompanySearchTerm('');
        }
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [selectedCompanyData]);

  // Recalculate price when exams change
  useEffect(() => {
    const total = selectedExamIds.reduce((sum, id) => {
      const exam = exams.find(e => e.name === id); 
      const price = exam ? exam.price : 0;
      return sum + price;
    }, 0);
    setEstimatedPrice(total);
  }, [selectedExamIds, exams]);

  const handleSelectCompany = (company: Company) => {
      setSelectedCompanyData(company);
      setCompanySearchTerm(company.name);
      setIsCompanyDropdownOpen(false);

      // Auto-fill logic
      setSelectedExamIds(company.defaultExams);
      setPaymentMethod(company.defaultPaymentMethod || 'INVOICE');

      // Institution Logic
      if (company.forcedInstitutionId) {
          setSelectedInstitutionId(company.forcedInstitutionId);
          setIsInstitutionLocked(true);
      } else {
          setSelectedInstitutionId('');
          setIsInstitutionLocked(false);
      }
  };

  const handleClearCompany = () => {
      setSelectedCompanyData(null);
      setCompanySearchTerm('');
      setSelectedExamIds([]);
      setSelectedInstitutionId('');
      setIsInstitutionLocked(false);
  };

  const toggleExam = (examName: string) => {
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const getHazardClassStyles = (hazard: HazardClass) => {
    switch (hazard) {
      case HazardClass.VERY_DANGEROUS: 
        return { 
          bg: 'bg-red-500/10', 
          border: 'border-red-500/30',
          badge: 'bg-red-500 text-white'
        };
      case HazardClass.DANGEROUS: 
        return { 
          bg: 'bg-orange-500/10', 
          border: 'border-orange-500/30',
          badge: 'bg-orange-500 text-white'
        };
      case HazardClass.LESS: 
        return { 
          bg: 'bg-emerald-500/10', 
          border: 'border-emerald-500/30',
          badge: 'bg-emerald-500 text-white'
        };
      default: 
        return { 
          bg: 'bg-slate-700/50', 
          border: 'border-slate-600',
          badge: 'bg-slate-600 text-white'
        };
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!fullName || !selectedCompanyData) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        company: selectedCompanyData.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData.assignedDoctor,
      specialistName: selectedCompanyData.assignedSpecialist,
      totalPrice: estimatedPrice,
      paymentMethod: paymentMethod,
      targetInstitutionId: selectedInstitutionId || undefined
    };

    onSubmit(newReferral);
  };

  return (
    <div className="h-full flex flex-col overflow-hidden animate-fadeIn bg-slate-950">
      {/* Header */}
      <div className="flex items-center justify-between mb-4 px-1 pt-1 shrink-0">
         <div className="flex items-center space-x-4">
            <button onClick={onClose} className="p-2 bg-slate-900 border border-slate-700 hover:border-slate-500 rounded-lg text-slate-400 hover:text-white transition-all shadow-sm">
               <ArrowLeft className="w-5 h-5" />
            </button>
            <div>
               <h1 className="text-xl font-bold text-white tracking-tight">Yeni Sevk Kaydı</h1>
               <p className="text-xs text-slate-400">
                 Personel, firma ve tetkik bilgilerini sırasıyla kontrol ediniz.
               </p>
            </div>
         </div>
      </div>

      {/* Main Layout: 9 Columns Left (Form), 3 Columns Right (Finance) */}
      <form id="referralForm" onSubmit={handleSubmit} className="flex-1 grid grid-cols-12 gap-6 min-h-0 pb-2">

          {/* LEFT COLUMN: Main Form Flow (Person -> Company -> Exams) */}
          <div className="col-span-12 lg:col-span-9 flex flex-col gap-4 overflow-y-auto custom-scrollbar pr-2">

             {/* 1. STEP: PERSONEL (Compact & Horizontal) */}
             <div className="bg-slate-900/80 backdrop-blur-sm rounded-xl border border-slate-800 p-5 shadow-lg">
                <div className="flex items-center space-x-2 text-slate-200 mb-3 border-b border-slate-800 pb-2">
                   <div className="p-1.5 bg-indigo-500/10 rounded-lg">
                      <User className="w-4 h-4 text-indigo-500" />
                   </div>
                   <span className="font-bold text-sm">1. Personel Bilgileri</span>
                </div>

                <div className="flex flex-col md:flex-row gap-4">
                  <div className="flex-1 relative">
                     <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                     <input 
                      required
                      autoFocus
                      type="text" 
                      value={fullName}
                      onChange={e => setFullName(e.target.value)}
                      className="w-full pl-10 pr-3 py-2.5 bg-slate-950 border border-slate-700 text-white text-sm rounded-lg focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all placeholder-slate-600"
                      placeholder="Ad Soyad (Örn: Ahmet Yılmaz)"
                    />
