                        ) : (
                           <div className="px-4 py-3 text-sm text-slate-500">Sonuç bulunamadı.</div>
                        )}
                      </div>
                    )}
                </div>

                {/* Combined Details Card */}
                {selectedCompanyData && (
                  <div className={`rounded-xl border flex flex-col md:flex-row overflow-hidden ${getHazardClassStyles(selectedCompanyData.hazardClass).bg} ${getHazardClassStyles(selectedCompanyData.hazardClass).border} animate-fadeIn`}>

                    {/* Left: Firm Info */}
                    <div className="p-4 flex-1 border-b md:border-b-0 md:border-r border-slate-700/30">
                       <span className={`text-[10px] font-bold px-2 py-0.5 rounded ${getHazardClassStyles(selectedCompanyData.hazardClass).badge}`}>
                          {selectedCompanyData.hazardClass.toUpperCase()}
                       </span>
                       <h3 className="text-white font-bold mt-2 text-sm">{selectedCompanyData.name}</h3>

                       <div className="mt-3 space-y-2">
                           <div className="flex items-center space-x-2">
                               <Stethoscope className="w-3.5 h-3.5 text-blue-400" />
                               <div className="flex flex-col">
                                   <span className="text-[10px] text-slate-400">İşyeri Hekimi</span>
                                   <span className="text-xs text-slate-200">{selectedCompanyData.assignedDoctor}</span>
                               </div>
                           </div>
                           <div className="flex items-center space-x-2">
                               <ShieldCheck className="w-3.5 h-3.5 text-emerald-400" />
                               <div className="flex flex-col">
                                   <span className="text-[10px] text-slate-400">İSG Uzmanı</span>
                                   <span className="text-xs text-slate-200">{selectedCompanyData.assignedSpecialist}</span>
                               </div>
                           </div>
                       </div>
                    </div>

                    {/* Right: Institution Selector (Prominent) */}
                    <div className="p-4 w-full md:w-64 bg-slate-900/30 flex flex-col justify-center">
                        <label className="text-[10px] text-slate-400 uppercase font-bold block mb-2 flex items-center">
                            <MapPin className="w-3 h-3 mr-1 text-purple-400" />
                            Sevk Edilecek Kurum
                        </label>
                        <div className="relative">
                           <select 
                                value={selectedInstitutionId} 
                                onChange={e => !isInstitutionLocked && setSelectedInstitutionId(e.target.value)}
                                disabled={isInstitutionLocked}
                                className={`w-full p-2.5 bg-slate-900 border text-xs text-white rounded-lg outline-none appearance-none font-medium transition-all ${isInstitutionLocked ? 'border-purple-500/50 bg-purple-900/10 cursor-not-allowed text-purple-200' : 'border-slate-600 focus:border-purple-500 hover:border-slate-500'}`}
                            >
                                <option value="">Seçim Yok (Serbest)</option>
                                {institutions.map(inst => (
                                    <option key={inst.id} value={inst.id}>{inst.name}</option>
