};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Settings, 
  Plus, 
  Search,
  Activity,
  LogOut,
  Stethoscope,
  Wallet,
  FileText,
  Menu,
  X
} from 'lucide-react';
import { ReferralList } from './components/ReferralList';
import { NewReferralView } from './components/NewReferralModal'; // Component updated to be a View
import { StatsCards } from './components/StatsCards';
import { FinanceView } from './components/FinanceView';
import { SettingsView } from './components/SettingsView';
import { EndOfDayReportModal } from './components/EndOfDayReportModal';
import { Referral, Status, Company, ExamDefinition, SafeTransaction, MedicalInstitution } from './types';
import { 
  loadReferrals, saveReferrals, 
  loadCompanies, saveCompanies,
  loadExams, saveExams,
  loadTransactions, saveTransactions,
  loadInstitutions, saveInstitutions
} from './services/storage';
import { PREDEFINED_COMPANIES, DEFAULT_EXAMS, DEFAULT_INSTITUTIONS } from './services/initialData';

const App: React.FC = () => {
  // Added 'create_referral' to navigation state
  const [activeTab, setActiveTab] = useState<'dashboard' | 'referrals' | 'finance' | 'settings' | 'create_referral'>('dashboard');

  // Mobile Menu State
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Data States
  const [referrals, setReferrals] = useState<Referral[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [exams, setExams] = useState<ExamDefinition[]>([]);
  const [institutions, setInstitutions] = useState<MedicalInstitution[]>([]);
  const [transactions, setTransactions] = useState<SafeTransaction[]>([]);

  // isModalOpen removed as it is now a page
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Initial load
  useEffect(() => {
    setReferrals(loadReferrals());
    setCompanies(loadCompanies(PREDEFINED_COMPANIES));
    setExams(loadExams(DEFAULT_EXAMS));
    setInstitutions(loadInstitutions(DEFAULT_INSTITUTIONS));
    setTransactions(loadTransactions());
  }, []);

  // Save Effects
  useEffect(() => saveReferrals(referrals), [referrals]);
  useEffect(() => saveCompanies(companies), [companies]);
  useEffect(() => saveExams(exams), [exams]);
  useEffect(() => saveInstitutions(institutions), [institutions]);
  useEffect(() => saveTransactions(transactions), [transactions]);

  // Handlers
  const handleCreateReferral = (referral: Referral) => {
    // 1. Add Referral (Always)
    setReferrals(prev => [referral, ...prev]);

    // 2. Add to Safe ONLY if Payment Method is CASH
    if (referral.paymentMethod === 'CASH' && referral.totalPrice && referral.totalPrice > 0) {
      const newTransaction: SafeTransaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'INCOME',
        amount: referral.totalPrice,
        description: `Sevk Geliri (Nakit): ${referral.employee.fullName} (${referral.employee.company})`,
        date: new Date().toISOString()
      };
      setTransactions(prev => [...prev, newTransaction]);
    }

    // Redirect back to referrals list after creation
    setActiveTab('referrals');
  };

  const handleUpdateStatus = (id: string, newStatus: Status) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, status: newStatus } : r
    ));
  };

  const handleAnalyze = (id: string, analysis: string) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, aiAnalysis: analysis } : r
    ));
  };

  const handleDelete = (id: string) => {
    if(window.confirm('Bu kaydı silmek istediğinize emin misiniz?')) {
      setReferrals(prev => prev.filter(r => r.id !== id));
    }
  };

  // Settings Handlers
  const handleAddCompany = (c: Company) => setCompanies(prev => [...prev, c]);
  const handleDeleteCompany = (id: string) => setCompanies(prev => prev.filter(c => c.id !== id));

  const handleAddExam = (e: ExamDefinition) => setExams(prev => [...prev, e]);
  const handleUpdateExam = (updated: ExamDefinition) => setExams(prev => prev.map(e => e.id === updated.id ? updated : e));
  const handleDeleteExam = (id: string) => setExams(prev => prev.filter(e => e.id !== id));

  const handleAddInstitution = (i: MedicalInstitution) => setInstitutions(prev => [...prev, i]);
  const handleDeleteInstitution = (id: string) => setInstitutions(prev => prev.filter(i => i.id !== id));

  // Finance Handlers
  const handleAddTransaction = (t: SafeTransaction) => setTransactions(prev => [...prev, t]);

  const filteredReferrals = useMemo(() => {
    return referrals.filter(r => 
      r.employee.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.company.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.tcNo.includes(searchTerm)
    );
  }, [referrals, searchTerm]);

  const stats = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    const totalIncome = transactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);

    return {
      total: referrals.length,
      today: referrals.filter(r => r.referralDate.startsWith(todayStr)).length,
      totalIncome: totalIncome
    };
  }, [referrals, transactions]);

  // Handle nav click (close mobile menu)
  const handleNavClick = (tab: typeof activeTab) => {
      setActiveTab(tab);
      setIsMobileMenuOpen(false);
  };

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden">

      {/* Mobile Sidebar Overlay */}
      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden backdrop-blur-sm"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 border-r border-slate-800 text-white flex flex-col shadow-xl transition-transform duration-300 md:relative md:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} print:hidden`}>
        <div className="p-6 flex items-center justify-between border-b border-slate-800">
          <div className="flex items-center space-x-3">
            <div className="p-2 bg-blue-600 rounded-lg shadow-lg shadow-blue-900/20">
                <Stethoscope className="w-6 h-6 text-white" />
            </div>
            <div>
                <h1 className="text-xl font-bold tracking-tight">OSGB Pro</h1>
                <p className="text-xs text-slate-400">Tetkik Takip Sistemi</p>
            </div>
          </div>
          <button onClick={() => setIsMobileMenuOpen(false)} className="md:hidden text-slate-400 hover:text-white">
            <X className="w-6 h-6" />
          </button>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => handleNavClick('dashboard')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'dashboard' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            <span className="font-medium">Genel Bakış</span>
          </button>

          <button 
            onClick={() => handleNavClick('referrals')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'referrals' || activeTab === 'create_referral' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Users className="w-5 h-5" />
            <span className="font-medium">Personel Takibi</span>
          </button>

          <button 
            onClick={() => handleNavClick('finance')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'finance' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Wallet className="w-5 h-5" />
            <span className="font-medium">Kasa & Finans</span>
          </button>

          <button 
            onClick={() => handleNavClick('settings')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'settings' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Settings className="w-5 h-5" />
            <span className="font-medium">Ayarlar</span>
          </button>
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="flex items-center space-x-3 text-slate-400 hover:text-white cursor-pointer px-4 py-2 transition-colors">
            <LogOut className="w-5 h-5" />
            <span>Çıkış Yap</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative bg-slate-950">
        {/* Header */}
        <header className="h-16 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-4 md:px-8 shadow-sm z-10 print:hidden">
          <div className="flex items-center">
              <button 
                onClick={() => setIsMobileMenuOpen(true)}
                className="mr-4 md:hidden text-slate-400 hover:text-white p-1 rounded-lg hover:bg-slate-800 transition-colors"
              >
                  <Menu className="w-6 h-6" />
              </button>
              <h2 className="text-lg md:text-xl font-semibold text-white truncate">
                {activeTab === 'dashboard' ? 'Kontrol Paneli' : 
                 activeTab === 'referrals' ? 'Tetkik & Sevk Listesi' : 
                 activeTab === 'create_referral' ? 'Yeni Sevk Girişi' :
                 activeTab === 'finance' ? 'Kasa Yönetimi' : 'Ayarlar'}
              </h2>
          </div>

          <div className="flex items-center space-x-4">
            {activeTab !== 'create_referral' && (
              <>
                <div className="relative hidden md:block">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400 w-4 h-4" />
                  <input 
                    type="text"
                    placeholder="Personel veya Firma ara..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent w-64 transition-all placeholder-slate-500"
                  />
                </div>
                <button 
                  onClick={() => setActiveTab('create_referral')}
                  className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-500 text-white px-3 py-2 md:px-4 md:py-2 rounded-lg text-sm font-medium transition-colors shadow-lg shadow-blue-900/20 active:transform active:scale-95 whitespace-nowrap"
                >
                  <Plus className="w-4 h-4" />
                  <span className="hidden md:inline">Yeni Sevk Oluştur</span>
                  <span className="md:hidden">Yeni Sevk</span>
                </button>
              </>
            )}
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-auto p-4 md:p-8 custom-scrollbar print:p-0 print:overflow-visible">
          {activeTab === 'dashboard' && (
            <div className="space-y-6">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-4 gap-3 md:gap-0">
                <h3 className="text-lg font-bold text-white hidden md:block">Günlük Özet</h3>
                <button 
                  onClick={() => setIsReportModalOpen(true)}
                  className="w-full md:w-auto flex items-center justify-center space-x-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-lg"
                >
                  <FileText className="w-4 h-4" />
                  <span>Gün Sonu Raporu Al (Z Raporu)</span>
                </button>
              </div>

              <StatsCards stats={stats} />

              <div className="mt-8">
                <h3 className="text-lg font-bold text-white mb-4 flex items-center">
                  <Activity className="w-5 h-5 mr-2 text-blue-500" />
                  Son Hareketler
                </h3>
                <ReferralList 
                  referrals={filteredReferrals.slice(0, 5)} 
                  institutions={institutions}
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                  compact
                />
              </div>
            </div>
          )}

          {activeTab === 'referrals' && (
            <div className="h-full flex flex-col">
               <ReferralList 
                  referrals={filteredReferrals} 
                  institutions={institutions}
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                />
            </div>
          )}

          {activeTab === 'create_referral' && (
            <NewReferralView
              onClose={() => setActiveTab('referrals')}
              onSubmit={handleCreateReferral}
              companies={companies}
              exams={exams}
              institutions={institutions}
            />
          )}

          {activeTab === 'finance' && (
            <FinanceView 
              transactions={transactions}
              onAddTransaction={handleAddTransaction}
            />
          )}

          {activeTab === 'settings' && (
             <SettingsView 
                companies={companies}
                onAddCompany={handleAddCompany}
                onDeleteCompany={handleDeleteCompany}
                exams={exams}
                onAddExam={handleAddExam}
                onUpdateExam={handleUpdateExam}
                onDeleteExam={handleDeleteExam}
                institutions={institutions}
                onAddInstitution={handleAddInstitution}
                onDeleteInstitution={handleDeleteInstitution}
             />
          )}
        </div>
      </main>

      {/* End of Day Report Modal - Still a modal */}
      {isReportModalOpen && (
        <EndOfDayReportModal
          onClose={() => setIsReportModalOpen(false)}
          referrals={referrals}
          transactions={transactions}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Building2, User, Activity, Stethoscope, ShieldCheck, Wallet, Receipt, Save, XCircle, Search, Check, ChevronDown, X, Info, Plus, MapPin, Hash, Lock } from 'lucide-react';
import { Referral, Status, Company, HazardClass, ExamDefinition, MedicalInstitution } from '../types';

interface NewReferralViewProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
  companies: Company[];
  exams: ExamDefinition[];
  institutions: MedicalInstitution[];
}

export const NewReferralView: React.FC<NewReferralViewProps> = ({ onClose, onSubmit, companies, exams, institutions }) => {
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');

  // Searchable Company Dropdown State
  const [companySearchTerm, setCompanySearchTerm] = useState('');
  const [isCompanyDropdownOpen, setIsCompanyDropdownOpen] = useState(false);
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Institution Selection
  const [selectedInstitutionId, setSelectedInstitutionId] = useState<string>('');
  const [isInstitutionLocked, setIsInstitutionLocked] = useState(false);

  // Exam Search State
  const [examSearchTerm, setExamSearchTerm] = useState('');

  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');
  const [estimatedPrice, setEstimatedPrice] = useState(0);

  // Payment Method State
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');

  // Step Validation States
  const isStep1Complete = fullName.length >= 3;
  const isStep2Complete = selectedCompanyData !== null;

  // Filter companies based on search
  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(companySearchTerm.toLowerCase())
  );

  // Filter exams based on search
  const filteredExams = exams.filter(e => 
    e.name.toLowerCase().includes(examSearchTerm.toLowerCase())
  );

  // Handle click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCompanyDropdownOpen(false);
        if (selectedCompanyData) {
            setCompanySearchTerm(selectedCompanyData.name);
        } else {
            setCompanySearchTerm('');
        }
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [selectedCompanyData]);

  // Recalculate price when exams change
  useEffect(() => {
    const total = selectedExamIds.reduce((sum, id) => {
      const exam = exams.find(e => e.name === id); 
      const price = exam ? exam.price : 0;
      return sum + price;
    }, 0);
    setEstimatedPrice(total);
  }, [selectedExamIds, exams]);

  const handleSelectCompany = (company: Company) => {
      setSelectedCompanyData(company);
      setCompanySearchTerm(company.name);
      setIsCompanyDropdownOpen(false);

      // Auto-fill logic
      setSelectedExamIds(company.defaultExams);
      setPaymentMethod(company.defaultPaymentMethod || 'INVOICE');

      // Institution Logic
      if (company.forcedInstitutionId) {
          setSelectedInstitutionId(company.forcedInstitutionId);
          setIsInstitutionLocked(true);
      } else {
          setSelectedInstitutionId('');
          setIsInstitutionLocked(false);
      }
  };

  const handleClearCompany = () => {
      setSelectedCompanyData(null);
      setCompanySearchTerm('');
      setSelectedExamIds([]);
      setSelectedInstitutionId('');
      setIsInstitutionLocked(false);
  };

  const toggleExam = (examName: string) => {
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const getHazardClassStyles = (hazard: HazardClass) => {
    switch (hazard) {
      case HazardClass.VERY_DANGEROUS: 
        return { 
          bg: 'bg-red-500/10', 
          border: 'border-red-500/30',
          badge: 'bg-red-500 text-white'
        };
      case HazardClass.DANGEROUS: 
        return { 
          bg: 'bg-orange-500/10', 
          border: 'border-orange-500/30',
          badge: 'bg-orange-500 text-white'
        };
      case HazardClass.LESS: 
        return { 
          bg: 'bg-emerald-500/10', 
          border: 'border-emerald-500/30',
          badge: 'bg-emerald-500 text-white'
        };
      default: 
        return { 
          bg: 'bg-slate-700/50', 
          border: 'border-slate-600',
          badge: 'bg-slate-600 text-white'
        };
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!fullName || !selectedCompanyData) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        company: selectedCompanyData.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData.assignedDoctor,
      specialistName: selectedCompanyData.assignedSpecialist,
      totalPrice: estimatedPrice,
      paymentMethod: paymentMethod,
      targetInstitutionId: selectedInstitutionId || undefined
    };

    onSubmit(newReferral);
  };

  return (
    <div className="h-full flex flex-col lg:overflow-hidden overflow-y-auto animate-fadeIn bg-slate-950">
      {/* Header */}
      <div className="flex items-center justify-between mb-4 px-1 pt-1 shrink-0">
         <div className="flex items-center space-x-4">
            <button onClick={onClose} className="p-2 bg-slate-900 border border-slate-700 hover:border-slate-500 rounded-lg text-slate-400 hover:text-white transition-all shadow-sm">
               <ArrowLeft className="w-5 h-5" />
            </button>
            <div>
               <h1 className="text-xl font-bold text-white tracking-tight">Yeni Sevk Kaydı</h1>
               <p className="text-xs text-slate-400 hidden md:block">
                 Bilgileri sırasıyla doldurunuz. Adımlar tamamlandıkça aktif olacaktır.
               </p>
            </div>
         </div>
      </div>

      {/* Main Layout */}
      <form id="referralForm" onSubmit={handleSubmit} className="flex-1 grid grid-cols-12 gap-4 lg:gap-6 lg:min-h-0 h-auto pb-2">

          {/* LEFT COLUMN: Main Form Flow */}
          <div className="col-span-12 lg:col-span-9 flex flex-col gap-4 lg:overflow-y-auto custom-scrollbar pr-0 lg:pr-2 pb-10">

             {/* 1. STEP: PERSONEL */}
             <div className={`transition-all duration-300 ${isStep1Complete ? 'border-indigo-500/50 bg-slate-900' : 'bg-slate-900/50'} backdrop-blur-sm rounded-xl border border-slate-800 p-4 md:p-5 shadow-lg relative`}>
                <div className="flex items-center justify-between mb-3 border-b border-slate-800 pb-2">
                   <div className="flex items-center space-x-2 text-slate-200">
                     <div className={`p-1.5 rounded-lg transition-colors ${isStep1Complete ? 'bg-indigo-500 text-white' : 'bg-indigo-500/10 text-indigo-500'}`}>
                        <User className="w-4 h-4" />
                     </div>
                     <span className={`font-bold text-sm ${isStep1Complete ? 'text-indigo-400' : ''}`}>1. Personel Bilgileri</span>
                   </div>
                   {isStep1Complete && <Check className="w-5 h-5 text-indigo-500" />}
                </div>

                <div className="flex flex-col md:flex-row gap-4">
                  <div className="flex-1 relative">
                     <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                     <input 
                      required
                      autoFocus
                      type="text" 
                      value={fullName}
                      onChange={e => setFullName(e.target.value)}
                      className="w-full pl-10 pr-3 py-2.5 bg-slate-950 border border-slate-700 text-white text-sm rounded-lg focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all placeholder-slate-600"
                      placeholder="Ad Soyad"
                    />
                  </div>

                  <div className="w-full md:w-1/3 relative">
                    <Hash className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                    <input 
                      type="text" 
                      maxLength={11}
                      value={tcNo}
                      onChange={e => setTcNo(e.target.value.replace(/\D/g,''))}
                      className="w-full pl-10 pr-3 py-2.5 bg-slate-950 border border-slate-700 text-white text-sm rounded-lg focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all placeholder-slate-600"
                      placeholder="TC Kimlik No"
                    />
                  </div>
                </div>
             </div>

             {/* 2. STEP: FIRMA & KURUM (Conditional Render / Style) */}
             <div className={`transition-all duration-500 ${isStep1Complete ? 'opacity-100 translate-y-0' : 'opacity-40 translate-y-4 pointer-events-none grayscale'}`}>
                 <div className={`rounded-xl border p-4 md:p-5 shadow-lg transition-colors ${isStep2Complete ? 'bg-slate-900 border-blue-500/50' : 'bg-slate-900/50 border-slate-800'}`}>
                    <div className="flex items-center justify-between mb-3 border-b border-slate-800 pb-2">
                       <div className="flex items-center space-x-2 text-slate-200">
                          <div className={`p-1.5 rounded-lg transition-colors ${isStep2Complete ? 'bg-blue-500 text-white' : 'bg-blue-500/10 text-blue-500'}`}>
                              <Building2 className="w-4 h-4" />
                          </div>
                          <span className={`font-bold text-sm ${isStep2Complete ? 'text-blue-400' : ''}`}>2. Firma ve Kurum</span>
                       </div>
                       {!isStep1Complete ? <Lock className="w-4 h-4 text-slate-600" /> : isStep2Complete && <Check className="w-5 h-5 text-blue-500" />}
                    </div>

                    {/* Company Search Bar */}
                    <div ref={dropdownRef} className="relative mb-4">
                        <div className="relative group">
                          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 z-10" />
                          <input
                            type="text"
                            required
                            disabled={!isStep1Complete}
                            value={companySearchTerm}
                            onChange={(e) => {
                                setCompanySearchTerm(e.target.value);
                                setIsCompanyDropdownOpen(true);
                                if(selectedCompanyData && e.target.value !== selectedCompanyData.name) {
                                    setSelectedCompanyData(null);
                                }
                            }}
                            onClick={() => setIsCompanyDropdownOpen(true)}
                            placeholder="Firma ara..."
                            className={`w-full pl-9 pr-8 py-3 bg-slate-950 border text-white text-sm rounded-lg focus:ring-1 focus:ring-blue-500 outline-none transition-all ${!selectedCompanyData && companySearchTerm ? 'border-blue-500' : 'border-slate-700'}`}
                          />
                          {selectedCompanyData ? (
                             <button type="button" onClick={handleClearCompany} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-red-400">
                                 <X className="w-4 h-4" />
                             </button>
                          ) : (
                             <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 pointer-events-none" />
                          )}
                        </div>

                        {isCompanyDropdownOpen && (
                          <div className="absolute top-full left-0 right-0 mt-1 max-h-56 overflow-y-auto bg-slate-900 border border-slate-700 rounded-lg shadow-xl z-50 custom-scrollbar divide-y divide-slate-800">
                            {filteredCompanies.length > 0 ? (
                              filteredCompanies.map(c => (
                                <div
                                  key={c.id}
                                  onClick={() => handleSelectCompany(c)}
                                  className="px-4 py-3 hover:bg-slate-800 cursor-pointer flex items-center justify-between transition-colors group border-b border-slate-800/50 last:border-0"
                                >
                                  <div className="flex flex-col">
                                      <span className="text-sm text-slate-200 font-medium group-hover:text-white transition-colors">{c.name}</span>
                                      <span className="text-[10px] text-slate-500">{c.assignedDoctor}</span>
                                  </div>
                                  <div className="flex items-center space-x-3">
                                       <span className={`text-[10px] px-2 py-0.5 rounded font-bold ${
                                           c.hazardClass === HazardClass.VERY_DANGEROUS ? 'text-red-400 bg-red-900/20 border border-red-500/20' :
                                           c.hazardClass === HazardClass.DANGEROUS ? 'text-orange-400 bg-orange-900/20 border border-orange-500/20' :
                                           'text-emerald-400 bg-emerald-900/20 border border-emerald-500/20'
                                       }`}>
                                          {c.hazardClass === HazardClass.VERY_DANGEROUS ? 'Çok Tehlikeli' : c.hazardClass === HazardClass.DANGEROUS ? 'Tehlikeli' : 'Az Tehlikeli'}
                                       </span>
                                      {selectedCompanyData?.id === c.id && <Check className="w-4 h-4 text-blue-500" />}
                                  </div>
                                </div>
                              ))
                            ) : (
                               <div className="px-4 py-3 text-sm text-slate-500">Sonuç bulunamadı.</div>
                            )}
                          </div>
                        )}
                    </div>

                    {/* Combined Details Card */}
                    {selectedCompanyData && (
                      <div className={`rounded-xl border overflow-hidden animate-fadeIn ${getHazardClassStyles(selectedCompanyData.hazardClass).border} bg-slate-900/40`}>
                          {/* Header Bar of the Card */}
                          <div className={`px-4 py-2 flex items-center justify-between border-b ${getHazardClassStyles(selectedCompanyData.hazardClass).bg} ${getHazardClassStyles(selectedCompanyData.hazardClass).border}`}>
                              <div className="flex items-center space-x-2">
                                 <Building2 className="w-4 h-4 opacity-70" />
                                 <span className="font-bold text-sm text-white truncate max-w-[150px] md:max-w-none">{selectedCompanyData.name}</span>
                              </div>
                              <span className={`text-[10px] font-bold px-2 py-0.5 rounded shadow-sm whitespace-nowrap ${getHazardClassStyles(selectedCompanyData.hazardClass).badge}`}>
                                  {selectedCompanyData.hazardClass.toUpperCase()}
                              </span>
                          </div>

                          <div className="flex flex-col md:flex-row">
                              {/* Left: Doctors Info */}
                              <div className="p-4 flex-1 space-y-3 border-b md:border-b-0 md:border-r border-slate-800">
                                   <div className="flex items-start space-x-3">
                                       <div className="mt-0.5 p-1.5 bg-slate-800 rounded text-blue-400">
                                           <Stethoscope className="w-4 h-4" />
                                       </div>
                                       <div>
                                           <span className="text-[10px] uppercase text-slate-500 font-bold">İşyeri Hekimi</span>
                                           <p className="text-sm text-slate-200">{selectedCompanyData.assignedDoctor}</p>
                                       </div>
                                   </div>
                                   <div className="flex items-start space-x-3">
                                       <div className="mt-0.5 p-1.5 bg-slate-800 rounded text-emerald-400">
                                           <ShieldCheck className="w-4 h-4" />
                                       </div>
                                       <div>
                                           <span className="text-[10px] uppercase text-slate-500 font-bold">İSG Uzmanı</span>
                                           <p className="text-sm text-slate-200">{selectedCompanyData.assignedSpecialist}</p>
                                       </div>
                                   </div>
                              </div>

                              {/* Right: Institution Selector */}
                              <div className="p-4 w-full md:w-72 bg-slate-950/30 flex flex-col justify-center">
                                    <label className="text-[10px] text-slate-400 uppercase font-bold mb-2 flex items-center">
                                        <MapPin className="w-3 h-3 mr-1.5 text-purple-400" />
                                        Sevk Edilecek Kurum
                                    </label>

                                    <div className="relative group">
                                        <select 
                                            value={selectedInstitutionId} 
                                            onChange={e => !isInstitutionLocked && setSelectedInstitutionId(e.target.value)}
                                            disabled={isInstitutionLocked}
                                            className={`w-full pl-3 pr-8 py-2.5 bg-slate-900 border text-xs text-white rounded-lg outline-none appearance-none font-medium transition-all ${isInstitutionLocked ? 'border-purple-500/50 bg-purple-900/10 cursor-not-allowed text-purple-200 shadow-[0_0_10px_rgba(168,85,247,0.1)]' : 'border-slate-700 hover:border-slate-500 focus:border-blue-500 focus:ring-1 focus:ring-blue-500/20'}`}
                                        >
                                            <option value="">Seçim Yok (Serbest)</option>
                                            {institutions.map(inst => (
                                                <option key={inst.id} value={inst.id}>{inst.name}</option>
                                            ))}
                                        </select>
                                        {!isInstitutionLocked && <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-500 pointer-events-none group-hover:text-slate-300 transition-colors" />}
                                        {isInstitutionLocked && <Lock className="absolute right-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-purple-500 pointer-events-none" />}
                                    </div>

                                    {isInstitutionLocked ? (
                                            <div className="mt-2 flex items-start space-x-1.5 text-[10px] text-purple-300 bg-purple-500/10 px-2 py-1.5 rounded border border-purple-500/20">
                                            <Info className="w-3 h-3 mt-0.5 shrink-0" />
                                            <span>Firma anlaşması gereği bu kurum zorunludur.</span>
                                            </div>
                                    ) : (
                                            <div className="mt-2 text-[10px] text-slate-500 flex items-center">
                                            <Info className="w-3 h-3 mr-1" />
                                            Firma kısıtlaması yok.
                                            </div>
                                    )}
                              </div>
                          </div>
                      </div>
                    )}
                 </div>
             </div>

             {/* 3. STEP: EXAMS (Conditional Render / Style) */}
             <div className={`transition-all duration-500 ${isStep2Complete ? 'opacity-100 translate-y-0' : 'opacity-40 translate-y-4 pointer-events-none grayscale'}`}>
                 <div className="bg-slate-900/80 backdrop-blur-sm rounded-xl border border-slate-800 p-4 md:p-5 shadow-lg">
                    <div className="flex items-center justify-between mb-4 border-b border-slate-800 pb-2">
                       <div className="flex items-center space-x-2 text-slate-200">
                          <div className={`p-1.5 rounded-lg ${isStep2Complete ? 'bg-pink-500/10 text-pink-500' : 'bg-slate-700 text-slate-500'}`}>
                             <Activity className="w-4 h-4" />
                          </div>
                          <span className={`font-bold text-sm ${isStep2Complete ? 'text-white' : 'text-slate-500'}`}>3. Tetkik Seçimi</span>
                       </div>
                       {!isStep2Complete ? <Lock className="w-4 h-4 text-slate-600" /> : <div className="text-xs text-slate-500">{selectedExamIds.length} tetkik seçili</div>}
                    </div>

                    {/* Selected Exams (Badges) */}
                    <div className="mb-6">
                       <label className="text-xs font-medium text-slate-400 block mb-2">Yapılacak İşlemler</label>
                       {selectedExamIds.length > 0 ? (
                         <div className="flex flex-wrap gap-2">
                           {selectedExamIds.map(id => {
                              const exam = exams.find(e => e.name === id);
                              return (
                                <div key={id} className="group flex items-center pl-3 pr-2 py-2 bg-blue-600/10 border border-blue-500/30 hover:border-blue-500/60 rounded-lg text-sm text-blue-200 transition-all shadow-sm">
                                   <span className="mr-2 font-medium">{id}</span>
                                   <span className="text-xs text-blue-400/70 mr-2 font-mono">₺{exam?.price}</span>
                                   <button 
                                     type="button" 
                                     onClick={() => toggleExam(id)}
                                     className="p-1 hover:bg-blue-500/20 rounded-full text-blue-400 hover:text-white transition-colors"
                                   >
                                      <X className="w-3.5 h-3.5" />
                                   </button>
                                </div>
                              );
                           })}
                         </div>
                       ) : (
                         <div className="flex flex-col items-center justify-center p-6 border-2 border-dashed border-slate-800 rounded-lg text-slate-600 bg-slate-900/30">
                            <Activity className="w-6 h-6 mb-2 opacity-20" />
                            <span className="text-xs italic">Henüz tetkik seçilmedi. Firma seçildiğinde otomatik doldurulur.</span>
                         </div>
                       )}
                    </div>

                    {/* Add More Exams (Small Grid) */}
                    <div className="bg-slate-950/50 rounded-lg p-3 border border-slate-800">
                       <div className="flex items-center space-x-2 mb-3">
                          <Search className="w-3.5 h-3.5 text-slate-500" />
                          <input 
                            type="text" 
                            disabled={!isStep2Complete}
                            value={examSearchTerm}
                            onChange={e => setExamSearchTerm(e.target.value)}
                            placeholder="Listede olmayan tetkik ekle..."
                            className="bg-transparent border-none text-xs text-white placeholder-slate-600 focus:ring-0 w-full outline-none disabled:cursor-not-allowed"
                          />
                       </div>
                       <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-2 max-h-40 overflow-y-auto custom-scrollbar">
                          {filteredExams.filter(e => !selectedExamIds.includes(e.name)).map(exam => (
                             <button
                               key={exam.id}
                               type="button"
                               onClick={() => toggleExam(exam.name)}
                               className="flex items-center justify-between px-3 py-2 bg-slate-800 hover:bg-slate-700 border border-slate-700 hover:border-slate-600 rounded text-xs text-slate-300 transition-all text-left group"
                             >
                                <span className="truncate mr-1">{exam.name}</span>
                                <Plus className="w-3 h-3 opacity-0 group-hover:opacity-100 text-blue-400" />
                             </button>
                          ))}
                          {filteredExams.length === 0 && (
                             <span className="col-span-full text-center text-xs text-slate-600 py-2">Tetkik bulunamadı.</span>
                          )}
                       </div>
                    </div>
                 </div>
             </div>
          </div>

          {/* RIGHT COLUMN: Finance & Actions (Span 3) */}
          <div className={`col-span-12 lg:col-span-3 lg:h-fit lg:sticky lg:top-4 h-auto transition-all duration-700 ${isStep2Complete ? 'opacity-100 translate-x-0' : 'opacity-40 translate-x-4 pointer-events-none blur-[1px]'}`}>
             <div className="bg-slate-900/80 backdrop-blur-sm rounded-xl border border-slate-800 p-4 md:p-5 shadow-lg flex flex-col gap-6">
                <div className="flex items-center space-x-2 text-slate-200 border-b border-slate-800 pb-2">
                   <div className="p-1.5 bg-emerald-500/10 rounded-lg">
                      <Wallet className="w-4 h-4 text-emerald-500" />
                   </div>
                   <span className="font-bold text-sm">4. Finansal Özet</span>
                </div>

                {/* Payment Method Toggle */}
                <div className="bg-slate-950 rounded-lg p-1 flex border border-slate-800">
                  <button
                    type="button"
                    onClick={() => setPaymentMethod('INVOICE')}
                    className={`flex-1 py-2 rounded text-[10px] font-bold transition-all flex flex-col items-center justify-center space-y-1 ${paymentMethod === 'INVOICE' ? 'bg-blue-600 text-white shadow' : 'text-slate-500 hover:text-slate-300'}`}
                  >
                    <Receipt className="w-4 h-4" />
                    <span>CARİ / FATURA</span>
                  </button>
                  <button
                    type="button"
                    onClick={() => setPaymentMethod('CASH')}
                    className={`flex-1 py-2 rounded text-[10px] font-bold transition-all flex flex-col items-center justify-center space-y-1 ${paymentMethod === 'CASH' ? 'bg-emerald-600 text-white shadow' : 'text-slate-500 hover:text-slate-300'}`}
                  >
                    <Wallet className="w-4 h-4" />
                    <span>NAKİT / ELDEN</span>
                  </button>
                </div>

                {/* Price Display */}
                <div className={`p-4 rounded-xl border text-center transition-all ${paymentMethod === 'CASH' ? 'bg-emerald-900/20 border-emerald-500/50' : 'bg-slate-950 border-slate-800'}`}>
                   <span className="text-[10px] text-slate-400 font-medium block mb-1 uppercase tracking-wider">
                      {paymentMethod === 'CASH' ? 'Tahsil Edilecek' : 'Cari Bakiye'}
                   </span>
                   <div className="flex items-center justify-center">
                      <span className="text-lg font-light text-slate-500 mr-1">₺</span>
                      <span className={`text-3xl font-bold tracking-tight ${paymentMethod === 'CASH' ? 'text-emerald-400' : 'text-blue-400'}`}>
                        {estimatedPrice.toLocaleString('tr-TR')}
                      </span>
                   </div>
                </div>

                {/* Notes Input */}
                <div>
                   <label className="text-xs font-medium text-slate-500 block mb-1">Notlar</label>
                   <textarea 
                      value={notes}
                      onChange={e => setNotes(e.target.value)}
                      rows={3}
                      className="w-full p-3 bg-slate-950 border border-slate-700 text-white rounded-lg focus:ring-1 focus:ring-slate-500 outline-none text-xs resize-none"
                      placeholder="İşlem notu..."
                   />
                </div>

                {/* Action Buttons */}
                <div className="grid grid-cols-2 gap-3 mt-2">
                    <button 
                      type="button"
                      onClick={onClose}
                      className="py-3 bg-slate-800 hover:bg-slate-700 border border-slate-700 text-slate-300 font-medium rounded-xl transition-all text-sm"
                    >
                      İptal
                    </button>
                    <button 
                      type="submit"
                      className={`py-3 text-white font-bold rounded-xl shadow-lg transition-all flex items-center justify-center space-x-2 active:scale-95 text-sm ${paymentMethod === 'CASH' ? 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-900/20' : 'bg-blue-600 hover:bg-blue-500 shadow-blue-900/20'}`}
                    >
                      <Save className="w-4 h-4" />
                      <span>KAYDET</span>
                    </button>
                </div>
             </div>
          </div>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { 
  MoreHorizontal, 
  CheckCircle, 
  Clock, 
  AlertCircle, 
  FileText, 
  Trash2,
  Sparkles,
  MapPin,
  Building2
} from 'lucide-react';
import { Referral, Status, MedicalInstitution } from '../types';
import { analyzeResults } from '../services/geminiService';

interface ReferralListProps {
  referrals: Referral[];
  institutions?: MedicalInstitution[];
  onUpdateStatus: (id: string, status: Status) => void;
  onAnalyze: (id: string, result: string) => void;
  onDelete: (id: string) => void;
  compact?: boolean;
}

export const ReferralList: React.FC<ReferralListProps> = ({ 
  referrals, 
  institutions = [],
  onUpdateStatus, 
  onAnalyze,
  onDelete,
  compact = false 
}) => {
  const [analyzingId, setAnalyzingId] = useState<string | null>(null);

  const handleAIAnalysis = async (referral: Referral) => {
    setAnalyzingId(referral.id);
    try {
      const result = await analyzeResults(referral);
      onAnalyze(referral.id, result);
    } catch (e) {
      alert("Analiz sırasında bir hata oluştu.");
    } finally {
      setAnalyzingId(null);
    }
  };

  const getInstitutionName = (id?: string) => {
    if (!id) return null;
    return institutions.find(i => i.id === id)?.name || "Bilinmeyen Kurum";
  };

  if (referrals.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-slate-500 bg-slate-800 rounded-xl border border-dashed border-slate-700">
        <FileText className="w-12 h-12 mb-2 opacity-50" />
        <p>Henüz kayıt bulunmamaktadır.</p>
      </div>
    );
  }

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-900/50 border-b border-slate-700">
              <th className="px-4 py-3 text-xs font-semibold text-slate-400 uppercase tracking-wider">Personel</th>
              <th className="px-4 py-3 text-xs font-semibold text-slate-400 uppercase tracking-wider">Firma</th>
              {!compact && <th className="px-4 py-3 text-xs font-semibold text-slate-400 uppercase tracking-wider">Kurum</th>}
              <th className="px-4 py-3 text-xs font-semibold text-slate-400 uppercase tracking-wider">Tarih</th>
              <th className="px-4 py-3 text-xs font-semibold text-slate-400 uppercase tracking-wider">Tetkikler</th>
              <th className="px-4 py-3 text-xs font-semibold text-slate-400 uppercase tracking-wider text-right">Tutar</th>
              {!compact && <th className="px-4 py-3 text-xs font-semibold text-slate-400 uppercase tracking-wider text-right">İşlemler</th>}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-700">
            {referrals.map((referral) => {
               const instName = getInstitutionName(referral.targetInstitutionId);
               return (
              <tr key={referral.id} className="hover:bg-slate-700/30 transition-colors group">
                <td className="px-4 py-3">
                  <div className="flex flex-col">
                    <span className="font-medium text-white text-sm whitespace-nowrap">{referral.employee.fullName}</span>
                    <span className="text-xs text-slate-500 font-mono">{referral.employee.tcNo}</span>
                  </div>
                </td>
                <td className="px-4 py-3">
                  <div className="flex items-center space-x-2">
                     <Building2 className="w-3 h-3 text-slate-500" />
                     <span className="text-sm text-slate-300 whitespace-nowrap">{referral.employee.company}</span>
                  </div>
                </td>
                {!compact && (
                  <td className="px-4 py-3">
                    {instName ? (
                      <div className="flex items-center space-x-2 text-purple-300 bg-purple-500/10 px-2 py-1 rounded border border-purple-500/20 w-fit whitespace-nowrap">
                         <MapPin className="w-3 h-3" />
                         <span className="text-xs font-medium">{instName}</span>
                      </div>
                    ) : (
                      <span className="text-xs text-slate-600 italic">Kurum Seçilmedi</span>
                    )}
                  </td>
                )}
                <td className="px-4 py-3">
                  <span className="text-sm text-slate-400 whitespace-nowrap">
                    {new Date(referral.referralDate).toLocaleDateString('tr-TR')}
                  </span>
                </td>
                <td className="px-4 py-3">
                  <div className="flex flex-wrap gap-1 min-w-[150px]">
                    {referral.exams.slice(0, compact ? 2 : 3).map((exam, i) => (
                      <span key={i} className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-medium bg-slate-700 text-slate-300 border border-slate-600 whitespace-nowrap">
                        {exam}
                      </span>
                    ))}
                    {referral.exams.length > (compact ? 2 : 3) && (
                      <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-medium bg-slate-700 text-slate-400">
                        +{referral.exams.length - (compact ? 2 : 3)}
                      </span>
                    )}
                  </div>
                </td>
                <td className="px-4 py-3 text-right">
                  <div className="flex flex-col items-end">
                    <span className="text-emerald-400 font-medium text-sm">₺{referral.totalPrice?.toLocaleString('tr-TR') || 0}</span>
                    <span className={`text-[10px] uppercase font-bold tracking-wider px-1.5 py-0.5 rounded ${referral.paymentMethod === 'CASH' ? 'text-emerald-300 bg-emerald-500/10' : 'text-blue-300 bg-blue-500/10'}`}>
                      {referral.paymentMethod === 'CASH' ? 'Nakit' : 'Cari'}
                    </span>
                  </div>
                </td>
                {!compact && (
                  <td className="px-4 py-3 text-right">
                    <div className="flex items-center justify-end space-x-2">
                       {/* AI Analysis Button */}
                       {!referral.aiAnalysis && (
                         <button 
                            onClick={() => handleAIAnalysis(referral)}
                            disabled={analyzingId === referral.id}
                            className="text-indigo-400 hover:bg-indigo-500/10 p-2 rounded-lg transition-colors flex items-center space-x-1"
                            title="AI ile Sonuçları Yorumla"
                         >
                            {analyzingId === referral.id ? (
                                <div className="animate-spin h-4 w-4 border-2 border-indigo-500 border-t-transparent rounded-full" />
                            ) : (
                                <Sparkles className="w-4 h-4" />
                            )}
                         </button>
                       )}

                       {referral.aiAnalysis && (
                          <div className="relative group/tooltip">
                            <span className="text-indigo-400 cursor-help bg-indigo-500/10 px-2 py-1 rounded text-xs border border-indigo-500/30">
                              AI Raporu
                            </span>
                            <div className="absolute right-0 bottom-full mb-2 w-64 bg-slate-900 border border-slate-700 text-slate-300 text-xs p-3 rounded shadow-xl opacity-0 group-hover/tooltip:opacity-100 pointer-events-none transition-opacity z-50">
                              {referral.aiAnalysis}
                            </div>
                          </div>
                       )}

                      <button 
                        onClick={() => onDelete(referral.id)}
                        className="text-slate-500 hover:text-red-400 hover:bg-red-500/10 p-2 rounded-lg transition-colors"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </td>
                )}
              </tr>
            )})}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export enum Status {
  PENDING = 'PENDING',       // Bekliyor (Henüz gitmedi)
  AT_HOSPITAL = 'AT_HOSPITAL', // Hastanede / Tetkikte
  AWAITING_RESULT = 'AWAITING_RESULT', // Sonuç Bekleniyor
  COMPLETED = 'COMPLETED',   // Tamamlandı
  CANCELLED = 'CANCELLED'    // İptal
}

// Deprecated enum usage in favor of dynamic list, keeping for type safety in legacy code
export enum ExamType {
  AUDIOMETRY = 'Odyometri',
  LUNG_XRAY = 'Akciğer Grafisi',
  HEMOGRAM = 'Hemogram',
  VISION = 'Göz Muayenesi',
  EKG = 'EKG',
  TETANUS = 'Tetanoz Aşısı',
  BLOOD_SUGAR = 'Açlık Kan Şekeri',
  LIVER_FUNC = 'Karaciğer Fonksiyon Testleri'
}

export interface ExamDefinition {
  id: string;
  code: string; // Excel mapping code (e.g. "101", "HEM")
  name: string;
  price: number;
}

export interface MedicalInstitution {
  id: string;
  name: string;
  address?: string;
  phone?: string;
}

export enum HazardClass {
  LESS = 'Az Tehlikeli',
  DANGEROUS = 'Tehlikeli',
  VERY_DANGEROUS = 'Çok Tehlikeli'
}

export interface Company {
  id: string;
  name: string;
  hazardClass: HazardClass;
  assignedDoctor: string;     // İşyeri Hekimi
  assignedSpecialist: string; // İSG Uzmanı
  defaultExams: string[];     // Changed from ExamType[] to string[] to support dynamic exams
  defaultPaymentMethod: 'CASH' | 'INVOICE'; // Firmanın varsayılan ödeme yöntemi
  forcedInstitutionId?: string; // Eğer varsa, bu firma sadece bu kuruma sevk edilebilir
}

export interface Employee {
  id: string;
  fullName: string;
  tcNo: string;
  birthDate?: string; // New field added
  company: string;
  department?: string;
}

export interface Referral {
  id: string;
  employee: Employee;
  exams: string[]; // Changed to string[]
  status: Status;
  referralDate: string; // ISO Date string
  notes?: string;
  aiAnalysis?: string; // Gemini analysis result
  resultSummary?: string;
  doctorName?: string; // Kayıt anındaki doktor
  specialistName?: string; // Kayıt anındaki uzman
  totalPrice?: number; // Calculated price at time of referral
  paymentMethod: 'CASH' | 'INVOICE'; // Nakit (Kasa) veya Cari (Fatura)
  targetInstitutionId?: string; // Hangi kuruma sevk edildiği
}

export interface Stats {
  total: number;
  today: number;
  totalIncome: number;
}

export interface SafeTransaction {
  id: string;
  type: 'INCOME' | 'EXPENSE';
  amount: number;
  description: string;
  date: string;
  category?: string;
}

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Building2, User, Activity, Stethoscope, ShieldCheck, Wallet, Receipt, Save, XCircle, Search, Check, ChevronDown, X, Info, Plus, MapPin, Hash, Lock, Calendar } from 'lucide-react';
import { Referral, Status, Company, HazardClass, ExamDefinition, MedicalInstitution } from '../types';

interface NewReferralViewProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
  companies: Company[];
  exams: ExamDefinition[];
  institutions: MedicalInstitution[];
}

export const NewReferralView: React.FC<NewReferralViewProps> = ({ onClose, onSubmit, companies, exams, institutions }) => {
  // Step 2: Employee State
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');
  const [birthDate, setBirthDate] = useState('');

  // Step 1: Searchable Company Dropdown State
  const [companySearchTerm, setCompanySearchTerm] = useState('');
  const [isCompanyDropdownOpen, setIsCompanyDropdownOpen] = useState(false);
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Institution Selection
  const [selectedInstitutionId, setSelectedInstitutionId] = useState<string>('');
  const [isInstitutionLocked, setIsInstitutionLocked] = useState(false);

  // Step 3: Exam Search State
  const [examSearchTerm, setExamSearchTerm] = useState('');

  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');
  const [estimatedPrice, setEstimatedPrice] = useState(0);

  // Payment Method State
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');

  // Step Validation States
  // 1. Step is Complete if a company is selected
  const isStep1Complete = selectedCompanyData !== null;

  // 2. Step is Complete if Name > 3 chars, TC is 11 digits, and BirthDate is filled
  const isStep2Complete = fullName.length >= 3 && tcNo.length === 11 && birthDate !== '';

  // Filter companies based on search
  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(companySearchTerm.toLowerCase())
  );

  // Filter exams based on search
  const filteredExams = exams.filter(e => 
    e.name.toLowerCase().includes(examSearchTerm.toLowerCase())
  );

  // Handle click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCompanyDropdownOpen(false);
        if (selectedCompanyData) {
            setCompanySearchTerm(selectedCompanyData.name);
        } else {
            setCompanySearchTerm('');
        }
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [selectedCompanyData]);

  // Recalculate price when exams change
  useEffect(() => {
    const total = selectedExamIds.reduce((sum, id) => {
      const exam = exams.find(e => e.name === id); 
      const price = exam ? exam.price : 0;
      return sum + price;
    }, 0);
    setEstimatedPrice(total);
  }, [selectedExamIds, exams]);

  const handleSelectCompany = (company: Company) => {
      setSelectedCompanyData(company);
      setCompanySearchTerm(company.name);
      setIsCompanyDropdownOpen(false);

      // Auto-fill logic
      setSelectedExamIds(company.defaultExams);
      setPaymentMethod(company.defaultPaymentMethod || 'INVOICE');

      // Institution Logic
      if (company.forcedInstitutionId) {
          setSelectedInstitutionId(company.forcedInstitutionId);
          setIsInstitutionLocked(true);
      } else {
          setSelectedInstitutionId('');
          setIsInstitutionLocked(false);
      }
  };

  const handleClearCompany = () => {
      setSelectedCompanyData(null);
      setCompanySearchTerm('');
      setSelectedExamIds([]);
      setSelectedInstitutionId('');
      setIsInstitutionLocked(false);
  };

  const toggleExam = (examName: string) => {
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const getHazardClassStyles = (hazard: HazardClass) => {
    switch (hazard) {
      case HazardClass.VERY_DANGEROUS: 
        return { 
          bg: 'bg-red-500/10', 
          border: 'border-red-500/30',
          badge: 'bg-red-500 text-white'
        };
      case HazardClass.DANGEROUS: 
        return { 
          bg: 'bg-orange-500/10', 
          border: 'border-orange-500/30',
          badge: 'bg-orange-500 text-white'
        };
      case HazardClass.LESS: 
        return { 
          bg: 'bg-emerald-500/10', 
          border: 'border-emerald-500/30',
          badge: 'bg-emerald-500 text-white'
        };
      default: 
        return { 
          bg: 'bg-slate-700/50', 
          border: 'border-slate-600',
          badge: 'bg-slate-600 text-white'
        };
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!fullName || !selectedCompanyData) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        birthDate,
        company: selectedCompanyData.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData.assignedDoctor,
      specialistName: selectedCompanyData.assignedSpecialist,
      totalPrice: estimatedPrice,
      paymentMethod: paymentMethod,
      targetInstitutionId: selectedInstitutionId || undefined
    };

    onSubmit(newReferral);
  };

  return (
    <div className="h-full flex flex-col lg:overflow-hidden overflow-y-auto animate-fadeIn bg-slate-950">
      {/* Header */}
      <div className="flex items-center justify-between mb-4 px-1 pt-1 shrink-0">
         <div className="flex items-center space-x-4">
            <button onClick={onClose} className="p-2 bg-slate-900 border border-slate-700 hover:border-slate-500 rounded-lg text-slate-400 hover:text-white transition-all shadow-sm">
               <ArrowLeft className="w-5 h-5" />
            </button>
            <div>
               <h1 className="text-xl font-bold text-white tracking-tight">Yeni Sevk Kaydı</h1>
               <p className="text-xs text-slate-400 hidden md:block">
                 Önce firma seçimi yapınız, ardından personel bilgilerini giriniz.
               </p>
            </div>
         </div>
      </div>

      {/* Main Layout */}
      <form id="referralForm" onSubmit={handleSubmit} className="flex-1 grid grid-cols-12 gap-4 lg:gap-6 lg:min-h-0 h-auto pb-2">

          {/* LEFT COLUMN: Main Form Flow */}
          <div className="col-span-12 lg:col-span-9 flex flex-col gap-4 lg:overflow-y-auto custom-scrollbar pr-0 lg:pr-2 pb-10">

             {/* 1. STEP: FIRMA & KURUM (Now First) */}
             <div className={`transition-all duration-300 rounded-xl border p-4 md:p-5 shadow-lg relative ${isStep1Complete ? 'bg-slate-900 border-blue-500/50' : 'bg-slate-900/50 border-blue-500'}`}>
                <div className="flex items-center justify-between mb-3 border-b border-slate-800 pb-2">
                   <div className="flex items-center space-x-2 text-slate-200">
                      <div className={`p-1.5 rounded-lg transition-colors ${isStep1Complete ? 'bg-blue-500 text-white' : 'bg-blue-500/10 text-blue-500'}`}>
                          <Building2 className="w-4 h-4" />
                      </div>
                      <span className={`font-bold text-sm ${isStep1Complete ? 'text-blue-400' : ''}`}>1. Firma ve Kurum Seçimi</span>
                   </div>
                   {isStep1Complete && <Check className="w-5 h-5 text-blue-500" />}
                </div>

                {/* Company Search Bar */}
                <div ref={dropdownRef} className="relative mb-4">
                    <div className="relative group">
                      <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 z-10" />
                      <input
                        autoFocus
                        type="text"
                        required
                        value={companySearchTerm}
                        onChange={(e) => {
                            setCompanySearchTerm(e.target.value);
                            setIsCompanyDropdownOpen(true);
                            if(selectedCompanyData && e.target.value !== selectedCompanyData.name) {
                                setSelectedCompanyData(null);
                            }
                        }}
                        onClick={() => setIsCompanyDropdownOpen(true)}
                        placeholder="Firma ara..."
                        className={`w-full pl-9 pr-8 py-3 bg-slate-950 border text-white text-sm rounded-lg focus:ring-1 focus:ring-blue-500 outline-none transition-all ${!selectedCompanyData && companySearchTerm ? 'border-blue-500' : 'border-slate-700'}`}
                      />
                      {selectedCompanyData ? (
                         <button type="button" onClick={handleClearCompany} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-red-400">
                             <X className="w-4 h-4" />
                         </button>
                      ) : (
                         <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 pointer-events-none" />
                      )}
                    </div>

                    {isCompanyDropdownOpen && (
                      <div className="absolute top-full left-0 right-0 mt-1 max-h-56 overflow-y-auto bg-slate-900 border border-slate-700 rounded-lg shadow-xl z-50 custom-scrollbar divide-y divide-slate-800">
                        {filteredCompanies.length > 0 ? (
                          filteredCompanies.map(c => (
                            <div
                              key={c.id}
                              onClick={() => handleSelectCompany(c)}
                              className="px-4 py-3 hover:bg-slate-800 cursor-pointer flex items-center justify-between transition-colors group border-b border-slate-800/50 last:border-0"
                            >
                              <div className="flex flex-col">
                                  <span className="text-sm text-slate-200 font-medium group-hover:text-white transition-colors">{c.name}</span>
                                  <span className="text-[10px] text-slate-500">{c.assignedDoctor}</span>
                              </div>
                              <div className="flex items-center space-x-3">
                                   <span className={`text-[10px] px-2 py-0.5 rounded font-bold ${
                                       c.hazardClass === HazardClass.VERY_DANGEROUS ? 'text-red-400 bg-red-900/20 border border-red-500/20' :
                                       c.hazardClass === HazardClass.DANGEROUS ? 'text-orange-400 bg-orange-900/20 border border-orange-500/20' :
                                       'text-emerald-400 bg-emerald-900/20 border border-emerald-500/20'
                                   }`}>
                                      {c.hazardClass === HazardClass.VERY_DANGEROUS ? 'Çok Tehlikeli' : c.hazardClass === HazardClass.DANGEROUS ? 'Tehlikeli' : 'Az Tehlikeli'}
                                   </span>
                                  {selectedCompanyData?.id === c.id && <Check className="w-4 h-4 text-blue-500" />}
                              </div>
                            </div>
                          ))
                        ) : (
                           <div className="px-4 py-3 text-sm text-slate-500">Sonuç bulunamadı.</div>
                        )}
                      </div>
                    )}
                </div>

                {/* Combined Details Card */}
                {selectedCompanyData && (
                  <div className={`rounded-xl border overflow-hidden animate-fadeIn ${getHazardClassStyles(selectedCompanyData.hazardClass).border} bg-slate-900/40`}>
                      {/* Header Bar of the Card */}
                      <div className={`px-4 py-2 flex items-center justify-between border-b ${getHazardClassStyles(selectedCompanyData.hazardClass).bg} ${getHazardClassStyles(selectedCompanyData.hazardClass).border}`}>
                          <div className="flex items-center space-x-2">
                             <Building2 className="w-4 h-4 opacity-70" />
                             <span className="font-bold text-sm text-white truncate max-w-[150px] md:max-w-none">{selectedCompanyData.name}</span>
                          </div>
                          <span className={`text-[10px] font-bold px-2 py-0.5 rounded shadow-sm whitespace-nowrap ${getHazardClassStyles(selectedCompanyData.hazardClass).badge}`}>
                              {selectedCompanyData.hazardClass.toUpperCase()}
                          </span>
                      </div>

                      <div className="flex flex-col md:flex-row">
                          {/* Left: Doctors Info */}
                          <div className="p-4 flex-1 space-y-3 border-b md:border-b-0 md:border-r border-slate-800">
                               <div className="flex items-start space-x-3">
                                   <div className="mt-0.5 p-1.5 bg-slate-800 rounded text-blue-400">
                                       <Stethoscope className="w-4 h-4" />
                                   </div>
                                   <div>
                                       <span className="text-[10px] uppercase text-slate-500 font-bold">İşyeri Hekimi</span>
                                       <p className="text-sm text-slate-200">{selectedCompanyData.assignedDoctor}</p>
                                   </div>
                               </div>
                               <div className="flex items-start space-x-3">
                                   <div className="mt-0.5 p-1.5 bg-slate-800 rounded text-emerald-400">
                                       <ShieldCheck className="w-4 h-4" />
                                   </div>
                                   <div>
                                       <span className="text-[10px] uppercase text-slate-500 font-bold">İSG Uzmanı</span>
                                       <p className="text-sm text-slate-200">{selectedCompanyData.assignedSpecialist}</p>
                                   </div>
                               </div>
                          </div>

                          {/* Right: Institution Selector */}
                          <div className="p-4 w-full md:w-72 bg-slate-950/30 flex flex-col justify-center">
                                <label className="text-[10px] text-slate-400 uppercase font-bold mb-2 flex items-center">
                                    <MapPin className="w-3 h-3 mr-1.5 text-purple-400" />
                                    Sevk Edilecek Kurum
                                </label>

                                <div className="relative group">
                                    <select 
                                        value={selectedInstitutionId} 
                                        onChange={e => !isInstitutionLocked && setSelectedInstitutionId(e.target.value)}
                                        disabled={isInstitutionLocked}
                                        className={`w-full pl-3 pr-8 py-2.5 bg-slate-900 border text-xs text-white rounded-lg outline-none appearance-none font-medium transition-all ${isInstitutionLocked ? 'border-purple-500/50 bg-purple-900/10 cursor-not-allowed text-purple-200 shadow-[0_0_10px_rgba(168,85,247,0.1)]' : 'border-slate-700 hover:border-slate-500 focus:border-blue-500 focus:ring-1 focus:ring-blue-500/20'}`}
                                    >
                                        <option value="">Seçim Yok (Serbest)</option>
                                        {institutions.map(inst => (
                                            <option key={inst.id} value={inst.id}>{inst.name}</option>
                                        ))}
                                    </select>
