                   </div>
                </div>

                {/* Notes Input */}
                <div>
                   <label className="text-xs font-medium text-slate-500 block mb-1">Notlar</label>
                   <textarea 
                      value={notes}
                      onChange={e => setNotes(e.target.value)}
                      rows={3}
                      className="w-full p-3 bg-slate-950 border border-slate-700 text-white rounded-lg focus:ring-1 focus:ring-slate-500 outline-none text-xs resize-none"
                      placeholder="İşlem notu..."
                   />
                </div>

                {/* Action Buttons */}
                <div className="grid grid-cols-2 gap-3 mt-2">
                    <button 
                      type="button"
                      onClick={onClose}
                      className="py-3 bg-slate-800 hover:bg-slate-700 border border-slate-700 text-slate-300 font-medium rounded-xl transition-all text-sm"
                    >
                      İptal
                    </button>
                    <button 
                      type="submit"
                      disabled={!isStep2Complete}
                      className={`py-3 text-white font-bold rounded-xl shadow-lg transition-all flex items-center justify-center space-x-2 active:scale-95 text-sm ${paymentMethod === 'CASH' ? 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-900/20' : 'bg-blue-600 hover:bg-blue-500 shadow-blue-900/20'} ${!isStep2Complete ? 'opacity-50 cursor-not-allowed' : ''}`}
                    >
                      <Save className="w-4 h-4" />
                      <span>KAYDET</span>
                    </button>
                </div>
             </div>
          </div>
      </form>
    </div>
  );
};

export enum Status {
  PENDING = 'PENDING',       // Bekliyor (Henüz gitmedi)
  AT_HOSPITAL = 'AT_HOSPITAL', // Hastanede / Tetkikte
  AWAITING_RESULT = 'AWAITING_RESULT', // Sonuç Bekleniyor
  COMPLETED = 'COMPLETED',   // Tamamlandı
  CANCELLED = 'CANCELLED'    // İptal
}

// Deprecated enum usage in favor of dynamic list, keeping for type safety in legacy code
export enum ExamType {
  AUDIOMETRY = 'Odyometri',
  LUNG_XRAY = 'Akciğer Grafisi',
  HEMOGRAM = 'Hemogram',
  VISION = 'Göz Muayenesi',
  EKG = 'EKG',
  TETANUS = 'Tetanoz Aşısı',
  BLOOD_SUGAR = 'Açlık Kan Şekeri',
  LIVER_FUNC = 'Karaciğer Fonksiyon Testleri'
}

export interface ExamDefinition {
  id: string;
  code: string; // Excel mapping code (e.g. "101", "HEM")
  name: string;
  price: number;
}

export interface MedicalInstitution {
  id: string;
  name: string;
  address?: string;
  phone?: string;
}

export enum HazardClass {
  LESS = 'Az Tehlikeli',
  DANGEROUS = 'Tehlikeli',
  VERY_DANGEROUS = 'Çok Tehlikeli'
}

export interface Company {
  id: string;
  name: string;
  hazardClass: HazardClass;
  assignedDoctor: string;     // İşyeri Hekimi
  assignedSpecialist: string; // İSG Uzmanı
  defaultExams: string[];     // Changed from ExamType[] to string[] to support dynamic exams
  defaultPaymentMethod: 'CASH' | 'INVOICE'; // Firmanın varsayılan ödeme yöntemi
  forcedInstitutionId?: string; // Eğer varsa, bu firma sadece bu kuruma sevk edilebilir
}

export interface Employee {
  id: string;
  fullName: string;
  tcNo: string;
  birthDate?: string; // New field added
  company: string;
  department?: string;
}

export interface Referral {
  id: string;
  employee: Employee;
  exams: string[]; // Changed to string[]
  status: Status;
  referralDate: string; // ISO Date string
  notes?: string;
  aiAnalysis?: string; // Gemini analysis result
  resultSummary?: string;
  doctorName?: string; // Kayıt anındaki doktor
  specialistName?: string; // Kayıt anındaki uzman
  totalPrice?: number; // Calculated price at time of referral
  paymentMethod: 'CASH' | 'INVOICE'; // Nakit (Kasa) veya Cari (Fatura)
  targetInstitutionId?: string; // Hangi kuruma sevk edildiği
}

export interface Stats {
  total: number;
  today: number;
  totalIncome: number;
}

export interface SafeTransaction {
  id: string;
  type: 'INCOME' | 'EXPENSE';
  amount: number;
  description: string;
  date: string;
  category?: string;
}

export interface AppSettings {
  ekgLimitAge: number; // Age threshold for mandatory EKG (default 40)
}

import { Referral, Company, ExamDefinition, SafeTransaction, MedicalInstitution, AppSettings } from '../types';

const STORAGE_KEY_REFERRALS = 'osgb_referrals_v1';
const STORAGE_KEY_COMPANIES = 'osgb_companies_v1';
const STORAGE_KEY_EXAMS = 'osgb_exams_v1';
const STORAGE_KEY_TRANSACTIONS = 'osgb_transactions_v1';
const STORAGE_KEY_INSTITUTIONS = 'osgb_institutions_v1';
const STORAGE_KEY_SETTINGS = 'osgb_settings_v1';

// Referrals
export const loadReferrals = (): Referral[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY_REFERRALS);
    return data ? JSON.parse(data) : [];
  } catch (error) {
    return [];
  }
};
export const saveReferrals = (data: Referral[]) => localStorage.setItem(STORAGE_KEY_REFERRALS, JSON.stringify(data));

// Companies
export const loadCompanies = (defaults: Company[]): Company[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY_COMPANIES);
    return data ? JSON.parse(data) : defaults;
  } catch (error) {
    return defaults;
  }
};
export const saveCompanies = (data: Company[]) => localStorage.setItem(STORAGE_KEY_COMPANIES, JSON.stringify(data));

// Exams
export const loadExams = (defaults: ExamDefinition[]): ExamDefinition[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY_EXAMS);
    return data ? JSON.parse(data) : defaults;
  } catch (error) {
    return defaults;
  }
};
export const saveExams = (data: ExamDefinition[]) => localStorage.setItem(STORAGE_KEY_EXAMS, JSON.stringify(data));

// Institutions
export const loadInstitutions = (defaults: MedicalInstitution[]): MedicalInstitution[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY_INSTITUTIONS);
    return data ? JSON.parse(data) : defaults;
  } catch (error) {
    return defaults;
  }
};
export const saveInstitutions = (data: MedicalInstitution[]) => localStorage.setItem(STORAGE_KEY_INSTITUTIONS, JSON.stringify(data));

// Safe Transactions
export const loadTransactions = (): SafeTransaction[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY_TRANSACTIONS);
    return data ? JSON.parse(data) : [];
  } catch (error) {
    return [];
  }
};
export const saveTransactions = (data: SafeTransaction[]) => localStorage.setItem(STORAGE_KEY_TRANSACTIONS, JSON.stringify(data));

// App Settings
export const loadAppSettings = (): AppSettings => {
  try {
    const data = localStorage.getItem(STORAGE_KEY_SETTINGS);
    return data ? JSON.parse(data) : { ekgLimitAge: 40 }; // Default 40
  } catch (error) {
    return { ekgLimitAge: 40 };
  }
};

export const saveAppSettings = (settings: AppSettings) => localStorage.setItem(STORAGE_KEY_SETTINGS, JSON.stringify(settings));

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Settings, 
  Plus, 
  Search,
  Activity,
  LogOut,
  Stethoscope,
  Wallet,
  FileText,
  Menu,
  X
} from 'lucide-react';
import { ReferralList } from './components/ReferralList';
import { NewReferralView } from './components/NewReferralModal'; // Component updated to be a View
import { StatsCards } from './components/StatsCards';
import { FinanceView } from './components/FinanceView';
import { SettingsView } from './components/SettingsView';
import { EndOfDayReportModal } from './components/EndOfDayReportModal';
import { Referral, Status, Company, ExamDefinition, SafeTransaction, MedicalInstitution, AppSettings } from './types';
import { 
  loadReferrals, saveReferrals, 
  loadCompanies, saveCompanies,
  loadExams, saveExams,
  loadTransactions, saveTransactions,
  loadInstitutions, saveInstitutions,
  loadAppSettings, saveAppSettings
} from './services/storage';
import { PREDEFINED_COMPANIES, DEFAULT_EXAMS, DEFAULT_INSTITUTIONS } from './services/initialData';

const App: React.FC = () => {
  // Added 'create_referral' to navigation state
  const [activeTab, setActiveTab] = useState<'dashboard' | 'referrals' | 'finance' | 'settings' | 'create_referral'>('dashboard');

  // Mobile Menu State
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Data States
  const [referrals, setReferrals] = useState<Referral[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [exams, setExams] = useState<ExamDefinition[]>([]);
  const [institutions, setInstitutions] = useState<MedicalInstitution[]>([]);
  const [transactions, setTransactions] = useState<SafeTransaction[]>([]);
  const [appSettings, setAppSettings] = useState<AppSettings>({ ekgLimitAge: 40 });

  // isModalOpen removed as it is now a page
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Initial load
  useEffect(() => {
    setReferrals(loadReferrals());
    setCompanies(loadCompanies(PREDEFINED_COMPANIES));
    setExams(loadExams(DEFAULT_EXAMS));
    setInstitutions(loadInstitutions(DEFAULT_INSTITUTIONS));
    setTransactions(loadTransactions());
    setAppSettings(loadAppSettings());
  }, []);

  // Save Effects
  useEffect(() => saveReferrals(referrals), [referrals]);
  useEffect(() => saveCompanies(companies), [companies]);
  useEffect(() => saveExams(exams), [exams]);
  useEffect(() => saveInstitutions(institutions), [institutions]);
  useEffect(() => saveTransactions(transactions), [transactions]);
  useEffect(() => saveAppSettings(appSettings), [appSettings]);

  // Handlers
  const handleCreateReferral = (referral: Referral) => {
    // 1. Add Referral (Always)
    setReferrals(prev => [referral, ...prev]);

    // 2. Add to Safe ONLY if Payment Method is CASH
    if (referral.paymentMethod === 'CASH' && referral.totalPrice && referral.totalPrice > 0) {
      const newTransaction: SafeTransaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'INCOME',
        amount: referral.totalPrice,
        description: `Sevk Geliri (Nakit): ${referral.employee.fullName} (${referral.employee.company})`,
        date: new Date().toISOString()
      };
      setTransactions(prev => [...prev, newTransaction]);
    }

    // Redirect back to referrals list after creation
    setActiveTab('referrals');
  };

  const handleUpdateStatus = (id: string, newStatus: Status) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, status: newStatus } : r
    ));
  };

  const handleAnalyze = (id: string, analysis: string) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, aiAnalysis: analysis } : r
    ));
  };

  const handleDelete = (id: string) => {
    if(window.confirm('Bu kaydı silmek istediğinize emin misiniz?')) {
      setReferrals(prev => prev.filter(r => r.id !== id));
    }
  };

  // Settings Handlers
  const handleAddCompany = (c: Company) => setCompanies(prev => [...prev, c]);
  const handleDeleteCompany = (id: string) => setCompanies(prev => prev.filter(c => c.id !== id));

  const handleAddExam = (e: ExamDefinition) => setExams(prev => [...prev, e]);
  const handleUpdateExam = (updated: ExamDefinition) => setExams(prev => prev.map(e => e.id === updated.id ? updated : e));
  const handleDeleteExam = (id: string) => setExams(prev => prev.filter(e => e.id !== id));

  const handleAddInstitution = (i: MedicalInstitution) => setInstitutions(prev => [...prev, i]);
  const handleDeleteInstitution = (id: string) => setInstitutions(prev => prev.filter(i => i.id !== id));

  const handleUpdateSettings = (newSettings: AppSettings) => setAppSettings(newSettings);

  // Finance Handlers
  const handleAddTransaction = (t: SafeTransaction) => setTransactions(prev => [...prev, t]);

  const filteredReferrals = useMemo(() => {
    return referrals.filter(r => 
      r.employee.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.company.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.tcNo.includes(searchTerm)
    );
  }, [referrals, searchTerm]);

  const stats = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    const totalIncome = transactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);

    return {
      total: referrals.length,
      today: referrals.filter(r => r.referralDate.startsWith(todayStr)).length,
      totalIncome: totalIncome
    };
  }, [referrals, transactions]);

  // Handle nav click (close mobile menu)
  const handleNavClick = (tab: typeof activeTab) => {
      setActiveTab(tab);
      setIsMobileMenuOpen(false);
  };

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden">

