import React, { useMemo, useState } from 'react';
import { X, Printer, Calculator, Calendar, Building2, CalendarDays, CalendarRange } from 'lucide-react';
import { Referral, SafeTransaction } from '../types';

interface EndOfDayReportModalProps {
  onClose: () => void;
  referrals: Referral[];
  transactions: SafeTransaction[];
}

type ReportPeriod = 'daily' | 'weekly' | 'monthly';

export const EndOfDayReportModal: React.FC<EndOfDayReportModalProps> = ({ onClose, referrals, transactions }) => {
  const [period, setPeriod] = useState<ReportPeriod>('daily');
  const now = new Date();

  // Calculate Date Range based on Period
  const dateRange = useMemo(() => {
    const end = new Date(); // Now
    const start = new Date(); 
    start.setHours(0, 0, 0, 0);

    if (period === 'weekly') {
      // Set to Monday of the current week
      const day = start.getDay() || 7; // Get current day (1=Mon, ..., 7=Sun)
      if (day !== 1) {
        start.setHours(-24 * (day - 1));
      }
    } else if (period === 'monthly') {
      // Set to 1st of the current month
      start.setDate(1);
    }
    // 'daily' is already set to start of today

    return { start, end };
  }, [period]);

  const reportData = useMemo(() => {
    // Filter referrals within range
    const filteredReferrals = referrals.filter(r => {
      const d = new Date(r.referralDate);
      return d >= dateRange.start && d <= dateRange.end;
    });

    // Filter transactions within range
    const filteredTransactions = transactions.filter(t => {
      const d = new Date(t.date);
      return d >= dateRange.start && d <= dateRange.end;
    });

    // Calculate Finances for the Period
    const totalIncome = filteredTransactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);

    const totalExpense = filteredTransactions
      .filter(t => t.type === 'EXPENSE')
      .reduce((acc, curr) => acc + curr.amount, 0);

    // Calculate Total Balance (Absolute Current System State - All Time)
    const currentTotalBalance = transactions.reduce((acc, curr) => {
      return curr.type === 'INCOME' ? acc + curr.amount : acc - curr.amount;
    }, 0);

    // Opening Balance for this Period = Current Balance - (Net Change during this period)
    const periodNetChange = totalIncome - totalExpense;
    const openingBalance = currentTotalBalance - periodNetChange;

    return {
      referrals: filteredReferrals,
      transactions: filteredTransactions,
      totalIncome,
      totalExpense,
      openingBalance,
      closingBalance: currentTotalBalance
    };
  }, [referrals, transactions, dateRange]);

  const getTitle = () => {
    switch(period) {
      case 'weekly': return 'Haftalık Faaliyet Raporu';
      case 'monthly': return 'Aylık Faaliyet Raporu';
      default: return 'Gün Sonu Raporu (Z Raporu)';
    }
  };

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4 print:p-0 print:bg-white print:fixed print:inset-0">
      <div className="bg-slate-900 rounded-2xl shadow-2xl w-full max-w-4xl overflow-hidden border border-slate-700 print:border-none print:shadow-none print:w-full print:max-w-none print:bg-white print:text-black">

        {/* Header - No Print controls */}
        <div className="px-6 py-4 border-b border-slate-700 flex justify-between items-center bg-slate-950/50 print:hidden">
          <h3 className="text-lg font-bold text-white flex items-center">
            <Calculator className="w-5 h-5 mr-2 text-blue-500" />
            Raporlama Merkezi
          </h3>
          <div className="flex items-center space-x-2">
            <button 
              onClick={handlePrint}
              className="p-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg transition-colors flex items-center space-x-2 text-sm"
            >
              <Printer className="w-4 h-4" />
              <span>Yazdır</span>
            </button>
            <button onClick={onClose} className="text-slate-400 hover:text-white hover:bg-slate-700 rounded-full p-1 transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* Period Selector Tabs (Hidden in Print) */}
        <div className="flex border-b border-slate-700 bg-slate-900 print:hidden">
            <button 
              onClick={() => setPeriod('daily')}
              className={`flex-1 py-3 text-sm font-medium transition-colors flex items-center justify-center space-x-2 ${period === 'daily' ? 'text-blue-400 border-b-2 border-blue-500 bg-slate-800/50' : 'text-slate-400 hover:bg-slate-800'}`}
            >
                <Calendar className="w-4 h-4" />
                <span>Günlük (Z Raporu)</span>
            </button>
            <button 
              onClick={() => setPeriod('weekly')}
              className={`flex-1 py-3 text-sm font-medium transition-colors flex items-center justify-center space-x-2 ${period === 'weekly' ? 'text-blue-400 border-b-2 border-blue-500 bg-slate-800/50' : 'text-slate-400 hover:bg-slate-800'}`}
            >
                <CalendarDays className="w-4 h-4" />
                <span>Bu Hafta</span>
            </button>
            <button 
              onClick={() => setPeriod('monthly')}
              className={`flex-1 py-3 text-sm font-medium transition-colors flex items-center justify-center space-x-2 ${period === 'monthly' ? 'text-blue-400 border-b-2 border-blue-500 bg-slate-800/50' : 'text-slate-400 hover:bg-slate-800'}`}
            >
                <CalendarRange className="w-4 h-4" />
                <span>Bu Ay</span>
            </button>
        </div>

        {/* Printable Content */}
        <div className="p-8 space-y-8 overflow-y-auto max-h-[85vh] custom-scrollbar print:overflow-visible print:max-h-none print:p-0">

          {/* Report Header */}
          <div className="text-center border-b border-slate-700 print:border-slate-300 pb-6">
            <h1 className="text-2xl font-bold text-white print:text-black mb-1">OSGB Tetkik Takip Sistemi</h1>
            <h2 className="text-lg text-slate-400 print:text-slate-600 font-medium">{getTitle()}</h2>
            <div className="flex flex-col items-center justify-center mt-2 text-sm text-slate-500 print:text-slate-500">
              <div className="flex items-center space-x-2">
                 <Calendar className="w-4 h-4" />
                 <span>Rapor Tarihi: {now.toLocaleDateString('tr-TR')} {now.toLocaleTimeString('tr-TR')}</span>
              </div>
              <div className="text-xs mt-1 font-mono text-slate-600 print:text-slate-400">
                Kapsam: {dateRange.start.toLocaleDateString('tr-TR')} - {dateRange.end.toLocaleDateString('tr-TR')}
              </div>
            </div>
          </div>

          {/* Financial Summary Grid */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 print:grid-cols-4 print:gap-2">
            <div className="p-4 rounded-lg bg-slate-800/50 border border-slate-700 print:bg-transparent print:border-slate-300">
              <p className="text-xs text-slate-400 print:text-slate-600 mb-1">
                  {period === 'daily' ? 'Güne Başlama (Devir)' : 'Dönem Başı Devir'}
              </p>
              <p className="text-lg font-bold text-white print:text-black">₺{reportData.openingBalance.toLocaleString('tr-TR')}</p>
            </div>
            <div className="p-4 rounded-lg bg-emerald-900/10 border border-emerald-500/20 print:bg-transparent print:border-slate-300">
              <p className="text-xs text-emerald-400 print:text-slate-600 mb-1">
                  {period === 'daily' ? 'Günlük Tahsilat (+)' : 'Dönem İçi Tahsilat (+)'}
              </p>
              <p className="text-lg font-bold text-emerald-400 print:text-black">₺{reportData.totalIncome.toLocaleString('tr-TR')}</p>
            </div>
            <div className="p-4 rounded-lg bg-red-900/10 border border-red-500/20 print:bg-transparent print:border-slate-300">
              <p className="text-xs text-red-400 print:text-slate-600 mb-1">
                  {period === 'daily' ? 'Günlük Çıkış (-)' : 'Dönem İçi Çıkış (-)'}
              </p>
              <p className="text-lg font-bold text-red-400 print:text-black">₺{reportData.totalExpense.toLocaleString('tr-TR')}</p>
            </div>
            <div className="p-4 rounded-lg bg-blue-900/10 border border-blue-500/20 print:bg-transparent print:border-slate-300">
              <p className="text-xs text-blue-400 print:text-slate-600 mb-1">Güncel Kasa</p>
              <p className="text-lg font-bold text-blue-400 print:text-black">₺{reportData.closingBalance.toLocaleString('tr-TR')}</p>
            </div>
          </div>

          {/* Personnel Summary */}
          <div>
            <h4 className="text-sm font-bold text-slate-300 print:text-black uppercase tracking-wider mb-3 flex items-center">
              <Building2 className="w-4 h-4 mr-2" />
