                        <h1 className="text-xl font-bold text-slate-900 tracking-tight">OSGB PRO</h1>
                        <p className="text-xs text-slate-500 font-medium uppercase tracking-widest">Tetkik Takip Sistemi</p>
                        </div>
                    )}
                 </div>
                 <div className="text-right">
                    <h2 className="text-lg font-bold text-slate-900 uppercase tracking-tight">{getTitle()}</h2>
                    <p className="text-xs text-slate-500 mt-1">Rapor No: #{Math.floor(Math.random() * 100000)}</p>
                    <p className="text-xs text-slate-500">Oluşturulma: {now.toLocaleDateString('tr-TR')} {now.toLocaleTimeString('tr-TR')}</p>
                 </div>
              </div>

              {/* Info Grid */}
              <div className="bg-slate-50 rounded border border-slate-200 p-4 flex justify-between items-center text-sm">
                  <div>
                     <span className="text-slate-500 font-medium block text-xs uppercase mb-1">Rapor Periyodu</span>
                     <span className="font-bold text-slate-800">
                        {dateRange.start.toLocaleDateString('tr-TR')} - {dateRange.end.toLocaleDateString('tr-TR')}
                     </span>
                  </div>
                  <div className="text-right">
                     <span className="text-slate-500 font-medium block text-xs uppercase mb-1">Şube / Birim</span>
                     <span className="font-bold text-slate-800">Merkez Ofis / Kasa</span>
                  </div>
              </div>

              {/* Financial Summary */}
              <div>
                 <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 flex items-center">
                    <Calculator className="w-3.5 h-3.5 mr-1" />
                    Finansal Özet Tablosu
                 </h3>
                 <div className="grid grid-cols-4 gap-4">
                    <div className="p-4 rounded border border-slate-200 bg-white shadow-sm">
                       <p className="text-[10px] text-slate-500 font-bold uppercase mb-1">AÇILIŞ BAKİYESİ</p>
                       <p className="text-lg font-bold text-slate-700">₺{reportData.openingBalance.toLocaleString('tr-TR')}</p>
                    </div>
                    <div className="p-4 rounded border border-emerald-100 bg-emerald-50/30 shadow-sm">
                       <p className="text-[10px] text-emerald-600 font-bold uppercase mb-1">GİRİŞLER (+)</p>
                       <p className="text-lg font-bold text-emerald-700">₺{reportData.totalIncome.toLocaleString('tr-TR')}</p>
                    </div>
                    <div className="p-4 rounded border border-red-100 bg-red-50/30 shadow-sm">
                       <p className="text-[10px] text-red-600 font-bold uppercase mb-1">ÇIKIŞLAR (-)</p>
                       <p className="text-lg font-bold text-red-700">₺{reportData.totalExpense.toLocaleString('tr-TR')}</p>
                    </div>
                    <div className="p-4 rounded border border-blue-200 bg-blue-50 shadow-sm relative overflow-hidden">
                       <div className="absolute right-0 top-0 p-2 opacity-10"><Calculator className="w-12 h-12" /></div>
                       <p className="text-[10px] text-blue-600 font-bold uppercase mb-1">GÜNCEL KASA</p>
                       <p className="text-xl font-bold text-blue-800">₺{reportData.closingBalance.toLocaleString('tr-TR')}</p>
                    </div>
                 </div>
              </div>

              {/* Transactions Table */}
              {reportData.transactions.length > 0 && (
                <div>
                  <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 mt-6 flex items-center">
                      <FileText className="w-3.5 h-3.5 mr-1" />
                      Kasa Hareket Dökümü
                  </h3>
                  <table className="w-full text-left text-xs border border-slate-200">
                     <thead className="bg-slate-100 text-slate-600">
                        <tr>
                           <th className="px-3 py-2 font-bold border-b border-slate-200">Saat</th>
                           <th className="px-3 py-2 font-bold border-b border-slate-200">Açıklama</th>
                           <th className="px-3 py-2 font-bold border-b border-slate-200 text-right">Giriş</th>
                           <th className="px-3 py-2 font-bold border-b border-slate-200 text-right">Çıkış</th>
                        </tr>
                     </thead>
                     <tbody className="divide-y divide-slate-100">
                        {reportData.transactions.map(tx => (
                           <tr key={tx.id}>
                              <td className="px-3 py-1.5 text-slate-500 font-mono">
                                 {new Date(tx.date).toLocaleTimeString('tr-TR', {hour: '2-digit', minute:'2-digit'})}
                              </td>
                              <td className="px-3 py-1.5 text-slate-800 font-medium">
                                 {tx.description}
                              </td>
                              <td className="px-3 py-1.5 text-right font-mono text-emerald-600">
                                 {tx.type === 'INCOME' ? `₺${tx.amount.toLocaleString('tr-TR')}` : '-'}
                              </td>
                              <td className="px-3 py-1.5 text-right font-mono text-red-600">
                                 {tx.type === 'EXPENSE' ? `₺${tx.amount.toLocaleString('tr-TR')}` : '-'}
                              </td>
                           </tr>
                        ))}
                     </tbody>
                  </table>
                </div>
              )}

              {/* Personnel Referrals Table */}
              <div>
                 <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 mt-6 flex items-center">
                    <Building2 className="w-3.5 h-3.5 mr-1" />
                    Personel Sevk Listesi
                 </h3>
                 <table className="w-full text-left text-xs border border-slate-200">
                    <thead className="bg-slate-100 text-slate-600">
                       <tr>
                          <th className="px-3 py-2 font-bold border-b border-slate-200">Tarih</th>
                          <th className="px-3 py-2 font-bold border-b border-slate-200">Personel</th>
                          <th className="px-3 py-2 font-bold border-b border-slate-200">Firma</th>
                          <th className="px-3 py-2 font-bold border-b border-slate-200">Ödeme</th>
                          <th className="px-3 py-2 font-bold border-b border-slate-200 text-right">Tutar</th>
                       </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                       {reportData.referrals.map(ref => (
                          <tr key={ref.id} className="text-slate-700">
                             <td className="px-3 py-1.5 text-slate-500 font-mono">
                                {new Date(ref.referralDate).toLocaleDateString('tr-TR')}
                             </td>
                             <td className="px-3 py-1.5 font-bold">{ref.employee.fullName}</td>
                             <td className="px-3 py-1.5">{ref.employee.company}</td>
                             <td className="px-3 py-1.5">
                                <span className={`px-1.5 py-0.5 rounded text-[10px] font-bold uppercase ${ref.paymentMethod === 'CASH' ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'}`}>
                                   {ref.paymentMethod === 'CASH' ? 'Nakit' : 'Cari'}
                                </span>
                             </td>
                             <td className="px-3 py-1.5 text-right font-mono font-medium">
                                ₺{ref.totalPrice?.toLocaleString('tr-TR')}
                             </td>
                          </tr>
                       ))}
                       {reportData.referrals.length === 0 && (
                          <tr><td colSpan={5} className="text-center py-4 text-slate-400 italic">Kayıt bulunamadı.</td></tr>
                       )}
                    </tbody>
                 </table>
              </div>

              {/* Signatures Footer */}
              <div className="mt-12 pt-8 border-t border-slate-200 grid grid-cols-2 gap-20">
                  <div className="text-center">
                     <p className="text-xs font-bold text-slate-900 uppercase mb-8">Teslim Eden (Kasa)</p>
                     <div className="h-px w-32 bg-slate-400 mx-auto"></div>
                     <p className="text-[10px] text-slate-500 mt-1">İmza / Tarih</p>
                  </div>
                  <div className="text-center">
                     <p className="text-xs font-bold text-slate-900 uppercase mb-8">Teslim Alan (Yönetici)</p>
                     <div className="h-px w-32 bg-slate-400 mx-auto"></div>
                     <p className="text-[10px] text-slate-500 mt-1">İmza / Tarih</p>
                  </div>
              </div>

              {/* Print Footer */}
              <div className="absolute bottom-4 left-0 right-0 text-center">
                 <p className="text-[10px] text-slate-400">Bu belge OSGB Pro sistemi tarafından elektronik ortamda oluşturulmuştur.</p>
              </div>

           </div>
        </div>
      </div>
    </div>
  );
};

export enum Status {
  PENDING = 'PENDING',       // Bekliyor (Henüz gitmedi)
  AT_HOSPITAL = 'AT_HOSPITAL', // Hastanede / Tetkikte
  AWAITING_RESULT = 'AWAITING_RESULT', // Sonuç Bekleniyor
  COMPLETED = 'COMPLETED',   // Tamamlandı
  CANCELLED = 'CANCELLED'    // İptal
}

// Deprecated enum usage in favor of dynamic list, keeping for type safety in legacy code
export enum ExamType {
  AUDIOMETRY = 'Odyometri',
  LUNG_XRAY = 'Akciğer Grafisi',
  HEMOGRAM = 'Hemogram',
  VISION = 'Göz Muayenesi',
  EKG = 'EKG',
  TETANUS = 'Tetanoz Aşısı',
  BLOOD_SUGAR = 'Açlık Kan Şekeri',
  LIVER_FUNC = 'Karaciğer Fonksiyon Testleri'
}

export interface ExamDefinition {
  id: string;
  code: string; // Excel mapping code (e.g. "101", "HEM")
  name: string;
  price: number; // Müşteriye satılan fiyat
  cost?: number; // OSGB'ye olan maliyeti (Kurum ödemesi)
}

export interface MedicalInstitution {
  id: string;
  name: string;
  address?: string;
  phone?: string;
}

export enum HazardClass {
  LESS = 'Az Tehlikeli',
  DANGEROUS = 'Tehlikeli',
  VERY_DANGEROUS = 'Çok Tehlikeli'
}

export interface Company {
  id: string;
  name: string;
  hazardClass: HazardClass;
  assignedDoctor: string;     // İşyeri Hekimi
  assignedSpecialist: string; // İSG Uzmanı
  defaultExams: string[];     // Changed from ExamType[] to string[] to support dynamic exams
  defaultPaymentMethod: 'CASH' | 'INVOICE'; // Firmanın varsayılan ödeme yöntemi
  forcedInstitutionId?: string; // Eğer varsa, bu firma sadece bu kuruma sevk edilebilir
}

export interface Employee {
  id: string;
  fullName: string;
  tcNo: string;
  birthDate?: string; // New field added
  company: string;
  department?: string;
}

export interface Referral {
  id: string;
  employee: Employee;
  exams: string[]; // Changed to string[]
  status: Status;
  referralDate: string; // ISO Date string
  notes?: string;
  aiAnalysis?: string; // Gemini analysis result
  resultSummary?: string;
  doctorName?: string; // Kayıt anındaki doktor
  specialistName?: string; // Kayıt anındaki uzman
  totalPrice?: number; // Müşteriden alınacak tutar
  totalCost?: number; // OSGB'nin ödeyeceği maliyet
  paymentMethod: 'CASH' | 'INVOICE'; // Nakit (Kasa) veya Cari (Fatura)
  targetInstitutionId?: string; // Hangi kuruma sevk edildiği
}

export interface Stats {
  total: number;
  today: number;
  totalIncome: number;
}

export interface SafeTransaction {
  id: string;
  type: 'INCOME' | 'EXPENSE';
  amount: number;
  description: string;
  date: string;
  category?: string;
}

export interface AppSettings {
  ekgLimitAge: number; // Age threshold for mandatory EKG (default 40)
  companyLogo?: string; // Base64 string for the logo
}

import React, { useState, useRef } from 'react';
import { Company, ExamDefinition, HazardClass, MedicalInstitution, AppSettings } from '../types';
import { Trash2, Plus, Building2, TestTube, Save, Check, Wallet, Receipt, Upload, FileDown, AlertCircle, MapPin, Sliders, CheckSquare, Square, Image as ImageIcon } from 'lucide-react';
import * as XLSX from 'xlsx';

interface SettingsViewProps {
  companies: Company[];
  onAddCompany: (c: Company) => void;
  onDeleteCompany: (id: string) => void;
  onBulkDeleteCompanies: (ids: string[]) => void;
  exams: ExamDefinition[];
  onAddExam: (e: ExamDefinition) => void;
  onUpdateExam: (e: ExamDefinition) => void;
  onDeleteExam: (id: string) => void;
  institutions: MedicalInstitution[];
  onAddInstitution: (i: MedicalInstitution) => void;
  onDeleteInstitution: (id: string) => void;
  settings: AppSettings;
  onUpdateSettings: (s: AppSettings) => void;
}

export const SettingsView: React.FC<SettingsViewProps> = ({
  companies,
  onAddCompany,
  onDeleteCompany,
  onBulkDeleteCompanies,
  exams,
  onAddExam,
  onUpdateExam,
  onDeleteExam,
  institutions,
  onAddInstitution,
  onDeleteInstitution,
  settings,
  onUpdateSettings
}) => {
  const [activeTab, setActiveTab] = useState<'general' | 'companies' | 'exams' | 'institutions'>('general');

  // General Settings State
  const [ekgAgeLimit, setEkgAgeLimit] = useState(settings.ekgLimitAge);
  const [logo, setLogo] = useState<string | undefined>(settings.companyLogo);

  // Company Form State
  const [cName, setCName] = useState('');
  const [cHazard, setCHazard] = useState<HazardClass>(HazardClass.LESS);
  const [cDoctor, setCDoctor] = useState('');
  const [cSpecialist, setCSpecialist] = useState('');
  const [cPaymentMethod, setCPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');
  const [cSelectedExams, setCSelectedExams] = useState<string[]>([]);
  const [cPreferredInst, setCPreferredInst] = useState<string>(''); // For forced institution

  // Company Selection State (Bulk Delete)
  const [selectedCompanyIds, setSelectedCompanyIds] = useState<string[]>([]);

  // File Import Ref
  const fileInputRef = useRef<HTMLInputElement>(null);
  const logoInputRef = useRef<HTMLInputElement>(null);

  // Exam Form State
  const [eName, setEName] = useState('');
  const [eCode, setECode] = useState('');
  const [ePrice, setEPrice] = useState('');
  const [eCost, setECost] = useState(''); // New Cost State

  // Institution Form State
  const [iName, setIName] = useState('');
  const [iPhone, setIPhone] = useState('');

  const toggleCompanyExam = (examName: string) => {
    setCSelectedExams(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const handleUpdateGeneralSettings = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdateSettings({ 
        ...settings, 
        ekgLimitAge: ekgAgeLimit,
        companyLogo: logo 
    });
    alert("Ayarlar güncellendi.");
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2000000) { // 2MB limit
          alert("Logo dosyası 2MB'dan küçük olmalıdır.");
          return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setLogo(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemoveLogo = () => {
      setLogo(undefined);
      if(logoInputRef.current) logoInputRef.current.value = '';
  };

  const handleAddCompany = (e: React.FormEvent) => {
    e.preventDefault();
    if (!cName) return;
    const newCompany: Company = {
      id: Math.random().toString(36).substr(2, 9),
      name: cName,
      hazardClass: cHazard,
      assignedDoctor: cDoctor || 'Belirlenmedi',
      assignedSpecialist: cSpecialist || 'Belirlenmedi',
      defaultExams: cSelectedExams,
      defaultPaymentMethod: cPaymentMethod,
      forcedInstitutionId: cPreferredInst || undefined
    };
    onAddCompany(newCompany);
    setCName('');
    setCDoctor('');
    setCSpecialist('');
    setCPaymentMethod('INVOICE');
    setCSelectedExams([]);
    setCPreferredInst('');
  };

  const handleAddInstitution = (e: React.FormEvent) => {
    e.preventDefault();
    if(!iName) return;
    const newInst: MedicalInstitution = {
      id: Math.random().toString(36).substr(2, 9),
      name: iName,
      phone: iPhone
    };
    onAddInstitution(newInst);
    setIName('');
    setIPhone('');
  };

  // Bulk Delete Logic
  const handleToggleSelectCompany = (id: string) => {
    setSelectedCompanyIds(prev => 
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  const handleSelectAllCompanies = () => {
    if (selectedCompanyIds.length === companies.length) {
      setSelectedCompanyIds([]);
    } else {
      setSelectedCompanyIds(companies.map(c => c.id));
    }
  };

  const handleBulkDelete = () => {
    if (selectedCompanyIds.length === 0) return;
    if (window.confirm(`Seçili ${selectedCompanyIds.length} firmayı silmek istediğinize emin misiniz?`)) {
      onBulkDeleteCompanies(selectedCompanyIds);
      setSelectedCompanyIds([]);
    }
  };

  // --- Bulk Import / Template Logic (Excel .xlsx) ---

  const downloadTemplate = () => {
    // Sheet 1: Firmalar (Template to fill)
    const headers = ["Firma Adı", "Tehlike Sınıfı (Az/Tehlikeli/Çok)", "Hekim Adı", "Uzman Adı", "Ödeme (Nakit/Fatura)", "Tetkik Kodları (Virgül ile)"];
    const exampleRow = ["Örnek Metal A.Ş.", "Tehlikeli", "Dr. Ahmet Yılmaz", "Uzm. Ayşe Demir", "Fatura", "101, 103, 105"];
    const wsFirmalar = XLSX.utils.aoa_to_sheet([headers, exampleRow]);

    wsFirmalar['!cols'] = [
      { wch: 30 }, // Firma Adı
      { wch: 25 }, // Tehlike
      { wch: 20 }, // Hekim
      { wch: 20 }, // Uzman
      { wch: 20 }, // Ödeme
      { wch: 30 }  // Tetkik Kodları
    ];

    // Sheet 2: Tetkik Referans (Read-only reference)
    const refHeaders = ["Tetkik Kodu", "Tetkik Adı", "Satış Fiyatı", "Maliyet"];
    const refRows = exams.map(e => [e.code, e.name, e.price, e.cost || 0]);
    const wsRef = XLSX.utils.aoa_to_sheet([refHeaders, ...refRows]);
    wsRef['!cols'] = [{ wch: 15 }, { wch: 30 }, { wch: 10 }, { wch: 10 }];

    // Create Workbook
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, wsFirmalar, "Firma_Listesi");
    XLSX.utils.book_append_sheet(wb, wsRef, "Tetkik_Referans_Listesi");

    // Write file
    XLSX.writeFile(wb, "firma_yukleme_sablonu.xlsx");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();

    reader.onload = (evt) => {
      const bstr = evt.target?.result;
      if (!bstr) return;

      try {
        const wb = XLSX.read(bstr, { type: 'binary' });

        // Use the first sheet
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        // Convert to JSON array
        const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];

        let successCount = 0;

        // Skip header row
        for (let i = 1; i < data.length; i++) {
          const row = data[i];
          if (!row || row.length === 0 || !row[0]) continue;

          const name = String(row[0]).trim();
          const hazardRaw = String(row[1] || '').toLowerCase();
          const doctor = String(row[2] || 'Belirlenmedi').trim();
          const specialist = String(row[3] || 'Belirlenmedi').trim();
          const paymentRaw = String(row[4] || '').toLowerCase();
          const examCodesStr = String(row[5] || '').trim();

          // Hazard Class
          let hazard = HazardClass.LESS;
          if (hazardRaw.includes('çok') || hazardRaw.includes('cok')) hazard = HazardClass.VERY_DANGEROUS;
          else if (hazardRaw.includes('az')) hazard = HazardClass.LESS;
          else if (hazardRaw.includes('tehlikeli')) hazard = HazardClass.DANGEROUS;

          // Payment
          let payment: 'CASH' | 'INVOICE' = 'INVOICE';
          if (paymentRaw.includes('nakit') || paymentRaw.includes('elden') || paymentRaw.includes('kasa')) {
            payment = 'CASH';
          }

          // Process Exam Codes (e.g., "101, 105") -> Match to Exam Names
          const requestedCodes = examCodesStr.split(',').map(s => s.trim()).filter(s => s !== '');
          const matchedExams = exams
            .filter(e => requestedCodes.includes(e.code) || requestedCodes.includes(e.code.toString()))
            .map(e => e.name);

          const newComp: Company = {
            id: Math.random().toString(36).substr(2, 9),
            name: name,
            hazardClass: hazard,
            assignedDoctor: doctor,
            assignedSpecialist: specialist,
            defaultPaymentMethod: payment,
            defaultExams: matchedExams 
          };

          onAddCompany(newComp);
          successCount++;
        }

        alert(`${successCount} adet firma ve ilişkili tetkikleri başarıyla yüklendi.`);
      } catch (error) {
        console.error("Excel okuma hatası:", error);
        alert("Dosya okunurken bir hata oluştu.");
      } finally {
        if(fileInputRef.current) fileInputRef.current.value = '';
      }
    };

    reader.readAsBinaryString(file);
  };

  // --- End Bulk Import Logic ---

  const handleAddExam = (e: React.FormEvent) => {
    e.preventDefault();
    if (!eName || !ePrice || !eCode) return;

    // Check for duplicate code
    if(exams.some(ex => ex.code === eCode)) {
        alert("Bu tetkik kodu zaten kullanılıyor!");
        return;
    }

    const newExam: ExamDefinition = {
      id: Math.random().toString(36).substr(2, 9),
      code: eCode,
      name: eName,
      price: parseFloat(ePrice),
      cost: parseFloat(eCost) || 0
    };
    onAddExam(newExam);
    setEName('');
    setECode('');
    setEPrice('');
    setECost('');
  };

  const handleUpdateExamField = (id: string, field: keyof ExamDefinition, value: string) => {
    const exam = exams.find(e => e.id === id);
    if (exam) {
      const updated = { ...exam };
      if (field === 'price') updated.price = parseFloat(value);
      if (field === 'cost') updated.cost = parseFloat(value);
      if (field === 'code') updated.code = value;
      // Name update could be added here if needed
      onUpdateExam(updated);
    }
  };

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden">
      <div className="flex border-b border-slate-700 overflow-x-auto">
        <button
          onClick={() => setActiveTab('general')}
          className={`px-6 py-4 text-center font-medium text-sm transition-colors whitespace-nowrap ${activeTab === 'general' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Genel Ayarlar
        </button>
        <button
          onClick={() => setActiveTab('companies')}
          className={`px-6 py-4 text-center font-medium text-sm transition-colors whitespace-nowrap ${activeTab === 'companies' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Firmalar
        </button>
        <button
          onClick={() => setActiveTab('institutions')}
          className={`px-6 py-4 text-center font-medium text-sm transition-colors whitespace-nowrap ${activeTab === 'institutions' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Anlaşmalı Kurumlar
        </button>
        <button
          onClick={() => setActiveTab('exams')}
          className={`px-6 py-4 text-center font-medium text-sm transition-colors whitespace-nowrap ${activeTab === 'exams' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Tetkikler
        </button>
      </div>

      <div className="p-6">
        {activeTab === 'general' && (
          <div className="space-y-6">
             <div className="bg-slate-900/30 p-6 rounded-lg border border-slate-700 max-w-2xl">
                <div className="flex items-center mb-4">
                   <div className="p-2 bg-indigo-500/10 rounded mr-3">
                      <Sliders className="w-5 h-5 text-indigo-500" />
                   </div>
                   <h3 className="text-lg font-bold text-white">Sistem Parametreleri</h3>
                </div>

                <form onSubmit={handleUpdateGeneralSettings} className="space-y-6">
                   {/* EKG Age Limit */}
                   <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 p-4 bg-slate-800 rounded border border-slate-600">
                      <div>
                         <label className="block text-sm font-medium text-white">EKG Zorunluluk Yaşı</label>
                         <p className="text-xs text-slate-400 mt-1">Bu yaş ve üzerindeki personel için EKG tetkiki otomatik olarak seçilir.</p>
                      </div>
                      <div className="flex items-center space-x-2">
                        <input 
                          type="number" 
                          min="18"
                          max="100"
                          value={ekgAgeLimit} 
