import React, { useMemo, useState } from 'react';
import { X, Printer, Calculator, Calendar, Building2, CalendarDays, CalendarRange, Stethoscope, Download, FileText } from 'lucide-react';
import { Referral, SafeTransaction, AppSettings } from '../types';

interface EndOfDayReportModalProps {
  onClose: () => void;
  referrals: Referral[];
  transactions: SafeTransaction[];
  settings?: AppSettings;
}

type ReportPeriod = 'daily' | 'weekly' | 'monthly';

export const EndOfDayReportModal: React.FC<EndOfDayReportModalProps> = ({ onClose, referrals, transactions, settings }) => {
  const [period, setPeriod] = useState<ReportPeriod>('daily');
  const now = new Date();

  // Calculate Date Range based on Period
  const dateRange = useMemo(() => {
    const end = new Date(); // Now
    const start = new Date(); 
    start.setHours(0, 0, 0, 0);

    if (period === 'weekly') {
      // Set to Monday of the current week
      const day = start.getDay() || 7; // Get current day (1=Mon, ..., 7=Sun)
      if (day !== 1) {
        start.setHours(-24 * (day - 1));
      }
    } else if (period === 'monthly') {
      // Set to 1st of the current month
      start.setDate(1);
    }
    // 'daily' is already set to start of today

    return { start, end };
  }, [period]);

  const reportData = useMemo(() => {
    // Filter referrals within range
    const filteredReferrals = referrals.filter(r => {
      const d = new Date(r.referralDate);
      return d >= dateRange.start && d <= dateRange.end;
    });

    // Filter transactions within range
    const filteredTransactions = transactions.filter(t => {
      const d = new Date(t.date);
      return d >= dateRange.start && d <= dateRange.end;
    });

    // Calculate Finances for the Period
    const totalIncome = filteredTransactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);

    const totalExpense = filteredTransactions
      .filter(t => t.type === 'EXPENSE')
      .reduce((acc, curr) => acc + curr.amount, 0);

    // Calculate Total Balance (Absolute Current System State - All Time)
    const currentTotalBalance = transactions.reduce((acc, curr) => {
      return curr.type === 'INCOME' ? acc + curr.amount : acc - curr.amount;
    }, 0);

    // Referral Costs (Maliyet)
    const totalReferralCost = filteredReferrals.reduce((acc, curr) => acc + (curr.totalCost || 0), 0);
    const totalReferralPrice = filteredReferrals.reduce((acc, curr) => acc + (curr.totalPrice || 0), 0);
    const estimatedProfit = totalReferralPrice - totalReferralCost;

    // Opening Balance for this Period = Current Balance - (Net Change during this period)
    const periodNetChange = totalIncome - totalExpense;
    const openingBalance = currentTotalBalance - periodNetChange;

    return {
      referrals: filteredReferrals,
      transactions: filteredTransactions,
      totalIncome,
      totalExpense,
      openingBalance,
      closingBalance: currentTotalBalance,
      totalReferralCost,
      totalReferralPrice,
      estimatedProfit
    };
  }, [referrals, transactions, dateRange]);

  const getTitle = () => {
    switch(period) {
      case 'weekly': return 'HAFTALIK FAALİYET RAPORU';
      case 'monthly': return 'AYLIK FAALİYET RAPORU';
      default: return 'GÜN SONU RAPORU (Z RAPORU)';
    }
  };

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="fixed inset-0 bg-slate-950/90 z-50 overflow-y-auto print:bg-white print:overflow-visible">
      {/* --- Screen Controls (Hidden on Print) --- */}
      <div className="sticky top-0 z-50 bg-slate-900/95 backdrop-blur border-b border-slate-800 px-4 py-3 flex justify-between items-center print:hidden shadow-lg">
        <div className="flex items-center space-x-4">
           <div className="flex bg-slate-800 rounded-lg p-1 border border-slate-700">
              <button 
                onClick={() => setPeriod('daily')}
                className={`px-3 py-1.5 rounded text-sm font-medium transition-all ${period === 'daily' ? 'bg-blue-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
              >
                Günlük
              </button>
              <button 
                onClick={() => setPeriod('weekly')}
                className={`px-3 py-1.5 rounded text-sm font-medium transition-all ${period === 'weekly' ? 'bg-blue-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
              >
                Haftalık
              </button>
              <button 
                onClick={() => setPeriod('monthly')}
                className={`px-3 py-1.5 rounded text-sm font-medium transition-all ${period === 'monthly' ? 'bg-blue-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
              >
                Aylık
              </button>
           </div>
           <span className="text-slate-500 text-sm hidden md:inline">|</span>
           <span className="text-slate-400 text-sm hidden md:inline">
              Önizleme Modu
           </span>
        </div>
        <div className="flex items-center space-x-3">
           <button 
             onClick={handlePrint}
             className="flex items-center space-x-2 bg-emerald-600 hover:bg-emerald-500 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-lg shadow-emerald-900/20 transition-all"
           >
             <Printer className="w-4 h-4" />
             <span>Yazdır / PDF</span>
           </button>
           <button 
             onClick={onClose}
             className="p-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-lg border border-slate-700 transition-colors"
           >
             <X className="w-5 h-5" />
           </button>
        </div>
      </div>

      {/* --- A4 Paper Container --- */}
      <div className="flex justify-center py-8 print:py-0 print:block">
        <div className="bg-white text-slate-900 w-[210mm] min-h-[297mm] shadow-2xl print:shadow-none print:w-full print:h-full print:m-0 box-border relative overflow-hidden">

           {/* Top Color Bar */}
           <div className="h-2 w-full bg-blue-900 print:bg-blue-900"></div>

           <div className="p-10 print:p-8 space-y-8">

              {/* Report Header */}
              <div className="flex justify-between items-start border-b-2 border-slate-100 pb-6">
                 <div className="flex items-center space-x-3">
                    {settings?.companyLogo ? (
                        <img src={settings.companyLogo} alt="Firma Logosu" className="h-16 w-auto object-contain" />
                    ) : (
                        <div className="p-3 bg-blue-50 rounded-lg border border-blue-100">
                          <Stethoscope className="w-8 h-8 text-blue-900" />
                        </div>
                    )}

                    {!settings?.companyLogo && (
                        <div>
                        <h1 className="text-xl font-bold text-slate-900 tracking-tight">OSGB PRO</h1>
                        <p className="text-xs text-slate-500 font-medium uppercase tracking-widest">Tetkik Takip Sistemi</p>
                        </div>
                    )}
                 </div>
                 <div className="text-right">
                    <h2 className="text-lg font-bold text-slate-900 uppercase tracking-tight">{getTitle()}</h2>
                    <p className="text-xs text-slate-500 mt-1">Rapor No: #{Math.floor(Math.random() * 100000)}</p>
                    <p className="text-xs text-slate-500">Oluşturulma: {now.toLocaleDateString('tr-TR')} {now.toLocaleTimeString('tr-TR')}</p>
                 </div>
              </div>

              {/* Info Grid */}
              <div className="bg-slate-50 rounded border border-slate-200 p-4 flex justify-between items-center text-sm">
                  <div>
                     <span className="text-slate-500 font-medium block text-xs uppercase mb-1">Rapor Periyodu</span>
                     <span className="font-bold text-slate-800">
                        {dateRange.start.toLocaleDateString('tr-TR')} - {dateRange.end.toLocaleDateString('tr-TR')}
                     </span>
                  </div>
                  <div className="text-right">
                     <span className="text-slate-500 font-medium block text-xs uppercase mb-1">Şube / Birim</span>
                     <span className="font-bold text-slate-800">Merkez Ofis / Kasa</span>
                  </div>
              </div>

              {/* Financial Summary */}
              <div>
                 <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 flex items-center">
                    <Calculator className="w-3.5 h-3.5 mr-1" />
                    Finansal Özet Tablosu
                 </h3>
                 <div className="grid grid-cols-4 gap-4">
                    <div className="p-4 rounded border border-slate-200 bg-white shadow-sm">
                       <p className="text-[10px] text-slate-500 font-bold uppercase mb-1">AÇILIŞ BAKİYESİ</p>
                       <p className="text-lg font-bold text-slate-700">₺{reportData.openingBalance.toLocaleString('tr-TR')}</p>
                    </div>
                    <div className="p-4 rounded border border-emerald-100 bg-emerald-50/30 shadow-sm">
                       <p className="text-[10px] text-emerald-600 font-bold uppercase mb-1">GİRİŞLER (+)</p>
                       <p className="text-lg font-bold text-emerald-700">₺{reportData.totalIncome.toLocaleString('tr-TR')}</p>
                    </div>
                    <div className="p-4 rounded border border-red-100 bg-red-50/30 shadow-sm">
                       <p className="text-[10px] text-red-600 font-bold uppercase mb-1">ÇIKIŞLAR (-)</p>
                       <p className="text-lg font-bold text-red-700">₺{reportData.totalExpense.toLocaleString('tr-TR')}</p>
                    </div>
                    <div className="p-4 rounded border border-blue-200 bg-blue-50 shadow-sm relative overflow-hidden">
                       <div className="absolute right-0 top-0 p-2 opacity-10"><Calculator className="w-12 h-12" /></div>
                       <p className="text-[10px] text-blue-600 font-bold uppercase mb-1">GÜNCEL KASA</p>
                       <p className="text-xl font-bold text-blue-800">₺{reportData.closingBalance.toLocaleString('tr-TR')}</p>
                    </div>
                 </div>
              </div>

              {/* Transactions Table */}
              {reportData.transactions.length > 0 && (
                <div>
                  <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 mt-6 flex items-center">
                      <FileText className="w-3.5 h-3.5 mr-1" />
                      Kasa Hareket Dökümü
                  </h3>
                  <table className="w-full text-left text-xs border border-slate-200">
                     <thead className="bg-slate-100 text-slate-600">
                        <tr>
                           <th className="px-3 py-2 font-bold border-b border-slate-200">Saat</th>
                           <th className="px-3 py-2 font-bold border-b border-slate-200">Açıklama</th>
                           <th className="px-3 py-2 font-bold border-b border-slate-200 text-right">Giriş</th>
                           <th className="px-3 py-2 font-bold border-b border-slate-200 text-right">Çıkış</th>
                        </tr>
                     </thead>
                     <tbody className="divide-y divide-slate-100">
                        {reportData.transactions.map(tx => (
                           <tr key={tx.id}>
                              <td className="px-3 py-1.5 text-slate-500 font-mono">
                                 {new Date(tx.date).toLocaleTimeString('tr-TR', {hour: '2-digit', minute:'2-digit'})}
                              </td>
                              <td className="px-3 py-1.5 text-slate-800 font-medium">
                                 {tx.description}
                              </td>
                              <td className="px-3 py-1.5 text-right font-mono text-emerald-600">
                                 {tx.type === 'INCOME' ? `₺${tx.amount.toLocaleString('tr-TR')}` : '-'}
                              </td>
                              <td className="px-3 py-1.5 text-right font-mono text-red-600">
                                 {tx.type === 'EXPENSE' ? `₺${tx.amount.toLocaleString('tr-TR')}` : '-'}
                              </td>
                           </tr>
                        ))}
                     </tbody>
                  </table>
                </div>
              )}

              {/* Personnel Referrals Table */}
              <div>
                 <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 mt-6 flex items-center">
                    <Building2 className="w-3.5 h-3.5 mr-1" />
                    Personel Sevk Listesi ve Maliyet Tablosu
                 </h3>
                 <table className="w-full text-left text-xs border border-slate-200">
                    <thead className="bg-slate-100 text-slate-600">
                       <tr>
                          <th className="px-3 py-2 font-bold border-b border-slate-200">Tarih</th>
                          <th className="px-3 py-2 font-bold border-b border-slate-200">Personel</th>
                          <th className="px-3 py-2 font-bold border-b border-slate-200">Firma</th>
                          <th className="px-3 py-2 font-bold border-b border-slate-200">Ödeme</th>
                          <th className="px-3 py-2 font-bold border-b border-slate-200 text-right">Satış (Ciro)</th>
                          <th className="px-3 py-2 font-bold border-b border-slate-200 text-right">Kurum Ödemesi (Maliyet)</th>
                       </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                       {reportData.referrals.map(ref => (
                          <tr key={ref.id} className="text-slate-700">
                             <td className="px-3 py-1.5 text-slate-500 font-mono">
                                {new Date(ref.referralDate).toLocaleDateString('tr-TR')}
                             </td>
                             <td className="px-3 py-1.5 font-bold">{ref.employee.fullName}</td>
                             <td className="px-3 py-1.5">{ref.employee.company}</td>
                             <td className="px-3 py-1.5">
                                <span className={`px-1.5 py-0.5 rounded text-[10px] font-bold uppercase ${ref.paymentMethod === 'CASH' ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'}`}>
                                   {ref.paymentMethod === 'CASH' ? 'Nakit' : 'Cari'}
                                </span>
                             </td>
                             <td className="px-3 py-1.5 text-right font-mono font-medium text-blue-700">
                                ₺{ref.totalPrice?.toLocaleString('tr-TR')}
                             </td>
                             <td className="px-3 py-1.5 text-right font-mono font-medium text-red-600">
                                ₺{ref.totalCost?.toLocaleString('tr-TR') || '0'}
                             </td>
                          </tr>
                       ))}
                       {reportData.referrals.length === 0 && (
                          <tr><td colSpan={6} className="text-center py-4 text-slate-400 italic">Kayıt bulunamadı.</td></tr>
                       )}
                       {reportData.referrals.length > 0 && (
                           <tr className="bg-slate-50 font-bold border-t-2 border-slate-300">
                               <td colSpan={4} className="px-3 py-2 text-right uppercase text-slate-600">Genel Toplam</td>
                               <td className="px-3 py-2 text-right text-blue-700">₺{reportData.totalReferralPrice.toLocaleString('tr-TR')}</td>
                               <td className="px-3 py-2 text-right text-red-600">₺{reportData.totalReferralCost.toLocaleString('tr-TR')}</td>
                           </tr>
                       )}
                    </tbody>
                 </table>

                 {/* Profit Summary */}
                 {reportData.referrals.length > 0 && (
                     <div className="mt-4 flex justify-end">
                         <div className="bg-slate-100 p-4 rounded-lg border border-slate-200 min-w-[250px]">
                             <div className="flex justify-between mb-2 text-xs">
                                 <span className="text-slate-500">Toplam Ciro:</span>
                                 <span className="font-bold">₺{reportData.totalReferralPrice.toLocaleString('tr-TR')}</span>
                             </div>
                             <div className="flex justify-between mb-2 text-xs">
                                 <span className="text-slate-500">Toplam Maliyet:</span>
                                 <span className="font-bold text-red-600">- ₺{reportData.totalReferralCost.toLocaleString('tr-TR')}</span>
                             </div>
                             <div className="border-t border-slate-300 pt-2 flex justify-between text-sm">
                                 <span className="font-bold text-slate-700">Tahmini Kâr:</span>
                                 <span className={`font-bold ${reportData.estimatedProfit >= 0 ? 'text-emerald-600' : 'text-red-600'}`}>
                                     ₺{reportData.estimatedProfit.toLocaleString('tr-TR')}
                                 </span>
                             </div>
                         </div>
                     </div>
                 )}
              </div>

              {/* Signatures Footer */}
              <div className="mt-12 pt-8 border-t border-slate-200 grid grid-cols-2 gap-20">
                  <div className="text-center">
                     <p className="text-xs font-bold text-slate-900 uppercase mb-8">Teslim Eden (Kasa)</p>
                     <div className="h-px w-32 bg-slate-400 mx-auto"></div>
                     <p className="text-[10px] text-slate-500 mt-1">İmza / Tarih</p>
                  </div>
                  <div className="text-center">
                     <p className="text-xs font-bold text-slate-900 uppercase mb-8">Teslim Alan (Yönetici)</p>
                     <div className="h-px w-32 bg-slate-400 mx-auto"></div>
                     <p className="text-[10px] text-slate-500 mt-1">İmza / Tarih</p>
                  </div>
              </div>

              {/* Print Footer */}
              <div className="absolute bottom-4 left-0 right-0 text-center">
                 <p className="text-[10px] text-slate-400">Bu belge OSGB Pro sistemi tarafından elektronik ortamda oluşturulmuştur.</p>
              </div>

           </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Settings, 
  Plus, 
  Search,
  Activity,
  LogOut,
  Stethoscope,
  Wallet,
  FileText,
  Menu,
  X
} from 'lucide-react';
import { ReferralList } from './components/ReferralList';
import { NewReferralView } from './components/NewReferralModal'; // Component updated to be a View
import { StatsCards } from './components/StatsCards';
import { FinanceView } from './components/FinanceView';
import { SettingsView } from './components/SettingsView';
import { EndOfDayReportModal } from './components/EndOfDayReportModal';
import { Referral, Status, Company, ExamDefinition, SafeTransaction, MedicalInstitution, AppSettings } from './types';
import { 
  loadReferrals, saveReferrals, 
  loadCompanies, saveCompanies,
  loadExams, saveExams,
  loadTransactions, saveTransactions,
  loadInstitutions, saveInstitutions,
  loadAppSettings, saveAppSettings
} from './services/storage';
import { PREDEFINED_COMPANIES, DEFAULT_EXAMS, DEFAULT_INSTITUTIONS } from './services/initialData';

const App: React.FC = () => {
  // Added 'create_referral' to navigation state
  const [activeTab, setActiveTab] = useState<'dashboard' | 'referrals' | 'finance' | 'settings' | 'create_referral'>('dashboard');

  // Mobile Menu State
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Data States
  const [referrals, setReferrals] = useState<Referral[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [exams, setExams] = useState<ExamDefinition[]>([]);
  const [institutions, setInstitutions] = useState<MedicalInstitution[]>([]);
  const [transactions, setTransactions] = useState<SafeTransaction[]>([]);
  const [appSettings, setAppSettings] = useState<AppSettings>({ ekgLimitAge: 40 });

  // isModalOpen removed as it is now a page
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Initial load
  useEffect(() => {
    setReferrals(loadReferrals());
    setCompanies(loadCompanies(PREDEFINED_COMPANIES));
    setExams(loadExams(DEFAULT_EXAMS));
    setInstitutions(loadInstitutions(DEFAULT_INSTITUTIONS));
    setTransactions(loadTransactions());
    setAppSettings(loadAppSettings());
  }, []);

  // Save Effects
  useEffect(() => saveReferrals(referrals), [referrals]);
  useEffect(() => saveCompanies(companies), [companies]);
  useEffect(() => saveExams(exams), [exams]);
  useEffect(() => saveInstitutions(institutions), [institutions]);
  useEffect(() => saveTransactions(transactions), [transactions]);
  useEffect(() => saveAppSettings(appSettings), [appSettings]);

  // Handlers
  const handleCreateReferral = (referral: Referral) => {
    // 1. Add Referral (Always)
    setReferrals(prev => [referral, ...prev]);

    // 2. Add to Safe ONLY if Payment Method is CASH
    if (referral.paymentMethod === 'CASH' && referral.totalPrice && referral.totalPrice > 0) {
      const newTransaction: SafeTransaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'INCOME',
        amount: referral.totalPrice,
        description: `Sevk Geliri (Nakit): ${referral.employee.fullName} (${referral.employee.company})`,
        date: new Date().toISOString()
      };
      setTransactions(prev => [...prev, newTransaction]);
    }

    // Redirect back to referrals list after creation
    setActiveTab('referrals');
  };

  const handleUpdateStatus = (id: string, newStatus: Status) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, status: newStatus } : r
    ));
  };

  const handleAnalyze = (id: string, analysis: string) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, aiAnalysis: analysis } : r
    ));
  };

  const handleDelete = (id: string) => {
    if(window.confirm('Bu kaydı silmek istediğinize emin misiniz?')) {
      setReferrals(prev => prev.filter(r => r.id !== id));
    }
  };

  // Settings Handlers
  const handleAddCompany = (c: Company) => setCompanies(prev => [...prev, c]);
  const handleDeleteCompany = (id: string) => setCompanies(prev => prev.filter(c => c.id !== id));
  // New Bulk Delete Handler
  const handleBulkDeleteCompanies = (ids: string[]) => {
      setCompanies(prev => prev.filter(c => !ids.includes(c.id)));
  };

  const handleAddExam = (e: ExamDefinition) => setExams(prev => [...prev, e]);
  const handleUpdateExam = (updated: ExamDefinition) => setExams(prev => prev.map(e => e.id === updated.id ? updated : e));
  const handleDeleteExam = (id: string) => setExams(prev => prev.filter(e => e.id !== id));

  const handleAddInstitution = (i: MedicalInstitution) => setInstitutions(prev => [...prev, i]);
  const handleDeleteInstitution = (id: string) => setInstitutions(prev => prev.filter(i => i.id !== id));

  const handleUpdateSettings = (newSettings: AppSettings) => setAppSettings(newSettings);

  // Finance Handlers
  const handleAddTransaction = (t: SafeTransaction) => setTransactions(prev => [...prev, t]);

  const filteredReferrals = useMemo(() => {
    return referrals.filter(r => 
      r.employee.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.company.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.tcNo.includes(searchTerm)
    );
  }, [referrals, searchTerm]);

  const stats = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    const totalIncome = transactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);

    return {
      total: referrals.length,
      today: referrals.filter(r => r.referralDate.startsWith(todayStr)).length,
      totalIncome: totalIncome
    };
  }, [referrals, transactions]);

  // Handle nav click (close mobile menu)
  const handleNavClick = (tab: typeof activeTab) => {
      setActiveTab(tab);
      setIsMobileMenuOpen(false);
  };

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden">

      {/* Mobile Sidebar Overlay */}
      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden backdrop-blur-sm"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 border-r border-slate-800 text-white flex flex-col shadow-xl transition-transform duration-300 md:relative md:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} print:hidden`}>
        <div className="p-6 flex items-center justify-between border-b border-slate-800">
          <div className="flex items-center space-x-3">
            {appSettings.companyLogo ? (
               <img src={appSettings.companyLogo} alt="Logo" className="w-10 h-10 object-contain rounded bg-white p-0.5" />
            ) : (
               <div className="p-2 bg-blue-600 rounded-lg shadow-lg shadow-blue-900/20">
                  <Stethoscope className="w-6 h-6 text-white" />
               </div>
            )}
            <div>
                <h1 className="text-xl font-bold tracking-tight">OSGB Pro</h1>
                <p className="text-xs text-slate-400">Tetkik Takip Sistemi</p>
            </div>
          </div>
          <button onClick={() => setIsMobileMenuOpen(false)} className="md:hidden text-slate-400 hover:text-white">
            <X className="w-6 h-6" />
          </button>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => handleNavClick('dashboard')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'dashboard' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            <span className="font-medium">Genel Bakış</span>
          </button>

          <button 
            onClick={() => handleNavClick('referrals')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'referrals' || activeTab === 'create_referral' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Users className="w-5 h-5" />
            <span className="font-medium">Personel Takibi</span>
          </button>

          <button 
            onClick={() => handleNavClick('finance')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'finance' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Wallet className="w-5 h-5" />
            <span className="font-medium">Kasa & Finans</span>
          </button>

          <button 
            onClick={() => handleNavClick('settings')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'settings' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Settings className="w-5 h-5" />
            <span className="font-medium">Ayarlar</span>
          </button>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative bg-slate-950">
        {/* Header */}
        <header className="h-16 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-4 md:px-8 shadow-sm z-10 print:hidden">
          <div className="flex items-center">
              <button 
                onClick={() => setIsMobileMenuOpen(true)}
                className="mr-4 md:hidden text-slate-400 hover:text-white p-1 rounded-lg hover:bg-slate-800 transition-colors"
              >
                  <Menu className="w-6 h-6" />
              </button>
              <h2 className="text-lg md:text-xl font-semibold text-white truncate">
                {activeTab === 'dashboard' ? 'Kontrol Paneli' : 
                 activeTab === 'referrals' ? 'Tetkik & Sevk Listesi' : 
                 activeTab === 'create_referral' ? 'Yeni Sevk Girişi' :
                 activeTab === 'finance' ? 'Kasa Yönetimi' : 'Ayarlar'}
              </h2>
          </div>

          <div className="flex items-center space-x-4">
            {activeTab !== 'create_referral' && (
              <>
                <div className="relative hidden md:block">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400 w-4 h-4" />
                  <input 
                    type="text"
                    placeholder="Personel veya Firma ara..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent w-64 transition-all placeholder-slate-500"
                  />
                </div>
                <button 
                  onClick={() => setActiveTab('create_referral')}
                  className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-500 text-white px-3 py-2 md:px-4 md:py-2 rounded-lg text-sm font-medium transition-colors shadow-lg shadow-blue-900/20 active:transform active:scale-95 whitespace-nowrap"
                >
                  <Plus className="w-4 h-4" />
                  <span className="hidden md:inline">Yeni Sevk Oluştur</span>
                  <span className="md:hidden">Yeni Sevk</span>
                </button>
              </>
            )}
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-auto p-4 md:p-8 custom-scrollbar print:p-0 print:overflow-visible">
          {activeTab === 'dashboard' && (
            <div className="space-y-6">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-4 gap-3 md:gap-0">
                <h3 className="text-lg font-bold text-white hidden md:block">Günlük Özet</h3>
                <button 
                  onClick={() => setIsReportModalOpen(true)}
                  className="w-full md:w-auto flex items-center justify-center space-x-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-lg"
                >
                  <FileText className="w-4 h-4" />
                  <span>Gün Sonu Raporu Al (Z Raporu)</span>
                </button>
              </div>

              <StatsCards stats={stats} />

              <div className="mt-8">
                <h3 className="text-lg font-bold text-white mb-4 flex items-center">
                  <Activity className="w-5 h-5 mr-2 text-blue-500" />
                  Son Hareketler
                </h3>
                <ReferralList 
                  referrals={filteredReferrals.slice(0, 5)} 
                  institutions={institutions}
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                  compact
                />
              </div>
            </div>
          )}

          {activeTab === 'referrals' && (
            <div className="h-full flex flex-col">
               <ReferralList 
                  referrals={filteredReferrals} 
                  institutions={institutions}
                  onUpdateStatus={handleUpdateStatus} 
                  onAnalyze={handleAnalyze}
                  onDelete={handleDelete}
                />
            </div>
          )}

          {activeTab === 'create_referral' && (
            <NewReferralView
              onClose={() => setActiveTab('referrals')}
              onSubmit={handleCreateReferral}
              companies={companies}
              exams={exams}
              institutions={institutions}
              settings={appSettings}
            />
          )}

          {activeTab === 'finance' && (
            <FinanceView 
              transactions={transactions}
              onAddTransaction={handleAddTransaction}
            />
          )}

          {activeTab === 'settings' && (
             <SettingsView 
                companies={companies}
                onAddCompany={handleAddCompany}
                onDeleteCompany={handleDeleteCompany}
                onBulkDeleteCompanies={handleBulkDeleteCompanies}
                exams={exams}
                onAddExam={handleAddExam}
                onUpdateExam={handleUpdateExam}
                onDeleteExam={handleDeleteExam}
                institutions={institutions}
                onAddInstitution={handleAddInstitution}
                onDeleteInstitution={handleDeleteInstitution}
                settings={appSettings}
                onUpdateSettings={handleUpdateSettings}
             />
          )}
        </div>
      </main>

      {/* End of Day Report Modal - Still a modal */}
      {isReportModalOpen && (
        <EndOfDayReportModal
          onClose={() => setIsReportModalOpen(false)}
          referrals={referrals}
          transactions={transactions}
          settings={appSettings}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { ArrowLeft, Building2, User, Activity, Stethoscope, ShieldCheck, Wallet, Receipt, Save, Search, Check, ChevronDown, X, Info, Plus, MapPin, Hash, Lock, Calendar, Trash2, AlertCircle } from 'lucide-react';
import { Referral, Status, Company, HazardClass, ExamDefinition, MedicalInstitution, AppSettings } from '../types';

interface NewReferralViewProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
  companies: Company[];
  exams: ExamDefinition[];
  institutions: MedicalInstitution[];
  settings: AppSettings;
}

export const NewReferralView: React.FC<NewReferralViewProps> = ({ onClose, onSubmit, companies, exams, institutions, settings }) => {
  // --- STATE MANAGEMENT ---

  // Personel State
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');
  const [birthDate, setBirthDate] = useState('');

  // Company Search State
  const [companySearchTerm, setCompanySearchTerm] = useState('');
  const [isCompanyDropdownOpen, setIsCompanyDropdownOpen] = useState(false);
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Institution & Exam State
  const [selectedInstitutionId, setSelectedInstitutionId] = useState<string>('');
  const [isInstitutionLocked, setIsInstitutionLocked] = useState(false);
  const [examSearchTerm, setExamSearchTerm] = useState('');
  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');

  // Financial State
  const [estimatedPrice, setEstimatedPrice] = useState(0);
  const [estimatedCost, setEstimatedCost] = useState(0);
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');

  // --- LOGIC & EFFECTS ---

  // Validation
  const isStep1Complete = selectedCompanyData !== null;
  const isFormValid = fullName.length >= 3 && tcNo.length === 11 && birthDate !== '' && selectedCompanyData !== null;

  // Age Calculation
  const patientAge = useMemo(() => {
     if(!birthDate) return 0;
     const today = new Date();
     const birth = new Date(birthDate);
     let age = today.getFullYear() - birth.getFullYear();
     const m = today.getMonth() - birth.getMonth();
     if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
        age--;
     }
     return age;
  }, [birthDate]);

  // Mandatory EKG
  const isEkgMandatory = patientAge >= settings.ekgLimitAge;

  useEffect(() => {
     if (isEkgMandatory) {
        const ekgExamName = 'EKG';
        if (!selectedExamIds.includes(ekgExamName)) {
            setSelectedExamIds(prev => [...prev, ekgExamName]);
        }
     }
  }, [isEkgMandatory, selectedExamIds]);

  // Search Filters
  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(companySearchTerm.toLowerCase())
  );

  const filteredExams = exams.filter(e => 
    e.name.toLowerCase().includes(examSearchTerm.toLowerCase())
  );

  // Dropdown Click Outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCompanyDropdownOpen(false);
        if (selectedCompanyData) setCompanySearchTerm(selectedCompanyData.name);
        else setCompanySearchTerm('');
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [selectedCompanyData]);

  // Price Calculation
  useEffect(() => {
    let totalPrice = 0;
    let totalCost = 0;
    selectedExamIds.forEach(id => {
      const exam = exams.find(e => e.name === id);
      if (exam) {
        totalPrice += exam.price;
        totalCost += (exam.cost || 0);
      }
    });
    setEstimatedPrice(totalPrice);
    setEstimatedCost(totalCost);
  }, [selectedExamIds, exams]);

  // Handlers
  const handleSelectCompany = (company: Company) => {
      setSelectedCompanyData(company);
      setCompanySearchTerm(company.name);
      setIsCompanyDropdownOpen(false);
      setSelectedExamIds(company.defaultExams);
      setPaymentMethod(company.defaultPaymentMethod || 'INVOICE');
      if (company.forcedInstitutionId) {
          setSelectedInstitutionId(company.forcedInstitutionId);
          setIsInstitutionLocked(true);
      } else {
          setSelectedInstitutionId('');
          setIsInstitutionLocked(false);
      }
  };

  const handleClearCompany = () => {
      setSelectedCompanyData(null);
      setCompanySearchTerm('');
      setSelectedExamIds([]);
      setSelectedInstitutionId('');
      setIsInstitutionLocked(false);
  };

  const toggleExam = (examName: string) => {
    if (isEkgMandatory && examName === 'EKG') return;
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isFormValid) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        birthDate,
        company: selectedCompanyData!.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData!.assignedDoctor,
      specialistName: selectedCompanyData!.assignedSpecialist,
      totalPrice: estimatedPrice,
      totalCost: estimatedCost,
      paymentMethod: paymentMethod,
      targetInstitutionId: selectedInstitutionId || undefined
    };
    onSubmit(newReferral);
  };

  const getHazardBadge = (hazard: HazardClass) => {
    const styles = {
        [HazardClass.VERY_DANGEROUS]: 'bg-red-500 text-white',
        [HazardClass.DANGEROUS]: 'bg-orange-500 text-white',
        [HazardClass.LESS]: 'bg-emerald-500 text-white'
    };
    return (
        <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider ${styles[hazard]}`}>
            {hazard}
        </span>
    );
  };

  return (
    <div className="h-full flex flex-col bg-slate-950 lg:overflow-hidden overflow-y-auto">
      {/* --- Top Bar --- */}
      <div className="flex items-center justify-between px-2 pt-2 pb-4 shrink-0">
         <div className="flex items-center space-x-3">
            <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 hover:text-white transition-colors">
               <ArrowLeft className="w-5 h-5" />
            </button>
            <div>
               <h1 className="text-xl font-bold text-white tracking-tight">Yeni Sevk Oluştur</h1>
            </div>
         </div>
      </div>

      <form onSubmit={handleSubmit} className="flex-1 grid grid-cols-1 lg:grid-cols-12 gap-6 pb-4 px-2 h-full lg:min-h-0">

          {/* === LEFT COLUMN: INPUTS & CATALOG === */}
          <div className="lg:col-span-8 flex flex-col gap-6 lg:overflow-y-auto custom-scrollbar pr-2">

             {/* 1. KART: Temel Bilgiler (Firma & Personel) */}
             <div className="bg-slate-900 rounded-xl border border-slate-800 p-5 shadow-sm">
                <h3 className="text-sm font-bold text-slate-300 uppercase tracking-wider mb-4 flex items-center">
                    <Building2 className="w-4 h-4 mr-2 text-blue-500" /> 
                    Firma ve Personel Bilgileri
                </h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                    {/* Firma Seçimi */}
                    <div className="md:col-span-2 relative" ref={dropdownRef}>
                        <label className="block text-xs text-slate-500 mb-1.5 ml-1">Firma Seçimi</label>
                        <div className="relative group">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 z-10" />
                            <input
                                autoFocus
                                type="text"
                                value={companySearchTerm}
                                onChange={(e) => {
                                    setCompanySearchTerm(e.target.value);
                                    setIsCompanyDropdownOpen(true);
                                    if(selectedCompanyData && e.target.value !== selectedCompanyData.name) setSelectedCompanyData(null);
                                }}
                                onClick={() => setIsCompanyDropdownOpen(true)}
                                placeholder="Firma adı ile arama yapın..."
                                className={`w-full pl-9 pr-8 py-2.5 bg-slate-950 border text-white text-sm rounded-lg focus:ring-1 focus:ring-blue-500 outline-none transition-all ${selectedCompanyData ? 'border-blue-500/50 bg-blue-900/10' : 'border-slate-700'}`}
                            />
                            {selectedCompanyData ? (
                                <button type="button" onClick={handleClearCompany} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-red-400 p-1"><X className="w-4 h-4" /></button>
                            ) : (
                                <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 pointer-events-none" />
                            )}
                        </div>

                        {/* Dropdown */}
                        {isCompanyDropdownOpen && (
                            <div className="absolute top-full left-0 right-0 mt-1 max-h-60 overflow-y-auto bg-slate-900 border border-slate-700 rounded-lg shadow-2xl z-50 custom-scrollbar divide-y divide-slate-800">
                                {filteredCompanies.length > 0 ? (
                                    filteredCompanies.map(c => (
                                        <div key={c.id} onClick={() => handleSelectCompany(c)} className="px-4 py-3 hover:bg-slate-800 cursor-pointer flex items-center justify-between group">
                                            <div>
                                                <div className="text-sm text-slate-200 font-medium">{c.name}</div>
                                                <div className="text-xs text-slate-500">{c.assignedDoctor}</div>
                                            </div>
                                            {getHazardBadge(c.hazardClass)}
                                        </div>
                                    ))
                                ) : <div className="px-4 py-3 text-sm text-slate-500">Sonuç yok.</div>}
                            </div>
                        )}
                    </div>

                    {/* Personel Inputs - Sadece Firma Seçilince Aktif */}
                    <div className={`contents transition-opacity duration-300 ${isStep1Complete ? 'opacity-100' : 'opacity-40 pointer-events-none grayscale'}`}>
                        <div>
                            <label className="block text-xs text-slate-500 mb-1.5 ml-1">Ad Soyad</label>
                            <div className="relative">
                                <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                                <input required type="text" value={fullName} onChange={e => setFullName(e.target.value)} className="w-full pl-9 py-2.5 bg-slate-950 border border-slate-700 rounded-lg text-white text-sm focus:border-indigo-500 outline-none" placeholder="Personel Adı" />
                            </div>
                        </div>
                        <div>
                            <label className="block text-xs text-slate-500 mb-1.5 ml-1">TC Kimlik No</label>
                            <div className="relative">
                                <Hash className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                                <input required maxLength={11} value={tcNo} onChange={e => setTcNo(e.target.value.replace(/\D/g,''))} className="w-full pl-9 py-2.5 bg-slate-950 border border-slate-700 rounded-lg text-white text-sm focus:border-indigo-500 outline-none" placeholder="11 Haneli TC" />
                            </div>
                        </div>
                        <div>
                            <label className="block text-xs text-slate-500 mb-1.5 ml-1">Doğum Tarihi</label>
                            <div className="relative">
                                <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                                <input required type="date" value={birthDate} onChange={e => setBirthDate(e.target.value)} className="w-full pl-9 py-2.5 bg-slate-950 border border-slate-700 rounded-lg text-white text-sm focus:border-indigo-500 outline-none" />
                            </div>
                        </div>
                        <div>
                             <label className="block text-xs text-slate-500 mb-1.5 ml-1">Sevk Edilecek Kurum</label>
                             <div className="relative">
                                <MapPin className={`absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 ${isInstitutionLocked ? 'text-purple-500' : 'text-slate-500'}`} />
                                <select 
                                    value={selectedInstitutionId} 
                                    onChange={e => !isInstitutionLocked && setSelectedInstitutionId(e.target.value)}
                                    disabled={isInstitutionLocked}
                                    className={`w-full pl-9 pr-8 py-2.5 bg-slate-950 border rounded-lg text-sm text-white outline-none appearance-none ${isInstitutionLocked ? 'border-purple-500/50 text-purple-200 cursor-not-allowed' : 'border-slate-700'}`}
                                >
                                    <option value="">Kurum Seçiniz (Serbest)</option>
                                    {institutions.map(inst => <option key={inst.id} value={inst.id}>{inst.name}</option>)}
                                </select>
                                {isInstitutionLocked && <Lock className="absolute right-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-purple-500" />}
                             </div>
                        </div>
                    </div>
                </div>
             </div>

             {/* 2. KART: Tetkik Kataloğu (Grid Selection) */}
             <div className={`bg-slate-900 rounded-xl border border-slate-800 p-5 shadow-sm flex-1 flex flex-col transition-opacity duration-300 ${isStep1Complete ? 'opacity-100' : 'opacity-40 pointer-events-none'}`}>
                 <div className="flex items-center justify-between mb-4">
                    <h3 className="text-sm font-bold text-slate-300 uppercase tracking-wider flex items-center">
                        <Activity className="w-4 h-4 mr-2 text-emerald-500" /> 
                        Tetkik Kataloğu
                    </h3>
                    <div className="relative w-48">
                        <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-500" />
                        <input 
                          type="text" 
                          placeholder="Tetkik ara..." 
                          value={examSearchTerm}
                          onChange={e => setExamSearchTerm(e.target.value)}
                          className="w-full pl-8 py-1.5 bg-slate-950 border border-slate-700 rounded text-xs text-white focus:border-emerald-500 outline-none"
                        />
                    </div>
                 </div>

                 {/* Exam Grid */}
                 <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3 overflow-y-auto custom-scrollbar pr-1 max-h-[300px]">
                    {filteredExams.map(exam => {
                        const isSelected = selectedExamIds.includes(exam.name);
                        const isEkgAndMandatory = isEkgMandatory && exam.name === 'EKG';

                        return (
                            <button
                                key={exam.id}
                                type="button"
                                onClick={() => toggleExam(exam.name)}
                                className={`relative p-3 rounded-lg border text-left transition-all duration-200 group flex flex-col justify-between min-h-[80px] ${
                                    isSelected 
                                    ? 'bg-blue-600/10 border-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.1)]' 
                                    : 'bg-slate-800/50 border-slate-700 hover:border-slate-500 hover:bg-slate-800'
                                }`}
                            >
                                <div className="flex justify-between items-start w-full">
                                    <span className={`text-xs font-bold leading-tight ${isSelected ? 'text-white' : 'text-slate-300'}`}>{exam.name}</span>
                                    {isSelected && <Check className="w-3.5 h-3.5 text-blue-400 shrink-0 ml-1" />}
                                </div>

                                <div className="mt-2 flex items-end justify-between w-full">
                                    <span className="text-[10px] text-slate-500 font-mono bg-slate-950/50 px-1.5 py-0.5 rounded">{exam.code}</span>
                                    <span className={`text-xs font-medium ${isSelected ? 'text-blue-300' : 'text-slate-400'}`}>₺{exam.price}</span>
                                </div>

                                {isEkgAndMandatory && (
                                    <div className="absolute -top-1.5 -right-1.5 bg-indigo-500 text-white text-[9px] px-1.5 py-0.5 rounded-full shadow-sm flex items-center border border-slate-900">
                                        <Lock className="w-2.5 h-2.5 mr-0.5" /> Zorunlu
                                    </div>
                                )}
                            </button>
                        );
                    })}
                 </div>
             </div>
          </div>

          {/* === RIGHT COLUMN: SUMMARY & FINANCE (Sticky) === */}
          <div className="lg:col-span-4 h-full lg:h-auto flex flex-col">
             <div className="bg-slate-900 rounded-xl border border-slate-800 shadow-xl flex flex-col h-full overflow-hidden sticky top-4">

                {/* Header */}
                <div className="bg-slate-800/50 p-4 border-b border-slate-800 flex items-center justify-between">
                    <div className="flex items-center space-x-2">
                        <Receipt className="w-4 h-4 text-indigo-400" />
                        <span className="font-bold text-sm text-white">Sevk Özeti (Sepet)</span>
                    </div>
                    <span className="bg-slate-800 text-slate-400 text-xs px-2 py-0.5 rounded-full border border-slate-700">{selectedExamIds.length} Kalem</span>
                </div>

                {/* Selected Items List (Scrollable) */}
                <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-1">
                    {selectedCompanyData ? (
                        <div className="mb-2 p-3 bg-slate-800/50 rounded-lg border border-slate-700/50 mx-2 mt-2">
                            <div className="flex justify-between items-start">
                                <div>
                                    <div className="text-xs text-slate-400 mb-0.5">Firma</div>
                                    <div className="text-sm font-bold text-white leading-tight">{selectedCompanyData.name}</div>
                                </div>
                                {getHazardBadge(selectedCompanyData.hazardClass)}
                            </div>
                            {fullName && (
                                <div className="mt-2 pt-2 border-t border-slate-700/50">
                                    <div className="text-xs text-slate-400 mb-0.5">Personel</div>
                                    <div className="text-sm text-slate-200">{fullName} <span className="text-slate-500 font-mono text-[10px]">({tcNo})</span></div>
                                </div>
                            )}
                        </div>
                    ) : (
                        <div className="p-4 text-center text-slate-500 text-xs italic">
                            Lütfen sol taraftan firma seçimi yapınız.
                        </div>
                    )}

                    {selectedExamIds.length > 0 && (
                        <div className="px-2">
                            <div className="text-[10px] text-slate-500 uppercase font-bold tracking-wider mb-2 mt-2 pl-1">Seçilen Tetkikler</div>
                            {selectedExamIds.map(id => {
                                const exam = exams.find(e => e.name === id);
                                const isEkgAndMandatory = isEkgMandatory && id === 'EKG';

                                return (
                                    <div key={id} className="group flex items-center justify-between p-2.5 bg-slate-800/30 hover:bg-slate-800 rounded-lg border border-transparent hover:border-slate-700 transition-all mb-1">
                                        <div className="flex items-center">
                                            {isEkgAndMandatory ? <Lock className="w-3.5 h-3.5 text-indigo-500 mr-2" /> : <div className="w-1.5 h-1.5 rounded-full bg-blue-500 mr-2.5"></div>}
                                            <span className="text-sm text-slate-300">{id}</span>
                                        </div>
                                        <div className="flex items-center space-x-3">
                                            <span className="text-sm font-medium text-white font-mono">₺{exam?.price}</span>
                                            {!isEkgAndMandatory && (
                                                <button onClick={() => toggleExam(id)} className="text-slate-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all">
                                                    <X className="w-4 h-4" />
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>

                {/* Footer / Calculation Area */}
                <div className="bg-slate-950 p-4 border-t border-slate-800 space-y-4">

                    {/* Payment Toggle */}
                    <div className="bg-slate-900 p-1 rounded-lg flex border border-slate-800">
                        <button
                            type="button"
                            onClick={() => setPaymentMethod('INVOICE')}
                            className={`flex-1 py-1.5 text-xs font-bold rounded transition-all ${paymentMethod === 'INVOICE' ? 'bg-blue-600 text-white shadow' : 'text-slate-500 hover:text-slate-300'}`}
                        >
                            FATURA (Cari)
                        </button>
                        <button
                            type="button"
                            onClick={() => setPaymentMethod('CASH')}
                            className={`flex-1 py-1.5 text-xs font-bold rounded transition-all ${paymentMethod === 'CASH' ? 'bg-emerald-600 text-white shadow' : 'text-slate-500 hover:text-slate-300'}`}
                        >
                            NAKİT
                        </button>
                    </div>

                    {/* Total Price */}
                    <div className="flex items-center justify-between pt-2">
                        <div className="flex flex-col">
                            <span className="text-xs text-slate-500">Toplam Tutar</span>
                            <span className={`text-2xl font-bold tracking-tight ${paymentMethod === 'CASH' ? 'text-emerald-400' : 'text-blue-400'}`}>
                                ₺{estimatedPrice.toLocaleString('tr-TR')}
                            </span>
                        </div>
                        {estimatedCost > 0 && (
                            <div className="text-right">
                                <span className="text-[10px] text-slate-600 block">Tahmini Maliyet</span>
                                <span className="text-xs font-mono text-red-400/70">₺{estimatedCost}</span>
                            </div>
                        )}
                    </div>

                    {/* Notes */}
                    <textarea 
                        value={notes}
                        onChange={e => setNotes(e.target.value)}
                        placeholder="Sevk notu ekle..."
                        rows={2}
                        className="w-full bg-slate-900 border border-slate-700 rounded-lg p-2 text-xs text-white focus:border-slate-500 outline-none resize-none"
                    />

                    {/* Action Buttons */}
                    <div className="grid grid-cols-3 gap-2">
                        <button type="button" onClick={onClose} className="col-span-1 py-3 rounded-xl bg-slate-800 text-slate-300 text-xs font-bold hover:bg-slate-700 transition-colors">
                            İptal
                        </button>
                        <button 
                            type="submit" 
                            disabled={!isFormValid}
                            className={`col-span-2 py-3 rounded-xl text-white text-sm font-bold shadow-lg flex items-center justify-center space-x-2 transition-all active:scale-95 ${
                                !isFormValid ? 'bg-slate-800 text-slate-500 cursor-not-allowed' :
                                paymentMethod === 'CASH' ? 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-900/20' : 'bg-blue-600 hover:bg-blue-500 shadow-blue-900/20'
                            }`}
                        >
                            <Save className="w-4 h-4" />
                            <span>KAYDET VE OLUŞTUR</span>
                        </button>
                    </div>
                </div>
             </div>
          </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { ArrowLeft, Building2, User, Activity, Stethoscope, ShieldCheck, Wallet, Receipt, Save, Search, Check, ChevronDown, X, Info, Plus, MapPin, Hash, Lock, Calendar, Trash2, AlertCircle } from 'lucide-react';
import { Referral, Status, Company, HazardClass, ExamDefinition, MedicalInstitution, AppSettings } from '../types';

interface NewReferralViewProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
  companies: Company[];
  exams: ExamDefinition[];
  institutions: MedicalInstitution[];
  settings: AppSettings;
}

export const NewReferralView: React.FC<NewReferralViewProps> = ({ onClose, onSubmit, companies, exams, institutions, settings }) => {
  // --- STATE MANAGEMENT ---

  // Personel State
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');
  const [birthDate, setBirthDate] = useState('');

  // Company Search State
  const [companySearchTerm, setCompanySearchTerm] = useState('');
  const [isCompanyDropdownOpen, setIsCompanyDropdownOpen] = useState(false);
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Institution & Exam State
  const [selectedInstitutionId, setSelectedInstitutionId] = useState<string>('');
  const [isInstitutionLocked, setIsInstitutionLocked] = useState(false);
  const [examSearchTerm, setExamSearchTerm] = useState('');
  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');

  // Financial State
  const [estimatedPrice, setEstimatedPrice] = useState(0);
  const [estimatedCost, setEstimatedCost] = useState(0);
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');

  // --- LOGIC & EFFECTS ---

  // Validation
  const isStep1Complete = selectedCompanyData !== null;
  const isFormValid = fullName.length >= 3 && tcNo.length === 11 && birthDate !== '' && selectedCompanyData !== null;

  // Age Calculation
  const patientAge = useMemo(() => {
     if(!birthDate) return 0;
     const today = new Date();
     const birth = new Date(birthDate);
     let age = today.getFullYear() - birth.getFullYear();
     const m = today.getMonth() - birth.getMonth();
     if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
        age--;
     }
     return age;
  }, [birthDate]);

  // Mandatory EKG
  const isEkgMandatory = patientAge >= settings.ekgLimitAge;

  useEffect(() => {
     if (isEkgMandatory) {
        const ekgExamName = 'EKG';
        if (!selectedExamIds.includes(ekgExamName)) {
            setSelectedExamIds(prev => [...prev, ekgExamName]);
        }
     }
  }, [isEkgMandatory, selectedExamIds]);

  // Search Filters
  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(companySearchTerm.toLowerCase())
  );

  const filteredExams = exams.filter(e => 
    e.name.toLowerCase().includes(examSearchTerm.toLowerCase())
  );

  // Dropdown Click Outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCompanyDropdownOpen(false);
        if (selectedCompanyData) setCompanySearchTerm(selectedCompanyData.name);
        else setCompanySearchTerm('');
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [selectedCompanyData]);

  // Price Calculation
  useEffect(() => {
    let totalPrice = 0;
    let totalCost = 0;
    selectedExamIds.forEach(id => {
      const exam = exams.find(e => e.name === id);
      if (exam) {
        totalPrice += exam.price;
        totalCost += (exam.cost || 0);
      }
    });
    setEstimatedPrice(totalPrice);
    setEstimatedCost(totalCost);
  }, [selectedExamIds, exams]);

  // Handlers
  const handleSelectCompany = (company: Company) => {
      setSelectedCompanyData(company);
      setCompanySearchTerm(company.name);
      setIsCompanyDropdownOpen(false);
      setSelectedExamIds(company.defaultExams);
      setPaymentMethod(company.defaultPaymentMethod || 'INVOICE');
      if (company.forcedInstitutionId) {
          setSelectedInstitutionId(company.forcedInstitutionId);
          setIsInstitutionLocked(true);
      } else {
          setSelectedInstitutionId('');
          setIsInstitutionLocked(false);
      }
  };

  const handleClearCompany = () => {
      setSelectedCompanyData(null);
      setCompanySearchTerm('');
      setSelectedExamIds([]);
      setSelectedInstitutionId('');
      setIsInstitutionLocked(false);
  };

  const toggleExam = (examName: string) => {
    if (isEkgMandatory && examName === 'EKG') return;
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isFormValid) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        birthDate,
        company: selectedCompanyData!.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData!.assignedDoctor,
      specialistName: selectedCompanyData!.assignedSpecialist,
      totalPrice: estimatedPrice,
      totalCost: estimatedCost,
      paymentMethod: paymentMethod,
      targetInstitutionId: selectedInstitutionId || undefined
    };
    onSubmit(newReferral);
  };

  const getHazardBadge = (hazard: HazardClass) => {
    const styles = {
        [HazardClass.VERY_DANGEROUS]: 'bg-red-500 text-white',
        [HazardClass.DANGEROUS]: 'bg-orange-500 text-white',
        [HazardClass.LESS]: 'bg-emerald-500 text-white'
    };
    return (
        <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider ${styles[hazard]}`}>
            {hazard}
        </span>
    );
  };

  return (
    <div className="h-full flex flex-col bg-slate-950 relative">
      {/* --- Top Bar --- */}
      <div className="flex items-center space-x-3 px-4 py-4 border-b border-slate-900 bg-slate-950 sticky top-0 z-10">
        <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 hover:text-white transition-colors">
            <ArrowLeft className="w-5 h-5" />
        </button>
        <div>
            <h1 className="text-lg font-bold text-white tracking-tight">Yeni Sevk Kaydı</h1>
            <p className="text-xs text-slate-400">Tüm alanları adım adım doldurunuz.</p>
        </div>
      </div>

      {/* --- Main Scrollable Content --- */}
      <div className="flex-1 overflow-y-auto custom-scrollbar p-4 pb-32">
         <div className="max-w-5xl mx-auto space-y-6">

            {/* 1. ADIM: FİRMA VE KİŞİ BİLGİSİ */}
            <div className="bg-slate-900 rounded-xl border border-slate-800 p-5 shadow-sm">
                <div className="flex items-center space-x-2 mb-4 border-b border-slate-800 pb-2">
                    <div className="bg-blue-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold">1</div>
                    <h3 className="text-sm font-bold text-slate-200">Firma ve Personel Bilgisi</h3>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {/* Firma Arama */}
                    <div className="md:col-span-2 relative" ref={dropdownRef}>
                        <label className="block text-xs font-medium text-slate-500 mb-1.5 ml-1">Firma Seçimi</label>
                        <div className="relative group">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 z-10" />
                            <input
                                autoFocus
                                type="text"
                                value={companySearchTerm}
                                onChange={(e) => {
                                    setCompanySearchTerm(e.target.value);
                                    setIsCompanyDropdownOpen(true);
                                    if(selectedCompanyData && e.target.value !== selectedCompanyData.name) setSelectedCompanyData(null);
                                }}
                                onClick={() => setIsCompanyDropdownOpen(true)}
                                placeholder="Firma adı yazın..."
                                className={`w-full pl-9 pr-8 py-3 bg-slate-950 border text-white text-sm rounded-lg focus:ring-1 focus:ring-blue-500 outline-none transition-all ${selectedCompanyData ? 'border-blue-500/50 bg-blue-900/10' : 'border-slate-700'}`}
                            />
                            {selectedCompanyData ? (
                                <button type="button" onClick={handleClearCompany} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-red-400 p-1"><X className="w-4 h-4" /></button>
                            ) : (
                                <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 pointer-events-none" />
                            )}
                        </div>

                        {/* Dropdown */}
                        {isCompanyDropdownOpen && (
                            <div className="absolute top-full left-0 right-0 mt-1 max-h-60 overflow-y-auto bg-slate-900 border border-slate-700 rounded-lg shadow-2xl z-50 custom-scrollbar divide-y divide-slate-800">
                                {filteredCompanies.length > 0 ? (
                                    filteredCompanies.map(c => (
                                        <div key={c.id} onClick={() => handleSelectCompany(c)} className="px-4 py-3 hover:bg-slate-800 cursor-pointer flex items-center justify-between group">
                                            <div>
                                                <div className="text-sm text-slate-200 font-medium">{c.name}</div>
                                                <div className="text-xs text-slate-500">{c.assignedDoctor}</div>
                                            </div>
                                            {getHazardBadge(c.hazardClass)}
                                        </div>
                                    ))
                                ) : <div className="px-4 py-3 text-sm text-slate-500">Sonuç yok.</div>}
                            </div>
                        )}
                    </div>

                    {/* Personel Bilgileri */}
                    <div className={`md:col-span-2 grid grid-cols-1 md:grid-cols-3 gap-4 transition-all duration-500 ${isStep1Complete ? 'opacity-100 translate-y-0' : 'opacity-40 translate-y-2 pointer-events-none grayscale'}`}>
                        <div>
                            <label className="block text-xs font-medium text-slate-500 mb-1.5 ml-1">Ad Soyad</label>
                            <input required type="text" value={fullName} onChange={e => setFullName(e.target.value)} className="w-full px-3 py-2.5 bg-slate-950 border border-slate-700 rounded-lg text-white text-sm focus:border-blue-500 outline-none" placeholder="Örn: Ahmet Yılmaz" />
                        </div>
                        <div>
                            <label className="block text-xs font-medium text-slate-500 mb-1.5 ml-1">TC Kimlik No</label>
                            <input required maxLength={11} value={tcNo} onChange={e => setTcNo(e.target.value.replace(/\D/g,''))} className="w-full px-3 py-2.5 bg-slate-950 border border-slate-700 rounded-lg text-white text-sm focus:border-blue-500 outline-none" placeholder="11 Haneli" />
                        </div>
                        <div>
                            <label className="block text-xs font-medium text-slate-500 mb-1.5 ml-1">Doğum Tarihi</label>
                            <input required type="date" value={birthDate} onChange={e => setBirthDate(e.target.value)} className="w-full px-3 py-2.5 bg-slate-950 border border-slate-700 rounded-lg text-white text-sm focus:border-blue-500 outline-none" />
                        </div>
                    </div>
                </div>
            </div>

            {/* 2. ADIM: ATANMIŞ UZMANLAR & KURUM */}
            {isStep1Complete && selectedCompanyData && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-fadeIn">
                    {/* Uzman/Doktor Kartı */}
                    <div className="md:col-span-2 bg-slate-900 rounded-xl border border-slate-800 p-5 shadow-sm">
                         <div className="flex items-center space-x-2 mb-4 border-b border-slate-800 pb-2">
                            <div className="bg-indigo-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold">2</div>
                            <h3 className="text-sm font-bold text-slate-200">Atanmış Görevliler</h3>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="bg-slate-950 p-3 rounded-lg border border-slate-800 flex items-start space-x-3">
                                <div className="p-2 bg-blue-500/10 rounded-lg">
                                    <Stethoscope className="w-5 h-5 text-blue-400" />
                                </div>
                                <div>
                                    <span className="block text-[10px] text-slate-500 font-bold uppercase">İşyeri Hekimi</span>
                                    <span className="text-sm text-slate-200 font-medium">{selectedCompanyData.assignedDoctor}</span>
                                </div>
                            </div>
                            <div className="bg-slate-950 p-3 rounded-lg border border-slate-800 flex items-start space-x-3">
                                <div className="p-2 bg-emerald-500/10 rounded-lg">
                                    <ShieldCheck className="w-5 h-5 text-emerald-400" />
                                </div>
                                <div>
                                    <span className="block text-[10px] text-slate-500 font-bold uppercase">İSG Uzmanı</span>
                                    <span className="text-sm text-slate-200 font-medium">{selectedCompanyData.assignedSpecialist}</span>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Kurum Seçimi */}
                    <div className="bg-slate-900 rounded-xl border border-slate-800 p-5 shadow-sm flex flex-col justify-between">
                        <div className="flex items-center space-x-2 mb-2">
                            <div className="bg-purple-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold">3</div>
                            <h3 className="text-sm font-bold text-slate-200">Gidilecek Kurum</h3>
                        </div>

                        <div className="relative mt-2">
                            <MapPin className={`absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 ${isInstitutionLocked ? 'text-purple-500' : 'text-slate-500'}`} />
                            <select 
                                value={selectedInstitutionId} 
                                onChange={e => !isInstitutionLocked && setSelectedInstitutionId(e.target.value)}
                                disabled={isInstitutionLocked}
                                className={`w-full pl-9 pr-8 py-3 bg-slate-950 border rounded-lg text-sm text-white outline-none appearance-none ${isInstitutionLocked ? 'border-purple-500/50 text-purple-200 cursor-not-allowed' : 'border-slate-700'}`}
                            >
                                <option value="">Kurum Seçiniz (Serbest)</option>
                                {institutions.map(inst => <option key={inst.id} value={inst.id}>{inst.name}</option>)}
                            </select>
                            {isInstitutionLocked && <Lock className="absolute right-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-purple-500" />}
                        </div>
                        {isInstitutionLocked && <div className="text-[10px] text-purple-400 mt-2">* Firma anlaşması gereği zorunludur.</div>}
                    </div>
                </div>
            )}

            {/* 3. ADIM: TETKİK SEÇİMİ */}
            <div className={`bg-slate-900 rounded-xl border border-slate-800 p-5 shadow-sm transition-all duration-500 ${isStep1Complete ? 'opacity-100 translate-y-0' : 'opacity-40 translate-y-4 pointer-events-none'}`}>
                 <div className="flex items-center justify-between mb-4 border-b border-slate-800 pb-2">
                    <div className="flex items-center space-x-2">
                        <div className="bg-emerald-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold">4</div>
                        <h3 className="text-sm font-bold text-slate-200">Tetkik Seçimi</h3>
                    </div>
                    <div className="relative w-64">
                        <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-500" />
                        <input 
                          type="text" 
                          placeholder="Tetkik ara..." 
                          value={examSearchTerm}
                          onChange={e => setExamSearchTerm(e.target.value)}
                          className="w-full pl-8 py-1.5 bg-slate-950 border border-slate-700 rounded text-xs text-white focus:border-emerald-500 outline-none"
                        />
                    </div>
                 </div>

                 <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
                    {filteredExams.map(exam => {
                        const isSelected = selectedExamIds.includes(exam.name);
                        const isEkgAndMandatory = isEkgMandatory && exam.name === 'EKG';

                        return (
                            <button
                                key={exam.id}
                                type="button"
                                onClick={() => toggleExam(exam.name)}
                                className={`relative p-3 rounded-lg border text-left transition-all duration-200 group flex flex-col justify-between min-h-[80px] ${
                                    isSelected 
                                    ? 'bg-blue-600/10 border-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.1)]' 
                                    : 'bg-slate-800/50 border-slate-700 hover:border-slate-500 hover:bg-slate-800'
                                }`}
                            >
                                <div className="flex justify-between items-start w-full">
                                    <span className={`text-xs font-bold leading-tight ${isSelected ? 'text-white' : 'text-slate-300'}`}>{exam.name}</span>
                                    {isSelected && <Check className="w-3.5 h-3.5 text-blue-400 shrink-0 ml-1" />}
                                </div>

                                <div className="mt-2 flex items-end justify-between w-full">
                                    <span className="text-[10px] text-slate-500 font-mono bg-slate-950/50 px-1.5 py-0.5 rounded">{exam.code}</span>
                                    <span className={`text-xs font-medium ${isSelected ? 'text-blue-300' : 'text-slate-400'}`}>₺{exam.price}</span>
                                </div>

                                {isEkgAndMandatory && (
                                    <div className="absolute -top-1.5 -right-1.5 bg-indigo-500 text-white text-[9px] px-1.5 py-0.5 rounded-full shadow-sm flex items-center border border-slate-900">
                                        <Lock className="w-2.5 h-2.5 mr-0.5" /> Zorunlu
                                    </div>
                                )}
                            </button>
                        );
                    })}
                 </div>

                 <div className="mt-4 pt-4 border-t border-slate-800">
                    <label className="text-xs font-medium text-slate-500 block mb-1">Notlar</label>
                    <textarea 
                        value={notes}
                        onChange={e => setNotes(e.target.value)}
                        placeholder="Sevk ile ilgili özel notlar..."
                        rows={1}
                        className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-xs text-white focus:border-slate-500 outline-none resize-none"
                    />
                 </div>
            </div>

         </div>
      </div>

      {/* --- BOTTOM BAR: FINANS VE ONAY (Sticky) --- */}
      <div className="absolute bottom-0 left-0 right-0 bg-slate-900 border-t border-slate-800 p-4 shadow-[0_-5px_20px_rgba(0,0,0,0.3)] z-20">
         <div className="max-w-5xl mx-auto flex flex-col md:flex-row items-center justify-between gap-4">

             {/* Sol: Ödeme Yöntemi */}
             <div className="flex items-center space-x-4 w-full md:w-auto">
                 <div className="bg-slate-950 p-1 rounded-lg flex border border-slate-800 w-full md:w-64">
                    <button
                        type="button"
                        onClick={() => setPaymentMethod('INVOICE')}
                        className={`flex-1 py-2 px-4 text-xs font-bold rounded transition-all flex items-center justify-center space-x-2 ${paymentMethod === 'INVOICE' ? 'bg-blue-600 text-white shadow' : 'text-slate-500 hover:text-slate-300'}`}
                    >
                        <Receipt className="w-4 h-4" />
                        <span>FATURA (Cari)</span>
                    </button>
                    <button
                        type="button"
                        onClick={() => setPaymentMethod('CASH')}
                        className={`flex-1 py-2 px-4 text-xs font-bold rounded transition-all flex items-center justify-center space-x-2 ${paymentMethod === 'CASH' ? 'bg-emerald-600 text-white shadow' : 'text-slate-500 hover:text-slate-300'}`}
                    >
                        <Wallet className="w-4 h-4" />
                        <span>NAKİT</span>
                    </button>
                </div>
             </div>

             {/* Orta: Tutar */}
             <div className="flex flex-col items-center md:items-end">
                <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">Toplam Tutar</span>
                <div className={`text-3xl font-bold tracking-tight ${paymentMethod === 'CASH' ? 'text-emerald-400' : 'text-blue-400'}`}>
                    ₺{estimatedPrice.toLocaleString('tr-TR')}
                </div>
                {estimatedCost > 0 && <span className="text-[10px] text-red-400/60">Maliyet: ₺{estimatedCost}</span>}
             </div>

             {/* Sağ: Buton */}
             <button 
                onClick={handleSubmit}
                disabled={!isFormValid}
                className={`w-full md:w-auto px-8 py-3 rounded-xl text-white font-bold shadow-lg flex items-center justify-center space-x-2 transition-all active:scale-95 ${
                    !isFormValid ? 'bg-slate-800 text-slate-500 cursor-not-allowed' :
                    paymentMethod === 'CASH' ? 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-900/20' : 'bg-blue-600 hover:bg-blue-500 shadow-blue-900/20'
                }`}
            >
                <Save className="w-5 h-5" />
                <span>KAYDET VE OLUŞTUR</span>
            </button>
         </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { ArrowLeft, Building2, User, Activity, Stethoscope, ShieldCheck, Wallet, Receipt, Save, Search, Check, ChevronDown, X, Info, Plus, MapPin, Hash, Lock, Calendar, Trash2, AlertCircle, ArrowDown } from 'lucide-react';
import { Referral, Status, Company, HazardClass, ExamDefinition, MedicalInstitution, AppSettings } from '../types';

interface NewReferralViewProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
  companies: Company[];
  exams: ExamDefinition[];
  institutions: MedicalInstitution[];
  settings: AppSettings;
}

export const NewReferralView: React.FC<NewReferralViewProps> = ({ onClose, onSubmit, companies, exams, institutions, settings }) => {
  // --- STATE MANAGEMENT ---

  // Personel State
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');
  const [birthDate, setBirthDate] = useState('');

  // Company Search State
  const [companySearchTerm, setCompanySearchTerm] = useState('');
  const [isCompanyDropdownOpen, setIsCompanyDropdownOpen] = useState(false);
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Institution & Exam State
  const [selectedInstitutionId, setSelectedInstitutionId] = useState<string>('');
  const [isInstitutionLocked, setIsInstitutionLocked] = useState(false);
  const [examSearchTerm, setExamSearchTerm] = useState('');
  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');

  // Financial State
  const [estimatedPrice, setEstimatedPrice] = useState(0);
  const [estimatedCost, setEstimatedCost] = useState(0);
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');

  // --- LOGIC & EFFECTS ---

  // Validation
  const isStep1Complete = selectedCompanyData !== null;
  const isFormValid = fullName.length >= 3 && tcNo.length === 11 && birthDate !== '' && selectedCompanyData !== null;

  // Age Calculation
  const patientAge = useMemo(() => {
     if(!birthDate) return 0;
     const today = new Date();
     const birth = new Date(birthDate);
     let age = today.getFullYear() - birth.getFullYear();
     const m = today.getMonth() - birth.getMonth();
     if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
        age--;
     }
     return age;
  }, [birthDate]);

  // Mandatory EKG
  const isEkgMandatory = patientAge >= settings.ekgLimitAge;

  useEffect(() => {
     if (isEkgMandatory) {
        const ekgExamName = 'EKG';
        if (!selectedExamIds.includes(ekgExamName)) {
            setSelectedExamIds(prev => [...prev, ekgExamName]);
        }
     }
  }, [isEkgMandatory, selectedExamIds]);

  // Search Filters
  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(companySearchTerm.toLowerCase())
  );

  const filteredExams = exams.filter(e => 
    e.name.toLowerCase().includes(examSearchTerm.toLowerCase())
  );

  // Dropdown Click Outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCompanyDropdownOpen(false);
        if (selectedCompanyData) setCompanySearchTerm(selectedCompanyData.name);
        else setCompanySearchTerm('');
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [selectedCompanyData]);

  // Price Calculation
  useEffect(() => {
    let totalPrice = 0;
    let totalCost = 0;
    selectedExamIds.forEach(id => {
      const exam = exams.find(e => e.name === id);
      if (exam) {
        totalPrice += exam.price;
        totalCost += (exam.cost || 0);
      }
    });
    setEstimatedPrice(totalPrice);
    setEstimatedCost(totalCost);
  }, [selectedExamIds, exams]);

  // Handlers
  const handleSelectCompany = (company: Company) => {
      setSelectedCompanyData(company);
      setCompanySearchTerm(company.name);
      setIsCompanyDropdownOpen(false);

      // Load Defaults
      setSelectedExamIds(company.defaultExams);

      // Set Payment Method based on Company Settings
      setPaymentMethod(company.defaultPaymentMethod || 'INVOICE');

      // Handle Institution Logic
      if (company.forcedInstitutionId) {
          setSelectedInstitutionId(company.forcedInstitutionId);
          setIsInstitutionLocked(true);
      } else {
          setSelectedInstitutionId('');
          setIsInstitutionLocked(false);
      }
  };

  const handleClearCompany = () => {
      setSelectedCompanyData(null);
      setCompanySearchTerm('');
      setSelectedExamIds([]);
      setSelectedInstitutionId('');
      setIsInstitutionLocked(false);
  };

  const toggleExam = (examName: string) => {
    if (isEkgMandatory && examName === 'EKG') return;
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isFormValid) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        birthDate,
        company: selectedCompanyData!.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData!.assignedDoctor,
      specialistName: selectedCompanyData!.assignedSpecialist,
      totalPrice: estimatedPrice,
      totalCost: estimatedCost,
      paymentMethod: paymentMethod,
      targetInstitutionId: selectedInstitutionId || undefined
    };
    onSubmit(newReferral);
  };

  const getHazardBadge = (hazard: HazardClass) => {
    const styles = {
        [HazardClass.VERY_DANGEROUS]: 'bg-red-500 text-white',
        [HazardClass.DANGEROUS]: 'bg-orange-500 text-white',
        [HazardClass.LESS]: 'bg-emerald-500 text-white'
    };
    return (
        <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider ${styles[hazard]}`}>
            {hazard}
        </span>
    );
  };

  return (
    <div className="h-full flex flex-col bg-slate-950 relative">
      {/* --- Top Bar --- */}
      <div className="flex items-center space-x-3 px-4 py-4 border-b border-slate-900 bg-slate-950 sticky top-0 z-10">
        <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 hover:text-white transition-colors">
            <ArrowLeft className="w-5 h-5" />
        </button>
        <div>
            <h1 className="text-lg font-bold text-white tracking-tight">Yeni Sevk Kaydı</h1>
            <p className="text-xs text-slate-400">İşlem adımlarını sırasıyla tamamlayınız.</p>
        </div>
      </div>

      {/* --- Main Scrollable Content --- */}
      <div className="flex-1 overflow-y-auto custom-scrollbar p-4 pb-32 space-y-8">
         <div className="max-w-4xl mx-auto space-y-8">

            {/* 1. ADIM: FİRMA VE KİŞİ BİLGİSİ */}
            <div className="bg-slate-900/50 rounded-xl border border-slate-800 p-6 shadow-sm relative">
                <div className="absolute -left-3 top-6 w-6 h-6 bg-blue-600 rounded-full flex items-center justify-center text-xs font-bold text-white ring-4 ring-slate-950">1</div>
                <h3 className="text-sm font-bold text-slate-200 mb-6 pl-2">Firma ve Personel Bilgisi</h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pl-2">
                    {/* Firma Arama */}
                    <div className="md:col-span-2 relative" ref={dropdownRef}>
                        <label className="block text-xs font-medium text-slate-400 mb-1.5 ml-1">Firma Seçimi</label>
                        <div className="relative group">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 z-10" />
                            <input
                                autoFocus
                                type="text"
                                value={companySearchTerm}
                                onChange={(e) => {
                                    setCompanySearchTerm(e.target.value);
                                    setIsCompanyDropdownOpen(true);
                                    if(selectedCompanyData && e.target.value !== selectedCompanyData.name) setSelectedCompanyData(null);
                                }}
                                onClick={() => setIsCompanyDropdownOpen(true)}
                                placeholder="Firma adı ile arama yapın..."
                                className={`w-full pl-9 pr-8 py-3 bg-slate-950 border text-white text-sm rounded-lg focus:ring-1 focus:ring-blue-500 outline-none transition-all ${selectedCompanyData ? 'border-blue-500/50 bg-blue-900/10' : 'border-slate-700'}`}
                            />
                            {selectedCompanyData ? (
                                <button type="button" onClick={handleClearCompany} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-red-400 p-1"><X className="w-4 h-4" /></button>
                            ) : (
                                <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 pointer-events-none" />
                            )}
                        </div>

                        {/* Dropdown */}
                        {isCompanyDropdownOpen && (
                            <div className="absolute top-full left-0 right-0 mt-1 max-h-60 overflow-y-auto bg-slate-900 border border-slate-700 rounded-lg shadow-2xl z-50 custom-scrollbar divide-y divide-slate-800">
                                {filteredCompanies.length > 0 ? (
                                    filteredCompanies.map(c => (
                                        <div key={c.id} onClick={() => handleSelectCompany(c)} className="px-4 py-3 hover:bg-slate-800 cursor-pointer flex items-center justify-between group">
                                            <div>
                                                <div className="text-sm text-slate-200 font-medium">{c.name}</div>
                                                <div className="text-xs text-slate-500">{c.assignedDoctor}</div>
                                            </div>
                                            {getHazardBadge(c.hazardClass)}
                                        </div>
                                    ))
                                ) : <div className="px-4 py-3 text-sm text-slate-500">Sonuç yok.</div>}
                            </div>
                        )}
                    </div>

                    {/* Personel Bilgileri - Firma Seçilince Açılır */}
                    <div className={`md:col-span-2 grid grid-cols-1 md:grid-cols-3 gap-4 transition-all duration-500 ${isStep1Complete ? 'opacity-100 translate-y-0' : 'opacity-40 translate-y-2 pointer-events-none grayscale'}`}>
                        <div>
                            <label className="block text-xs font-medium text-slate-400 mb-1.5 ml-1">Ad Soyad</label>
                            <input required type="text" value={fullName} onChange={e => setFullName(e.target.value)} className="w-full px-3 py-2.5 bg-slate-950 border border-slate-700 rounded-lg text-white text-sm focus:border-blue-500 outline-none" placeholder="Örn: Ahmet Yılmaz" />
                        </div>
                        <div>
                            <label className="block text-xs font-medium text-slate-400 mb-1.5 ml-1">TC Kimlik No</label>
                            <input required maxLength={11} value={tcNo} onChange={e => setTcNo(e.target.value.replace(/\D/g,''))} className="w-full px-3 py-2.5 bg-slate-950 border border-slate-700 rounded-lg text-white text-sm focus:border-blue-500 outline-none" placeholder="11 Haneli" />
                        </div>
                        <div>
                            <label className="block text-xs font-medium text-slate-400 mb-1.5 ml-1">Doğum Tarihi</label>
                            <input required type="date" value={birthDate} onChange={e => setBirthDate(e.target.value)} className="w-full px-3 py-2.5 bg-slate-950 border border-slate-700 rounded-lg text-white text-sm focus:border-blue-500 outline-none" />
                        </div>
                    </div>
                </div>
            </div>

            {/* Aradaki Ok İşareti */}
            {isStep1Complete && (
                <div className="flex justify-center -my-2 animate-bounce">
                    <ArrowDown className="w-5 h-5 text-slate-700" />
                </div>
            )}

            {/* 2. ADIM: ATANMIŞ UZMANLAR & KURUM */}
            {isStep1Complete && selectedCompanyData && (
                <div className="bg-slate-900/50 rounded-xl border border-slate-800 p-6 shadow-sm relative animate-fadeIn">
                     <div className="absolute -left-3 top-6 w-6 h-6 bg-indigo-600 rounded-full flex items-center justify-center text-xs font-bold text-white ring-4 ring-slate-950">2</div>
                     <h3 className="text-sm font-bold text-slate-200 mb-6 pl-2">Görevli ve Kurum Bilgisi</h3>

                     <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pl-2">
                        {/* Sol Taraf: Uzmanlar */}
                        <div className="space-y-3">
                            <label className="block text-xs font-medium text-slate-400 ml-1">Atanmış Görevliler</label>
                            <div className="bg-slate-950 p-3 rounded-lg border border-slate-800 flex items-start space-x-3">
                                <div className="p-2 bg-blue-500/10 rounded-lg">
                                    <Stethoscope className="w-5 h-5 text-blue-400" />
                                </div>
                                <div>
                                    <span className="block text-[10px] text-slate-500 font-bold uppercase">İşyeri Hekimi</span>
                                    <span className="text-sm text-slate-200 font-medium">{selectedCompanyData.assignedDoctor}</span>
                                </div>
                            </div>
                            <div className="bg-slate-950 p-3 rounded-lg border border-slate-800 flex items-start space-x-3">
                                <div className="p-2 bg-emerald-500/10 rounded-lg">
                                    <ShieldCheck className="w-5 h-5 text-emerald-400" />
                                </div>
                                <div>
                                    <span className="block text-[10px] text-slate-500 font-bold uppercase">İSG Uzmanı</span>
                                    <span className="text-sm text-slate-200 font-medium">{selectedCompanyData.assignedSpecialist}</span>
                                </div>
                            </div>
                        </div>

                        {/* Sağ Taraf: Kurum */}
                        <div>
                             <label className="block text-xs font-medium text-slate-400 mb-3 ml-1">Sevk Edilecek Kurum</label>
                             <div className="relative">
                                <MapPin className={`absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 ${isInstitutionLocked ? 'text-purple-500' : 'text-slate-500'}`} />
                                <select 
                                    value={selectedInstitutionId} 
                                    onChange={e => !isInstitutionLocked && setSelectedInstitutionId(e.target.value)}
                                    disabled={isInstitutionLocked}
                                    className={`w-full pl-9 pr-8 py-3 bg-slate-950 border rounded-lg text-sm text-white outline-none appearance-none ${isInstitutionLocked ? 'border-purple-500/50 text-purple-200 cursor-not-allowed' : 'border-slate-700'}`}
                                >
                                    <option value="">Kurum Seçiniz (Serbest)</option>
                                    {institutions.map(inst => <option key={inst.id} value={inst.id}>{inst.name}</option>)}
                                </select>
                                {isInstitutionLocked && <Lock className="absolute right-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-purple-500" />}
                             </div>
                             {isInstitutionLocked ? (
                                 <div className="mt-2 text-xs text-purple-400 flex items-center">
                                     <Lock className="w-3 h-3 mr-1" />
                                     Firma anlaşması gereği bu kurum zorunludur.
                                 </div>
                             ) : (
                                 <div className="mt-2 text-xs text-slate-500">
                                     Personel tetkik için bu kuruma yönlendirilecektir.
                                 </div>
                             )}
                        </div>
                    </div>
                </div>
            )}

            {/* Aradaki Ok İşareti */}
            {isStep1Complete && (
                <div className="flex justify-center -my-2 animate-bounce animation-delay-200">
                    <ArrowDown className="w-5 h-5 text-slate-700" />
                </div>
            )}

            {/* 3. ADIM: TETKİK SEÇİMİ */}
            <div className={`bg-slate-900/50 rounded-xl border border-slate-800 p-6 shadow-sm relative transition-all duration-500 ${isStep1Complete ? 'opacity-100 translate-y-0' : 'opacity-40 translate-y-4 pointer-events-none'}`}>
                 <div className="absolute -left-3 top-6 w-6 h-6 bg-emerald-600 rounded-full flex items-center justify-center text-xs font-bold text-white ring-4 ring-slate-950">3</div>

                 <div className="flex items-center justify-between mb-6 pl-2 border-b border-slate-800 pb-4">
                    <h3 className="text-sm font-bold text-slate-200">İstenen Tetkikler</h3>
                    <div className="relative w-64">
                        <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-500" />
                        <input 
                          type="text" 
                          placeholder="Listede tetkik ara..." 
                          value={examSearchTerm}
                          onChange={e => setExamSearchTerm(e.target.value)}
                          className="w-full pl-8 py-1.5 bg-slate-950 border border-slate-700 rounded text-xs text-white focus:border-emerald-500 outline-none"
                        />
                    </div>
                 </div>

                 <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3 pl-2">
                    {filteredExams.map(exam => {
                        const isSelected = selectedExamIds.includes(exam.name);
                        const isEkgAndMandatory = isEkgMandatory && exam.name === 'EKG';

                        return (
                            <button
                                key={exam.id}
                                type="button"
                                onClick={() => toggleExam(exam.name)}
                                className={`relative p-3 rounded-lg border text-left transition-all duration-200 group flex flex-col justify-between min-h-[80px] ${
                                    isSelected 
                                    ? 'bg-blue-600/10 border-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.1)]' 
                                    : 'bg-slate-800/50 border-slate-700 hover:border-slate-500 hover:bg-slate-800'
                                }`}
                            >
                                <div className="flex justify-between items-start w-full">
                                    <span className={`text-xs font-bold leading-tight ${isSelected ? 'text-white' : 'text-slate-300'}`}>{exam.name}</span>
                                    {isSelected && <Check className="w-3.5 h-3.5 text-blue-400 shrink-0 ml-1" />}
                                </div>

                                <div className="mt-2 flex items-end justify-between w-full">
                                    <span className="text-[10px] text-slate-500 font-mono bg-slate-950/50 px-1.5 py-0.5 rounded">{exam.code}</span>
                                    <span className={`text-xs font-medium ${isSelected ? 'text-blue-300' : 'text-slate-400'}`}>₺{exam.price}</span>
                                </div>

                                {isEkgAndMandatory && (
                                    <div className="absolute -top-1.5 -right-1.5 bg-indigo-500 text-white text-[9px] px-1.5 py-0.5 rounded-full shadow-sm flex items-center border border-slate-900">
                                        <Lock className="w-2.5 h-2.5 mr-0.5" /> Zorunlu
                                    </div>
                                )}
                            </button>
                        );
                    })}
                 </div>

                 <div className="mt-6 pl-2 pt-4 border-t border-slate-800/50">
                    <label className="text-xs font-medium text-slate-500 block mb-1">Sevk Notu / Açıklama</label>
                    <textarea 
                        value={notes}
                        onChange={e => setNotes(e.target.value)}
                        placeholder="Sevk belgesinde görünecek özel bir not ekleyin..."
                        rows={1}
                        className="w-full bg-slate-950 border border-slate-700 rounded-lg p-3 text-sm text-white focus:border-slate-500 outline-none resize-none"
                    />
                 </div>
            </div>

         </div>
      </div>

      {/* --- BOTTOM BAR: FINANS VE ONAY (Sticky) --- */}
      <div className="absolute bottom-0 left-0 right-0 bg-slate-900 border-t border-slate-800 p-4 shadow-[0_-5px_20px_rgba(0,0,0,0.3)] z-20">
         <div className="max-w-4xl mx-auto flex flex-col md:flex-row items-center justify-between gap-4">

             {/* Sol: Ödeme Yöntemi */}
             <div className="flex items-center space-x-4 w-full md:w-auto">
                 <div className="flex flex-col">
                    <span className="text-[10px] text-slate-500 mb-1 ml-1 uppercase tracking-wide font-bold">Ödeme Yöntemi</span>
                    <div className="bg-slate-950 p-1 rounded-lg flex border border-slate-800 w-full md:w-64 relative">
                        {selectedCompanyData && (
                            <div className={`absolute -top-8 left-0 right-0 text-center`}>
                                <span className={`text-[10px] px-2 py-0.5 rounded-full border ${selectedCompanyData.defaultPaymentMethod === 'CASH' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' : 'bg-blue-500/10 text-blue-400 border-blue-500/20'}`}>
                                    {selectedCompanyData.defaultPaymentMethod === 'CASH' ? 'Nakit' : 'Fatura'} (Firma Tercihi)
                                </span>
                            </div>
                        )}
                        <button
                            type="button"
                            onClick={() => setPaymentMethod('INVOICE')}
                            className={`flex-1 py-2 px-4 text-xs font-bold rounded transition-all flex items-center justify-center space-x-2 ${paymentMethod === 'INVOICE' ? 'bg-blue-600 text-white shadow' : 'text-slate-500 hover:text-slate-300'}`}
                        >
                            <Receipt className="w-4 h-4" />
                            <span>FATURA (Cari)</span>
                        </button>
                        <button
                            type="button"
                            onClick={() => setPaymentMethod('CASH')}
                            className={`flex-1 py-2 px-4 text-xs font-bold rounded transition-all flex items-center justify-center space-x-2 ${paymentMethod === 'CASH' ? 'bg-emerald-600 text-white shadow' : 'text-slate-500 hover:text-slate-300'}`}
                        >
                            <Wallet className="w-4 h-4" />
                            <span>NAKİT</span>
                        </button>
                    </div>
                 </div>
             </div>

             {/* Orta: Tutar */}
             <div className="flex flex-col items-center md:items-end">
                <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">Toplam Tutar</span>
                <div className={`text-3xl font-bold tracking-tight ${paymentMethod === 'CASH' ? 'text-emerald-400' : 'text-blue-400'}`}>
                    ₺{estimatedPrice.toLocaleString('tr-TR')}
                </div>
                {estimatedCost > 0 && <span className="text-[10px] text-red-400/60">Maliyet: ₺{estimatedCost}</span>}
             </div>

             {/* Sağ: Buton */}
             <button 
                onClick={handleSubmit}
                disabled={!isFormValid}
                className={`w-full md:w-auto px-8 py-3 rounded-xl text-white font-bold shadow-lg flex items-center justify-center space-x-2 transition-all active:scale-95 ${
                    !isFormValid ? 'bg-slate-800 text-slate-500 cursor-not-allowed' :
                    paymentMethod === 'CASH' ? 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-900/20' : 'bg-blue-600 hover:bg-blue-500 shadow-blue-900/20'
                }`}
            >
                <Save className="w-5 h-5" />
                <span>KAYDET VE OLUŞTUR</span>
            </button>
         </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { ArrowLeft, Building2, User, Activity, Stethoscope, ShieldCheck, Wallet, Receipt, Save, Search, Check, ChevronDown, X, Info, Plus, MapPin, Hash, Lock, Calendar, Trash2, AlertCircle, ArrowDown } from 'lucide-react';
import { Referral, Status, Company, HazardClass, ExamDefinition, MedicalInstitution, AppSettings } from '../types';

interface NewReferralViewProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
  companies: Company[];
  exams: ExamDefinition[];
  institutions: MedicalInstitution[];
  settings: AppSettings;
}

export const NewReferralView: React.FC<NewReferralViewProps> = ({ onClose, onSubmit, companies, exams, institutions, settings }) => {
  // --- STATE MANAGEMENT ---

  // Personel State
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');
  const [birthDate, setBirthDate] = useState('');

  // Company Search State
  const [companySearchTerm, setCompanySearchTerm] = useState('');
  const [isCompanyDropdownOpen, setIsCompanyDropdownOpen] = useState(false);
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Institution & Exam State
  const [selectedInstitutionId, setSelectedInstitutionId] = useState<string>('');
  const [isInstitutionLocked, setIsInstitutionLocked] = useState(false);
  const [examSearchTerm, setExamSearchTerm] = useState('');
  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');

  // Financial State
  const [estimatedPrice, setEstimatedPrice] = useState(0);
  const [estimatedCost, setEstimatedCost] = useState(0);
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');

  // --- LOGIC & EFFECTS ---

  // Validation
  const isStep1Complete = selectedCompanyData !== null;
  const isFormValid = fullName.length >= 3 && tcNo.length === 11 && birthDate !== '' && selectedCompanyData !== null;

  // Age Calculation
  const patientAge = useMemo(() => {
     if(!birthDate) return 0;
     const today = new Date();
     const birth = new Date(birthDate);
     let age = today.getFullYear() - birth.getFullYear();
     const m = today.getMonth() - birth.getMonth();
     if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
        age--;
     }
     return age;
  }, [birthDate]);

  // Mandatory EKG
  const isEkgMandatory = patientAge >= settings.ekgLimitAge;

  useEffect(() => {
     if (isEkgMandatory) {
        const ekgExamName = 'EKG';
        if (!selectedExamIds.includes(ekgExamName)) {
            setSelectedExamIds(prev => [...prev, ekgExamName]);
        }
     }
  }, [isEkgMandatory, selectedExamIds]);

  // Search Filters
  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(companySearchTerm.toLowerCase())
  );

  const filteredExams = exams.filter(e => 
    e.name.toLowerCase().includes(examSearchTerm.toLowerCase())
  );

  // Dropdown Click Outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCompanyDropdownOpen(false);
        if (selectedCompanyData) setCompanySearchTerm(selectedCompanyData.name);
        else setCompanySearchTerm('');
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [selectedCompanyData]);

  // Price Calculation
  useEffect(() => {
    let totalPrice = 0;
    let totalCost = 0;
    selectedExamIds.forEach(id => {
      const exam = exams.find(e => e.name === id);
      if (exam) {
        totalPrice += exam.price;
        totalCost += (exam.cost || 0);
      }
    });
    setEstimatedPrice(totalPrice);
    setEstimatedCost(totalCost);
  }, [selectedExamIds, exams]);

  // Handlers
  const handleSelectCompany = (company: Company) => {
      setSelectedCompanyData(company);
      setCompanySearchTerm(company.name);
      setIsCompanyDropdownOpen(false);

      // Load Defaults
      setSelectedExamIds(company.defaultExams);

      // Set Payment Method based on Company Settings (LOCKED)
      setPaymentMethod(company.defaultPaymentMethod || 'INVOICE');

      // Handle Institution Logic
      if (company.forcedInstitutionId) {
          setSelectedInstitutionId(company.forcedInstitutionId);
          setIsInstitutionLocked(true);
      } else {
          setSelectedInstitutionId('');
          setIsInstitutionLocked(false);
      }
  };

  const handleClearCompany = () => {
      setSelectedCompanyData(null);
      setCompanySearchTerm('');
      setSelectedExamIds([]);
      setSelectedInstitutionId('');
      setIsInstitutionLocked(false);
  };

  const toggleExam = (examName: string) => {
    if (isEkgMandatory && examName === 'EKG') return;
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isFormValid) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        birthDate,
        company: selectedCompanyData!.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData!.assignedDoctor,
      specialistName: selectedCompanyData!.assignedSpecialist,
      totalPrice: estimatedPrice,
      totalCost: estimatedCost,
      paymentMethod: paymentMethod,
      targetInstitutionId: selectedInstitutionId || undefined
    };
    onSubmit(newReferral);
  };

  const getHazardBadge = (hazard: HazardClass) => {
    const styles = {
        [HazardClass.VERY_DANGEROUS]: 'bg-red-500 text-white',
        [HazardClass.DANGEROUS]: 'bg-orange-500 text-white',
        [HazardClass.LESS]: 'bg-emerald-500 text-white'
    };
    return (
        <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider ${styles[hazard]}`}>
            {hazard}
        </span>
    );
  };

  return (
    <div className="h-full flex flex-col bg-slate-950 relative">
      {/* --- Top Bar --- */}
      <div className="flex items-center space-x-3 px-4 py-4 border-b border-slate-900 bg-slate-950 sticky top-0 z-10">
        <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 hover:text-white transition-colors">
            <ArrowLeft className="w-5 h-5" />
        </button>
        <div>
            <h1 className="text-lg font-bold text-white tracking-tight">Yeni Sevk Kaydı</h1>
            <p className="text-xs text-slate-400">İşlem adımlarını sırasıyla tamamlayınız.</p>
        </div>
      </div>

      {/* --- Main Scrollable Content --- */}
      <div className="flex-1 overflow-y-auto custom-scrollbar p-4 pb-32 space-y-8">
         <div className="max-w-4xl mx-auto space-y-8">

            {/* 1. ADIM: FİRMA VE KİŞİ BİLGİSİ */}
            <div className="bg-slate-900/50 rounded-xl border border-slate-800 p-6 shadow-sm relative">
                <div className="absolute -left-3 top-6 w-6 h-6 bg-blue-600 rounded-full flex items-center justify-center text-xs font-bold text-white ring-4 ring-slate-950">1</div>
                <h3 className="text-sm font-bold text-slate-200 mb-6 pl-2">Firma ve Personel Bilgisi</h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pl-2">
                    {/* Firma Arama */}
                    <div className="md:col-span-2 relative" ref={dropdownRef}>
                        <label className="block text-xs font-medium text-slate-400 mb-1.5 ml-1">Firma Seçimi</label>
                        <div className="relative group">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 z-10" />
                            <input
                                autoFocus
                                type="text"
                                value={companySearchTerm}
                                onChange={(e) => {
                                    setCompanySearchTerm(e.target.value);
                                    setIsCompanyDropdownOpen(true);
                                    if(selectedCompanyData && e.target.value !== selectedCompanyData.name) setSelectedCompanyData(null);
                                }}
                                onClick={() => setIsCompanyDropdownOpen(true)}
                                placeholder="Firma adı ile arama yapın..."
                                className={`w-full pl-9 pr-8 py-3 bg-slate-950 border text-white text-sm rounded-lg focus:ring-1 focus:ring-blue-500 outline-none transition-all ${selectedCompanyData ? 'border-blue-500/50 bg-blue-900/10' : 'border-slate-700'}`}
                            />
                            {selectedCompanyData ? (
                                <button type="button" onClick={handleClearCompany} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-red-400 p-1"><X className="w-4 h-4" /></button>
                            ) : (
                                <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 pointer-events-none" />
                            )}
                        </div>

                        {/* Dropdown */}
                        {isCompanyDropdownOpen && (
                            <div className="absolute top-full left-0 right-0 mt-1 max-h-60 overflow-y-auto bg-slate-900 border border-slate-700 rounded-lg shadow-2xl z-50 custom-scrollbar divide-y divide-slate-800">
                                {filteredCompanies.length > 0 ? (
                                    filteredCompanies.map(c => (
                                        <div key={c.id} onClick={() => handleSelectCompany(c)} className="px-4 py-3 hover:bg-slate-800 cursor-pointer flex items-center justify-between group">
                                            <div>
                                                <div className="text-sm text-slate-200 font-medium">{c.name}</div>
                                                <div className="text-xs text-slate-500">{c.assignedDoctor}</div>
                                            </div>
                                            {getHazardBadge(c.hazardClass)}
                                        </div>
                                    ))
                                ) : <div className="px-4 py-3 text-sm text-slate-500">Sonuç yok.</div>}
                            </div>
                        )}
                    </div>

                    {/* Personel Bilgileri - Firma Seçilince Açılır */}
                    <div className={`md:col-span-2 grid grid-cols-1 md:grid-cols-3 gap-4 transition-all duration-500 ${isStep1Complete ? 'opacity-100 translate-y-0' : 'opacity-40 translate-y-2 pointer-events-none grayscale'}`}>
                        <div>
                            <label className="block text-xs font-medium text-slate-400 mb-1.5 ml-1">Ad Soyad</label>
                            <input required type="text" value={fullName} onChange={e => setFullName(e.target.value)} className="w-full px-3 py-2.5 bg-slate-950 border border-slate-700 rounded-lg text-white text-sm focus:border-blue-500 outline-none" placeholder="Örn: Ahmet Yılmaz" />
                        </div>
                        <div>
                            <label className="block text-xs font-medium text-slate-400 mb-1.5 ml-1">TC Kimlik No</label>
                            <input required maxLength={11} value={tcNo} onChange={e => setTcNo(e.target.value.replace(/\D/g,''))} className="w-full px-3 py-2.5 bg-slate-950 border border-slate-700 rounded-lg text-white text-sm focus:border-blue-500 outline-none" placeholder="11 Haneli" />
                        </div>
                        <div>
                            <label className="block text-xs font-medium text-slate-400 mb-1.5 ml-1">Doğum Tarihi</label>
                            <input required type="date" value={birthDate} onChange={e => setBirthDate(e.target.value)} className="w-full px-3 py-2.5 bg-slate-950 border border-slate-700 rounded-lg text-white text-sm focus:border-blue-500 outline-none" />
                        </div>
                    </div>
                </div>
            </div>

            {/* Aradaki Ok İşareti */}
            {isStep1Complete && (
                <div className="flex justify-center -my-2 animate-bounce">
                    <ArrowDown className="w-5 h-5 text-slate-700" />
                </div>
            )}

            {/* 2. ADIM: ATANMIŞ UZMANLAR & KURUM */}
            {isStep1Complete && selectedCompanyData && (
                <div className="bg-slate-900/50 rounded-xl border border-slate-800 p-6 shadow-sm relative animate-fadeIn">
                     <div className="absolute -left-3 top-6 w-6 h-6 bg-indigo-600 rounded-full flex items-center justify-center text-xs font-bold text-white ring-4 ring-slate-950">2</div>
                     <h3 className="text-sm font-bold text-slate-200 mb-6 pl-2">Görevli ve Kurum Bilgisi</h3>

                     <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pl-2">
                        {/* Sol Taraf: Uzmanlar */}
                        <div className="space-y-3">
                            <label className="block text-xs font-medium text-slate-400 ml-1">Atanmış Görevliler</label>
                            <div className="bg-slate-950 p-3 rounded-lg border border-slate-800 flex items-start space-x-3">
                                <div className="p-2 bg-blue-500/10 rounded-lg">
                                    <Stethoscope className="w-5 h-5 text-blue-400" />
                                </div>
                                <div>
                                    <span className="block text-[10px] text-slate-500 font-bold uppercase">İşyeri Hekimi</span>
                                    <span className="text-sm text-slate-200 font-medium">{selectedCompanyData.assignedDoctor}</span>
                                </div>
                            </div>
                            <div className="bg-slate-950 p-3 rounded-lg border border-slate-800 flex items-start space-x-3">
                                <div className="p-2 bg-emerald-500/10 rounded-lg">
                                    <ShieldCheck className="w-5 h-5 text-emerald-400" />
                                </div>
                                <div>
                                    <span className="block text-[10px] text-slate-500 font-bold uppercase">İSG Uzmanı</span>
                                    <span className="text-sm text-slate-200 font-medium">{selectedCompanyData.assignedSpecialist}</span>
                                </div>
                            </div>
                        </div>

                        {/* Sağ Taraf: Kurum */}
                        <div>
                             <label className="block text-xs font-medium text-slate-400 mb-3 ml-1">Sevk Edilecek Kurum</label>
                             <div className="relative">
                                <MapPin className={`absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 ${isInstitutionLocked ? 'text-purple-500' : 'text-slate-500'}`} />
                                <select 
                                    value={selectedInstitutionId} 
                                    onChange={e => !isInstitutionLocked && setSelectedInstitutionId(e.target.value)}
                                    disabled={isInstitutionLocked}
                                    className={`w-full pl-9 pr-8 py-3 bg-slate-950 border rounded-lg text-sm text-white outline-none appearance-none ${isInstitutionLocked ? 'border-purple-500/50 text-purple-200 cursor-not-allowed' : 'border-slate-700'}`}
                                >
                                    <option value="">Kurum Seçiniz (Serbest)</option>
                                    {institutions.map(inst => <option key={inst.id} value={inst.id}>{inst.name}</option>)}
                                </select>
                                {isInstitutionLocked && <Lock className="absolute right-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-purple-500" />}
                             </div>
                             {isInstitutionLocked ? (
                                 <div className="mt-2 text-xs text-purple-400 flex items-center">
                                     <Lock className="w-3 h-3 mr-1" />
                                     Firma anlaşması gereği bu kurum zorunludur.
                                 </div>
                             ) : (
                                 <div className="mt-2 text-xs text-slate-500">
                                     Personel tetkik için bu kuruma yönlendirilecektir.
                                 </div>
                             )}
                        </div>
                    </div>
                </div>
            )}

            {/* Aradaki Ok İşareti */}
            {isStep1Complete && (
                <div className="flex justify-center -my-2 animate-bounce animation-delay-200">
                    <ArrowDown className="w-5 h-5 text-slate-700" />
                </div>
            )}

            {/* 3. ADIM: TETKİK SEÇİMİ */}
            <div className={`bg-slate-900/50 rounded-xl border border-slate-800 p-6 shadow-sm relative transition-all duration-500 ${isStep1Complete ? 'opacity-100 translate-y-0' : 'opacity-40 translate-y-4 pointer-events-none'}`}>
                 <div className="absolute -left-3 top-6 w-6 h-6 bg-emerald-600 rounded-full flex items-center justify-center text-xs font-bold text-white ring-4 ring-slate-950">3</div>

                 <div className="flex items-center justify-between mb-6 pl-2 border-b border-slate-800 pb-4">
                    <h3 className="text-sm font-bold text-slate-200">İstenen Tetkikler</h3>
                    <div className="relative w-64">
                        <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-500" />
                        <input 
                          type="text" 
                          placeholder="Listede tetkik ara..." 
                          value={examSearchTerm}
                          onChange={e => setExamSearchTerm(e.target.value)}
                          className="w-full pl-8 py-1.5 bg-slate-950 border border-slate-700 rounded text-xs text-white focus:border-emerald-500 outline-none"
                        />
                    </div>
                 </div>

                 <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3 pl-2">
                    {filteredExams.map(exam => {
                        const isSelected = selectedExamIds.includes(exam.name);
                        const isEkgAndMandatory = isEkgMandatory && exam.name === 'EKG';

                        return (
                            <button
                                key={exam.id}
                                type="button"
                                onClick={() => toggleExam(exam.name)}
                                className={`relative p-3 rounded-lg border text-left transition-all duration-200 group flex flex-col justify-between min-h-[80px] ${
                                    isSelected 
                                    ? 'bg-blue-600/10 border-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.1)]' 
                                    : 'bg-slate-800/50 border-slate-700 hover:border-slate-500 hover:bg-slate-800'
                                }`}
                            >
                                <div className="flex justify-between items-start w-full">
                                    <span className={`text-xs font-bold leading-tight ${isSelected ? 'text-white' : 'text-slate-300'}`}>{exam.name}</span>
                                    {isSelected && <Check className="w-3.5 h-3.5 text-blue-400 shrink-0 ml-1" />}
                                </div>

                                <div className="mt-2 flex items-end justify-between w-full">
                                    <span className="text-[10px] text-slate-500 font-mono bg-slate-950/50 px-1.5 py-0.5 rounded">{exam.code}</span>
                                    <span className={`text-xs font-medium ${isSelected ? 'text-blue-300' : 'text-slate-400'}`}>₺{exam.price}</span>
                                </div>

                                {isEkgAndMandatory && (
                                    <div className="absolute -top-1.5 -right-1.5 bg-indigo-500 text-white text-[9px] px-1.5 py-0.5 rounded-full shadow-sm flex items-center border border-slate-900">
                                        <Lock className="w-2.5 h-2.5 mr-0.5" /> Zorunlu
                                    </div>
                                )}
                            </button>
                        );
                    })}
                 </div>

                 <div className="mt-6 pl-2 pt-4 border-t border-slate-800/50">
                    <label className="text-xs font-medium text-slate-500 block mb-1">Sevk Notu / Açıklama</label>
                    <textarea 
                        value={notes}
                        onChange={e => setNotes(e.target.value)}
                        placeholder="Sevk belgesinde görünecek özel bir not ekleyin..."
                        rows={1}
                        className="w-full bg-slate-950 border border-slate-700 rounded-lg p-3 text-sm text-white focus:border-slate-500 outline-none resize-none"
                    />
                 </div>
            </div>

         </div>
      </div>

      {/* --- BOTTOM BAR: FINANS VE ONAY (Sticky) --- */}
      <div className="absolute bottom-0 left-0 right-0 bg-slate-900 border-t border-slate-800 p-4 shadow-[0_-5px_20px_rgba(0,0,0,0.3)] z-20">
         <div className="max-w-4xl mx-auto flex flex-col md:flex-row items-center justify-between gap-4">

             {/* Sol: Ödeme Yöntemi (SABİT / KİLİTLİ) */}
             <div className="flex items-center space-x-4 w-full md:w-auto">
                 <div className="flex flex-col">
                    <span className="text-[10px] text-slate-500 mb-1 ml-1 uppercase tracking-wide font-bold">Ödeme Yöntemi</span>
                    <div className="bg-slate-950 p-1.5 rounded-lg border border-slate-800 w-full md:w-64">
                       {selectedCompanyData ? (
                           <div className={`w-full py-2 px-4 rounded-md border flex items-center justify-between transition-all cursor-not-allowed
                                ${paymentMethod === 'INVOICE' 
                                    ? 'bg-blue-500/10 border-blue-500/30 text-blue-200' 
                                    : 'bg-emerald-500/10 border-emerald-500/30 text-emerald-200'
                                }`}>
                                <div className="flex items-center space-x-2">
                                    {paymentMethod === 'INVOICE' ? <Receipt className="w-4 h-4" /> : <Wallet className="w-4 h-4" />}
                                    <span className="text-xs font-bold">{paymentMethod === 'INVOICE' ? 'FATURA (Cari)' : 'NAKİT'}</span>
                                </div>
                                <div className="flex items-center space-x-1 text-[10px] opacity-60">
                                    <Lock className="w-3 h-3" />
                                    <span>Sabit</span>
                                </div>
                           </div>
                       ) : (
                           <div className="w-full py-2 px-4 text-center text-xs text-slate-500 italic border border-transparent">
                               Firma seçimi bekleniyor...
                           </div>
                       )}
                    </div>
                    {selectedCompanyData && (
                        <span className="text-[10px] text-slate-500 mt-1 ml-1">* Firma ayarı gereği bu yöntem geçerlidir.</span>
                    )}
                 </div>
             </div>

             {/* Orta: Tutar */}
             <div className="flex flex-col items-center md:items-end">
                <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">Toplam Tutar</span>
                <div className={`text-3xl font-bold tracking-tight ${paymentMethod === 'CASH' ? 'text-emerald-400' : 'text-blue-400'}`}>
                    ₺{estimatedPrice.toLocaleString('tr-TR')}
                </div>
                {estimatedCost > 0 && <span className="text-[10px] text-red-400/60">Maliyet: ₺{estimatedCost}</span>}
             </div>

             {/* Sağ: Buton */}
             <button 
                onClick={handleSubmit}
                disabled={!isFormValid}
                className={`w-full md:w-auto px-8 py-3 rounded-xl text-white font-bold shadow-lg flex items-center justify-center space-x-2 transition-all active:scale-95 ${
                    !isFormValid ? 'bg-slate-800 text-slate-500 cursor-not-allowed' :
                    paymentMethod === 'CASH' ? 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-900/20' : 'bg-blue-600 hover:bg-blue-500 shadow-blue-900/20'
                }`}
            >
                <Save className="w-5 h-5" />
                <span>KAYDET VE OLUŞTUR</span>
            </button>
         </div>
      </div>
    </div>
  );
};

