// https://vitejs.dev/config/
export default defineConfig({
  plugins: [react()],
  base: './', // Electron için zorunlu
  server: {
    port: 5173,
    strictPort: true,
  },
  build: {
    // Electron (Chromium) için hedef belirleme. 
    // Bu, kodun modern tarayıcılarda doğal çalışmasını sağlar, performansı artırır.
    target: 'chrome100', 
    minify: 'esbuild', // Hızlı derleme için
    cssCodeSplit: true,
    chunkSizeWarningLimit: 1000,
    rollupOptions: {
      output: {
        // Kütüphaneleri ayrı dosyalara bölerek önbellekleme performansını artırır
        manualChunks: {
          vendor: ['react', 'react-dom', 'lucide-react', 'xlsx', 'uuid']
        }
      }
    }
  }
})

export enum Status {
  PENDING = 'PENDING',       // Bekliyor (Henüz gitmedi)
  AT_HOSPITAL = 'AT_HOSPITAL', // Hastanede / Tetkikte
  AWAITING_RESULT = 'AWAITING_RESULT', // Sonuç Bekleniyor
  COMPLETED = 'COMPLETED',   // Tamamlandı
  CANCELLED = 'CANCELLED'    // İptal
}

// Deprecated enum usage in favor of dynamic list, keeping for type safety in legacy code
export enum ExamType {
  AUDIOMETRY = 'Odyometri',
  LUNG_XRAY = 'Akciğer Grafisi',
  HEMOGRAM = 'Hemogram',
  VISION = 'Göz Muayenesi',
  EKG = 'EKG',
  TETANUS = 'Tetanoz Aşısı',
  BLOOD_SUGAR = 'Açlık Kan Şekeri',
  LIVER_FUNC = 'Karaciğer Fonksiyon Testleri'
}

export interface ExamDefinition {
  id: string;
  code: string; // Excel mapping code (e.g. "101", "HEM")
  name: string;
  price: number; // Müşteriye satılan fiyat
  cost?: number; // OSGB'ye olan maliyeti (Kurum ödemesi)
}

export interface MedicalInstitution {
  id: string;
  name: string;
  address?: string;
  phone?: string;
}

export enum HazardClass {
  LESS = 'Az Tehlikeli',
  DANGEROUS = 'Tehlikeli',
  VERY_DANGEROUS = 'Çok Tehlikeli'
}

export interface Company {
  id: string;
  name: string;
  hazardClass: HazardClass;
  assignedDoctor: string;     // İşyeri Hekimi
  assignedSpecialist: string; // İSG Uzmanı
  defaultExams: string[];     // Changed from ExamType[] to string[] to support dynamic exams
  defaultPaymentMethod: 'CASH' | 'INVOICE'; // Firmanın varsayılan ödeme yöntemi
  forcedInstitutionId?: string; // Eğer varsa, bu firma sadece bu kuruma sevk edilebilir
}

export interface Employee {
  id: string;
  fullName: string;
  tcNo: string;
  birthDate?: string; // New field added
  company: string;
  department?: string;
}

export interface Referral {
  id: string;
  employee: Employee;
  exams: string[]; // Changed to string[]
  status: Status;
  referralDate: string; // ISO Date string
  notes?: string;
  resultSummary?: string;
  doctorName?: string; // Kayıt anındaki doktor
  specialistName?: string; // Kayıt anındaki uzman
  totalPrice?: number; // Müşteriden alınacak tutar
  totalCost?: number; // OSGB'nin ödeyeceği maliyet
  paymentMethod: 'CASH' | 'INVOICE'; // Nakit (Kasa) veya Cari (Fatura)
  targetInstitutionId?: string; // Hangi kuruma sevk edildiği
}

export interface Stats {
  total: number;
  today: number;
  totalIncome: number;
}

export interface SafeTransaction {
  id: string;
  type: 'INCOME' | 'EXPENSE';
  amount: number;
  description: string;
  date: string;
  category?: string;
}

export interface AppSettings {
  ekgLimitAge: number; // Age threshold for mandatory EKG (default 40)
  companyLogo?: string; // Base64 string for the logo
}

import React, { useState, useEffect, useMemo, Suspense, lazy } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Settings, 
  Plus, 
  Search,
  Activity,
  LogOut,
  Stethoscope,
  Wallet,
  FileText,
  Menu,
  X,
  Loader2
} from 'lucide-react';
import { ReferralList } from './components/ReferralList';
import { StatsCards } from './components/StatsCards';
import { EndOfDayReportModal } from './components/EndOfDayReportModal';
import { Referral, Status, Company, ExamDefinition, SafeTransaction, MedicalInstitution, AppSettings } from './types';
import { 
  loadReferrals, saveReferrals, 
  loadCompanies, saveCompanies,
  loadExams, saveExams,
  loadTransactions, saveTransactions,
  loadInstitutions, saveInstitutions,
  loadAppSettings, saveAppSettings
} from './services/storage';
import { PREDEFINED_COMPANIES, DEFAULT_EXAMS, DEFAULT_INSTITUTIONS } from './services/initialData';

// --- LAZY LOADING ---
// Bu bileşenler sadece ihtiyaç duyulduğunda yüklenecek, açılışı yavaşlatmayacak.
const NewReferralView = lazy(() => import('./components/NewReferralModal').then(module => ({ default: module.NewReferralView })));
const FinanceView = lazy(() => import('./components/FinanceView').then(module => ({ default: module.FinanceView })));
const SettingsView = lazy(() => import('./components/SettingsView').then(module => ({ default: module.SettingsView })));

// Loading Component
const PageLoader = () => (
  <div className="flex flex-col items-center justify-center h-full text-slate-500">
    <Loader2 className="w-8 h-8 animate-spin mb-2 text-blue-500" />
    <span className="text-xs font-medium">Yükleniyor...</span>
  </div>
);

const App: React.FC = () => {
  // Added 'create_referral' to navigation state
  const [activeTab, setActiveTab] = useState<'dashboard' | 'referrals' | 'finance' | 'settings' | 'create_referral'>('dashboard');

  // Mobile Menu State
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Data States
  const [referrals, setReferrals] = useState<Referral[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [exams, setExams] = useState<ExamDefinition[]>([]);
  const [institutions, setInstitutions] = useState<MedicalInstitution[]>([]);
  const [transactions, setTransactions] = useState<SafeTransaction[]>([]);
  const [appSettings, setAppSettings] = useState<AppSettings>({ ekgLimitAge: 40 });

  // isModalOpen removed as it is now a page
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Initial load
  useEffect(() => {
    setReferrals(loadReferrals());
    setCompanies(loadCompanies(PREDEFINED_COMPANIES));
    setExams(loadExams(DEFAULT_EXAMS));
    setInstitutions(loadInstitutions(DEFAULT_INSTITUTIONS));
    setTransactions(loadTransactions());
    setAppSettings(loadAppSettings());
  }, []);

  // Save Effects
  useEffect(() => saveReferrals(referrals), [referrals]);
  useEffect(() => saveCompanies(companies), [companies]);
  useEffect(() => saveExams(exams), [exams]);
  useEffect(() => saveInstitutions(institutions), [institutions]);
  useEffect(() => saveTransactions(transactions), [transactions]);
  useEffect(() => saveAppSettings(appSettings), [appSettings]);

  // Handlers
  const handleCreateReferral = (referral: Referral) => {
    // 1. Add Referral (Always)
    setReferrals(prev => [referral, ...prev]);

    // 2. Add to Safe ONLY if Payment Method is CASH
    if (referral.paymentMethod === 'CASH' && referral.totalPrice && referral.totalPrice > 0) {
      const newTransaction: SafeTransaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'INCOME',
        amount: referral.totalPrice,
        description: `Sevk Geliri (Nakit): ${referral.employee.fullName} (${referral.employee.company})`,
        date: new Date().toISOString()
      };
      setTransactions(prev => [...prev, newTransaction]);
    }

    // Redirect back to referrals list after creation
    setActiveTab('referrals');
  };

  const handleUpdateStatus = (id: string, newStatus: Status) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, status: newStatus } : r
    ));
  };

  const handleDelete = (id: string) => {
    if(window.confirm('Bu kaydı silmek istediğinize emin misiniz?')) {
      setReferrals(prev => prev.filter(r => r.id !== id));
    }
  };

  // Settings Handlers
  const handleAddCompany = (c: Company) => setCompanies(prev => [...prev, c]);
  const handleDeleteCompany = (id: string) => setCompanies(prev => prev.filter(c => c.id !== id));
  // New Bulk Delete Handler
  const handleBulkDeleteCompanies = (ids: string[]) => {
      setCompanies(prev => prev.filter(c => !ids.includes(c.id)));
  };

  const handleAddExam = (e: ExamDefinition) => setExams(prev => [...prev, e]);
  const handleUpdateExam = (updated: ExamDefinition) => setExams(prev => prev.map(e => e.id === updated.id ? updated : e));
  const handleDeleteExam = (id: string) => setExams(prev => prev.filter(e => e.id !== id));

  const handleAddInstitution = (i: MedicalInstitution) => setInstitutions(prev => [...prev, i]);
  const handleDeleteInstitution = (id: string) => setInstitutions(prev => prev.filter(i => i.id !== id));

  const handleUpdateSettings = (newSettings: AppSettings) => setAppSettings(newSettings);

  // Finance Handlers
  const handleAddTransaction = (t: SafeTransaction) => setTransactions(prev => [...prev, t]);

  const filteredReferrals = useMemo(() => {
    return referrals.filter(r => 
      r.employee.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.company.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.tcNo.includes(searchTerm)
    );
  }, [referrals, searchTerm]);

  const stats = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    const totalIncome = transactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);

    return {
      total: referrals.length,
      today: referrals.filter(r => r.referralDate.startsWith(todayStr)).length,
      totalIncome: totalIncome
    };
  }, [referrals, transactions]);

  // Handle nav click (close mobile menu)
  const handleNavClick = (tab: typeof activeTab) => {
      setActiveTab(tab);
      setIsMobileMenuOpen(false);
  };

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden">

      {/* Mobile Sidebar Overlay */}
      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden backdrop-blur-sm"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 border-r border-slate-800 text-white flex flex-col shadow-xl transition-transform duration-300 md:relative md:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} print:hidden`}>
        <div className="p-6 flex items-center justify-between border-b border-slate-800">
          <div className="flex items-center space-x-3">
            {appSettings.companyLogo ? (
               <img src={appSettings.companyLogo} alt="Logo" className="w-10 h-10 object-contain rounded bg-white p-0.5" />
            ) : (
               <div className="p-2 bg-blue-600 rounded-lg shadow-lg shadow-blue-900/20">
                  <Stethoscope className="w-6 h-6 text-white" />
               </div>
            )}
            <div>
                <h1 className="text-xl font-bold tracking-tight">OSGB Pro</h1>
                <p className="text-xs text-slate-400">Tetkik Takip Sistemi</p>
            </div>
          </div>
          <button onClick={() => setIsMobileMenuOpen(false)} className="md:hidden text-slate-400 hover:text-white">
            <X className="w-6 h-6" />
          </button>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => handleNavClick('dashboard')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'dashboard' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            <span className="font-medium">Genel Bakış</span>
          </button>

          <button 
            onClick={() => handleNavClick('referrals')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'referrals' || activeTab === 'create_referral' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Users className="w-5 h-5" />
            <span className="font-medium">Personel Takibi</span>
          </button>

          <button 
            onClick={() => handleNavClick('finance')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'finance' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Wallet className="w-5 h-5" />
            <span className="font-medium">Kasa & Finans</span>
          </button>

          <button 
            onClick={() => handleNavClick('settings')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'settings' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Settings className="w-5 h-5" />
            <span className="font-medium">Ayarlar</span>
          </button>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative bg-slate-950">
        {/* Header */}
        <header className="h-16 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-4 md:px-8 shadow-sm z-10 print:hidden">
          <div className="flex items-center">
              <button 
                onClick={() => setIsMobileMenuOpen(true)}
                className="mr-4 md:hidden text-slate-400 hover:text-white p-1 rounded-lg hover:bg-slate-800 transition-colors"
              >
                  <Menu className="w-6 h-6" />
              </button>
              <h2 className="text-lg md:text-xl font-semibold text-white truncate">
                {activeTab === 'dashboard' ? 'Kontrol Paneli' : 
                 activeTab === 'referrals' ? 'Tetkik & Sevk Listesi' : 
                 activeTab === 'create_referral' ? 'Yeni Sevk Girişi' :
                 activeTab === 'finance' ? 'Kasa Yönetimi' : 'Ayarlar'}
              </h2>
          </div>

          <div className="flex items-center space-x-4">
            {activeTab !== 'create_referral' && (
              <>
                <div className="relative hidden md:block">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400 w-4 h-4" />
                  <input 
                    type="text"
                    placeholder="Personel veya Firma ara..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent w-64 transition-all placeholder-slate-500"
                  />
                </div>
                <button 
                  onClick={() => setActiveTab('create_referral')}
                  className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-500 text-white px-3 py-2 md:px-4 md:py-2 rounded-lg text-sm font-medium transition-colors shadow-lg shadow-blue-900/20 active:transform active:scale-95 whitespace-nowrap"
                >
                  <Plus className="w-4 h-4" />
                  <span className="hidden md:inline">Yeni Sevk Oluştur</span>
                  <span className="md:hidden">Yeni Sevk</span>
                </button>
              </>
            )}
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-auto p-4 md:p-8 custom-scrollbar print:p-0 print:overflow-visible">
          <Suspense fallback={<PageLoader />}>
            {activeTab === 'dashboard' && (
              <div className="space-y-6">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-4 gap-3 md:gap-0">
                  <h3 className="text-lg font-bold text-white hidden md:block">Günlük Özet</h3>
                  <button 
                    onClick={() => setIsReportModalOpen(true)}
                    className="w-full md:w-auto flex items-center justify-center space-x-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-lg"
                  >
                    <FileText className="w-4 h-4" />
                    <span>Gün Sonu Raporu Al (Z Raporu)</span>
                  </button>
                </div>

                <StatsCards stats={stats} />

                <div className="mt-8">
                  <h3 className="text-lg font-bold text-white mb-4 flex items-center">
                    <Activity className="w-5 h-5 mr-2 text-blue-500" />
                    Son Hareketler
                  </h3>
                  <ReferralList 
                    referrals={filteredReferrals.slice(0, 5)} 
                    institutions={institutions}
                    onUpdateStatus={handleUpdateStatus} 
                    onDelete={handleDelete}
                    compact
                  />
                </div>
              </div>
            )}

            {activeTab === 'referrals' && (
              <div className="h-full flex flex-col">
                <ReferralList 
                    referrals={filteredReferrals} 
                    institutions={institutions}
                    onUpdateStatus={handleUpdateStatus} 
                    onDelete={handleDelete}
                  />
              </div>
            )}

            {activeTab === 'create_referral' && (
              <NewReferralView
                onClose={() => setActiveTab('referrals')}
                onSubmit={handleCreateReferral}
                companies={companies}
                exams={exams}
                institutions={institutions}
                settings={appSettings}
              />
            )}

            {activeTab === 'finance' && (
              <FinanceView 
                transactions={transactions}
                onAddTransaction={handleAddTransaction}
              />
            )}

            {activeTab === 'settings' && (
              <SettingsView 
                  companies={companies}
                  onAddCompany={handleAddCompany}
                  onDeleteCompany={handleDeleteCompany}
                  onBulkDeleteCompanies={handleBulkDeleteCompanies}
                  exams={exams}
                  onAddExam={handleAddExam}
                  onUpdateExam={handleUpdateExam}
                  onDeleteExam={handleDeleteExam}
                  institutions={institutions}
                  onAddInstitution={handleAddInstitution}
                  onDeleteInstitution={handleDeleteInstitution}
                  settings={appSettings}
                  onUpdateSettings={handleUpdateSettings}
              />
            )}
          </Suspense>
        </div>
      </main>

      {/* End of Day Report Modal - Still a modal */}
      {isReportModalOpen && (
        <EndOfDayReportModal
          onClose={() => setIsReportModalOpen(false)}
          referrals={referrals}
          transactions={transactions}
          settings={appSettings}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { 
  Trash2,
  MapPin,
  Building2,
  FileText,
  CalendarDays,
  MoreVertical,
  CheckCircle2,
  Clock,
  Ban,
  AlertCircle
} from 'lucide-react';
import { Referral, Status, MedicalInstitution } from '../types';

interface ReferralListProps {
  referrals: Referral[];
  institutions?: MedicalInstitution[];
  onUpdateStatus: (id: string, status: Status) => void;
  onDelete: (id: string) => void;
  compact?: boolean;
}

export const ReferralList: React.FC<ReferralListProps> = ({ 
  referrals, 
  institutions = [],
  onUpdateStatus, 
  onDelete,
  compact = false 
}) => {
  const [openMenuId, setOpenMenuId] = useState<string | null>(null);

  const getInstitutionName = (id?: string) => {
    if (!id) return null;
    return institutions.find(i => i.id === id)?.name || "Bilinmeyen Kurum";
  };

  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map(part => part[0])
      .slice(0, 2)
      .join('')
      .toUpperCase();
  };

  const getAvatarColor = (name: string) => {
    const colors = [
      'bg-blue-500', 'bg-emerald-500', 'bg-violet-500', 'bg-amber-500', 'bg-rose-500', 'bg-cyan-500'
    ];
    let hash = 0;
    for (let i = 0; i < name.length; i++) {
      hash = name.charCodeAt(i) + ((hash << 5) - hash);
    }
    return colors[Math.abs(hash) % colors.length];
  };

  const StatusBadge = ({ status, onClick }: { status: Status; onClick?: () => void }) => {
    const configs = {
      [Status.PENDING]: { bg: 'bg-amber-500/10', text: 'text-amber-500', border: 'border-amber-500/20', icon: Clock, label: 'Bekliyor' },
      [Status.AT_HOSPITAL]: { bg: 'bg-blue-500/10', text: 'text-blue-500', border: 'border-blue-500/20', icon: MapPin, label: 'Hastanede' },
      [Status.AWAITING_RESULT]: { bg: 'bg-purple-500/10', text: 'text-purple-500', border: 'border-purple-500/20', icon: FileText, label: 'Sonuç Bekliyor' },
      [Status.COMPLETED]: { bg: 'bg-emerald-500/10', text: 'text-emerald-500', border: 'border-emerald-500/20', icon: CheckCircle2, label: 'Tamamlandı' },
      [Status.CANCELLED]: { bg: 'bg-red-500/10', text: 'text-red-500', border: 'border-red-500/20', icon: Ban, label: 'İptal' },
    };

    const config = configs[status] || configs[Status.PENDING];
    const Icon = config.icon;

    return (
      <div 
        onClick={onClick}
        className={`flex items-center space-x-1.5 px-2.5 py-1 rounded-full border ${config.bg} ${config.text} ${config.border} ${onClick ? 'cursor-pointer hover:bg-opacity-20' : ''}`}
      >
        <Icon className="w-3.5 h-3.5" />
        <span className="text-[11px] font-bold uppercase tracking-wide">{config.label}</span>
      </div>
    );
  };

  // Toggle status menu
  const toggleMenu = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setOpenMenuId(openMenuId === id ? null : id);
  };

  // Close menu on click elsewhere (could be improved with a click-outside hook)
  React.useEffect(() => {
    const handleClick = () => setOpenMenuId(null);
    window.addEventListener('click', handleClick);
    return () => window.removeEventListener('click', handleClick);
  }, []);

  if (referrals.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-slate-500 bg-slate-800/50 rounded-xl border border-dashed border-slate-700">
        <div className="p-4 bg-slate-800 rounded-full mb-3">
            <FileText className="w-8 h-8 opacity-50" />
        </div>
        <p className="font-medium">Henüz kayıt bulunmamaktadır.</p>
        <p className="text-xs mt-1">Yeni sevk oluşturmak için butona tıklayın.</p>
      </div>
    );
  }

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden flex flex-col h-full">
      <div className="overflow-x-auto custom-scrollbar flex-1">
        <table className="w-full text-left border-collapse">
          <thead className="sticky top-0 z-10 bg-slate-900 border-b border-slate-700 shadow-sm">
            <tr>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider w-1/4">Personel</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Firma & Kurum</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Tarih</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider text-center">Durum</th>
              {!compact && <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Tetkikler</th>}
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider text-right">Tutar</th>
              <th className="px-4 py-4 w-10"></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-700/50 bg-slate-800">
            {referrals.map((referral) => {
               const instName = getInstitutionName(referral.targetInstitutionId);
               return (
              <tr key={referral.id} className="hover:bg-slate-700/30 transition-colors group">
                {/* Personel */}
                <td className="px-6 py-4">
                  <div className="flex items-center space-x-3">
                    <div className={`w-9 h-9 rounded-full flex items-center justify-center text-xs font-bold text-white shadow-lg ${getAvatarColor(referral.employee.fullName)}`}>
                        {getInitials(referral.employee.fullName)}
                    </div>
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-200 text-sm">{referral.employee.fullName}</span>
                      <span className="text-[11px] text-slate-500 font-mono tracking-wide">{referral.employee.tcNo}</span>
                    </div>
                  </div>
                </td>

                {/* Firma & Kurum */}
                <td className="px-6 py-4">
                  <div className="flex flex-col space-y-1.5">
                      <div className="flex items-center space-x-1.5">
                         <Building2 className="w-3.5 h-3.5 text-slate-500" />
                         <span className="text-sm text-slate-300 font-medium truncate max-w-[150px]" title={referral.employee.company}>{referral.employee.company}</span>
                      </div>
                      {!compact && (
                        <div className="flex items-center space-x-1.5">
                            <MapPin className="w-3.5 h-3.5 text-slate-600" />
                            <span className={`text-xs truncate max-w-[150px] ${instName ? 'text-slate-400' : 'text-slate-600 italic'}`}>
                                {instName || 'Kurum Yok'}
                            </span>
                        </div>
                      )}
                  </div>
                </td>

                {/* Tarih */}
                <td className="px-6 py-4">
                    <div className="flex items-center space-x-2 text-slate-400">
                        <CalendarDays className="w-4 h-4 text-slate-600" />
                        <span className="text-sm font-medium">{new Date(referral.referralDate).toLocaleDateString('tr-TR')}</span>
                    </div>
                </td>

                {/* Durum */}
                <td className="px-6 py-4 text-center relative">
                    <div className="flex justify-center">
                        <StatusBadge 
                            status={referral.status} 
                            onClick={(e: any) => toggleMenu(referral.id, e)} 
                        />
                    </div>

                    {/* Status Menu */}
                    {openMenuId === referral.id && (
                        <div className="absolute top-12 left-1/2 -translate-x-1/2 w-48 bg-slate-900 border border-slate-700 rounded-lg shadow-xl z-50 py-1 flex flex-col animate-in fade-in zoom-in-95 duration-100">
                            {Object.values(Status).map(s => (
                                <button
                                    key={s}
                                    onClick={(e) => { e.stopPropagation(); onUpdateStatus(referral.id, s); setOpenMenuId(null); }}
                                    className={`text-left px-4 py-2 text-xs hover:bg-slate-800 transition-colors ${referral.status === s ? 'text-blue-400 font-bold' : 'text-slate-400'}`}
                                >
                                    {s === Status.PENDING && 'Bekliyor'}
                                    {s === Status.AT_HOSPITAL && 'Hastanede'}
                                    {s === Status.AWAITING_RESULT && 'Sonuç Bekleniyor'}
                                    {s === Status.COMPLETED && 'Tamamlandı'}
                                    {s === Status.CANCELLED && 'İptal'}
                                </button>
                            ))}
                        </div>
                    )}
                </td>

                {/* Tetkikler (Full View Only) */}
                {!compact && (
                    <td className="px-6 py-4">
