  onDelete: (id: string) => void;
  compact?: boolean;
}

export const ReferralList: React.FC<ReferralListProps> = ({ 
  referrals, 
  institutions = [],
  onUpdateStatus, 
  onDelete,
  compact = false 
}) => {
  const [openMenuId, setOpenMenuId] = useState<string | null>(null);

  const getInstitutionName = (id?: string) => {
    if (!id) return null;
    return institutions.find(i => i.id === id)?.name || "Bilinmeyen Kurum";
  };

  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map(part => part[0])
      .slice(0, 2)
      .join('')
      .toUpperCase();
  };

  const getAvatarColor = (name: string) => {
    const colors = [
      'bg-blue-500', 'bg-emerald-500', 'bg-violet-500', 'bg-amber-500', 'bg-rose-500', 'bg-cyan-500'
    ];
    let hash = 0;
    for (let i = 0; i < name.length; i++) {
      hash = name.charCodeAt(i) + ((hash << 5) - hash);
    }
    return colors[Math.abs(hash) % colors.length];
  };

  const StatusBadge = ({ status, onClick }: { status: Status; onClick?: (e: React.MouseEvent) => void }) => {
    const configs = {
      [Status.PENDING]: { bg: 'bg-amber-500/10', text: 'text-amber-500', border: 'border-amber-500/20', icon: Clock, label: 'Bekliyor' },
      [Status.AT_HOSPITAL]: { bg: 'bg-blue-500/10', text: 'text-blue-500', border: 'border-blue-500/20', icon: MapPin, label: 'Hastanede' },
      [Status.AWAITING_RESULT]: { bg: 'bg-purple-500/10', text: 'text-purple-500', border: 'border-purple-500/20', icon: FileText, label: 'Sonuç Bekliyor' },
      [Status.COMPLETED]: { bg: 'bg-emerald-500/10', text: 'text-emerald-500', border: 'border-emerald-500/20', icon: CheckCircle2, label: 'Tamamlandı' },
      [Status.CANCELLED]: { bg: 'bg-red-500/10', text: 'text-red-500', border: 'border-red-500/20', icon: Ban, label: 'İptal' },
    };

    const config = configs[status] || configs[Status.PENDING];
    const Icon = config.icon;

    return (
      <div 
        onClick={onClick}
        className={`flex items-center space-x-1.5 px-2.5 py-1 rounded-full border ${config.bg} ${config.text} ${config.border} ${onClick ? 'cursor-pointer hover:bg-opacity-20' : ''}`}
      >
        <Icon className="w-3.5 h-3.5" />
        <span className="text-[11px] font-bold uppercase tracking-wide">{config.label}</span>
      </div>
    );
  };

  // Toggle status menu
  const toggleMenu = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setOpenMenuId(openMenuId === id ? null : id);
  };

  // Close menu on click elsewhere (could be improved with a click-outside hook)
  React.useEffect(() => {
    const handleClick = () => setOpenMenuId(null);
    window.addEventListener('click', handleClick);
    return () => window.removeEventListener('click', handleClick);
  }, []);

  if (referrals.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-slate-500 bg-slate-800/50 rounded-xl border border-dashed border-slate-700">
        <div className="p-4 bg-slate-800 rounded-full mb-3">
            <FileText className="w-8 h-8 opacity-50" />
        </div>
        <p className="font-medium">Henüz kayıt bulunmamaktadır.</p>
        <p className="text-xs mt-1">Yeni sevk oluşturmak için butona tıklayın.</p>
      </div>
    );
