              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider text-right">Tutar</th>
              <th className="px-4 py-4 w-10"></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-700/50 bg-slate-800">
            {referrals.map((referral) => {
               const instName = getInstitutionName(referral.targetInstitutionId);
               return (
              <tr key={referral.id} className="hover:bg-slate-700/30 transition-colors group">
                {/* Personel */}
                <td className="px-6 py-4">
                  <div className="flex items-center space-x-3">
                    <div className={`w-9 h-9 rounded-full flex items-center justify-center text-xs font-bold text-white shadow-lg ${getAvatarColor(referral.employee.fullName)}`}>
                        {getInitials(referral.employee.fullName)}
                    </div>
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-200 text-sm">{referral.employee.fullName}</span>
                      <span className="text-[11px] text-slate-500 font-mono tracking-wide">{referral.employee.tcNo}</span>
                    </div>
                  </div>
                </td>

                {/* Firma & Kurum */}
                <td className="px-6 py-4">
                  <div className="flex flex-col space-y-1.5">
                      <div className="flex items-center space-x-1.5">
                         <Building2 className="w-3.5 h-3.5 text-slate-500" />
                         <span className="text-sm text-slate-300 font-medium truncate max-w-[150px]" title={referral.employee.company}>{referral.employee.company}</span>
                      </div>
                      {!compact && (
                        <div className="flex items-center space-x-1.5">
                            <MapPin className="w-3.5 h-3.5 text-slate-600" />
                            <span className={`text-xs truncate max-w-[150px] ${instName ? 'text-slate-400' : 'text-slate-600 italic'}`}>
                                {instName || 'Kurum Yok'}
                            </span>
                        </div>
                      )}
                  </div>
                </td>

                {/* Tarih */}
                <td className="px-6 py-4">
                    <div className="flex items-center space-x-2 text-slate-400">
                        <CalendarDays className="w-4 h-4 text-slate-600" />
                        <span className="text-sm font-medium">{new Date(referral.referralDate).toLocaleDateString('tr-TR')}</span>
                    </div>
                </td>

                {/* Tetkikler (Full View Only) */}
                {!compact && (
                    <td className="px-6 py-4">
                        <div className="flex flex-wrap gap-1.5 max-w-[200px]">
                            {referral.exams.slice(0, 3).map((exam, i) => (
                            <span key={i} className="inline-flex items-center px-2 py-1 rounded text-[10px] font-medium bg-slate-900 text-slate-400 border border-slate-700">
                                {exam}
                            </span>
                            ))}
                            {referral.exams.length > 3 && (
                            <span className="inline-flex items-center px-2 py-1 rounded text-[10px] font-medium bg-slate-800 text-slate-500">
                                +{referral.exams.length - 3}
                            </span>
                            )}
                        </div>
                    </td>
                )}

                {/* Tutar */}
                <td className="px-6 py-4 text-right">
                  <div className="flex flex-col items-end">
                    <span className="text-white font-bold text-sm">₺{referral.totalPrice?.toLocaleString('tr-TR') || 0}</span>
                    <span className={`text-[9px] uppercase font-bold tracking-wider px-1.5 py-0.5 rounded mt-1 ${referral.paymentMethod === 'CASH' ? 'text-emerald-400 bg-emerald-500/10' : 'text-blue-400 bg-blue-500/10'}`}>
                      {referral.paymentMethod === 'CASH' ? 'Nakit' : 'Fatura'}
                    </span>
                  </div>
                </td>

                {/* Actions */}
                <td className="px-4 py-4 text-right">
                    <button 
                        onClick={() => onDelete(referral.id)}
                        className="text-slate-600 hover:text-red-400 hover:bg-red-500/10 p-2 rounded-lg transition-all opacity-0 group-hover:opacity-100"
                        title="Kaydı Sil"
                    >
                        <Trash2 className="w-4 h-4" />
                    </button>
                </td>
              </tr>
            )})}
          </tbody>
        </table>
      </div>
    </div>
  );
};

