import React from 'react';
import { 
  Trash2,
  MapPin,
  Building2,
  FileText,
  CalendarDays
} from 'lucide-react';
import { Referral, MedicalInstitution } from '../types';

interface ReferralListProps {
  referrals: Referral[];
  institutions?: MedicalInstitution[];
  onDelete: (id: string) => void;
  compact?: boolean;
}

export const ReferralList: React.FC<ReferralListProps> = ({ 
  referrals, 
  institutions = [],
  onDelete,
  compact = false 
}) => {

  const getInstitutionName = (id?: string) => {
    if (!id) return null;
    return institutions.find(i => i.id === id)?.name || "Bilinmeyen Kurum";
  };

  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map(part => part[0])
      .slice(0, 2)
      .join('')
      .toUpperCase();
  };

  const getAvatarColor = (name: string) => {
    const colors = [
      'bg-blue-500', 'bg-emerald-500', 'bg-violet-500', 'bg-amber-500', 'bg-rose-500', 'bg-cyan-500'
    ];
    let hash = 0;
    for (let i = 0; i < name.length; i++) {
      hash = name.charCodeAt(i) + ((hash << 5) - hash);
    }
    return colors[Math.abs(hash) % colors.length];
  };

  if (referrals.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-slate-500 bg-slate-800/50 rounded-xl border border-dashed border-slate-700">
        <div className="p-4 bg-slate-800 rounded-full mb-3">
            <FileText className="w-8 h-8 opacity-50" />
        </div>
        <p className="font-medium">Henüz kayıt bulunmamaktadır.</p>
        <p className="text-xs mt-1">Yeni sevk oluşturmak için butona tıklayın.</p>
      </div>
    );
  }

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden flex flex-col h-full">
      <div className="overflow-x-auto custom-scrollbar flex-1">
        <table className="w-full text-left border-collapse">
          <thead className="sticky top-0 z-10 bg-slate-900 border-b border-slate-700 shadow-sm">
            <tr>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider w-1/4">Personel</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Firma & Kurum</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Tarih</th>
              {!compact && <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Tetkikler</th>}
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider text-right">Tutar</th>
              <th className="px-4 py-4 w-10"></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-700/50 bg-slate-800">
            {referrals.map((referral) => {
               const instName = getInstitutionName(referral.targetInstitutionId);
               return (
              <tr key={referral.id} className="hover:bg-slate-700/30 transition-colors group">
                {/* Personel */}
                <td className="px-6 py-4">
                  <div className="flex items-center space-x-3">
                    <div className={`w-9 h-9 rounded-full flex items-center justify-center text-xs font-bold text-white shadow-lg ${getAvatarColor(referral.employee.fullName)}`}>
