                {/* Tutar */}
                <td className="px-6 py-4 text-right">
                  <div className="flex flex-col items-end">
                    <span className="text-white font-bold text-sm">₺{referral.totalPrice?.toLocaleString('tr-TR') || 0}</span>
                    <span className={`text-[9px] uppercase font-bold tracking-wider px-1.5 py-0.5 rounded mt-1 ${referral.paymentMethod === 'CASH' ? 'text-emerald-400 bg-emerald-500/10' : 'text-blue-400 bg-blue-500/10'}`}>
                      {referral.paymentMethod === 'CASH' ? 'Nakit' : 'Fatura'}
                    </span>
                  </div>
                </td>

                {/* Actions */}
                <td className="px-4 py-4 text-right">
                    <button 
                        onClick={() => onDelete(referral.id)}
                        className="text-slate-600 hover:text-red-400 hover:bg-red-500/10 p-2 rounded-lg transition-all opacity-0 group-hover:opacity-100"
                        title="Kaydı Sil"
                    >
                        <Trash2 className="w-4 h-4" />
                    </button>
                </td>
              </tr>
            )})}
          </tbody>
        </table>
      </div>
    </div>
  );
};

