// Veri kalıcılığı için store başlatma
const store = new Store();

function createWindow() {
  const mainWindow = new BrowserWindow({
    width: 1280,
    height: 800,
    minWidth: 1024,
    minHeight: 768,
    title: "OSGB Tetkik Takip Sistemi",
