import React, { useState, useEffect, useRef, useMemo } from 'react';
import { ArrowLeft, Building2, User, Stethoscope, ShieldCheck, Wallet, Receipt, Save, Search, Check, ChevronDown, X, MapPin, Lock, Info, AlertCircle, Calendar } from 'lucide-react';
import { Referral, Status, Company, HazardClass, ExamDefinition, MedicalInstitution, AppSettings } from '../types';

interface NewReferralViewProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
  companies: Company[];
  exams: ExamDefinition[];
  institutions: MedicalInstitution[];
  settings: AppSettings;
}

export const NewReferralView: React.FC<NewReferralViewProps> = ({ onClose, onSubmit, companies, exams, institutions, settings }) => {
  // --- STATE MANAGEMENT ---

  // Personel State
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');
  const [birthDate, setBirthDate] = useState('');

  // Company Search State
  const [companySearchTerm, setCompanySearchTerm] = useState('');
  const [isCompanyDropdownOpen, setIsCompanyDropdownOpen] = useState(false);
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Institution & Exam State
  const [selectedInstitutionId, setSelectedInstitutionId] = useState<string>('');
  const [isInstitutionLocked, setIsInstitutionLocked] = useState(false);
  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');

  // Financial State
  const [estimatedPrice, setEstimatedPrice] = useState(0);
  const [estimatedCost, setEstimatedCost] = useState(0);
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');

  // --- LOGIC & EFFECTS ---

  // Validation
  const isFormValid = fullName.length >= 3 && tcNo.length === 11 && birthDate !== '' && selectedCompanyData !== null && selectedExamIds.length > 0;

  // Age Calculation
  const patientAge = useMemo(() => {
     if(!birthDate) return 0;
     const today = new Date();
     const birth = new Date(birthDate);
     let age = today.getFullYear() - birth.getFullYear();
     const m = today.getMonth() - birth.getMonth();
     if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
        age--;
     }
     return age;
  }, [birthDate]);

  // Mandatory EKG
  const isEkgMandatory = patientAge >= settings.ekgLimitAge;

  useEffect(() => {
     if (isEkgMandatory) {
        const ekgExamName = 'EKG';
        if (!selectedExamIds.includes(ekgExamName)) {
            setSelectedExamIds(prev => [...prev, ekgExamName]);
        }
     }
  }, [isEkgMandatory, selectedExamIds]);

  // Search Filters
  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(companySearchTerm.toLowerCase())
  );

  // Dropdown Click Outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCompanyDropdownOpen(false);
        if (selectedCompanyData) setCompanySearchTerm(selectedCompanyData.name);
        else setCompanySearchTerm('');
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [selectedCompanyData]);

  // Price Calculation
  useEffect(() => {
    let totalPrice = 0;
    let totalCost = 0;
    selectedExamIds.forEach(id => {
      const exam = exams.find(e => e.name === id);
      if (exam) {
        totalPrice += exam.price;
        totalCost += (exam.cost || 0);
      }
    });
    setEstimatedPrice(totalPrice);
    setEstimatedCost(totalCost);
  }, [selectedExamIds, exams]);

  // Handlers
  const handleSelectCompany = (company: Company) => {
      setSelectedCompanyData(company);
      setCompanySearchTerm(company.name);
      setIsCompanyDropdownOpen(false);

      // Load Defaults
      setSelectedExamIds(company.defaultExams);

      // Set Payment Method based on Company Settings (LOCKED)
      setPaymentMethod(company.defaultPaymentMethod || 'INVOICE');

      // Handle Institution Logic
      if (company.forcedInstitutionId) {
          setSelectedInstitutionId(company.forcedInstitutionId);
          setIsInstitutionLocked(true);
      } else {
          setSelectedInstitutionId('');
          setIsInstitutionLocked(false);
      }
  };

  const handleClearCompany = () => {
      setSelectedCompanyData(null);
      setCompanySearchTerm('');
      setSelectedExamIds([]);
      setSelectedInstitutionId('');
      setIsInstitutionLocked(false);
  };

  const toggleExam = (examName: string) => {
    if (isEkgMandatory && examName === 'EKG') return;
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isFormValid) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        birthDate,
        company: selectedCompanyData!.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData!.assignedDoctor,
      specialistName: selectedCompanyData!.assignedSpecialist,
      totalPrice: estimatedPrice,
      totalCost: estimatedCost,
      paymentMethod: paymentMethod,
      targetInstitutionId: selectedInstitutionId || undefined
    };
    onSubmit(newReferral);
  };

  const getHazardBadge = (hazard: HazardClass) => {
    const styles = {
        [HazardClass.VERY_DANGEROUS]: 'bg-red-500 text-white',
        [HazardClass.DANGEROUS]: 'bg-orange-500 text-white',
        [HazardClass.LESS]: 'bg-emerald-500 text-white'
    };
    return (
        <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider ${styles[hazard]}`}>
            {hazard}
        </span>
    );
  };

  return (
    <div className="h-full flex flex-col bg-slate-950 relative overflow-hidden">

      {/* Header */}
      <div className="flex items-center justify-between px-6 py-4 border-b border-slate-800 bg-slate-900 shrink-0">
        <div className="flex items-center space-x-4">
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 hover:text-white transition-colors">
              <ArrowLeft className="w-5 h-5" />
          </button>
          <div>
              <h1 className="text-xl font-bold text-white tracking-tight">Yeni Sevk Girişi</h1>
              <p className="text-xs text-slate-400">Tek ekranda hızlı sevk oluşturma modülü</p>
          </div>
        </div>

        {/* Quick Tips */}
        <div className="hidden md:flex items-center space-x-4 text-xs text-slate-500">
           <div className="flex items-center"><span className="w-2 h-2 rounded-full bg-blue-500 mr-2"></span>Firma Varsayılanları</div>
           <div className="flex items-center"><span className="w-2 h-2 rounded-full bg-indigo-500 mr-2"></span>Zorunlu Tetkikler</div>
        </div>
      </div>

      {/* Main Grid Content */}
      <div className="flex-1 p-6 overflow-hidden">
        <div className="h-full grid grid-cols-1 lg:grid-cols-12 gap-6">

            {/* COLUMN 1: KİM? (Personel ve Firma) - %30 */}
            <div className="lg:col-span-4 flex flex-col space-y-6 overflow-y-auto custom-scrollbar pr-2">

                {/* 1. Firma Seçimi Kartı */}
                <div className="bg-slate-900 border border-slate-800 rounded-xl p-5 shadow-sm">
                    <div className="flex items-center mb-4">
                        <div className="p-2 bg-blue-500/10 rounded-lg mr-3">
                            <Building2 className="w-5 h-5 text-blue-500" />
                        </div>
                        <h3 className="font-bold text-slate-200">Firma Bilgisi</h3>
                    </div>

                    <div className="relative" ref={dropdownRef}>
                        <label className="block text-xs font-medium text-slate-500 mb-1.5 ml-1 uppercase">Hangi Firma?</label>
                        <div className="relative">
                            <input
                                autoFocus
                                type="text"
                                value={companySearchTerm}
                                onChange={(e) => {
                                    setCompanySearchTerm(e.target.value);
                                    setIsCompanyDropdownOpen(true);
                                    if(selectedCompanyData && e.target.value !== selectedCompanyData.name) setSelectedCompanyData(null);
                                }}
                                onClick={() => setIsCompanyDropdownOpen(true)}
                                placeholder="Firma adı yazın..."
                                className={`w-full pl-4 pr-10 py-3 bg-slate-950 border text-white text-sm rounded-lg focus:ring-2 focus:ring-blue-600 outline-none transition-all font-medium ${selectedCompanyData ? 'border-blue-500/50' : 'border-slate-700'}`}
                            />
                            {selectedCompanyData ? (
                                <button onClick={handleClearCompany} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-red-400"><X className="w-4 h-4" /></button>
                            ) : (
                                <Search className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 pointer-events-none" />
                            )}
                        </div>

                        {/* Dropdown */}
                        {isCompanyDropdownOpen && (
                            <div className="absolute top-full left-0 right-0 mt-2 max-h-60 overflow-y-auto bg-slate-800 border border-slate-700 rounded-xl shadow-2xl z-50 custom-scrollbar">
                                {filteredCompanies.length > 0 ? (
                                    filteredCompanies.map(c => (
                                        <div key={c.id} onClick={() => handleSelectCompany(c)} className="px-4 py-3 hover:bg-slate-700 cursor-pointer border-b border-slate-700/50 last:border-0 group">
                                            <div className="flex justify-between items-center">
                                                <span className="text-sm text-slate-200 font-bold group-hover:text-white">{c.name}</span>
                                                {getHazardBadge(c.hazardClass)}
                                            </div>
                                            <div className="text-xs text-slate-500 mt-1 flex items-center space-x-2">
                                                 <span>{c.assignedDoctor.split(' ')[0]}...</span>
                                                 <span className="w-1 h-1 rounded-full bg-slate-600"></span>
                                                 <span>{c.defaultPaymentMethod === 'CASH' ? 'Nakit' : 'Fatura'}</span>
                                            </div>
                                        </div>
                                    ))
                                ) : <div className="p-4 text-sm text-slate-500 text-center">Sonuç bulunamadı.</div>}
                            </div>
                        )}
                    </div>

                    {selectedCompanyData && (
                        <div className="mt-4 p-3 bg-slate-950/50 rounded-lg border border-slate-800/50">
                             <div className="flex items-center space-x-2 text-xs text-slate-400 mb-1">
                                <Stethoscope className="w-3 h-3" />
                                <span>{selectedCompanyData.assignedDoctor}</span>
                             </div>
                             <div className="flex items-center space-x-2 text-xs text-slate-400">
                                <ShieldCheck className="w-3 h-3" />
                                <span>{selectedCompanyData.assignedSpecialist}</span>
                             </div>
                        </div>
                    )}
                </div>

                {/* 2. Personel Bilgisi Kartı */}
                <div className={`bg-slate-900 border border-slate-800 rounded-xl p-5 shadow-sm transition-all duration-300 ${!selectedCompanyData ? 'opacity-50 pointer-events-none grayscale' : ''}`}>
                    <div className="flex items-center mb-4">
                        <div className="p-2 bg-emerald-500/10 rounded-lg mr-3">
                            <User className="w-5 h-5 text-emerald-500" />
                        </div>
                        <h3 className="font-bold text-slate-200">Personel Bilgisi</h3>
                    </div>

                    <div className="space-y-4">
                        <div>
                            <label className="text-[10px] uppercase font-bold text-slate-500 mb-1 block ml-1">Ad Soyad</label>
                            <input type="text" value={fullName} onChange={e => setFullName(e.target.value)} className="w-full px-4 py-2.5 bg-slate-950 border border-slate-700 rounded-lg text-white text-sm focus:border-emerald-500 outline-none placeholder-slate-600" placeholder="Örn: Ahmet Yılmaz" />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-[10px] uppercase font-bold text-slate-500 mb-1 block ml-1">TC Kimlik</label>
                                <input maxLength={11} value={tcNo} onChange={e => setTcNo(e.target.value.replace(/\D/g,''))} className="w-full px-4 py-2.5 bg-slate-950 border border-slate-700 rounded-lg text-white text-sm focus:border-emerald-500 outline-none placeholder-slate-600" placeholder="11 Haneli" />
                            </div>
                            <div>
                                <label className="text-[10px] uppercase font-bold text-slate-500 mb-1 block ml-1">Doğum Tarihi</label>
                                <div className="relative">
                                    <input type="date" value={birthDate} onChange={e => setBirthDate(e.target.value)} className="w-full px-4 py-2.5 bg-slate-950 border border-slate-700 rounded-lg text-white text-sm focus:border-emerald-500 outline-none" />
                                    {isEkgMandatory && (
                                        <div className="absolute -bottom-5 right-0 text-[10px] text-indigo-400 font-bold flex items-center">
                                            <AlertCircle className="w-3 h-3 mr-1" />
                                            {patientAge} Yaş (EKG Zorunlu)
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* COLUMN 2: NE? (Tetkikler) - %45 */}
            <div className={`lg:col-span-5 flex flex-col transition-all duration-300 ${!selectedCompanyData ? 'opacity-40 pointer-events-none' : ''}`}>
                <div className="bg-slate-900 border border-slate-800 rounded-xl p-1 h-full flex flex-col shadow-sm">
                    <div className="p-4 border-b border-slate-800 flex justify-between items-center">
                        <h3 className="font-bold text-slate-200 flex items-center">
                            <span className="w-2 h-2 rounded-full bg-indigo-500 mr-2"></span>
                            İstenen Tetkikler
                        </h3>
                        <div className="text-xs text-slate-500">
                            {selectedExamIds.length} adet seçildi
                        </div>
                    </div>

                    <div className="p-4 flex-1 overflow-y-auto custom-scrollbar">
                        <div className="grid grid-cols-2 gap-3">
                            {exams.map(exam => {
                                const isSelected = selectedExamIds.includes(exam.name);
                                const isEkgAndMandatory = isEkgMandatory && exam.name === 'EKG';

                                return (
                                    <button
                                        key={exam.id}
                                        type="button"
                                        onClick={() => toggleExam(exam.name)}
                                        className={`relative group p-4 rounded-xl border text-left transition-all duration-200 flex flex-col justify-between min-h-[90px] ${
                                            isSelected 
                                            ? 'bg-blue-600 border-blue-500 shadow-lg shadow-blue-900/40 transform scale-[1.02]' 
                                            : 'bg-slate-950 border-slate-800 hover:border-slate-600 hover:bg-slate-900'
                                        }`}
                                    >
                                        <div className="flex justify-between items-start w-full">
                                            <span className={`text-sm font-bold leading-tight pr-4 ${isSelected ? 'text-white' : 'text-slate-300 group-hover:text-white'}`}>
                                                {exam.name}
                                            </span>
                                            {isSelected && (
                                                <div className="bg-white/20 p-1 rounded-full">
                                                    <Check className="w-3 h-3 text-white" />
                                                </div>
                                            )}
                                        </div>

                                        <div className="mt-2 flex items-end justify-between w-full">
                                            <span className={`text-[10px] font-mono px-1.5 py-0.5 rounded ${isSelected ? 'bg-white/20 text-white' : 'bg-slate-800 text-slate-500'}`}>
                                                {exam.code}
                                            </span>
                                            <span className={`text-sm font-bold ${isSelected ? 'text-blue-100' : 'text-slate-500'}`}>
                                                ₺{exam.price}
                                            </span>
                                        </div>

                                        {isEkgAndMandatory && (
                                            <div className="absolute -top-2 -right-2 bg-indigo-500 text-white text-[10px] font-bold px-2 py-0.5 rounded-full shadow-lg border-2 border-slate-900 flex items-center z-10">
                                                <Lock className="w-3 h-3 mr-1" />
                                                Zorunlu
                                            </div>
                                        )}
                                    </button>
                                );
                            })}
                        </div>
                    </div>
                </div>
            </div>

            {/* COLUMN 3: NEREYE & ONAY - %25 */}
            <div className={`lg:col-span-3 flex flex-col space-y-6 transition-all duration-300 ${!selectedCompanyData ? 'opacity-40 pointer-events-none' : ''}`}>

