                            className={`w-full px-4 py-3 bg-slate-950 border rounded-lg text-sm text-white outline-none appearance-none transition-colors ${isInstitutionLocked ? 'border-purple-500/50 text-purple-200' : 'border-slate-700 focus:border-purple-500'}`}
                        >
                            <option value="">Kurum Seçiniz (Serbest)</option>
                            {institutions.map(inst => <option key={inst.id} value={inst.id}>{inst.name}</option>)}
                        </select>
                        {isInstitutionLocked && <Lock className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-purple-500" />}
                    </div>
                    {isInstitutionLocked && (
                         <div className="mt-2 text-[10px] text-purple-400 font-medium">
                             * Firma anlaşması gereği kilitli.
                         </div>
                     )}
