    setReferrals(loadReferrals());
    setCompanies(loadCompanies(PREDEFINED_COMPANIES));
    setExams(loadExams(DEFAULT_EXAMS));
    setInstitutions(loadInstitutions(DEFAULT_INSTITUTIONS));
    setTransactions(loadTransactions());
    setAppSettings(loadAppSettings());
  }, []);

  // Save Effects
  useEffect(() => saveReferrals(referrals), [referrals]);
  useEffect(() => saveCompanies(companies), [companies]);
  useEffect(() => saveExams(exams), [exams]);
  useEffect(() => saveInstitutions(institutions), [institutions]);
  useEffect(() => saveTransactions(transactions), [transactions]);
  useEffect(() => saveAppSettings(appSettings), [appSettings]);

  // Handlers
  const handleCreateReferral = (referral: Referral) => {
    // 1. Add Referral (Always)
    setReferrals(prev => [referral, ...prev]);

    // 2. Add to Safe ONLY if Payment Method is CASH
    if (referral.paymentMethod === 'CASH' && referral.totalPrice && referral.totalPrice > 0) {
      const newTransaction: SafeTransaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'INCOME',
        amount: referral.totalPrice,
        description: `Sevk Geliri (Nakit): ${referral.employee.fullName} (${referral.employee.company})`,
        date: new Date().toISOString()
      };
      setTransactions(prev => [...prev, newTransaction]);
    }

    // Redirect back to referrals list after creation
    setActiveTab('referrals');
  };

  const handleUpdateStatus = (id: string, newStatus: Status) => {
    setReferrals(prev => prev.map(r => 
      r.id === id ? { ...r, status: newStatus } : r
    ));
  };

  const handleDelete = (id: string) => {
    if(window.confirm('Bu kaydı silmek istediğinize emin misiniz?')) {
      setReferrals(prev => prev.filter(r => r.id !== id));
    }
  };

  // Settings Handlers
  const handleAddCompany = (c: Company) => setCompanies(prev => [...prev, c]);
  const handleDeleteCompany = (id: string) => setCompanies(prev => prev.filter(c => c.id !== id));
  // New Bulk Delete Handler
  const handleBulkDeleteCompanies = (ids: string[]) => {
      setCompanies(prev => prev.filter(c => !ids.includes(c.id)));
  };

  const handleAddExam = (e: ExamDefinition) => setExams(prev => [...prev, e]);
  const handleUpdateExam = (updated: ExamDefinition) => setExams(prev => prev.map(e => e.id === updated.id ? updated : e));
  const handleDeleteExam = (id: string) => setExams(prev => prev.filter(e => e.id !== id));

  const handleAddInstitution = (i: MedicalInstitution) => setInstitutions(prev => [...prev, i]);
  const handleDeleteInstitution = (id: string) => setInstitutions(prev => prev.filter(i => i.id !== id));

  const handleUpdateSettings = (newSettings: AppSettings) => setAppSettings(newSettings);

  // Finance Handlers
  const handleAddTransaction = (t: SafeTransaction) => setTransactions(prev => [...prev, t]);

  const filteredReferrals = useMemo(() => {
    return referrals.filter(r => 
      r.employee.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.company.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.employee.tcNo.includes(searchTerm)
    );
  }, [referrals, searchTerm]);

  const stats = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    const totalIncome = transactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);

    return {
      total: referrals.length,
      today: referrals.filter(r => r.referralDate.startsWith(todayStr)).length,
      totalIncome: totalIncome
    };
  }, [referrals, transactions]);

  // Handle nav click (close mobile menu)
  const handleNavClick = (tab: typeof activeTab) => {
      setActiveTab(tab);
      setIsMobileMenuOpen(false);
  };

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden">

      {/* Mobile Sidebar Overlay */}
      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden backdrop-blur-sm"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 border-r border-slate-800 text-white flex flex-col shadow-xl transition-transform duration-300 md:relative md:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} print:hidden`}>
        <div className="p-6 flex items-center justify-between border-b border-slate-800">
          <div className="flex items-center space-x-3">
            {appSettings.companyLogo ? (
               <img src={appSettings.companyLogo} alt="Logo" className="w-10 h-10 object-contain rounded bg-white p-0.5" />
            ) : (
               <div className="p-2 bg-blue-600 rounded-lg shadow-lg shadow-blue-900/20">
                  <Stethoscope className="w-6 h-6 text-white" />
               </div>
            )}
            <div>
                <h1 className="text-xl font-bold tracking-tight">OSGB Pro</h1>
                <p className="text-xs text-slate-400">Tetkik Takip Sistemi</p>
            </div>
          </div>
          <button onClick={() => setIsMobileMenuOpen(false)} className="md:hidden text-slate-400 hover:text-white">
            <X className="w-6 h-6" />
          </button>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => handleNavClick('dashboard')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'dashboard' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            <span className="font-medium">Genel Bakış</span>
          </button>

          <button 
            onClick={() => handleNavClick('referrals')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'referrals' || activeTab === 'create_referral' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Users className="w-5 h-5" />
            <span className="font-medium">Personel Takibi</span>
          </button>

          <button 
            onClick={() => handleNavClick('finance')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'finance' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Wallet className="w-5 h-5" />
            <span className="font-medium">Kasa & Finans</span>
          </button>

          <button 
            onClick={() => handleNavClick('settings')}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${activeTab === 'settings' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Settings className="w-5 h-5" />
            <span className="font-medium">Ayarlar</span>
          </button>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative bg-slate-950">
        {/* Header */}
        <header className="h-16 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-4 md:px-8 shadow-sm z-10 print:hidden shrink-0">
          <div className="flex items-center">
              <button 
                onClick={() => setIsMobileMenuOpen(true)}
                className="mr-4 md:hidden text-slate-400 hover:text-white p-1 rounded-lg hover:bg-slate-800 transition-colors"
              >
                  <Menu className="w-6 h-6" />
              </button>
              <h2 className="text-lg md:text-xl font-semibold text-white truncate">
                {activeTab === 'dashboard' ? 'Kontrol Paneli' : 
                 activeTab === 'referrals' ? 'Tetkik & Sevk Listesi' : 
                 activeTab === 'create_referral' ? 'Yeni Sevk Girişi' :
                 activeTab === 'finance' ? 'Kasa Yönetimi' : 'Ayarlar'}
              </h2>
          </div>

          <div className="flex items-center space-x-4">
            {activeTab !== 'create_referral' && (
              <>
                <div className="relative hidden md:block">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400 w-4 h-4" />
                  <input 
                    type="text"
                    placeholder="Personel veya Firma ara..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent w-64 transition-all placeholder-slate-500"
                  />
                </div>
                <button 
                  onClick={() => setActiveTab('create_referral')}
                  className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-500 text-white px-3 py-2 md:px-4 md:py-2 rounded-lg text-sm font-medium transition-colors shadow-lg shadow-blue-900/20 active:transform active:scale-95 whitespace-nowrap"
                >
                  <Plus className="w-4 h-4" />
                  <span className="hidden md:inline">Yeni Sevk Oluştur</span>
                  <span className="md:hidden">Yeni Sevk</span>
                </button>
              </>
            )}
          </div>
        </header>

        {/* Content Area - DYNAMIC PADDING ADJUSTMENT HERE */}
        <div className={`flex-1 ${activeTab === 'create_referral' ? 'overflow-hidden p-0' : 'overflow-auto p-4 md:p-8 custom-scrollbar'} print:p-0 print:overflow-visible`}>
          <Suspense fallback={<PageLoader />}>
            {activeTab === 'dashboard' && (
              <div className="space-y-6">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-4 gap-3 md:gap-0">
                  <h3 className="text-lg font-bold text-white hidden md:block">Günlük Özet</h3>
                  <button 
                    onClick={() => setIsReportModalOpen(true)}
                    className="w-full md:w-auto flex items-center justify-center space-x-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-lg"
                  >
                    <FileText className="w-4 h-4" />
                    <span>Gün Sonu Raporu Al (Z Raporu)</span>
                  </button>
                </div>

                <StatsCards stats={stats} />

                <div className="mt-8">
                  <h3 className="text-lg font-bold text-white mb-4 flex items-center">
                    <Activity className="w-5 h-5 mr-2 text-blue-500" />
                    Son Hareketler
                  </h3>
                  <ReferralList 
                    referrals={filteredReferrals.slice(0, 5)} 
                    institutions={institutions}
                    onUpdateStatus={handleUpdateStatus} 
                    onDelete={handleDelete}
                    compact
                  />
                </div>
              </div>
            )}

            {activeTab === 'referrals' && (
              <div className="h-full flex flex-col">
                <ReferralList 
                    referrals={filteredReferrals} 
                    institutions={institutions}
                    onUpdateStatus={handleUpdateStatus} 
                    onDelete={handleDelete}
                  />
              </div>
            )}

            {activeTab === 'create_referral' && (
              <NewReferralView
                onClose={() => setActiveTab('referrals')}
                onSubmit={handleCreateReferral}
                companies={companies}
                exams={exams}
                institutions={institutions}
                settings={appSettings}
              />
            )}

            {activeTab === 'finance' && (
              <FinanceView 
                transactions={transactions}
                onAddTransaction={handleAddTransaction}
              />
            )}

            {activeTab === 'settings' && (
              <SettingsView 
                  companies={companies}
                  onAddCompany={handleAddCompany}
                  onDeleteCompany={handleDeleteCompany}
                  onBulkDeleteCompanies={handleBulkDeleteCompanies}
                  exams={exams}
                  onAddExam={handleAddExam}
                  onUpdateExam={handleUpdateExam}
                  onDeleteExam={handleDeleteExam}
                  institutions={institutions}
                  onAddInstitution={handleAddInstitution}
                  onDeleteInstitution={handleDeleteInstitution}
                  settings={appSettings}
                  onUpdateSettings={handleUpdateSettings}
              />
            )}
          </Suspense>
        </div>
      </main>

      {/* End of Day Report Modal - Still a modal */}
      {isReportModalOpen && (
        <EndOfDayReportModal
          onClose={() => setIsReportModalOpen(false)}
          referrals={referrals}
          transactions={transactions}
          settings={appSettings}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { ArrowLeft, Building2, User, Stethoscope, ShieldCheck, Wallet, Receipt, Save, Search, Check, ChevronDown, X, MapPin, Lock, Info, AlertCircle, Calendar } from 'lucide-react';
import { Referral, Status, Company, HazardClass, ExamDefinition, MedicalInstitution, AppSettings } from '../types';

interface NewReferralViewProps {
  onClose: () => void;
  onSubmit: (referral: Referral) => void;
  companies: Company[];
  exams: ExamDefinition[];
  institutions: MedicalInstitution[];
  settings: AppSettings;
}

export const NewReferralView: React.FC<NewReferralViewProps> = ({ onClose, onSubmit, companies, exams, institutions, settings }) => {
  // --- STATE MANAGEMENT ---

  // Personel State
  const [fullName, setFullName] = useState('');
  const [tcNo, setTcNo] = useState('');
  const [birthDate, setBirthDate] = useState('');

  // Company Search State
  const [companySearchTerm, setCompanySearchTerm] = useState('');
  const [isCompanyDropdownOpen, setIsCompanyDropdownOpen] = useState(false);
  const [selectedCompanyData, setSelectedCompanyData] = useState<Company | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Institution & Exam State
  const [selectedInstitutionId, setSelectedInstitutionId] = useState<string>('');
  const [isInstitutionLocked, setIsInstitutionLocked] = useState(false);
  const [selectedExamIds, setSelectedExamIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');

  // Financial State
  const [estimatedPrice, setEstimatedPrice] = useState(0);
  const [estimatedCost, setEstimatedCost] = useState(0);
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');

  // --- LOGIC & EFFECTS ---

  // Validation
  const isFormValid = fullName.length >= 3 && tcNo.length === 11 && birthDate !== '' && selectedCompanyData !== null && selectedExamIds.length > 0;

  // Age Calculation
  const patientAge = useMemo(() => {
     if(!birthDate) return 0;
     const today = new Date();
     const birth = new Date(birthDate);
     let age = today.getFullYear() - birth.getFullYear();
     const m = today.getMonth() - birth.getMonth();
     if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
        age--;
     }
     return age;
  }, [birthDate]);

  // Mandatory EKG
  const isEkgMandatory = patientAge >= settings.ekgLimitAge;

  useEffect(() => {
     if (isEkgMandatory) {
        const ekgExamName = 'EKG';
        if (!selectedExamIds.includes(ekgExamName)) {
            setSelectedExamIds(prev => [...prev, ekgExamName]);
        }
     }
  }, [isEkgMandatory, selectedExamIds]);

  // Search Filters
  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(companySearchTerm.toLowerCase())
  );

  // Dropdown Click Outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCompanyDropdownOpen(false);
        if (selectedCompanyData) setCompanySearchTerm(selectedCompanyData.name);
        else setCompanySearchTerm('');
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [selectedCompanyData]);

  // Price Calculation
  useEffect(() => {
    let totalPrice = 0;
    let totalCost = 0;
    selectedExamIds.forEach(id => {
      const exam = exams.find(e => e.name === id);
      if (exam) {
        totalPrice += exam.price;
        totalCost += (exam.cost || 0);
      }
    });
    setEstimatedPrice(totalPrice);
    setEstimatedCost(totalCost);
  }, [selectedExamIds, exams]);

  // Handlers
  const handleSelectCompany = (company: Company) => {
      setSelectedCompanyData(company);
      setCompanySearchTerm(company.name);
      setIsCompanyDropdownOpen(false);

      // Load Defaults
      setSelectedExamIds(company.defaultExams);

      // Set Payment Method based on Company Settings (LOCKED)
      setPaymentMethod(company.defaultPaymentMethod || 'INVOICE');

      // Handle Institution Logic
      if (company.forcedInstitutionId) {
          setSelectedInstitutionId(company.forcedInstitutionId);
          setIsInstitutionLocked(true);
      } else {
          setSelectedInstitutionId('');
          setIsInstitutionLocked(false);
      }
  };

  const handleClearCompany = () => {
      setSelectedCompanyData(null);
      setCompanySearchTerm('');
      setSelectedExamIds([]);
      setSelectedInstitutionId('');
      setIsInstitutionLocked(false);
  };

  const toggleExam = (examName: string) => {
    if (isEkgMandatory && examName === 'EKG') return;
    setSelectedExamIds(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isFormValid) return;

    const newReferral: Referral = {
      id: Math.random().toString(36).substr(2, 9),
      employee: {
        id: Math.random().toString(36).substr(2, 9),
        fullName,
        tcNo,
        birthDate,
        company: selectedCompanyData!.name
      },
      exams: selectedExamIds,
      status: Status.PENDING,
      referralDate: new Date().toISOString(),
      notes,
      doctorName: selectedCompanyData!.assignedDoctor,
      specialistName: selectedCompanyData!.assignedSpecialist,
      totalPrice: estimatedPrice,
      totalCost: estimatedCost,
      paymentMethod: paymentMethod,
      targetInstitutionId: selectedInstitutionId || undefined
    };
    onSubmit(newReferral);
  };

  const getHazardBadge = (hazard: HazardClass) => {
    const styles = {
        [HazardClass.VERY_DANGEROUS]: 'bg-red-500 text-white',
        [HazardClass.DANGEROUS]: 'bg-orange-500 text-white',
        [HazardClass.LESS]: 'bg-emerald-500 text-white'
    };
    return (
        <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider ${styles[hazard]}`}>
            {hazard}
        </span>
    );
  };

  return (
    <div className="h-full flex flex-col bg-slate-950 relative overflow-hidden">

      {/* Header */}
      <div className="flex items-center justify-between px-4 py-3 border-b border-slate-800 bg-slate-900 shrink-0 h-16">
        <div className="flex items-center space-x-3">
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 hover:text-white transition-colors">
              <ArrowLeft className="w-5 h-5" />
          </button>
          <div>
              <h1 className="text-lg font-bold text-white tracking-tight">Yeni Sevk Girişi</h1>
              <p className="text-xs text-slate-400">Tek ekranda hızlı sevk oluşturma modülü</p>
          </div>
        </div>

        {/* Quick Tips */}
        <div className="hidden md:flex items-center space-x-4 text-xs text-slate-500">
           <div className="flex items-center"><span className="w-2 h-2 rounded-full bg-blue-500 mr-2"></span>Firma Varsayılanları</div>
           <div className="flex items-center"><span className="w-2 h-2 rounded-full bg-indigo-500 mr-2"></span>Zorunlu Tetkikler</div>
        </div>
      </div>

      {/* Main Grid Content */}
      <div className="flex-1 p-4 overflow-hidden min-h-0">
        <div className="h-full grid grid-cols-1 lg:grid-cols-12 gap-4">

            {/* COLUMN 1: KİM? (Personel ve Firma) - %30 */}
            <div className="lg:col-span-4 flex flex-col space-y-4 overflow-y-auto custom-scrollbar pr-1 min-h-0">

                {/* 1. Firma Seçimi Kartı */}
                <div className="bg-slate-900 border border-slate-800 rounded-xl p-4 shadow-sm shrink-0">
                    <div className="flex items-center mb-3">
                        <div className="p-1.5 bg-blue-500/10 rounded-lg mr-2">
                            <Building2 className="w-4 h-4 text-blue-500" />
                        </div>
                        <h3 className="font-bold text-slate-200 text-sm">Firma Bilgisi</h3>
                    </div>

                    <div className="relative" ref={dropdownRef}>
                        <div className="relative">
                            <input
                                autoFocus
                                type="text"
                                value={companySearchTerm}
                                onChange={(e) => {
                                    setCompanySearchTerm(e.target.value);
                                    setIsCompanyDropdownOpen(true);
                                    if(selectedCompanyData && e.target.value !== selectedCompanyData.name) setSelectedCompanyData(null);
                                }}
                                onClick={() => setIsCompanyDropdownOpen(true)}
                                placeholder="Firma adı yazın..."
                                className={`w-full pl-3 pr-8 py-2.5 bg-slate-950 border text-white text-sm rounded-lg focus:ring-2 focus:ring-blue-600 outline-none transition-all font-medium ${selectedCompanyData ? 'border-blue-500/50' : 'border-slate-700'}`}
                            />
                            {selectedCompanyData ? (
                                <button onClick={handleClearCompany} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400 hover:text-red-400"><X className="w-3.5 h-3.5" /></button>
                            ) : (
                                <Search className="absolute right-2 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-600 pointer-events-none" />
                            )}
                        </div>

                        {/* Dropdown */}
                        {isCompanyDropdownOpen && (
                            <div className="absolute top-full left-0 right-0 mt-1 max-h-56 overflow-y-auto bg-slate-800 border border-slate-700 rounded-lg shadow-2xl z-50 custom-scrollbar">
                                {filteredCompanies.length > 0 ? (
                                    filteredCompanies.map(c => (
                                        <div key={c.id} onClick={() => handleSelectCompany(c)} className="px-3 py-2.5 hover:bg-slate-700 cursor-pointer border-b border-slate-700/50 last:border-0 group">
                                            <div className="flex justify-between items-center">
                                                <span className="text-sm text-slate-200 font-bold group-hover:text-white truncate max-w-[180px]">{c.name}</span>
                                                {getHazardBadge(c.hazardClass)}
                                            </div>
                                            <div className="text-xs text-slate-500 mt-0.5 flex items-center space-x-2">
                                                 <span>{c.assignedDoctor.split(' ')[0]}...</span>
                                                 <span className="w-0.5 h-0.5 rounded-full bg-slate-600"></span>
                                                 <span>{c.defaultPaymentMethod === 'CASH' ? 'Nakit' : 'Fatura'}</span>
                                            </div>
                                        </div>
                                    ))
                                ) : <div className="p-3 text-xs text-slate-500 text-center">Sonuç bulunamadı.</div>}
                            </div>
                        )}
                    </div>

                    {selectedCompanyData && (
                        <div className="mt-3 p-2 bg-slate-950/50 rounded-lg border border-slate-800/50">
                             <div className="flex items-center space-x-2 text-[11px] text-slate-400 mb-1">
                                <Stethoscope className="w-3 h-3" />
                                <span className="truncate">{selectedCompanyData.assignedDoctor}</span>
                             </div>
                             <div className="flex items-center space-x-2 text-[11px] text-slate-400">
                                <ShieldCheck className="w-3 h-3" />
                                <span className="truncate">{selectedCompanyData.assignedSpecialist}</span>
                             </div>
                        </div>
                    )}
                </div>

                {/* 2. Personel Bilgisi Kartı */}
                <div className={`bg-slate-900 border border-slate-800 rounded-xl p-4 shadow-sm transition-all duration-300 shrink-0 ${!selectedCompanyData ? 'opacity-50 pointer-events-none grayscale' : ''}`}>
                    <div className="flex items-center mb-3">
                        <div className="p-1.5 bg-emerald-500/10 rounded-lg mr-2">
                            <User className="w-4 h-4 text-emerald-500" />
                        </div>
                        <h3 className="font-bold text-slate-200 text-sm">Personel Bilgisi</h3>
                    </div>

                    <div className="space-y-3">
                        <div>
                            <label className="text-[10px] uppercase font-bold text-slate-500 mb-1 block ml-1">Ad Soyad</label>
