import React from 'react';
import { 
  Trash2,
  MapPin,
  Building2,
  FileText,
  CalendarDays
} from 'lucide-react';
import { Referral, Status, MedicalInstitution } from '../types';

interface ReferralListProps {
  referrals: Referral[];
  institutions?: MedicalInstitution[];
  onUpdateStatus?: (id: string, status: Status) => void;
  onDelete: (id: string) => void;
  compact?: boolean;
}

export const ReferralList: React.FC<ReferralListProps> = ({ 
  referrals, 
  institutions = [],
  onDelete,
  compact = false 
}) => {

  const getInstitutionName = (id?: string) => {
    if (!id) return null;
    return institutions.find(i => i.id === id)?.name || "Bilinmeyen Kurum";
  };

  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map(part => part[0])
      .slice(0, 2)
      .join('')
      .toUpperCase();
  };

  const getAvatarColor = (name: string) => {
    const colors = [
      'bg-blue-500', 'bg-emerald-500', 'bg-violet-500', 'bg-amber-500', 'bg-rose-500', 'bg-cyan-500'
    ];
    let hash = 0;
    for (let i = 0; i < name.length; i++) {
      hash = name.charCodeAt(i) + ((hash << 5) - hash);
    }
    return colors[Math.abs(hash) % colors.length];
  };

  if (referrals.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-slate-500 bg-slate-800/50 rounded-xl border border-dashed border-slate-700">
        <div className="p-4 bg-slate-800 rounded-full mb-3">
            <FileText className="w-8 h-8 opacity-50" />
        </div>
        <p className="font-medium">Kayıt bulunamadı.</p>
        <p className="text-xs mt-1">Arama kriterlerini değiştirin veya yeni sevk oluşturun.</p>
      </div>
    );
  }

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden flex flex-col h-full">
      <div className="overflow-x-auto custom-scrollbar flex-1">
        <table className="w-full text-left border-collapse">
          <thead className="sticky top-0 z-10 bg-slate-900 border-b border-slate-700 shadow-sm">
            <tr>
              <th className="px-4 py-3 text-xs font-bold text-slate-400 uppercase tracking-wider w-1/4">Personel</th>
              <th className="px-4 py-3 text-xs font-bold text-slate-400 uppercase tracking-wider">Firma & Kurum</th>
              <th className="px-4 py-3 text-xs font-bold text-slate-400 uppercase tracking-wider">Tarih</th>
              {!compact && <th className="px-4 py-3 text-xs font-bold text-slate-400 uppercase tracking-wider">Tetkikler</th>}
              <th className="px-4 py-3 text-xs font-bold text-slate-400 uppercase tracking-wider text-right">Tutar</th>
              <th className="px-4 py-3 w-10"></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-700/50 bg-slate-800">
            {referrals.map((referral) => {
               const instName = getInstitutionName(referral.targetInstitutionId);
               return (
              <tr key={referral.id} className="hover:bg-slate-700/30 transition-colors group">
                {/* Personel */}
                <td className="px-4 py-2.5">
                  <div className="flex items-center space-x-3">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-[10px] font-bold text-white shadow-lg ${getAvatarColor(referral.employee.fullName)}`}>
                        {getInitials(referral.employee.fullName)}
                    </div>
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-200 text-sm">{referral.employee.fullName}</span>
                      <span className="text-[11px] text-slate-500 font-mono tracking-wide">{referral.employee.tcNo}</span>
                    </div>
                  </div>
                </td>

                {/* Firma & Kurum */}
                <td className="px-4 py-2.5">
                  <div className="flex flex-col space-y-1">
                      <div className="flex items-center space-x-1.5">
                         <Building2 className="w-3.5 h-3.5 text-slate-500" />
                         <span className="text-sm text-slate-300 font-medium truncate max-w-[150px]" title={referral.employee.company}>{referral.employee.company}</span>
                      </div>
                      {!compact && (
                        <div className="flex items-center space-x-1.5">
                            <MapPin className="w-3.5 h-3.5 text-slate-600" />
                            <span className={`text-xs truncate max-w-[150px] ${instName ? 'text-slate-400' : 'text-slate-600 italic'}`}>
                                {instName || 'Kurum Yok'}
                            </span>
                        </div>
                      )}
                  </div>
                </td>

                {/* Tarih */}
                <td className="px-4 py-2.5">
                    <div className="flex items-center space-x-2 text-slate-400">
                        <CalendarDays className="w-4 h-4 text-slate-600" />
                        <span className="text-xs font-medium">{new Date(referral.referralDate).toLocaleDateString('tr-TR')}</span>
                    </div>
                </td>

                {/* Tetkikler (Full View Only) */}
                {!compact && (
                    <td className="px-4 py-2.5">
                        <div className="flex flex-wrap gap-1 max-w-[200px]">
                            {referral.exams.slice(0, 3).map((exam, i) => (
                            <span key={i} className="inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-medium bg-slate-900 text-slate-400 border border-slate-700">
                                {exam}
                            </span>
                            ))}
                            {referral.exams.length > 3 && (
                            <span className="inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-medium bg-slate-800 text-slate-500">
                                +{referral.exams.length - 3}
                            </span>
                            )}
                        </div>
                    </td>
                )}

                {/* Tutar */}
                <td className="px-4 py-2.5 text-right">
                  <div className="flex flex-col items-end">
                    <span className="text-white font-bold text-sm">₺{referral.totalPrice?.toLocaleString('tr-TR') || 0}</span>
                    <span className={`text-[9px] uppercase font-bold tracking-wider px-1 py-0.5 rounded ${referral.paymentMethod === 'CASH' ? 'text-emerald-400 bg-emerald-500/10' : 'text-blue-400 bg-blue-500/10'}`}>
                      {referral.paymentMethod === 'CASH' ? 'Nakit' : 'Fatura'}
                    </span>
                  </div>
                </td>

                {/* Actions */}
                <td className="px-4 py-2.5 text-right">
                    <button 
                        onClick={() => onDelete(referral.id)}
                        className="text-slate-600 hover:text-red-400 hover:bg-red-500/10 p-1.5 rounded-lg transition-all opacity-0 group-hover:opacity-100"
                        title="Kaydı Sil"
                    >
                        <Trash2 className="w-4 h-4" />
                    </button>
                </td>
              </tr>
            )})}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Company, ExamDefinition, HazardClass, MedicalInstitution, AppSettings } from '../types';
import { Trash2, Plus, Building2, TestTube, Save, Check, Wallet, Receipt, Upload, FileDown, AlertCircle, MapPin, Sliders, CheckSquare, Square, Image as ImageIcon, Edit2, XCircle } from 'lucide-react';
import * as XLSX from 'xlsx';

interface SettingsViewProps {
  companies: Company[];
  onAddCompany: (c: Company) => void;
  onUpdateCompany: (c: Company) => void;
  onDeleteCompany: (id: string) => void;
  onBulkDeleteCompanies: (ids: string[]) => void;
  exams: ExamDefinition[];
  onAddExam: (e: ExamDefinition) => void;
  onUpdateExam: (e: ExamDefinition) => void;
  onDeleteExam: (id: string) => void;
  institutions: MedicalInstitution[];
  onAddInstitution: (i: MedicalInstitution) => void;
  onDeleteInstitution: (id: string) => void;
  settings: AppSettings;
  onUpdateSettings: (s: AppSettings) => void;
}

export const SettingsView: React.FC<SettingsViewProps> = ({
  companies,
  onAddCompany,
  onUpdateCompany,
  onDeleteCompany,
  onBulkDeleteCompanies,
  exams,
  onAddExam,
  onUpdateExam,
  onDeleteExam,
  institutions,
  onAddInstitution,
  onDeleteInstitution,
  settings,
  onUpdateSettings
}) => {
  const [activeTab, setActiveTab] = useState<'general' | 'companies' | 'exams' | 'institutions'>('general');

  // General Settings State
  const [ekgAgeLimit, setEkgAgeLimit] = useState(settings.ekgLimitAge);
  const [logo, setLogo] = useState<string | undefined>(settings.companyLogo);

  // Company Form State
  const [editingCompanyId, setEditingCompanyId] = useState<string | null>(null);
  const [cName, setCName] = useState('');
  const [cHazard, setCHazard] = useState<HazardClass>(HazardClass.LESS);
  const [cDoctor, setCDoctor] = useState('');
  const [cSpecialist, setCSpecialist] = useState('');
  const [cPaymentMethod, setCPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');
  const [cSelectedExams, setCSelectedExams] = useState<string[]>([]);
  const [cPreferredInst, setCPreferredInst] = useState<string>(''); // For forced institution

  // Company Selection State (Bulk Delete)
  const [selectedCompanyIds, setSelectedCompanyIds] = useState<string[]>([]);

  // File Import Ref
  const fileInputRef = useRef<HTMLInputElement>(null);
  const logoInputRef = useRef<HTMLInputElement>(null);

  // Exam Form State
  const [eName, setEName] = useState('');
  const [eCode, setECode] = useState('');
  const [ePrice, setEPrice] = useState('');
  const [eCost, setECost] = useState(''); // New Cost State

  // Institution Form State
  const [iName, setIName] = useState('');
  const [iPhone, setIPhone] = useState('');

  const toggleCompanyExam = (examName: string) => {
    setCSelectedExams(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const handleUpdateGeneralSettings = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdateSettings({ 
        ...settings, 
        ekgLimitAge: ekgAgeLimit,
        companyLogo: logo 
    });
    alert("Ayarlar güncellendi.");
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2000000) { // 2MB limit
          alert("Logo dosyası 2MB'dan küçük olmalıdır.");
          return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setLogo(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemoveLogo = () => {
      setLogo(undefined);
      if(logoInputRef.current) logoInputRef.current.value = '';
  };

  // Populate form for editing
  const handleEditCompany = (company: Company) => {
    setEditingCompanyId(company.id);
    setCName(company.name);
    setCHazard(company.hazardClass);
    setCDoctor(company.assignedDoctor);
    setCSpecialist(company.assignedSpecialist);
    setCPaymentMethod(company.defaultPaymentMethod);
    setCSelectedExams(company.defaultExams);
    setCPreferredInst(company.forcedInstitutionId || '');
    // Scroll to form (simple implementation)
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleCancelEdit = () => {
    setEditingCompanyId(null);
    setCName('');
    setCDoctor('');
    setCSpecialist('');
    setCPaymentMethod('INVOICE');
    setCSelectedExams([]);
    setCPreferredInst('');
  };

  const handleCompanySubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!cName) return;

    if (editingCompanyId) {
      // UPDATE Existing
      const updatedCompany: Company = {
        id: editingCompanyId,
        name: cName,
        hazardClass: cHazard,
        assignedDoctor: cDoctor || 'Belirlenmedi',
        assignedSpecialist: cSpecialist || 'Belirlenmedi',
        defaultExams: cSelectedExams,
        defaultPaymentMethod: cPaymentMethod,
        forcedInstitutionId: cPreferredInst || undefined
      };
      onUpdateCompany(updatedCompany);
      handleCancelEdit(); // Reset form
    } else {
      // ADD New
      const newCompany: Company = {
        id: Math.random().toString(36).substr(2, 9),
        name: cName,
        hazardClass: cHazard,
        assignedDoctor: cDoctor || 'Belirlenmedi',
        assignedSpecialist: cSpecialist || 'Belirlenmedi',
        defaultExams: cSelectedExams,
        defaultPaymentMethod: cPaymentMethod,
        forcedInstitutionId: cPreferredInst || undefined
      };
      onAddCompany(newCompany);
      handleCancelEdit(); // Reset form using same helper
    }
  };

  const handleAddInstitution = (e: React.FormEvent) => {
    e.preventDefault();
    if(!iName) return;
    const newInst: MedicalInstitution = {
      id: Math.random().toString(36).substr(2, 9),
      name: iName,
      phone: iPhone
    };
    onAddInstitution(newInst);
    setIName('');
    setIPhone('');
  };

  // Bulk Delete Logic
  const handleToggleSelectCompany = (id: string) => {
    setSelectedCompanyIds(prev => 
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  const handleSelectAllCompanies = () => {
    if (selectedCompanyIds.length === companies.length) {
      setSelectedCompanyIds([]);
    } else {
      setSelectedCompanyIds(companies.map(c => c.id));
    }
  };

  const handleBulkDelete = () => {
    if (selectedCompanyIds.length === 0) return;
    if (window.confirm(`Seçili ${selectedCompanyIds.length} firmayı silmek istediğinize emin misiniz?`)) {
      onBulkDeleteCompanies(selectedCompanyIds);
      setSelectedCompanyIds([]);
    }
  };

  // --- Bulk Import / Template Logic (Excel .xlsx) ---

  const downloadTemplate = () => {
    // Sheet 1: Firmalar (Template to fill)
    const headers = ["Firma Adı", "Tehlike Sınıfı (Az/Tehlikeli/Çok)", "Hekim Adı", "Uzman Adı", "Ödeme (Nakit/Fatura)", "Tetkik Kodları (Virgül ile)"];
    const exampleRow = ["Örnek Metal A.Ş.", "Tehlikeli", "Dr. Ahmet Yılmaz", "Uzm. Ayşe Demir", "Fatura", "101, 103, 105"];
    const wsFirmalar = XLSX.utils.aoa_to_sheet([headers, exampleRow]);

    wsFirmalar['!cols'] = [
      { wch: 30 }, // Firma Adı
      { wch: 25 }, // Tehlike
      { wch: 20 }, // Hekim
      { wch: 20 }, // Uzman
      { wch: 20 }, // Ödeme
      { wch: 30 }  // Tetkik Kodları
    ];

    // Sheet 2: Tetkik Referans (Read-only reference)
    const refHeaders = ["Tetkik Kodu", "Tetkik Adı", "Satış Fiyatı", "Maliyet"];
    const refRows = exams.map(e => [e.code, e.name, e.price, e.cost || 0]);
    const wsRef = XLSX.utils.aoa_to_sheet([refHeaders, ...refRows]);
    wsRef['!cols'] = [{ wch: 15 }, { wch: 30 }, { wch: 10 }, { wch: 10 }];

    // Create Workbook
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, wsFirmalar, "Firma_Listesi");
    XLSX.utils.book_append_sheet(wb, wsRef, "Tetkik_Referans_Listesi");

    // Write file
    XLSX.writeFile(wb, "firma_yukleme_sablonu.xlsx");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();

    reader.onload = (evt) => {
      const bstr = evt.target?.result;
      if (!bstr) return;

      try {
        const wb = XLSX.read(bstr, { type: 'binary' });

        // Use the first sheet
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        // Convert to JSON array
        const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];

        let successCount = 0;

        // Skip header row
        for (let i = 1; i < data.length; i++) {
          const row = data[i];
          if (!row || row.length === 0 || !row[0]) continue;

          const name = String(row[0]).trim();
          const hazardRaw = String(row[1] || '').toLowerCase();
          const doctor = String(row[2] || 'Belirlenmedi').trim();
          const specialist = String(row[3] || 'Belirlenmedi').trim();
          const paymentRaw = String(row[4] || '').toLowerCase();
          const examCodesStr = String(row[5] || '').trim();

          // Hazard Class
          let hazard = HazardClass.LESS;
          if (hazardRaw.includes('çok') || hazardRaw.includes('cok')) hazard = HazardClass.VERY_DANGEROUS;
          else if (hazardRaw.includes('az')) hazard = HazardClass.LESS;
          else if (hazardRaw.includes('tehlikeli')) hazard = HazardClass.DANGEROUS;

          // Payment
          let payment: 'CASH' | 'INVOICE' = 'INVOICE';
          if (paymentRaw.includes('nakit') || paymentRaw.includes('elden') || paymentRaw.includes('kasa')) {
            payment = 'CASH';
          }

          // Process Exam Codes (e.g., "101, 105") -> Match to Exam Names
          const requestedCodes = examCodesStr.split(',').map(s => s.trim()).filter(s => s !== '');
          const matchedExams = exams
            .filter(e => requestedCodes.includes(e.code) || requestedCodes.includes(e.code.toString()))
            .map(e => e.name);

          const newComp: Company = {
            id: Math.random().toString(36).substr(2, 9),
            name: name,
            hazardClass: hazard,
            assignedDoctor: doctor,
            assignedSpecialist: specialist,
            defaultPaymentMethod: payment,
            defaultExams: matchedExams 
          };

          onAddCompany(newComp);
          successCount++;
        }

        alert(`${successCount} adet firma ve ilişkili tetkikleri başarıyla yüklendi.`);
      } catch (error) {
        console.error("Excel okuma hatası:", error);
        alert("Dosya okunurken bir hata oluştu.");
      } finally {
        if(fileInputRef.current) fileInputRef.current.value = '';
      }
    };

    reader.readAsBinaryString(file);
  };

  // --- End Bulk Import Logic ---

  const handleAddExam = (e: React.FormEvent) => {
    e.preventDefault();
    if (!eName || !ePrice || !eCode) return;

    // Check for duplicate code
    if(exams.some(ex => ex.code === eCode)) {
        alert("Bu tetkik kodu zaten kullanılıyor!");
        return;
    }

    const newExam: ExamDefinition = {
      id: Math.random().toString(36).substr(2, 9),
      code: eCode,
      name: eName,
      price: parseFloat(ePrice),
      cost: parseFloat(eCost) || 0
    };
    onAddExam(newExam);
    setEName('');
    setECode('');
    setEPrice('');
    setECost('');
  };

  const handleUpdateExamField = (id: string, field: keyof ExamDefinition, value: string) => {
    const exam = exams.find(e => e.id === id);
    if (exam) {
      const updated = { ...exam };
      if (field === 'price') updated.price = parseFloat(value);
      if (field === 'cost') updated.cost = parseFloat(value);
      if (field === 'code') updated.code = value;
      // Name update could be added here if needed
      onUpdateExam(updated);
    }
  };

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden">
      <div className="flex border-b border-slate-700 overflow-x-auto">
        <button
          onClick={() => setActiveTab('general')}
          className={`px-6 py-4 text-center font-medium text-sm transition-colors whitespace-nowrap ${activeTab === 'general' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Genel Ayarlar
        </button>
        <button
          onClick={() => setActiveTab('companies')}
          className={`px-6 py-4 text-center font-medium text-sm transition-colors whitespace-nowrap ${activeTab === 'companies' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Firmalar
        </button>
        <button
          onClick={() => setActiveTab('institutions')}
          className={`px-6 py-4 text-center font-medium text-sm transition-colors whitespace-nowrap ${activeTab === 'institutions' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Anlaşmalı Kurumlar
        </button>
        <button
          onClick={() => setActiveTab('exams')}
          className={`px-6 py-4 text-center font-medium text-sm transition-colors whitespace-nowrap ${activeTab === 'exams' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Tetkikler
        </button>
      </div>

      <div className="p-6">
        {activeTab === 'general' && (
