                            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-500 pointer-events-none" />
                            {isInstitutionLocked && <Lock className="absolute right-8 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-purple-500" />}
                        </div>
                        {isInstitutionLocked && (
                            <div className="mt-1.5 text-[9px] text-purple-400 font-medium">
