                            </div>
                        )}
                        {!selectedInstitutionId && !isInstitutionLocked && (
                            <div className="mt-1.5 text-[9px] text-red-400 font-medium flex items-center animate-pulse">
                                <AlertCircle className="w-3 h-3 mr-1" />
                                Lütfen kurum seçiniz.
                            </div>
                        )}
                    </div>

                    {/* 2. Not */}
                    <div className="bg-slate-900 border border-slate-800 rounded-xl p-4 shadow-sm">
                        <label className="text-[10px] uppercase font-bold text-slate-500 mb-2 block ml-1">Sevk Notu (Opsiyonel)</label>
                        <textarea 
                            value={notes}
                            onChange={e => setNotes(e.target.value)}
                            placeholder="Özel bir not ekleyin..."
                            rows={3}
                            className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2.5 text-xs text-white focus:border-slate-500 outline-none resize-none"
                        />
                    </div>
                </div>

                {/* Sticky Bottom Section (Price & Save) */}
                <div className="mt-auto shrink-0">
                    <div className="bg-slate-800 rounded-xl p-4 border border-slate-700 shadow-lg relative overflow-hidden">
                        <div className="absolute top-0 right-0 p-4 opacity-5">
                            <Receipt className="w-20 h-20 text-white" />
                        </div>

                        {/* Ödeme Yöntemi */}
                        <div className="flex items-center justify-between mb-3 relative z-10">
                            <span className="text-[10px] text-slate-400 font-medium uppercase">Ödeme Tipi</span>
                            {paymentMethod === 'CASH' ? (
                                <div className="px-2 py-0.5 bg-emerald-500/10 border border-emerald-500/20 rounded text-emerald-400 text-[10px] font-bold flex items-center">
                                    <Wallet className="w-3 h-3 mr-1" /> NAKİT
                                </div>
                            ) : (
                                <div className="px-2 py-0.5 bg-blue-500/10 border border-blue-500/20 rounded text-blue-400 text-[10px] font-bold flex items-center">
                                    <Receipt className="w-3 h-3 mr-1" /> FATURA
                                </div>
                            )}
                        </div>

                        {/* Tutar */}
                        <div className="mb-4 relative z-10">
                            <div className="text-2xl font-bold text-white tracking-tight">₺{estimatedPrice.toLocaleString('tr-TR')}</div>
                            <div className="text-[10px] text-slate-500 mt-0.5">
                                Maliyet: <span className="text-slate-400">₺{estimatedCost}</span>
                            </div>
                        </div>

                        {/* Buton */}
                        <button 
                            onClick={handleSubmit}
                            disabled={!isFormValid}
                            className={`w-full py-3 rounded-lg font-bold text-white shadow-lg flex items-center justify-center space-x-2 transition-all active:scale-95 relative z-10 ${
                                !isFormValid ? 'bg-slate-700 text-slate-500 cursor-not-allowed' :
                                paymentMethod === 'CASH' ? 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-900/30' : 'bg-blue-600 hover:bg-blue-500 shadow-blue-900/30'
                            }`}
                        >
                            <Save className="w-4 h-4" />
                            <span className="text-sm">
                                {!isFormValid && selectedInstitutionId === '' ? 'KURUM SEÇİNİZ' : 'KAYDI OLUŞTUR'}
                            </span>
                        </button>
                    </div>
                </div>

            </div>
        </div>
      </div>
    </div>
  );
};

import { Referral, Company, ExamDefinition, SafeTransaction, MedicalInstitution, AppSettings } from '../types';

const STORAGE_KEY_REFERRALS = 'osgb_referrals_v1';
const STORAGE_KEY_COMPANIES = 'osgb_companies_v1';
const STORAGE_KEY_EXAMS = 'osgb_exams_v1';
const STORAGE_KEY_TRANSACTIONS = 'osgb_transactions_v1';
const STORAGE_KEY_INSTITUTIONS = 'osgb_institutions_v1';
const STORAGE_KEY_SETTINGS = 'osgb_settings_v1';

// Referrals
export const loadReferrals = (): Referral[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY_REFERRALS);
    return data ? JSON.parse(data) : [];
  } catch (error) {
    return [];
  }
};
export const saveReferrals = (data: Referral[]) => localStorage.setItem(STORAGE_KEY_REFERRALS, JSON.stringify(data));

// Companies
export const loadCompanies = (defaults: Company[] = []): Company[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY_COMPANIES);
    return data ? JSON.parse(data) : defaults;
  } catch (error) {
    return defaults;
  }
};
export const saveCompanies = (data: Company[]) => localStorage.setItem(STORAGE_KEY_COMPANIES, JSON.stringify(data));

// Exams
export const loadExams = (defaults: ExamDefinition[] = []): ExamDefinition[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY_EXAMS);
    return data ? JSON.parse(data) : defaults;
  } catch (error) {
    return defaults;
  }
};
export const saveExams = (data: ExamDefinition[]) => localStorage.setItem(STORAGE_KEY_EXAMS, JSON.stringify(data));

// Institutions
export const loadInstitutions = (defaults: MedicalInstitution[] = []): MedicalInstitution[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY_INSTITUTIONS);
    return data ? JSON.parse(data) : defaults;
  } catch (error) {
    return defaults;
  }
};
export const saveInstitutions = (data: MedicalInstitution[]) => localStorage.setItem(STORAGE_KEY_INSTITUTIONS, JSON.stringify(data));

// Safe Transactions
export const loadTransactions = (): SafeTransaction[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY_TRANSACTIONS);
    return data ? JSON.parse(data) : [];
  } catch (error) {
    return [];
  }
};
export const saveTransactions = (data: SafeTransaction[]) => localStorage.setItem(STORAGE_KEY_TRANSACTIONS, JSON.stringify(data));

// App Settings
export const loadAppSettings = (): AppSettings => {
  try {
    const data = localStorage.getItem(STORAGE_KEY_SETTINGS);
    return data ? JSON.parse(data) : { ekgLimitAge: 40 }; // Default 40
  } catch (error) {
    return { ekgLimitAge: 40 };
  }
};

export const saveAppSettings = (settings: AppSettings) => localStorage.setItem(STORAGE_KEY_SETTINGS, JSON.stringify(settings));

// --- BACKUP & RESTORE UTILITIES ---

export interface BackupData {
  version: string;
  timestamp: string;
  companies: Company[];
  referrals: Referral[];
  exams: ExamDefinition[];
  institutions: MedicalInstitution[];
  transactions: SafeTransaction[];
  settings: AppSettings;
}

export const exportFullData = (): string => {
  const backup: BackupData = {
    version: '1.0',
    timestamp: new Date().toISOString(),
    companies: loadCompanies(),
    referrals: loadReferrals(),
    exams: loadExams(),
    institutions: loadInstitutions(),
    transactions: loadTransactions(),
    settings: loadAppSettings()
  };
  return JSON.stringify(backup, null, 2);
};

export const restoreFullData = (jsonData: string): boolean => {
  try {
    const data: BackupData = JSON.parse(jsonData);

    // Basic validation
    if (!data.companies || !data.referrals) {
      throw new Error("Geçersiz yedek dosyası formatı.");
    }

    // Save all data
    if(data.companies) saveCompanies(data.companies);
    if(data.referrals) saveReferrals(data.referrals);
    if(data.exams) saveExams(data.exams);
    if(data.institutions) saveInstitutions(data.institutions);
    if(data.transactions) saveTransactions(data.transactions);
    if(data.settings) saveAppSettings(data.settings);

    return true;
  } catch (error) {
    console.error("Yedek yükleme hatası:", error);
    return false;
  }
};

import React, { useState, useRef } from 'react';
import { Company, ExamDefinition, HazardClass, MedicalInstitution, AppSettings } from '../types';
import { Trash2, Plus, Building2, TestTube, Save, Check, Wallet, Receipt, Upload, FileDown, AlertCircle, MapPin, Sliders, CheckSquare, Square, Image as ImageIcon, Edit2, XCircle, Database, Download, RefreshCw, AlertTriangle } from 'lucide-react';
import * as XLSX from 'xlsx';
import { exportFullData, restoreFullData } from '../services/storage';

interface SettingsViewProps {
  companies: Company[];
  onAddCompany: (c: Company) => void;
  onUpdateCompany: (c: Company) => void;
  onDeleteCompany: (id: string) => void;
  onBulkDeleteCompanies: (ids: string[]) => void;
  exams: ExamDefinition[];
  onAddExam: (e: ExamDefinition) => void;
  onUpdateExam: (e: ExamDefinition) => void;
  onDeleteExam: (id: string) => void;
  institutions: MedicalInstitution[];
  onAddInstitution: (i: MedicalInstitution) => void;
  onDeleteInstitution: (id: string) => void;
  settings: AppSettings;
  onUpdateSettings: (s: AppSettings) => void;
}

export const SettingsView: React.FC<SettingsViewProps> = ({
  companies,
  onAddCompany,
  onUpdateCompany,
  onDeleteCompany,
  onBulkDeleteCompanies,
  exams,
  onAddExam,
  onUpdateExam,
  onDeleteExam,
  institutions,
  onAddInstitution,
  onDeleteInstitution,
  settings,
  onUpdateSettings
}) => {
  const [activeTab, setActiveTab] = useState<'general' | 'companies' | 'exams' | 'institutions' | 'backup'>('general');

  // General Settings State
  const [ekgAgeLimit, setEkgAgeLimit] = useState(settings.ekgLimitAge);
  const [logo, setLogo] = useState<string | undefined>(settings.companyLogo);

  // Company Form State
  const [editingCompanyId, setEditingCompanyId] = useState<string | null>(null);
  const [cName, setCName] = useState('');
  const [cHazard, setCHazard] = useState<HazardClass>(HazardClass.LESS);
  const [cDoctor, setCDoctor] = useState('');
  const [cSpecialist, setCSpecialist] = useState('');
  const [cPaymentMethod, setCPaymentMethod] = useState<'CASH' | 'INVOICE'>('INVOICE');
  const [cSelectedExams, setCSelectedExams] = useState<string[]>([]);
  const [cPreferredInst, setCPreferredInst] = useState<string>(''); // For forced institution

  // Company Selection State (Bulk Delete)
  const [selectedCompanyIds, setSelectedCompanyIds] = useState<string[]>([]);

  // File Import Ref
  const fileInputRef = useRef<HTMLInputElement>(null);
  const logoInputRef = useRef<HTMLInputElement>(null);
  const backupInputRef = useRef<HTMLInputElement>(null);

  // Exam Form State
  const [eName, setEName] = useState('');
  const [eCode, setECode] = useState('');
  const [ePrice, setEPrice] = useState('');
  const [eCost, setECost] = useState(''); // New Cost State

  // Institution Form State
  const [iName, setIName] = useState('');
  const [iPhone, setIPhone] = useState('');

  const toggleCompanyExam = (examName: string) => {
    setCSelectedExams(prev => 
      prev.includes(examName) ? prev.filter(e => e !== examName) : [...prev, examName]
    );
  };

  const handleUpdateGeneralSettings = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdateSettings({ 
        ...settings, 
        ekgLimitAge: ekgAgeLimit,
        companyLogo: logo 
    });
    alert("Ayarlar güncellendi.");
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2000000) { // 2MB limit
          alert("Logo dosyası 2MB'dan küçük olmalıdır.");
          return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setLogo(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemoveLogo = () => {
      setLogo(undefined);
      if(logoInputRef.current) logoInputRef.current.value = '';
  };

  // Populate form for editing
  const handleEditCompany = (company: Company) => {
    setEditingCompanyId(company.id);
    setCName(company.name);
    setCHazard(company.hazardClass);
    setCDoctor(company.assignedDoctor);
    setCSpecialist(company.assignedSpecialist);
    setCPaymentMethod(company.defaultPaymentMethod);
    setCSelectedExams(company.defaultExams);
    setCPreferredInst(company.forcedInstitutionId || '');
    // Scroll to form (simple implementation)
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleCancelEdit = () => {
    setEditingCompanyId(null);
    setCName('');
    setCDoctor('');
    setCSpecialist('');
    setCPaymentMethod('INVOICE');
    setCSelectedExams([]);
    setCPreferredInst('');
  };

  const handleCompanySubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!cName) return;

    if (editingCompanyId) {
      // UPDATE Existing
      const updatedCompany: Company = {
        id: editingCompanyId,
        name: cName,
        hazardClass: cHazard,
        assignedDoctor: cDoctor || 'Belirlenmedi',
        assignedSpecialist: cSpecialist || 'Belirlenmedi',
        defaultExams: cSelectedExams,
        defaultPaymentMethod: cPaymentMethod,
        forcedInstitutionId: cPreferredInst || undefined
      };
      onUpdateCompany(updatedCompany);
      handleCancelEdit(); // Reset form
    } else {
      // ADD New
      const newCompany: Company = {
        id: Math.random().toString(36).substr(2, 9),
        name: cName,
        hazardClass: cHazard,
        assignedDoctor: cDoctor || 'Belirlenmedi',
        assignedSpecialist: cSpecialist || 'Belirlenmedi',
        defaultExams: cSelectedExams,
        defaultPaymentMethod: cPaymentMethod,
        forcedInstitutionId: cPreferredInst || undefined
      };
      onAddCompany(newCompany);
      handleCancelEdit(); // Reset form using same helper
    }
  };

  const handleAddInstitution = (e: React.FormEvent) => {
    e.preventDefault();
    if(!iName) return;
    const newInst: MedicalInstitution = {
      id: Math.random().toString(36).substr(2, 9),
      name: iName,
      phone: iPhone
    };
    onAddInstitution(newInst);
    setIName('');
    setIPhone('');
  };

  // Bulk Delete Logic
  const handleToggleSelectCompany = (id: string) => {
    setSelectedCompanyIds(prev => 
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  const handleSelectAllCompanies = () => {
    if (selectedCompanyIds.length === companies.length) {
      setSelectedCompanyIds([]);
    } else {
      setSelectedCompanyIds(companies.map(c => c.id));
    }
  };

  const handleBulkDelete = () => {
    if (selectedCompanyIds.length === 0) return;
    if (window.confirm(`Seçili ${selectedCompanyIds.length} firmayı silmek istediğinize emin misiniz?`)) {
      onBulkDeleteCompanies(selectedCompanyIds);
      setSelectedCompanyIds([]);
    }
  };

  // --- Bulk Import / Template Logic (Excel .xlsx) ---

  const downloadTemplate = () => {
    // Sheet 1: Firmalar (Template to fill)
    const headers = ["Firma Adı", "Tehlike Sınıfı (Az/Tehlikeli/Çok)", "Hekim Adı", "Uzman Adı", "Ödeme (Nakit/Fatura)", "Tetkik Kodları (Virgül ile)"];
    const exampleRow = ["Örnek Metal A.Ş.", "Tehlikeli", "Dr. Ahmet Yılmaz", "Uzm. Ayşe Demir", "Fatura", "101, 103, 105"];
    const wsFirmalar = XLSX.utils.aoa_to_sheet([headers, exampleRow]);

    wsFirmalar['!cols'] = [
      { wch: 30 }, // Firma Adı
      { wch: 25 }, // Tehlike
      { wch: 20 }, // Hekim
      { wch: 20 }, // Uzman
      { wch: 20 }, // Ödeme
      { wch: 30 }  // Tetkik Kodları
    ];

    // Sheet 2: Tetkik Referans (Read-only reference)
    const refHeaders = ["Tetkik Kodu", "Tetkik Adı", "Satış Fiyatı", "Maliyet"];
    const refRows = exams.map(e => [e.code, e.name, e.price, e.cost || 0]);
    const wsRef = XLSX.utils.aoa_to_sheet([refHeaders, ...refRows]);
    wsRef['!cols'] = [{ wch: 15 }, { wch: 30 }, { wch: 10 }, { wch: 10 }];

    // Create Workbook
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, wsFirmalar, "Firma_Listesi");
    XLSX.utils.book_append_sheet(wb, wsRef, "Tetkik_Referans_Listesi");

    // Write file
    XLSX.writeFile(wb, "firma_yukleme_sablonu.xlsx");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();

    reader.onload = (evt) => {
      const bstr = evt.target?.result;
      if (!bstr) return;

      try {
        const wb = XLSX.read(bstr, { type: 'binary' });

        // Use the first sheet
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        // Convert to JSON array
        const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];

        let successCount = 0;

        // Skip header row
        for (let i = 1; i < data.length; i++) {
          const row = data[i];
          if (!row || row.length === 0 || !row[0]) continue;

          const name = String(row[0]).trim();
          const hazardRaw = String(row[1] || '').toLowerCase();
          const doctor = String(row[2] || 'Belirlenmedi').trim();
          const specialist = String(row[3] || 'Belirlenmedi').trim();
          const paymentRaw = String(row[4] || '').toLowerCase();
          const examCodesStr = String(row[5] || '').trim();

          // Hazard Class
          let hazard = HazardClass.LESS;
          if (hazardRaw.includes('çok') || hazardRaw.includes('cok')) hazard = HazardClass.VERY_DANGEROUS;
          else if (hazardRaw.includes('az')) hazard = HazardClass.LESS;
          else if (hazardRaw.includes('tehlikeli')) hazard = HazardClass.DANGEROUS;

          // Payment
          let payment: 'CASH' | 'INVOICE' = 'INVOICE';
          if (paymentRaw.includes('nakit') || paymentRaw.includes('elden') || paymentRaw.includes('kasa')) {
            payment = 'CASH';
          }

          // Process Exam Codes (e.g., "101, 105") -> Match to Exam Names
          const requestedCodes = examCodesStr.split(',').map(s => s.trim()).filter(s => s !== '');
          const matchedExams = exams
            .filter(e => requestedCodes.includes(e.code) || requestedCodes.includes(e.code.toString()))
            .map(e => e.name);

          const newComp: Company = {
            id: Math.random().toString(36).substr(2, 9),
            name: name,
            hazardClass: hazard,
            assignedDoctor: doctor,
            assignedSpecialist: specialist,
            defaultPaymentMethod: payment,
            defaultExams: matchedExams 
          };

          onAddCompany(newComp);
          successCount++;
        }

        alert(`${successCount} adet firma ve ilişkili tetkikleri başarıyla yüklendi.`);
      } catch (error) {
        console.error("Excel okuma hatası:", error);
        alert("Dosya okunurken bir hata oluştu.");
      } finally {
        if(fileInputRef.current) fileInputRef.current.value = '';
      }
    };

    reader.readAsBinaryString(file);
  };

  // --- End Bulk Import Logic ---

  // --- Backup & Restore Logic ---
  const handleBackup = () => {
    const jsonString = exportFullData();
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);

    const a = document.createElement('a');
    a.href = url;
    const dateStr = new Date().toISOString().split('T')[0];
    a.download = `osgb_yedek_${dateStr}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!window.confirm("DİKKAT: Yedek dosyasını yüklediğinizde MEVCUT TÜM VERİLER SİLİNECEK ve yerine yedektekiler gelecektir. Devam etmek istiyor musunuz?")) {
        if(backupInputRef.current) backupInputRef.current.value = '';
        return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
        const content = event.target?.result;
        if (typeof content === 'string') {
            const success = restoreFullData(content);
            if (success) {
                alert("Yedek başarıyla yüklendi. Sayfa yenileniyor...");
                window.location.reload();
            } else {
                alert("Yedek yüklenirken bir hata oluştu. Dosya bozuk olabilir.");
            }
        }
    };
    reader.readAsText(file);
    if(backupInputRef.current) backupInputRef.current.value = '';
  };
  // --- End Backup Logic ---

  const handleAddExam = (e: React.FormEvent) => {
    e.preventDefault();
    if (!eName || !ePrice || !eCode) return;

    // Check for duplicate code
    if(exams.some(ex => ex.code === eCode)) {
        alert("Bu tetkik kodu zaten kullanılıyor!");
        return;
    }

    const newExam: ExamDefinition = {
      id: Math.random().toString(36).substr(2, 9),
      code: eCode,
      name: eName,
      price: parseFloat(ePrice),
      cost: parseFloat(eCost) || 0
    };
    onAddExam(newExam);
    setEName('');
    setECode('');
    setEPrice('');
    setECost('');
  };

  const handleUpdateExamField = (id: string, field: keyof ExamDefinition, value: string) => {
    const exam = exams.find(e => e.id === id);
    if (exam) {
      const updated = { ...exam };
      if (field === 'price') updated.price = parseFloat(value);
      if (field === 'cost') updated.cost = parseFloat(value);
      if (field === 'code') updated.code = value;
      // Name update could be added here if needed
      onUpdateExam(updated);
    }
  };

  return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden">
      <div className="flex border-b border-slate-700 overflow-x-auto">
        <button
          onClick={() => setActiveTab('general')}
          className={`px-6 py-4 text-center font-medium text-sm transition-colors whitespace-nowrap ${activeTab === 'general' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Genel Ayarlar
        </button>
        <button
          onClick={() => setActiveTab('companies')}
          className={`px-6 py-4 text-center font-medium text-sm transition-colors whitespace-nowrap ${activeTab === 'companies' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Firmalar
        </button>
        <button
          onClick={() => setActiveTab('institutions')}
          className={`px-6 py-4 text-center font-medium text-sm transition-colors whitespace-nowrap ${activeTab === 'institutions' ? 'bg-slate-900/50 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
        >
          Anlaşmalı Kurumlar
        </button>
