import React, { useMemo, useState } from 'react';
import { X, Printer, Calculator, Calendar, Building2, CalendarDays, CalendarRange, Stethoscope, Download, FileText, PieChart, CreditCard, Banknote, Receipt, Wallet } from 'lucide-react';
import { Referral, SafeTransaction, AppSettings, MedicalInstitution } from '../types';

interface EndOfDayReportModalProps {
  onClose: () => void;
  referrals: Referral[];
  transactions: SafeTransaction[];
  settings?: AppSettings;
  institutions: MedicalInstitution[];
}

interface ReportData {
  referrals: Referral[];
  transactions: SafeTransaction[];
  totalIncome: number;
  totalExpense: number;
  openingBalance: number;
  closingBalance: number;
  totalReferralCost: number;
  totalReferralPrice: number;
  estimatedProfit: number;
  institutionCosts: Record<string, number>;
  companyStats: Record<string, { count: number, total: number }>;
  totalReferralCash: number;
  totalReferralPos: number;
  totalReferralInvoice: number;
}

type ReportPeriod = 'daily' | 'weekly' | 'monthly';

export const EndOfDayReportModal: React.FC<EndOfDayReportModalProps> = ({ onClose, referrals, transactions, settings, institutions }) => {
  const [period, setPeriod] = useState<ReportPeriod>('daily');
  const now = new Date();

  // Calculate Date Range based on Period
  const dateRange = useMemo(() => {
    const end = new Date(); // Now
    const start = new Date(); 
    start.setHours(0, 0, 0, 0);

    if (period === 'weekly') {
      // Set to Monday of the current week
      const day = start.getDay() || 7; // Get current day (1=Mon, ..., 7=Sun)
      if (day !== 1) {
        start.setHours(-24 * (day - 1));
      }
    } else if (period === 'monthly') {
      // Set to 1st of the current month
      start.setDate(1);
    }
    // 'daily' is already set to start of today

    return { start, end };
  }, [period]);

  const reportData = useMemo<ReportData>(() => {
    // Filter referrals within range
    const filteredReferrals = referrals.filter(r => {
      const d = new Date(r.referralDate);
      return d >= dateRange.start && d <= dateRange.end;
    });

    // Filter transactions within range
    const filteredTransactions = transactions.filter(t => {
      const d = new Date(t.date);
      return d >= dateRange.start && d <= dateRange.end;
    });

    // Calculate Finances for the Period
    const totalIncome = filteredTransactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);

    const totalExpense = filteredTransactions
      .filter(t => t.type === 'EXPENSE')
      .reduce((acc, curr) => acc + curr.amount, 0);

    // Calculate Payment Method Breakdown
    const totalReferralCash = filteredReferrals
        .filter(r => r.paymentMethod === 'CASH')
        .reduce((acc, curr) => acc + (curr.totalPrice || 0), 0);

    const totalReferralPos = filteredReferrals
        .filter(r => r.paymentMethod === 'POS')
        .reduce((acc, curr) => acc + (curr.totalPrice || 0), 0);

    const totalReferralInvoice = filteredReferrals
        .filter(r => r.paymentMethod === 'INVOICE')
        .reduce((acc, curr) => acc + (curr.totalPrice || 0), 0);

    // Calculate Total Balance (Absolute Current System State - All Time)
    const currentTotalBalance = transactions.reduce((acc, curr) => {
      return curr.type === 'INCOME' ? acc + curr.amount : acc - curr.amount;
    }, 0);

    // Referral Costs (Maliyet)
    const totalReferralCost = filteredReferrals.reduce((acc, curr) => acc + (curr.totalCost || 0), 0);
    const totalReferralPrice = filteredReferrals.reduce((acc, curr) => acc + (curr.totalPrice || 0), 0);
    const estimatedProfit = totalReferralPrice - totalReferralCost;

    // Group Costs by Institution
    const institutionCosts: Record<string, number> = {};
    filteredReferrals.forEach(ref => {
      if (ref.totalCost && ref.totalCost > 0) {
        const id = ref.targetInstitutionId || 'unknown';
        institutionCosts[id] = (institutionCosts[id] || 0) + ref.totalCost;
      }
    });

    // Group Stats by Company
    const companyStats: Record<string, { count: number, total: number }> = {};
    filteredReferrals.forEach(ref => {
        const name = ref.employee.company;
        if (!companyStats[name]) {
            companyStats[name] = { count: 0, total: 0 };
        }
        companyStats[name].count += 1;
        companyStats[name].total += (ref.totalPrice || 0);
    });

    // Opening Balance for this Period = Current Balance - (Net Change during this period)
    const periodNetChange = totalIncome - totalExpense;
    const openingBalance = currentTotalBalance - periodNetChange;

    return {
      referrals: filteredReferrals,
      transactions: filteredTransactions,
      totalIncome,
      totalExpense,
      openingBalance,
      closingBalance: currentTotalBalance,
      totalReferralCost,
      totalReferralPrice,
      estimatedProfit,
      institutionCosts,
      companyStats,
      totalReferralCash,
      totalReferralPos,
      totalReferralInvoice
    };
  }, [referrals, transactions, dateRange]);

  const getTitle = () => {
    switch(period) {
      case 'weekly': return 'HAFTALIK FAALİYET RAPORU';
      case 'monthly': return 'AYLIK FAALİYET RAPORU';
      default: return 'GÜN SONU RAPORU (Z RAPORU)';
    }
  };

  return (
    /* 
      PRINT CONFIGURATION:
      - Screen: Fixed modal with scroll.
      - Print: Static positioning, visible overflow to allow multi-page printing without cutting content.
    */
    <div className="fixed inset-0 bg-slate-950/90 z-50 overflow-y-auto print:static print:inset-auto print:bg-white print:z-auto print:h-auto print:overflow-visible print:block">

      {/* --- Screen Controls (Hidden on Print) --- */}
      <div className="sticky top-0 z-50 bg-slate-900/95 backdrop-blur border-b border-slate-800 px-4 py-3 flex justify-between items-center print:hidden shadow-lg">
        <div className="flex items-center space-x-4">
           <div className="flex bg-slate-800 rounded-lg p-1 border border-slate-700">
              <button 
                onClick={() => setPeriod('daily')}
                className={`px-3 py-1.5 rounded text-sm font-medium transition-all ${period === 'daily' ? 'bg-blue-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
              >
                Günlük
              </button>
              <button 
                onClick={() => setPeriod('weekly')}
                className={`px-3 py-1.5 rounded text-sm font-medium transition-all ${period === 'weekly' ? 'bg-blue-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
              >
                Haftalık
              </button>
              <button 
                onClick={() => setPeriod('monthly')}
                className={`px-3 py-1.5 rounded text-sm font-medium transition-all ${period === 'monthly' ? 'bg-blue-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
              >
                Aylık
              </button>
           </div>
           <span className="text-slate-500 text-sm hidden md:inline">|</span>
           <span className="text-slate-400 text-sm hidden md:inline">
              Önizleme Modu
           </span>
        </div>
        <div className="flex items-center space-x-3">
           <button 
             onClick={() => window.print()}
             className="flex items-center space-x-2 bg-emerald-600 hover:bg-emerald-500 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-lg shadow-emerald-900/20 transition-all"
           >
             <Printer className="w-4 h-4" />
             <span>Yazdır / PDF</span>
           </button>
           <button 
             onClick={() => onClose()}
             className="p-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-lg border border-slate-700 transition-colors"
           >
             <X className="w-5 h-5" />
           </button>
        </div>
      </div>

      {/* --- Report Container --- */}
      <div className="flex justify-center py-8 print:py-0 print:block print:w-full">
        <div className="bg-white text-slate-900 w-[210mm] min-h-[297mm] shadow-2xl box-border relative print:w-full print:max-w-none print:min-h-0 print:h-auto print:shadow-none print:overflow-visible print:rounded-none">

           {/* Top Color Bar */}
           <div className="h-2 w-full bg-blue-900 print:bg-blue-900"></div>

           <div className="p-10 print:p-8 space-y-8">

              {/* --- REPORT HEADER & SUMMARIES (Prints at Top of Page 1) --- */}
              <div className="print:break-inside-avoid">

                  {/* Header */}
                  <div className="flex justify-between items-start border-b-2 border-slate-100 pb-6 mb-6">
                     <div className="flex items-center space-x-3">
                        {settings?.companyLogo ? (
                            <img src={settings.companyLogo} alt="Firma Logosu" className="h-16 w-auto object-contain" />
                        ) : (
                            <div className="p-3 bg-blue-50 rounded-lg border border-blue-100">
                              <Stethoscope className="w-8 h-8 text-blue-900" />
                            </div>
                        )}

                        {!settings?.companyLogo && (
                            <div>
                            <h1 className="text-xl font-bold text-slate-900 tracking-tight">OSGB PRO</h1>
                            <p className="text-xs text-slate-500 font-medium uppercase tracking-widest">Tetkik Takip Sistemi</p>
                            </div>
                        )}
                     </div>
                     <div className="text-right">
                        <h2 className="text-lg font-bold text-slate-900 uppercase tracking-tight">{getTitle()}</h2>
                        <p className="text-xs text-slate-500 mt-1">Rapor No: #{Math.floor(Math.random() * 100000)}</p>
                        <p className="text-xs text-slate-500">Oluşturulma: {now.toLocaleDateString('tr-TR')} {now.toLocaleTimeString('tr-TR')}</p>
                     </div>
                  </div>

                  {/* Info Grid */}
                  <div className="bg-slate-50 rounded border border-slate-200 p-4 flex justify-between items-center text-sm print:bg-transparent print:border-slate-300 mb-6">
                      <div>
                         <span className="text-slate-500 font-medium block text-xs uppercase mb-1">Rapor Periyodu</span>
                         <span className="font-bold text-slate-800">
                            {dateRange.start.toLocaleDateString('tr-TR')} - {dateRange.end.toLocaleDateString('tr-TR')}
                         </span>
                      </div>
                      <div className="text-right">
                         <span className="text-slate-500 font-medium block text-xs uppercase mb-1">Şube / Birim</span>
                         <span className="font-bold text-slate-800">Merkez Ofis / Kasa</span>
                      </div>
                  </div>

                  {/* Payment Methods Breakdown */}
                  <div className="mb-6">
                     <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 flex items-center">
                        <Wallet className="w-3.5 h-3.5 mr-1" />
                        Tahsilat & Ciro Dağılımı
                     </h3>
                     <div className="grid grid-cols-3 gap-4">
                        <div className="p-4 rounded border border-emerald-200 bg-emerald-50 flex items-center justify-between print:border-emerald-300">
                           <div>
                              <p className="text-[10px] text-emerald-600 font-bold uppercase mb-1">ELDEN NAKİT</p>
                              <p className="text-xl font-bold text-emerald-700">₺{reportData.totalReferralCash.toLocaleString('tr-TR')}</p>
                           </div>
                           <div className="p-2 bg-emerald-100 rounded-full print:bg-emerald-50">
                               <Banknote className="w-5 h-5 text-emerald-600" />
                           </div>
                        </div>

                        <div className="p-4 rounded border border-purple-200 bg-purple-50 flex items-center justify-between print:border-purple-300">
                           <div>
                              <p className="text-[10px] text-purple-600 font-bold uppercase mb-1">ELDEN POS</p>
                              <p className="text-xl font-bold text-purple-700">₺{reportData.totalReferralPos.toLocaleString('tr-TR')}</p>
                           </div>
                           <div className="p-2 bg-purple-100 rounded-full print:bg-purple-50">
                               <CreditCard className="w-5 h-5 text-purple-600" />
                           </div>
                        </div>

                        <div className="p-4 rounded border border-blue-200 bg-blue-50 flex items-center justify-between print:border-blue-300">
                           <div>
                              <p className="text-[10px] text-blue-600 font-bold uppercase mb-1">FATURA (CARİ)</p>
                              <p className="text-xl font-bold text-blue-700">₺{reportData.totalReferralInvoice.toLocaleString('tr-TR')}</p>
                           </div>
                           <div className="p-2 bg-blue-100 rounded-full print:bg-blue-50">
                               <Receipt className="w-5 h-5 text-blue-600" />
                           </div>
                        </div>
                     </div>
                  </div>

                  {/* Company Breakdown */}
                  {Object.keys(reportData.companyStats).length > 0 && (
                    <div className="mb-6">
                       <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 flex items-center">
                          <Building2 className="w-3.5 h-3.5 mr-1" />
                          Firma Bazlı Sevk ve Ciro Dağılımı
                       </h3>
                       <table className="w-full text-left text-xs border border-slate-200 rounded-lg overflow-hidden">
