                                </div>
                                <div className="p-3 rounded border border-slate-200 bg-white">
                                   <p className="text-[9px] text-slate-500 font-bold uppercase mb-1">TOPLAM GİRİŞ</p>
                                   <p className="text-base font-bold text-emerald-600">₺{reportData.totalIncome.toLocaleString('tr-TR')}</p>
                                </div>
                                <div className="p-3 rounded border border-slate-200 bg-white">
                                   <p className="text-[9px] text-slate-500 font-bold uppercase mb-1">ÇIKIŞLAR (GİDER)</p>
