                                       </tr>
                                   </thead>
                                   <tbody className="divide-y divide-slate-100">
                                       {Object.entries(reportData.companyStats).map(([company, stats]: [string, { count: number, total: number }], idx) => (
                                           <tr key={idx} className="even:bg-slate-50 print:even:bg-slate-50">
                                               <td className="px-3 py-1 text-slate-700 font-medium truncate max-w-[200px]">{company}</td>
                                               <td className="px-3 py-1 text-center text-slate-600">{stats.count}</td>
                                               <td className="px-3 py-1 text-right font-bold text-slate-800">₺{stats.total.toLocaleString()}</td>
