import React, { useMemo, useState } from 'react';
import { X, Printer, Calculator, Calendar, Building2, CalendarDays, CalendarRange, Stethoscope, Download, FileText, PieChart, CreditCard, Banknote, Receipt, Wallet, FileSpreadsheet } from 'lucide-react';
import { Referral, SafeTransaction, AppSettings, MedicalInstitution } from '../types';
import * as XLSX from 'xlsx';

interface EndOfDayReportModalProps {
  onClose: () => void;
  referrals: Referral[];
  transactions: SafeTransaction[];
  settings?: AppSettings;
  institutions: MedicalInstitution[];
}

interface ReportData {
  referrals: Referral[];
  transactions: SafeTransaction[];
  totalIncome: number;
  totalExpense: number;
  openingBalance: number;
  closingBalance: number;
  totalReferralCost: number;
  totalReferralPrice: number;
  estimatedProfit: number;
  institutionCosts: Record<string, number>;
  companyStats: Record<string, { count: number, total: number }>;
  totalReferralCash: number;
  totalReferralPos: number;
  totalReferralInvoice: number;
}

type ReportPeriod = 'daily' | 'weekly' | 'monthly';

export const EndOfDayReportModal: React.FC<EndOfDayReportModalProps> = ({ onClose, referrals, transactions, settings, institutions }) => {
  const [period, setPeriod] = useState<ReportPeriod>('daily');
  const now = new Date();

  // Calculate Date Range based on Period
  const dateRange = useMemo(() => {
    const end = new Date(); // Now
    const start = new Date(); 
    start.setHours(0, 0, 0, 0);

    if (period === 'weekly') {
      // Set to Monday of the current week
      const day = start.getDay() || 7; // Get current day (1=Mon, ..., 7=Sun)
      if (day !== 1) {
        start.setDate(start.getDate() - (day - 1));
      }
    } else if (period === 'monthly') {
      // Set to 1st of the current month
      start.setDate(1);
    }
    // 'daily' is already set to start of today

    return { start, end };
  }, [period]);

  const reportData = useMemo<ReportData>(() => {
    // Filter referrals within range
    const filteredReferrals = referrals.filter(r => {
      const d = new Date(r.referralDate);
      return d >= dateRange.start && d <= dateRange.end;
    });

    // Filter transactions within range
    const filteredTransactions = transactions.filter(t => {
      const d = new Date(t.date);
      return d >= dateRange.start && d <= dateRange.end;
    });

    // Calculate Finances for the Period
    const totalIncome = filteredTransactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);

    const totalExpense = filteredTransactions
      .filter(t => t.type === 'EXPENSE')
      .reduce((acc, curr) => acc + curr.amount, 0);

    // Calculate Payment Method Breakdown
    const totalReferralCash = filteredReferrals
        .filter(r => r.paymentMethod === 'CASH')
        .reduce((acc, curr) => acc + (curr.totalPrice || 0), 0);

    const totalReferralPos = filteredReferrals
        .filter(r => r.paymentMethod === 'POS')
        .reduce((acc, curr) => acc + (curr.totalPrice || 0), 0);

    const totalReferralInvoice = filteredReferrals
        .filter(r => r.paymentMethod === 'INVOICE')
        .reduce((acc, curr) => acc + (curr.totalPrice || 0), 0);

    // Calculate Total Balance (Absolute Current System State - All Time)
    const currentTotalBalance = transactions.reduce((acc, curr) => {
      return curr.type === 'INCOME' ? acc + curr.amount : acc - curr.amount;
    }, 0);

    // Referral Costs (Maliyet)
    const totalReferralCost = filteredReferrals.reduce((acc, curr) => acc + (curr.totalCost || 0), 0);
    const totalReferralPrice = filteredReferrals.reduce((acc, curr) => acc + (curr.totalPrice || 0), 0);
    const estimatedProfit = totalReferralPrice - totalReferralCost;

    // Group Costs by Institution
    const institutionCosts: Record<string, number> = {};
    filteredReferrals.forEach(ref => {
      if (ref.totalCost && ref.totalCost > 0) {
        const id = ref.targetInstitutionId || 'unknown';
        institutionCosts[id] = (institutionCosts[id] || 0) + ref.totalCost;
      }
    });

    // Group Stats by Company
    const companyStats: Record<string, { count: number, total: number }> = {};
    filteredReferrals.forEach(ref => {
        const name = ref.employee.company;
        if (!companyStats[name]) {
            companyStats[name] = { count: 0, total: 0 };
        }
        companyStats[name].count += 1;
        companyStats[name].total += (ref.totalPrice || 0);
    });

    // Opening Balance for this Period = Current Balance - (Net Change during this period)
    const periodNetChange = totalIncome - totalExpense;
    const openingBalance = currentTotalBalance - periodNetChange;

    return {
      referrals: filteredReferrals,
      transactions: filteredTransactions,
      totalIncome,
      totalExpense,
      openingBalance,
      closingBalance: currentTotalBalance,
      totalReferralCost,
      totalReferralPrice,
      estimatedProfit,
      institutionCosts,
      companyStats,
      totalReferralCash,
      totalReferralPos,
      totalReferralInvoice
    };
  }, [referrals, transactions, dateRange]);

  const getTitle = () => {
    switch(period) {
      case 'weekly': return 'HAFTALIK FAALİYET RAPORU';
      case 'monthly': return 'AYLIK FAALİYET RAPORU';
      default: return 'GÜN SONU RAPORU (Z RAPORU)';
    }
  };

  const handleDownloadExcel = () => {
    const wb = XLSX.utils.book_new();
    const dateStr = new Date().toISOString().split('T')[0];

    // --- 1. SHEET: ÖZET RAPOR ---
    const summaryData = [
        ["RAPOR ÖZETİ"],
        ["Rapor Türü", getTitle()],
        ["Tarih Aralığı", `${dateRange.start.toLocaleDateString()} - ${dateRange.end.toLocaleDateString()}`],
        ["Oluşturulma Tarihi", new Date().toLocaleString()],
        [], // Boş satır
        ["FİNANSAL DURUM (GENEL KASA)"],
        ["Açılış Bakiyesi", reportData.openingBalance],
        ["Dönem İçi Gelir", reportData.totalIncome],
        ["Dönem İçi Gider", reportData.totalExpense],
        ["Kapanış Bakiyesi", reportData.closingBalance],
        [],
        ["TAHSİLAT TÜRÜNE GÖRE CİRO"],
        ["Nakit (Elden)", reportData.totalReferralCash],
        ["Kredi Kartı / POS (Elden)", reportData.totalReferralPos],
        ["Fatura / Cari (Vadeli)", reportData.totalReferralInvoice],
        ["TOPLAM CİRO", reportData.totalReferralPrice],
        [],
        ["KÂRLILIK ANALİZİ"],
        ["Toplam Satış (Ciro)", reportData.totalReferralPrice],
        ["Toplam Maliyet (Kurum Ödemeleri)", reportData.totalReferralCost],
        ["Tahmini Brüt Kâr", reportData.estimatedProfit]
    ];

    const wsSummary = XLSX.utils.aoa_to_sheet(summaryData);

    // Sütun genişlikleri
    wsSummary['!cols'] = [{ wch: 30 }, { wch: 20 }];

    XLSX.utils.book_append_sheet(wb, wsSummary, "Ozet_Rapor");

    // --- 2. SHEET: DETAYLI SEVK LİSTESİ ---
    const referralRows = reportData.referrals.map(r => ({
        "Tarih": new Date(r.referralDate).toLocaleDateString(),
        "Saat": new Date(r.referralDate).toLocaleTimeString(),
        "Personel Adı": r.employee.fullName,
        "TC Kimlik": r.employee.tcNo,
        "Firma": r.employee.company,
        "Yapılan Tetkikler": r.exams.join(", "),
        "Sevk Edilen Kurum": r.targetInstitutionId ? (institutions.find(i => i.id === r.targetInstitutionId)?.name || "Bilinmiyor") : "-",
        "Ödeme Yöntemi": r.paymentMethod === 'CASH' ? 'NAKİT' : r.paymentMethod === 'POS' ? 'POS' : 'FATURA',
        "Tutar (TL)": r.totalPrice,
        "Maliyet (TL)": r.totalCost,
        "Notlar": r.notes || ""
    }));

    const wsReferrals = XLSX.utils.json_to_sheet(referralRows);
    wsReferrals['!cols'] = [
        { wch: 12 }, { wch: 8 }, { wch: 20 }, { wch: 15 }, { wch: 25 }, { wch: 30 }, { wch: 20 }, { wch: 15 }, { wch: 10 }, { wch: 10 }, { wch: 30 }
    ];
    XLSX.utils.book_append_sheet(wb, wsReferrals, "Detayli_Sevk_Listesi");

    // --- 3. SHEET: KASA HAREKETLERİ ---
    const txRows = reportData.transactions.map(t => ({
        "Tarih": new Date(t.date).toLocaleDateString(),
        "Saat": new Date(t.date).toLocaleTimeString(),
        "İşlem Türü": t.type === 'INCOME' ? 'GELİR (TAHSİLAT)' : 'GİDER (ÖDEME)',
        "Açıklama": t.description,
        "Tutar (TL)": t.amount
    }));

    const wsTx = XLSX.utils.json_to_sheet(txRows);
    wsTx['!cols'] = [{ wch: 12 }, { wch: 8 }, { wch: 20 }, { wch: 50 }, { wch: 15 }];
    XLSX.utils.book_append_sheet(wb, wsTx, "Kasa_Hareketleri");

    // Dosyayı İndir
    XLSX.writeFile(wb, `OSGB_Rapor_${period}_${dateStr}.xlsx`);
  };

  return (
    /* 
      PRINT CONFIGURATION:
      - Screen: Fixed modal with scroll. Added overflow-x-auto for horizontal scroll on small screens.
      - Print: Static positioning, visible overflow.
    */
    <div className="fixed inset-0 bg-slate-950/90 z-50 overflow-y-auto overflow-x-auto print:static print:inset-auto print:bg-white print:z-auto print:h-auto print:overflow-visible print:block">

      {/* --- Screen Controls (Hidden on Print) --- */}
      <div className="sticky top-0 left-0 right-0 z-50 bg-slate-900/95 backdrop-blur border-b border-slate-800 px-4 py-3 flex justify-between items-center print:hidden shadow-lg w-full min-w-[320px]">
        <div className="flex items-center space-x-4">
           <div className="flex bg-slate-800 rounded-lg p-1 border border-slate-700">
              <button 
                onClick={() => setPeriod('daily')}
                className={`px-3 py-1.5 rounded text-sm font-medium transition-all ${period === 'daily' ? 'bg-blue-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
              >
                Günlük
              </button>
              <button 
                onClick={() => setPeriod('weekly')}
                className={`px-3 py-1.5 rounded text-sm font-medium transition-all ${period === 'weekly' ? 'bg-blue-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
              >
                Haftalık
              </button>
              <button 
                onClick={() => setPeriod('monthly')}
                className={`px-3 py-1.5 rounded text-sm font-medium transition-all ${period === 'monthly' ? 'bg-blue-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
              >
                Aylık
              </button>
           </div>
           <span className="text-slate-500 text-sm hidden md:inline">|</span>
           <span className="text-slate-400 text-sm hidden md:inline">
              Önizleme Modu (Yatay)
           </span>
        </div>
        <div className="flex items-center space-x-3">
           <button 
             onClick={handleDownloadExcel}
             className="flex items-center space-x-2 bg-green-600 hover:bg-green-500 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-lg shadow-green-900/20 transition-all border border-green-500/50"
           >
             <FileSpreadsheet className="w-4 h-4" />
             <span>Excel İndir</span>
           </button>
           <button 
             onClick={() => window.print()}
             className="flex items-center space-x-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-lg transition-all"
           >
             <Printer className="w-4 h-4" />
             <span>Yazdır</span>
           </button>
           <button 
             onClick={() => onClose()}
             className="p-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-lg border border-slate-700 transition-colors"
           >
             <X className="w-5 h-5" />
           </button>
        </div>
      </div>

      {/* --- Report Container --- */}
      {/* Changed Width to 297mm (A4 Landscape) */}
      <div className="flex justify-center py-8 px-4 print:p-0 print:block print:w-full min-w-min">
        <div className="bg-white text-slate-900 w-[297mm] min-h-[210mm] shadow-2xl box-border relative print:w-full print:max-w-none print:min-h-0 print:h-auto print:shadow-none print:overflow-visible print:rounded-none">

           {/* Top Color Bar */}
           <div className="h-2 w-full bg-blue-900 print:bg-blue-900"></div>

           <div className="p-10 print:p-6 space-y-6">

              {/* --- REPORT HEADER & SUMMARIES (Prints at Top of Page 1) --- */}
              <div className="print:break-inside-avoid">

                  {/* Header */}
                  <div className="flex justify-between items-start border-b-2 border-slate-100 pb-4 mb-6">
                     <div className="flex items-center space-x-3">
                        {settings?.companyLogo ? (
                            <img src={settings.companyLogo} alt="Firma Logosu" className="h-16 w-auto object-contain" />
                        ) : (
                            <div className="p-3 bg-blue-50 rounded-lg border border-blue-100">
                              <Stethoscope className="w-8 h-8 text-blue-900" />
                            </div>
                        )}

                        {!settings?.companyLogo && (
                            <div>
                            <h1 className="text-xl font-bold text-slate-900 tracking-tight">OSGB PRO</h1>
                            <p className="text-xs text-slate-500 font-medium uppercase tracking-widest">Tetkik Takip Sistemi</p>
                            </div>
                        )}
                     </div>
                     <div className="text-right">
                        <h2 className="text-lg font-bold text-slate-900 uppercase tracking-tight">{getTitle()}</h2>
                        <p className="text-xs text-slate-500 mt-1">Rapor No: #{Math.floor(Math.random() * 100000)}</p>
                        <p className="text-xs text-slate-500">Oluşturulma: {now.toLocaleDateString()} {now.toLocaleTimeString()}</p>
                     </div>
                  </div>

                  {/* Info Grid (Horizontal Layout for Landscape) */}
                  <div className="grid grid-cols-2 gap-8 mb-6">
                      <div className="bg-slate-50 rounded border border-slate-200 p-3 flex justify-between items-center text-sm print:bg-transparent print:border-slate-300">
                          <div>
                             <span className="text-slate-500 font-medium block text-xs uppercase mb-1">Rapor Periyodu</span>
                             <span className="font-bold text-slate-800">
                                {dateRange.start.toLocaleDateString()} - {dateRange.end.toLocaleDateString()}
                             </span>
                          </div>
                      </div>
                      <div className="bg-slate-50 rounded border border-slate-200 p-3 flex justify-between items-center text-sm print:bg-transparent print:border-slate-300">
                          <div className="text-right w-full">
                             <span className="text-slate-500 font-medium block text-xs uppercase mb-1">Şube / Birim</span>
                             <span className="font-bold text-slate-800">Merkez Ofis / Kasa</span>
                          </div>
                      </div>
                  </div>

                  <div className="grid grid-cols-2 gap-8">
                      {/* Left Side: Payment Breakdown & Company Stats */}
                      <div className="space-y-6">
                          {/* Payment Methods Breakdown */}
                          <div>
                             <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 flex items-center">
                                <Wallet className="w-3.5 h-3.5 mr-1" />
                                Tahsilat & Ciro Dağılımı
                             </h3>
                             <div className="grid grid-cols-3 gap-2">
                                <div className="p-3 rounded border border-emerald-200 bg-emerald-50 flex flex-col justify-between print:border-emerald-300">
                                   <div className="flex justify-between items-start mb-2">
                                      <p className="text-[9px] text-emerald-600 font-bold uppercase">ELDEN NAKİT</p>
                                      <Banknote className="w-4 h-4 text-emerald-600" />
                                   </div>
                                   <p className="text-lg font-bold text-emerald-700">₺{reportData.totalReferralCash.toLocaleString()}</p>
                                </div>

                                <div className="p-3 rounded border border-purple-200 bg-purple-50 flex flex-col justify-between print:border-purple-300">
                                   <div className="flex justify-between items-start mb-2">
                                      <p className="text-[9px] text-purple-600 font-bold uppercase">ELDEN POS</p>
                                      <CreditCard className="w-4 h-4 text-purple-600" />
                                   </div>
